{
  "name": "Pastelería Pro",
  "description": "Una suite de gestión integral para pastelerías que incluye un Chef AI asistente, gestión de pedidos y control de inventario en tiempo real."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum OrderStatus {
  PENDING = 'Pendiente',
  BAKING = 'En Horno',
  READY = 'Listo',
  DELIVERED = 'Entregado'
}

export interface Order {
  id: string;
  customerName: string;
  items: string[];
  total: number;
  status: OrderStatus;
  date: string;
}

export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  threshold: number;
  category: 'Ingrediente' | 'Empaque' | 'Decoración';
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  CHEF = 'CHEF',
  ORDERS = 'ORDERS',
  INVENTORY = 'INVENTORY'
}

import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { ChatMessage } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
Eres "Chef Pierre", un maestro pastelero de renombre mundial y experto consultor para la aplicación "Pastelería Pro".
Tu objetivo es ayudar al usuario (el dueño o pastelero principal) con:
1. Recetas precisas (ingredientes en gramos, pasos detallados).
2. Resolución de problemas (ej: "¿Por qué mi bizcocho se hundió?").
3. Sugerencias de decoración y presentación.
4. Consejos de gestión de inventario basados en tendencias.

Tus respuestas deben ser:
- Profesionales pero cálidas y alentadoras.
- Estructuradas (usa listas y negritas).
- En español.

Si te preguntan por algo fuera de la cocina o el negocio de pastelería, redirige amablemente el tema a la pastelería.
`;

let chatSession: Chat | null = null;

export const getChefResponse = async (history: ChatMessage[], newMessage: string): Promise<string> => {
  try {
    if (!chatSession) {
      chatSession = ai.chats.create({
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
        },
        // We initialize history mapping simple roles to the API expected format if needed,
        // but for a fresh session, we rely on the internal state of the Chat object.
        // If we needed to restore history:
        // history: history.map(h => ({ role: h.role, parts: [{ text: h.text }] }))
      });
    }

    const result: GenerateContentResponse = await chatSession.sendMessage({
      message: newMessage
    });

    return result.text || "Lo siento, tuve un problema pensando en esa receta. ¿Podrías repetirlo?";
  } catch (error) {
    console.error("Error communicating with Gemini:", error);
    return "Disculpa, mi horno mental está un poco sobrecalentado. Por favor, intenta de nuevo en un momento.";
  }
};

import React from 'react';

interface StatsCardProps {
  title: string;
  value: string | number;
  icon: React.ReactNode;
  trend?: string;
  trendUp?: boolean;
  color: string;
}

export const StatsCard: React.FC<StatsCardProps> = ({ title, value, icon, trend, trendUp, color }) => {
  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-start justify-between transition-transform hover:scale-[1.02]">
      <div>
        <p className="text-sm font-medium text-slate-500">{title}</p>
        <h3 className="text-3xl font-bold text-slate-800 mt-2">{value}</h3>
        {trend && (
          <p className={`text-xs font-medium mt-2 flex items-center ${trendUp ? 'text-green-600' : 'text-red-500'}`}>
            {trendUp ? '↑' : '↓'} {trend}
            <span className="text-slate-400 ml-1">vs mes anterior</span>
          </p>
        )}
      </div>
      <div className={`p-3 rounded-xl ${color} text-white shadow-md`}>
        {icon}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, ChefHat, Bot, User, Sparkles } from 'lucide-react';
import { getChefResponse } from '../services/geminiService';
import { ChatMessage } from '../types';

export const ChefChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'model',
      text: '¡Bonjour! Soy Chef Pierre. ¿En qué puedo ayudarte hoy? ¿Necesitas una nueva receta de macarons o consejos para tu masa madre?',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await getChefResponse(messages, userMsg.text);
      const modelMsg: ChatMessage = { role: 'model', text: responseText, timestamp: new Date() };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-2rem)] md:h-[calc(100vh-3rem)] max-w-4xl mx-auto bg-white rounded-3xl shadow-lg border border-rose-100 overflow-hidden">
      {/* Header */}
      <div className="bg-rose-500 p-4 flex items-center justify-between text-white">
        <div className="flex items-center gap-3">
          <div className="bg-white/20 p-2 rounded-full">
            <ChefHat size={24} />
          </div>
          <div>
            <h2 className="font-bold text-lg">Chef Pierre AI</h2>
            <p className="text-xs text-rose-100 flex items-center gap-1">
              <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
              En línea
            </p>
          </div>
        </div>
        <Sparkles className="text-yellow-300 opacity-75" />
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`flex items-start gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${
              msg.role === 'user' ? 'bg-indigo-600' : 'bg-rose-500'
            }`}>
              {msg.role === 'user' ? <User size={20} className="text-white" /> : <Bot size={20} className="text-white" />}
            </div>
            <div className={`max-w-[80%] p-4 rounded-2xl shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-slate-700 rounded-tl-none border border-slate-100'
            }`}>
              <div className="whitespace-pre-wrap leading-relaxed text-sm">
                {msg.text}
              </div>
              <p className={`text-[10px] mt-2 text-right ${msg.role === 'user' ? 'text-indigo-200' : 'text-slate-400'}`}>
                {msg.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-center gap-2 text-slate-400 text-sm ml-14">
            <div className="w-2 h-2 bg-rose-400 rounded-full animate-bounce"></div>
            <div className="w-2 h-2 bg-rose-400 rounded-full animate-bounce delay-100"></div>
            <div className="w-2 h-2 bg-rose-400 rounded-full animate-bounce delay-200"></div>
            Chef Pierre está escribiendo...
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex items-center gap-2 bg-slate-50 rounded-full px-4 py-2 border border-slate-200 focus-within:border-rose-300 focus-within:ring-2 focus-within:ring-rose-100 transition-all">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyPress}
            placeholder="Pregunta sobre recetas, técnicas o inventario..."
            className="flex-1 bg-transparent border-none outline-none text-slate-700 placeholder:text-slate-400"
            disabled={isLoading}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className="p-2 bg-rose-500 hover:bg-rose-600 disabled:bg-slate-300 rounded-full text-white transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Order, OrderStatus } from '../types';
import { Plus, Search, Clock, CheckCircle, Truck, Flame } from 'lucide-react';

const MOCK_ORDERS: Order[] = [
  { id: 'ORD-001', customerName: 'María García', items: ['Tarta de Chocolate', '12 Cupcakes Vainilla'], total: 45.50, status: OrderStatus.BAKING, date: '2023-10-24 10:30' },
  { id: 'ORD-002', customerName: 'Restaurante El Sol', items: ['20 Croissants', '5 Barras Pan Artesanal'], total: 32.00, status: OrderStatus.READY, date: '2023-10-24 09:15' },
  { id: 'ORD-003', customerName: 'Juan Pérez', items: ['Pastel de Bodas (3 Pisos)'], total: 250.00, status: OrderStatus.PENDING, date: '2023-10-25 14:00' },
  { id: 'ORD-004', customerName: 'Café Central', items: ['30 Galletas Avena', '10 Brownies'], total: 55.00, status: OrderStatus.DELIVERED, date: '2023-10-23 16:45' },
];

export const Orders: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [filter, setFilter] = useState('Todas');

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case OrderStatus.BAKING: return 'bg-orange-100 text-orange-800 border-orange-200';
      case OrderStatus.READY: return 'bg-green-100 text-green-800 border-green-200';
      case OrderStatus.DELIVERED: return 'bg-slate-100 text-slate-800 border-slate-200';
    }
  };

  const getStatusIcon = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return <Clock size={14} />;
      case OrderStatus.BAKING: return <Flame size={14} />;
      case OrderStatus.READY: return <CheckCircle size={14} />;
      case OrderStatus.DELIVERED: return <Truck size={14} />;
    }
  };

  const handleStatusChange = (id: string) => {
    setOrders(orders.map(o => {
      if (o.id === id) {
        // Simple cycle for demo
        const nextStatus = 
          o.status === OrderStatus.PENDING ? OrderStatus.BAKING :
          o.status === OrderStatus.BAKING ? OrderStatus.READY :
          o.status === OrderStatus.READY ? OrderStatus.DELIVERED : OrderStatus.DELIVERED;
        return { ...o, status: nextStatus };
      }
      return o;
    }));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Pedidos</h2>
          <p className="text-slate-500">Gestiona el flujo de trabajo de la pastelería.</p>
        </div>
        <button className="flex items-center gap-2 bg-rose-500 hover:bg-rose-600 text-white px-4 py-2 rounded-lg shadow-md transition-all">
          <Plus size={18} />
          Nuevo Pedido
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        {/* Filters */}
        <div className="p-4 border-b border-slate-100 flex flex-col sm:flex-row gap-4 justify-between items-center bg-slate-50/50">
          <div className="flex items-center bg-white border border-slate-200 rounded-lg px-3 py-2 w-full sm:w-64">
            <Search size={18} className="text-slate-400 mr-2" />
            <input 
              type="text" 
              placeholder="Buscar pedido o cliente..." 
              className="bg-transparent border-none outline-none text-sm w-full"
            />
          </div>
          <div className="flex gap-2">
            {['Todas', 'Pendiente', 'En Horno', 'Listo'].map(f => (
              <button
                key={f}
                onClick={() => setFilter(f)}
                className={`px-3 py-1.5 text-xs font-medium rounded-full transition-colors ${
                  filter === f ? 'bg-rose-100 text-rose-700' : 'text-slate-500 hover:bg-slate-100'
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-slate-600">
            <thead className="bg-slate-50 text-xs uppercase font-semibold text-slate-500">
              <tr>
                <th className="px-6 py-4">ID Pedido</th>
                <th className="px-6 py-4">Cliente</th>
                <th className="px-6 py-4">Detalles</th>
                <th className="px-6 py-4">Total</th>
                <th className="px-6 py-4">Estado</th>
                <th className="px-6 py-4">Acción</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {orders.map((order) => (
                <tr key={order.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4 font-medium text-slate-800">{order.id}</td>
                  <td className="px-6 py-4">{order.customerName}</td>
                  <td className="px-6 py-4">
                    <ul className="list-disc list-inside text-xs text-slate-500">
                      {order.items.map((item, idx) => <li key={idx}>{item}</li>)}
                    </ul>
                  </td>
                  <td className="px-6 py-4 font-semibold">${order.total.toFixed(2)}</td>
                  <td className="px-6 py-4">
                    <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium border ${getStatusColor(order.status)}`}>
                      {getStatusIcon(order.status)}
                      {order.status}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    {order.status !== OrderStatus.DELIVERED && (
                      <button 
                        onClick={() => handleStatusChange(order.id)}
                        className="text-rose-600 hover:text-rose-800 font-medium text-xs hover:underline"
                      >
                        Avanzar Estado
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutGrid, ChefHat, ShoppingBag, Box, Menu, X, DollarSign, TrendingUp, Users } from 'lucide-react';
import { AppView } from './types';
import { StatsCard } from './components/StatsCard';
import { ChefChat } from './components/ChefChat';
import { Orders } from './components/Orders';
import { Inventory } from './components/Inventory';
import { AreaChart, Area, ResponsiveContainer, Tooltip as ChartTooltip, XAxis, YAxis } from 'recharts';

const SALES_DATA = [
  { day: 'Lun', sales: 450 },
  { day: 'Mar', sales: 620 },
  { day: 'Mie', sales: 500 },
  { day: 'Jue', sales: 850 },
  { day: 'Vie', sales: 1200 },
  { day: 'Sab', sales: 1800 },
  { day: 'Dom', sales: 1400 },
];

function App() {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const renderContent = () => {
    switch (currentView) {
      case AppView.CHEF:
        return <ChefChat />;
      case AppView.ORDERS:
        return <Orders />;
      case AppView.INVENTORY:
        return <Inventory />;
      case AppView.DASHBOARD:
      default:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold text-slate-800">Panel Principal</h2>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              <StatsCard 
                title="Ventas Hoy" 
                value="$1,450" 
                icon={<DollarSign size={20} />} 
                color="bg-emerald-500" 
                trend="12%" 
                trendUp={true} 
              />
              <StatsCard 
                title="Pedidos Pendientes" 
                value="8" 
                icon={<ShoppingBag size={20} />} 
                color="bg-orange-500" 
              />
              <StatsCard 
                title="Stock Bajo" 
                value="3 Items" 
                icon={<Box size={20} />} 
                color="bg-red-500" 
                trend="2" 
                trendUp={false} 
              />
              <StatsCard 
                title="Clientes Nuevos" 
                value="12" 
                icon={<Users size={20} />} 
                color="bg-blue-500" 
                trend="5%" 
                trendUp={true} 
              />
            </div>

            {/* Sales Chart Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-bold text-lg text-slate-800 flex items-center gap-2">
                  <TrendingUp size={20} className="text-rose-500"/>
                  Rendimiento Semanal
                </h3>
                <select className="bg-slate-50 border border-slate-200 text-sm rounded-lg px-3 py-1 outline-none focus:ring-2 focus:ring-rose-200">
                  <option>Esta Semana</option>
                  <option>Mes Pasado</option>
                </select>
              </div>
              <div className="h-[300px]">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={SALES_DATA}>
                    <defs>
                      <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.2}/>
                        <stop offset="95%" stopColor="#f43f5e" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <XAxis dataKey="day" axisLine={false} tickLine={false} tick={{fill: '#94a3b8'}} dy={10} />
                    <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8'}} tickFormatter={(val) => `$${val}`} />
                    <ChartTooltip 
                      contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} 
                    />
                    <Area 
                      type="monotone" 
                      dataKey="sales" 
                      stroke="#f43f5e" 
                      strokeWidth={3}
                      fillOpacity={1} 
                      fill="url(#colorSales)" 
                    />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Quick Actions / Recent Activity could go here */}
              <div 
                onClick={() => setCurrentView(AppView.CHEF)}
                className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-2xl p-6 text-white cursor-pointer transform transition-all hover:scale-[1.02] shadow-lg shadow-indigo-200"
              >
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-xl font-bold mb-2">Consulta al Chef AI</h3>
                    <p className="text-indigo-100 text-sm mb-4">¿Dudas con una receta? Pierre está listo para ayudarte.</p>
                    <span className="bg-white/20 px-4 py-2 rounded-lg text-sm font-medium backdrop-blur-sm">Iniciar Chat</span>
                  </div>
                  <ChefHat size={48} className="opacity-50" />
                </div>
              </div>

               <div 
                onClick={() => setCurrentView(AppView.ORDERS)}
                className="bg-gradient-to-br from-rose-500 to-orange-500 rounded-2xl p-6 text-white cursor-pointer transform transition-all hover:scale-[1.02] shadow-lg shadow-rose-200"
              >
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-xl font-bold mb-2">Gestión Rápida</h3>
                    <p className="text-rose-100 text-sm mb-4">Tienes 3 pedidos que requieren horneado inmediato.</p>
                    <span className="bg-white/20 px-4 py-2 rounded-lg text-sm font-medium backdrop-blur-sm">Ver Pedidos</span>
                  </div>
                  <ShoppingBag size={48} className="opacity-50" />
                </div>
              </div>
            </div>
          </div>
        );
    }
  };

  const NavItem = ({ view, icon, label }: { view: AppView, icon: React.ReactNode, label: string }) => (
    <button
      onClick={() => {
        setCurrentView(view);
        setIsSidebarOpen(false); // Close mobile menu on select
      }}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 ${
        currentView === view 
          ? 'bg-rose-50 text-rose-600 font-semibold shadow-sm' 
          : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
      }`}
    >
      {icon}
      <span>{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex bg-[#fdf2f8]">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/20 backdrop-blur-sm z-40 lg:hidden"
          onClick={toggleSidebar}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed lg:sticky top-0 h-screen w-64 bg-white border-r border-slate-100 p-6 z-50 transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="flex items-center gap-3 mb-10 px-2">
          <div className="w-8 h-8 bg-rose-500 rounded-lg flex items-center justify-center text-white font-bold">
            P
          </div>
          <h1 className="text-xl font-bold text-slate-800">Pastelería Pro</h1>
        </div>

        <nav className="space-y-2">
          <NavItem view={AppView.DASHBOARD} icon={<LayoutGrid size={20} />} label="Panel" />
          <NavItem view={AppView.CHEF} icon={<ChefHat size={20} />} label="Chef AI" />
          <NavItem view={AppView.ORDERS} icon={<ShoppingBag size={20} />} label="Pedidos" />
          <NavItem view={AppView.INVENTORY} icon={<Box size={20} />} label="Inventario" />
        </nav>

        <div className="absolute bottom-8 left-6 right-6">
          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <div className="flex items-center gap-3 mb-3">
              <div className="w-8 h-8 rounded-full bg-rose-100 flex items-center justify-center text-rose-600 font-bold text-xs">
                JS
              </div>
              <div>
                <p className="text-sm font-semibold text-slate-700">Juan Sweet</p>
                <p className="text-xs text-slate-400">Dueño</p>
              </div>
            </div>
            <button className="w-full text-xs text-slate-500 hover:text-rose-500 font-medium">
              Cerrar Sesión
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 lg:p-8 overflow-x-hidden">
        {/* Mobile Header */}
