import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus } from '../types';
import { STATUS_COLORS } from '../constants';
import { Plus, X, Clock, AlertCircle, User } from 'lucide-react';
import { formatCurrency } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrderStatus } = useBakery();
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New Order State
  const [customerId, setCustomerId] = useState('');
  const [customerNameInput, setCustomerNameInput] = useState(''); // For new/manual customers
  const [isExistingCustomer, setIsExistingCustomer] = useState(true);

  const [date, setDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);

  // Error state for validation
  const [error, setError] = useState('');

  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    setSelectedProduct('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrder = () => {
    setError('');

    // Customer Validation
    let finalCustomerName = '';
    let finalCustomerId = '';

    if (isExistingCustomer) {
        if (!customerId) {
            setError('Por favor selecciona un cliente de la lista.');
            return;
        }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) {
            setError('Por favor ingresa el nombre del cliente.');
            return;
        }
        finalCustomerName = customerNameInput;
        // In a more complex app, we might create the customer here automatically.
        finalCustomerId = 'temp_' + Date.now(); 
    }

    if(!date) {
      setError('Por favor selecciona una fecha de entrega.');
      return;
    }
    if(cart.length === 0) {
      setError('Debes agregar al menos un producto a la lista con el botón "+".');
      return;
    }

    // Calculate total
    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const newOrder: Order = {
      id: Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: 'Pendiente',
      items: cart,
      totalPrice: total
    };

    addOrder(newOrder);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
  };

  const statusOptions: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Pedidos</h2>

        {/* Desktop Button */}
        <button 
          onClick={() => setIsModalOpen(true)}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          <Plus size={18} /> Nuevo Pedido
        </button>
      </div>

      {/* Mobile Floating Action Button (FAB) */}
      <button 
        onClick={() => setIsModalOpen(true)}
        className="md:hidden fixed bottom-20 right-4 bg-indigo-600 text-white p-4 rounded-full shadow-lg z-40 hover:bg-indigo-700 transition-colors"
        aria-label="Nuevo Pedido"
      >
        <Plus size={24} />
      </button>

      <div className="grid gap-4">
        {orders.length === 0 && <p className="text-center text-slate-400 py-10">No hay pedidos registrados.</p>}
        {orders.map(order => (
          <div key={order.id} className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row justify-between gap-4">
            <div className="flex-1">
              <div className="flex justify-between items-start">
                 <div className="flex items-center gap-2">
                    <User size={16} className="text-indigo-500" />
                    <h3 className={`font-bold text-lg text-slate-800`}>
                        {order.customerName}
                    </h3>
                 </div>
                 <span className="text-sm text-slate-500 flex items-center gap-1">
                    <Clock size={14} /> {order.deliveryDate}
                 </span>
              </div>
              <ul className="mt-2 text-sm text-slate-600 space-y-1 ml-6">
                {order.items.map((item, idx) => {
                  const pName = products.find(p => p.id === item.productId)?.name;
                  return <li key={idx} className="flex gap-2"><span>{item.quantity}x</span> <span>{pName}</span></li>
                })}
              </ul>
              <div className="mt-2 ml-6 font-bold text-slate-800">Total: {formatCurrency(order.totalPrice)}</div>
            </div>

            <div className="flex flex-col gap-2 justify-center border-t md:border-t-0 md:border-l border-slate-100 pt-4 md:pt-0 md:pl-4 min-w-[200px]">
              <label className="text-xs text-slate-400 font-semibold uppercase">Estado</label>
              <select 
                className={`p-2 rounded-lg border text-sm font-medium ${STATUS_COLORS[order.status]}`}
                value={order.status}
                onChange={(e) => updateOrderStatus(order.id, e.target.value as OrderStatus)}
              >
                {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <p className="text-xs text-slate-400 mt-1">
                {order.status === 'Pagado' && '✓ Pago confirmado'}
                {order.status === 'Entregado' && '• Entregado (Por cobrar)'}
                {order.status === 'Completado' && '✓ Stock descontado'}
                {order.status === 'Pendiente' && '• En espera'}
                {order.status === 'En Proceso' && '• Cocinando...'}
              </p>
            </div>
          </div>
        ))}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white">
              <h3 className="font-bold">Nuevo Pedido</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">

               {/* Customer Selection Logic */}
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex gap-2 mb-2 text-sm">
                      <button 
                        onClick={() => setIsExistingCustomer(true)}
                        className={`flex-1 py-1 rounded ${isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100 text-slate-600'}`}
                      >
                        Seleccionar
                      </button>
                      <button 
                        onClick={() => setIsExistingCustomer(false)}
                        className={`flex-1 py-1 rounded ${!isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100 text-slate-600'}`}
                      >
                        Nuevo / Casual
                      </button>
                  </div>

                  {isExistingCustomer ? (
                      <select 
                        className="w-full p-2 border rounded focus:ring-2 focus:ring-indigo-500 outline-none"
                        value={customerId}
                        onChange={e => setCustomerId(e.target.value)}
                      >
                          <option value="">-- Buscar Cliente --</option>
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                  ) : (
                      <input 
                        className="w-full p-2 border rounded focus:ring-2 focus:ring-indigo-500 outline-none" 
                        value={customerNameInput} 
                        onChange={e => setCustomerNameInput(e.target.value)} 
                        placeholder="Nombre del cliente"
                      />
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700">Fecha de Entrega</label>
                  <input 
                    type="date" 
                    className="w-full p-2 border rounded focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={date} 
                    onChange={e => setDate(e.target.value)} 
                  />
               </div>

               <div className="bg-slate-50 p-4 rounded-lg">
                 <h4 className="font-medium text-slate-700 mb-2">Agregar Productos</h4>
                 <div className="flex gap-2 mb-2">
                    <select 
                        className="flex-1 p-2 border rounded text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                        value={selectedProduct} 
                        onChange={e => setSelectedProduct(e.target.value)}
                    >
                        <option value="">Seleccionar Producto...</option>
                        {products.map(p => <option key={p.id} value={p.id}>{p.name} ({formatCurrency(p.price)})</option>)}
                    </select>
                    <input 
                        type="number" 
                        min="1"
                        className="w-20 p-2 border rounded text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                        value={qty} 
                        onChange={e => setQty(e.target.value === '' ? '' : Math.max(1, Number(e.target.value)))} 
                    />
                    <button 
                        onClick={addToCart} 
                        className="bg-slate-800 text-white p-2 rounded hover:bg-slate-900 transition-colors"
                        disabled={!selectedProduct}
                    >
                        <Plus size={18} />
                    </button>
                 </div>

                 <div className="space-y-1">
                    {cart.length === 0 && (
                        <p className="text-xs text-slate-400 italic text-center py-2">No hay productos en la lista</p>
                    )}
                    {cart.map((item, i) => {
                        const pName = products.find(p => p.id === item.productId)?.name;
                        return (
                            <div key={i} className="flex justify-between text-sm bg-white p-2 rounded shadow-sm border border-slate-100">
                                <span>{item.quantity}x {pName}</span>
                                <button onClick={() => removeFromCart(i)} className="text-red-500 hover:text-red-700"><X size={14}/></button>
                            </div>
                        )
                    })}
                 </div>
               </div>

               {error && (
                 <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm flex items-center gap-2">
                   <AlertCircle size={16} className="shrink-0" />
                   {error}
                 </div>
               )}

               <button 
                onClick={handleCreateOrder} 
                className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-md"
               >
                Confirmar Pedido
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { ProductionRequirement, UnitType } from '../types';
import { toBaseUnit, formatStock } from '../utils/conversions';
import { Calendar, ClipboardList } from 'lucide-react';

export const Production: React.FC = () => {
  const { orders, products, ingredients } = useBakery();
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  // QUERY / LOGIC: Generate Production List
  const requirements = useMemo(() => {
    // 1. Filter orders for the date and exclude delivered ones (keep pending/in process)
    const dailyOrders = orders.filter(o => 
      o.deliveryDate === selectedDate && o.status !== 'Entregado' && o.status !== 'Completado'
    );

    const map = new Map<string, number>(); // ingredientId -> totalBaseAmount

    // 2. Iterate orders -> items -> product recipes
    dailyOrders.forEach(order => {
      order.items.forEach(orderItem => {
        const product = products.find(p => p.id === orderItem.productId);
        if(!product) return;

        product.recipe.forEach(recipeItem => {
           // Normalize to base unit (e.g. g or ml)
           const amountBase = toBaseUnit(recipeItem.quantity, recipeItem.unit);
           const totalNeeded = amountBase * orderItem.quantity;

           const current = map.get(recipeItem.ingredientId) || 0;
           map.set(recipeItem.ingredientId, current + totalNeeded);
        });
      });
    });

    // 3. Transform to view model
    const result: ProductionRequirement[] = [];
    map.forEach((totalNeeded, ingId) => {
      const ing = ingredients.find(i => i.id === ingId);
      if(ing) {
        result.push({
          ingredientId: ingId,
          ingredientName: ing.name,
          totalNeeded: totalNeeded,
          currentStock: ing.currentStock,
          unit: ing.unit,
          missing: Math.max(0, totalNeeded - ing.currentStock)
        });
      }
    });

    return result;
  }, [orders, products, ingredients, selectedDate]);

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ClipboardList /> Planificación de Producción
           </h2>
           <p className="text-slate-500 text-sm">Calcula la materia prima necesaria para los pedidos del día.</p>
        </div>
        <div className="flex items-center gap-2 bg-white p-2 rounded-lg border border-slate-200 shadow-sm">
           <Calendar size={18} className="text-indigo-600" />
           <input 
             type="date" 
             value={selectedDate}
             onChange={(e) => setSelectedDate(e.target.value)}
             className="outline-none text-slate-700 font-medium bg-transparent"
           />
        </div>
      </header>

      {requirements.length === 0 ? (
        <div className="bg-white rounded-xl p-8 text-center border-2 border-dashed border-slate-200 text-slate-400">
          No hay pedidos pendientes de producción para esta fecha.
        </div>
      ) : (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="p-4 bg-indigo-50 border-b border-indigo-100 text-indigo-800 text-sm">
            <span className="font-bold">Resumen:</span> Se calculó el total de materia prima para {orders.filter(o => o.deliveryDate === selectedDate && o.status !== 'Entregado' && o.status !== 'Completado').length} pedidos pendientes.
          </div>
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-semibold">
              <tr>
                <th className="px-6 py-4">Materia Prima</th>
                <th className="px-6 py-4 text-right">Cantidad Total Necesaria</th>
                <th className="px-6 py-4 text-right">Stock Disponible</th>
                <th className="px-6 py-4 text-center">Estado</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {requirements.map(req => {
                const isEnough = req.currentStock >= req.totalNeeded;
                return (
                  <tr key={req.ingredientId} className={!isEnough ? 'bg-red-50' : ''}>
                    <td className="px-6 py-4 font-medium text-slate-800">{req.ingredientName}</td>
                    <td className="px-6 py-4 text-right font-bold text-slate-700">
                      {formatStock(req.totalNeeded, req.unit)}
                    </td>
                    <td className="px-6 py-4 text-right text-slate-500">
                      {formatStock(req.currentStock, req.unit)}
                    </td>
                    <td className="px-6 py-4 text-center">
                      {isEnough ? (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                          Suficiente
                        </span>
                      ) : (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">
                          Faltan {formatStock(req.missing, req.unit)}
                        </span>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      <div className="bg-slate-100 p-4 rounded-lg text-xs text-slate-500">
        <strong>Nota Técnica:</strong> Esta lista consolida todas las recetas de los pedidos "Pendientes" o "En Proceso" para la fecha seleccionada. No incluye pedidos ya marcados como "Completados".
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Product, RecipeItem, UnitType, Ingredient } from '../types';
import { UNIT_OPTIONS } from '../constants';
import { Plus, Trash2, ChevronDown, ChevronUp, Calculator, DollarSign, ArrowRight, Edit2, Save, X } from 'lucide-react';
import { formatStock, fromBaseUnit, formatCurrency } from '../utils/conversions';

export const Recipes: React.FC = () => {
  const { products, ingredients, addProduct, updateProduct, deleteProduct } = useBakery();
  const [isCreating, setIsCreating] = useState(false);

  // State to track if we are editing an existing product
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [productName, setProductName] = useState('');
  const [productPrice, setProductPrice] = useState<number | ''>('');
  const [recipeItems, setRecipeItems] = useState<RecipeItem[]>([]);

  // Costing Calculator State
  const [fixedCosts, setFixedCosts] = useState<number | ''>('');
  const [estimatedUnits, setEstimatedUnits] = useState<number | ''>('');

  // Temp state for adding ingredient to recipe
  const [selectedIngId, setSelectedIngId] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [selectedUnit, setSelectedUnit] = useState<UnitType>(UnitType.GRAMS);

  const handleAddIngredient = () => {
    if(!selectedIngId || !amount || Number(amount) <= 0) return;

    setRecipeItems([...recipeItems, {
      ingredientId: selectedIngId,
      quantity: Number(amount),
      unit: selectedUnit
    }]);

    setAmount('');
    setSelectedIngId('');
  };

  const handleUpdateItemQuantity = (index: number, newQty: string) => {
    const val = newQty === '' ? 0 : parseFloat(newQty);
    const updatedItems = [...recipeItems];
    updatedItems[index].quantity = val;
    setRecipeItems(updatedItems);
  };

  const handleDeleteItem = (index: number) => {
    const updatedItems = recipeItems.filter((_, i) => i !== index);
    setRecipeItems(updatedItems);
  };

  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setProductName(product.name);
    setProductPrice(product.price);
    // Clone array to allow editing without mutating original until save
    setRecipeItems(product.recipe.map(item => ({...item}))); 

    // Reset calculator fields as they are transient
    setFixedCosts('');
    setEstimatedUnits('');

    setIsCreating(true);
  };

  const handleSaveProduct = () => {
    if(!productName || recipeItems.length === 0 || !productPrice) return;

    // Filter out items with 0 quantity just in case
    const validItems = recipeItems.filter(item => item.quantity > 0);

    if (editingProduct) {
        // Update Existing
        const updatedProd: Product = {
            ...editingProduct,
            name: productName,
            price: Number(productPrice),
            recipe: validItems
        };
        updateProduct(updatedProd);
    } else {
        // Create New
        const newProd: Product = {
            id: Date.now().toString(),
            name: productName,
            price: Number(productPrice),
            recipe: validItems
        };
        addProduct(newProd);
    }

    closeForm();
  };

  const closeForm = () => {
    setIsCreating(false);
    setEditingProduct(null);
    resetForm();
  };

  const resetForm = () => {
    setProductName('');
    setProductPrice('');
    setRecipeItems([]);
    setFixedCosts('');
    setEstimatedUnits('');
    setEditingProduct(null);
  };

  // Cost Estimation
  const calculateVariableCost = (items: RecipeItem[]) => {
    return items.reduce((acc, item) => {
      const ing = ingredients.find(i => i.id === item.ingredientId);
      if(!ing) return acc;

      // Cost is stored per ing.unit (Display unit).
      // We need to match item.quantity (item.unit) to ing.unit.

      // Case 1: Same unit
      if (item.unit === ing.unit) {
          return acc + (item.quantity * ing.costPerUnit);
      }

      // Case 2: Different units (e.g. g vs kg)

      // 1. Get Base Quantity of Item
      let itemBase = 0;
      switch(item.unit) {
          case UnitType.KILOGRAMS: itemBase = item.quantity * 1000; break;
          case UnitType.LITERS: itemBase = item.quantity * 1000; break;
          default: itemBase = item.quantity;
      }

      // 2. Convert Base Quantity to Ing Unit
      const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);

      return acc + (itemQtyInIngUnit * ing.costPerUnit);
    }, 0);
  };

  const cvu = calculateVariableCost(recipeItems);

  // Suggested Price Formula
  // Price = (CVU + (CFT / Q)) / (1 - 0.60)
  // Margin 60%
  const calculateSuggestedPrice = () => {
      const cft = Number(fixedCosts) || 0;
      const q = Number(estimatedUnits) || 1; // avoid div by 0

      const fixedCostPerUnit = cft / q;
      const totalUnitCost = cvu + fixedCostPerUnit;

      // Margin 60% -> Cost is 40% of price
      const price = totalUnitCost / (1 - 0.60);
      return Math.round(price); // Round to integer for CLP
  };

  const suggestedPrice = calculateSuggestedPrice();

  const toggleCreate = () => {
    if(isCreating) {
        closeForm();
    } else {
        resetForm();
        setIsCreating(true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Recetas y Productos</h2>
        {/* Desktop Button */}
        <button 
          onClick={toggleCreate}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          {isCreating ? 'Cancelar' : <><Plus size={18} /> Nuevo Producto</>}
        </button>
      </div>

      {/* Mobile Floating Action Button (FAB) */}
      <button 
        onClick={toggleCreate}
        className={`md:hidden fixed bottom-20 right-4 p-4 rounded-full shadow-lg z-40 transition-colors ${isCreating ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white`}
        aria-label={isCreating ? "Cancelar" : "Nuevo Producto"}
      >
        {isCreating ? <X size={24} /> : <Plus size={24} />}
      </button>

      {isCreating && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-lg space-y-6 animate-in fade-in slide-in-from-top-4">
          <h3 className="font-bold text-lg text-slate-800 border-b pb-2">
              {editingProduct ? 'Editar Receta' : 'Crear Nueva Receta'}
          </h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1">Nombre del Producto</label>
                  <input 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={productName} 
                    onChange={e => setProductName(e.target.value)} 
                    placeholder="Ej: Tarta de Frutilla"
                  />
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                    <h4 className="font-medium text-slate-700 mb-3 text-sm uppercase tracking-wide">Ingredientes (Costo Variable)</h4>

                    <div className="flex flex-col gap-2 mb-4 bg-white p-3 rounded border border-slate-200 shadow-sm">
                      <label className="text-xs font-bold text-slate-500">Agregar Ingrediente</label>
                      <div className="grid grid-cols-12 gap-2 items-end">
                          <div className="col-span-12 sm:col-span-5">
                            <select 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500 bg-white"
                                value={selectedIngId}
                                onChange={e => {
                                const ing = ingredients.find(i => i.id === e.target.value);
                                setSelectedIngId(e.target.value);
                                if(ing) setSelectedUnit(ing.unit);
                                }}
                            >
                                <option value="">-- Seleccionar --</option>
                                {ingredients.map(i => <option key={i.id} value={i.id}>{i.name} ({formatCurrency(i.costPerUnit)}/{i.unit})</option>)}
                            </select>
                          </div>

                          <div className="col-span-4 sm:col-span-3">
                              <input 
                                type="number" 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500" 
                                placeholder="Cant."
                                value={amount}
                                onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))}
                              />
                          </div>

                          <div className="col-span-6 sm:col-span-3">
                              <select 
                                className="w-full p-2 border rounded text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={selectedUnit}
                                onChange={e => setSelectedUnit(e.target.value as UnitType)}
                              >
                                {/* Show all units to allow flexibility */}
                                {UNIT_OPTIONS.map(u => (
                                  <option key={u.value} value={u.value}>{u.label}</option>
                                ))}
                              </select>
                          </div>

                          <div className="col-span-2 sm:col-span-1">
                              <button 
                                onClick={handleAddIngredient}
                                disabled={!selectedIngId}
                                className="w-full bg-indigo-600 text-white p-2 rounded hover:bg-indigo-700 disabled:bg-slate-300 flex items-center justify-center transition-colors h-[38px]"
                              >
                                <Plus size={18} />
                              </button>
                          </div>
                      </div>
                    </div>

                    {recipeItems.length > 0 ? (
                       <div className="space-y-2 mb-2">
                         <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 px-2">
                            <div className="col-span-5">Ingrediente</div>
                            <div className="col-span-5 text-right">Cantidad</div>
                            <div className="col-span-2 text-center"></div>
                         </div>
                         {recipeItems.map((item, idx) => {
                           const ingName = ingredients.find(i => i.id === item.ingredientId)?.name || 'Ingrediente eliminado';
                           return (
                             <div key={idx} className="grid grid-cols-12 gap-2 items-center bg-white p-2 border rounded shadow-sm text-sm">
                               <div className="col-span-5 truncate font-medium text-slate-700" title={ingName}>
                                 {ingName}
                                </div>
                               <div className="col-span-5 flex justify-end items-center gap-1">
                                 <input 
                                    type="number"
                                    min="0"
                                    step="any"
                                    className="w-20 p-1 border border-slate-200 rounded text-right focus:border-indigo-500 outline-none"
                                    value={item.quantity === 0 ? '' : item.quantity}
                                    onChange={(e) => handleUpdateItemQuantity(idx, e.target.value)}
                                 />
                                 <span className="text-xs text-slate-500 w-8">{item.unit}</span>
                               </div>
                               <div className="col-span-2 text-center">
                                 <button 
                                    onClick={() => handleDeleteItem(idx)} 
                                    className="text-red-400 hover:text-red-600 p-1 rounded-full hover:bg-red-50"
                                 >
                                    <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                           )
                         })}
                         <div className="flex justify-between items-center pt-3 border-t border-slate-200 mt-3">
                            <span className="text-slate-500 font-medium text-sm">Costo Variable Total (CVU):</span>
                            <span className="text-slate-800 font-bold text-lg">{formatCurrency(cvu)}</span>
                         </div>
                       </div>
                    ) : (
                        <p className="text-xs text-slate-400 italic text-center py-4">Agrega ingredientes para calcular el costo.</p>
                    )}
                </div>
            </div>

            <div className="space-y-4">
               {/* Pricing Calculator */}
               <div className="bg-indigo-50 p-5 rounded-xl border border-indigo-100">
                  <div className="flex items-center gap-2 mb-4 text-indigo-800">
                     <Calculator size={20} />
                     <h4 className="font-bold">Calculadora de Precios</h4>
                  </div>

                  <div className="space-y-3 mb-4">
                      <div className="grid grid-cols-2 gap-3">
                        <div>
                           <label className="text-xs font-semibold text-slate-500 block mb-1">Costos Fijos Asignados (CFT)</label>
                           <div className="relative">
                               <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400 text-xs">$</span>
                               <input 
                                 type="number" 
                                 className="w-full pl-5 p-2 border border-indigo-200 rounded text-sm focus:ring-1 focus:ring-indigo-500"
                                 placeholder="0"
                                 value={fixedCosts}
                                 onChange={e => setFixedCosts(e.target.value === '' ? '' : Number(e.target.value))}
                               />
                           </div>
                        </div>
                        <div>
                           <label className="text-xs font-semibold text-slate-500 block mb-1">Ventas Estimadas (Q)</label>
                           <input 
                             type="number" 
                             className="w-full p-2 border border-indigo-200 rounded text-sm focus:ring-1 focus:ring-indigo-500"
                             placeholder="Unidades/mes"
                             value={estimatedUnits}
                             onChange={e => setEstimatedUnits(e.target.value === '' ? '' : Number(e.target.value))}
                           />
                        </div>
                      </div>

                      <div className="bg-white p-3 rounded-lg border border-indigo-100 space-y-1">
                          <div className="flex justify-between text-xs text-slate-500">
                              <span>Costo Variable (CVU):</span>
                              <span>{formatCurrency(cvu)}</span>
                          </div>
                          <div className="flex justify-between text-xs text-slate-500">
                              <span>Costo Fijo Unitario (CFT/Q):</span>
                              <span>{formatCurrency((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0)}</span>
                          </div>
                          <div className="flex justify-between text-xs text-slate-800 font-semibold pt-1 border-t border-slate-100">
                              <span>Costo Total Unitario:</span>
                              <span>{formatCurrency(cvu + ((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0))}</span>
                          </div>
                      </div>

                      <div className="flex justify-between items-center bg-indigo-100 p-3 rounded-lg">
                          <div>
                              <span className="text-xs text-indigo-600 font-bold uppercase block">Precio Sugerido</span>
                              <span className="text-[10px] text-indigo-400">Margen 60%</span>
                          </div>
                          <div className="text-xl font-bold text-indigo-800">
                              {formatCurrency(suggestedPrice)}
                          </div>
                      </div>

                      <button 
                        onClick={() => setProductPrice(suggestedPrice)}
                        disabled={!isFinite(suggestedPrice) || suggestedPrice <= 0}
                        className="w-full py-1.5 text-xs bg-indigo-200 text-indigo-800 rounded font-semibold hover:bg-indigo-300 transition-colors disabled:opacity-50"
                      >
                         Usar Precio Sugerido
                      </button>
                  </div>

                  <div>
                    <label className="label text-sm font-bold text-slate-700 mb-1 block">Precio de Venta Final</label>
                    <div className="relative">
                        <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input 
                            type="number" 
                            className="w-full pl-9 p-3 border border-slate-300 rounded-lg text-lg font-bold text-slate-800" 
                            value={productPrice} 
                            onChange={e => setProductPrice(e.target.value === '' ? '' : Number(e.target.value))} 
                            placeholder="0"
                        />
                    </div>
                  </div>
               </div>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
             <button 
                onClick={handleSaveProduct}
                className="bg-green-600 text-white py-3 px-8 rounded-lg font-bold hover:bg-green-700 shadow-md flex items-center gap-2"
             >
                {editingProduct ? 'Actualizar Producto' : 'Guardar Producto'} <Save size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Product List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {products.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            ingredients={ingredients} 
            onEdit={handleEditClick}
          />
        ))}
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ 
    product: Product, 
    ingredients: Ingredient[], 
    onEdit: (p: Product) => void 
}> = ({ product, ingredients, onEdit }) => {
    const [expanded, setExpanded] = useState(false);
    const { deleteProduct } = useBakery();

    const handleDelete = (e: React.MouseEvent) => {
        // e.stopPropagation() is less critical now that buttons are structurally separated, 
        // but kept for safety.
        e.stopPropagation();
        if(window.confirm(`¿Estás seguro que deseas eliminar "${product.name}"? Esta acción no se puede deshacer.`)) {
            deleteProduct(product.id);
        }
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow">
            <div className="p-4 flex justify-between items-center hover:bg-slate-50">
                <div 
                    className="flex-1 cursor-pointer"
                    onClick={() => setExpanded(!expanded)}
                >
                    <h3 className="font-bold text-slate-800 text-lg">{product.name}</h3>
                    <p className="text-slate-500 text-sm flex items-center gap-2">
                        {product.recipe.length} ingredientes
                    </p>
                </div>
                <div className="flex items-center gap-3 pl-4">
                    <span className="font-bold text-emerald-600 text-lg bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100 whitespace-nowrap">
                        {formatCurrency(product.price)}
                    </span>
                    <button 
                        onClick={(e) => { e.stopPropagation(); onEdit(product); }}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                        title="Editar receta"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={handleDelete}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                        title="Eliminar receta"
                    >
                        <Trash2 size={18} />
                    </button>
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="p-1 text-slate-400"
                    >
                        {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </button>
                </div>
            </div>
            {expanded && (
                <div className="p-4 bg-slate-50 border-t border-slate-100 animate-in fade-in slide-in-from-top-1">
                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Fórmula (Unitario)</h4>
                    <ul className="space-y-2 text-sm">
                        {product.recipe.map((r, i) => {
                            const ing = ingredients.find(ing => ing.id === r.ingredientId);
                            // Calculate simple cost share for display
                            let costShare = 0;
                            if(ing) {
                                let itemBase = 0;
                                switch(r.unit) {
                                    case UnitType.KILOGRAMS: itemBase = r.quantity * 1000; break;
                                    case UnitType.LITERS: itemBase = r.quantity * 1000; break;
                                    default: itemBase = r.quantity;
                                }
                                const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);
                                costShare = itemQtyInIngUnit * ing.costPerUnit;
                            }

                            return (
                                <li key={i} className="flex justify-between items-center text-slate-700 p-2 bg-white rounded border border-slate-100">
                                    <span className="font-medium">{ing?.name || 'Desconocido'}</span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-600">{r.quantity} {r.unit}</div>
                                        <div className="text-[10px] text-slate-400">~{formatCurrency(costShare)}</div>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Customer } from '../types';
import { Plus, Search, Edit2, Trash2, Phone, Mail, MapPin, X } from 'lucide-react';
import { formatCurrency } from '../utils/conversions';

export const Customers: React.FC = () => {
  const { customers, addCustomer, updateCustomer, deleteCustomer, orders } = useBakery();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Customer>>({
    name: '',
    phone: '',
    email: '',
    address: '',
    notes: ''
  });

  const handleEdit = (customer: Customer) => {
    setEditingId(customer.id);
    setFormData(customer);
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    setEditingId(null);
    setFormData({ name: '', phone: '', email: '', address: '', notes: '' });
    setIsModalOpen(true);
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    // Prevent any potential parent click handlers from firing
    e.stopPropagation(); 
    if (window.confirm('¿Seguro que deseas eliminar este cliente? Se mantendrá el historial de pedidos.')) {
      deleteCustomer(id);
    }
  };

  const handleSave = () => {
    if (!formData.name) return;

    if (editingId) {
      updateCustomer({ ...formData, id: editingId } as Customer);
    } else {
      addCustomer({
        ...formData,
        id: Date.now().toString()
      } as Customer);
    }
    setIsModalOpen(false);
  };

  const getCustomerStats = (customerId: string) => {
    const customerOrders = orders.filter(o => o.customerId === customerId);
    const totalSpent = customerOrders.filter(o => o.status === 'Entregado').reduce((acc, o) => acc + o.totalPrice, 0);
    return {
      count: customerOrders.length,
      spent: totalSpent
    };
  };

  const filtered = customers.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.phone?.includes(searchTerm)
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Clientes</h2>
        {/* Desktop Button */}
        <button 
          onClick={handleAdd}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          <Plus size={18} /> Nuevo Cliente
        </button>
      </div>

      {/* Mobile Floating Action Button (FAB) */}
      <button 
        onClick={handleAdd}
        className="md:hidden fixed bottom-20 right-4 bg-indigo-600 text-white p-4 rounded-full shadow-lg z-40 hover:bg-indigo-700 transition-colors"
        aria-label="Nuevo Cliente"
