import React, { useRef, useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Download, Upload, Database as DatabaseIcon, AlertTriangle, CheckCircle } from 'lucide-react';

export const Database: React.FC = () => {
  const { ingredients, products, orders, customers, restoreDatabase } = useBakery();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [message, setMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  const handleExport = () => {
    try {
      const data = {
        ingredients,
        products,
        orders,
        customers,
        backupDate: new Date().toISOString(),
        version: "1.0"
      };

      const jsonString = JSON.stringify(data, null, 2);
      const blob = new Blob([jsonString], { type: "application/json" });
      const url = URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = url;
      link.download = `pasteleria_backup_${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      setMessage({ type: 'success', text: 'Respaldo generado y descargado correctamente.' });
    } catch (error) {
      console.error(error);
      setMessage({ type: 'error', text: 'Error al generar el respaldo.' });
    }
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const parsedData = JSON.parse(content);

        // Basic validation
        if (!parsedData.ingredients || !parsedData.products || !parsedData.orders) {
          throw new Error("El archivo no tiene el formato correcto.");
        }

        if (window.confirm("¿Estás seguro de restaurar esta copia de seguridad? Se reemplazarán todos los datos actuales.")) {
            restoreDatabase(parsedData);
            setMessage({ type: 'success', text: 'Base de datos restaurada correctamente.' });
        }
      } catch (error) {
        console.error(error);
        setMessage({ type: 'error', text: 'Error al leer el archivo. Asegúrate de que sea un respaldo válido.' });
      }

      // Reset input
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      <header className="mb-6">
        <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <DatabaseIcon className="text-indigo-600" /> Base de Datos
        </h2>
        <p className="text-slate-500">Gestiona las copias de seguridad de tu sistema.</p>
      </header>

      {message && (
        <div className={`p-4 rounded-lg flex items-center gap-2 ${message.type === 'success' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
            {message.type === 'success' ? <CheckCircle size={20} /> : <AlertTriangle size={20} />}
            {message.text}
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Export Card */}
        <div className="bg-white p-8 rounded-xl shadow-sm border border-slate-200 flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600 mb-4">
                <Download size={32} />
            </div>
            <h3 className="text-xl font-bold text-slate-800 mb-2">Exportar Respaldo</h3>
            <p className="text-slate-500 mb-6 text-sm">
                Descarga un archivo JSON con todos tus productos, ingredientes, clientes y pedidos.
                Guarda este archivo en un lugar seguro.
            </p>
            <button 
                onClick={handleExport}
                className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-md flex items-center justify-center gap-2"
            >
                <Download size={18} /> Descargar Copia
            </button>
        </div>

        {/* Import Card */}
        <div className="bg-white p-8 rounded-xl shadow-sm border border-slate-200 flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-amber-50 rounded-full flex items-center justify-center text-amber-600 mb-4">
                <Upload size={32} />
            </div>
            <h3 className="text-xl font-bold text-slate-800 mb-2">Restaurar Copia</h3>
            <p className="text-slate-500 mb-6 text-sm">
                Sube un archivo de respaldo previamente generado para recuperar tu información. 
                <span className="block text-amber-600 font-bold mt-1">¡Atención! Esto sobrescribirá los datos actuales.</span>
            </p>
            <input 
                type="file" 
                ref={fileInputRef}
                onChange={handleFileChange}
                accept="application/json"
                className="hidden" 
            />
            <button 
                onClick={handleImportClick}
                className="w-full bg-white border-2 border-slate-200 text-slate-700 py-3 rounded-lg font-bold hover:border-indigo-600 hover:text-indigo-600 transition-colors flex items-center justify-center gap-2"
            >
                <Upload size={18} /> Subir Archivo
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { suggestRecipe, analyzeProductionData } from '../services/geminiService';
import { Sparkles, MessageSquare, Loader2, BarChart2, AlertCircle } from 'lucide-react';

export const AiAssistant: React.FC = () => {
  const { ingredients, orders } = useBakery();
  const [activeTab, setActiveTab] = useState<'recipe' | 'analysis'>('recipe');
  const [prompt, setPrompt] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleRecipeSuggest = async () => {
    if (!prompt) return;
    setLoading(true);
    setErrorMsg(null);
    setResponse('');
    try {
      const result = await suggestRecipe(ingredients, prompt);
      setResponse(result || 'No se pudo generar respuesta.');
    } catch (error: any) {
      console.error(error);
      setErrorMsg(`Error: ${error.message || 'No se pudo conectar con el Chef IA.'}`);
    } finally {
      setLoading(false);
    }
  };

  const handleAnalysis = async () => {
    setLoading(true);
    setErrorMsg(null);
    setResponse('');
    try {
      const result = await analyzeProductionData(orders, ingredients);
      setResponse(result || 'Sin datos suficientes.');
    } catch (error: any) {
      console.error(error);
      setErrorMsg(`Error: ${error.message || 'Error analizando datos.'}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="h-full flex flex-col space-y-4 max-w-4xl mx-auto">
      <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl p-6 text-white shadow-lg">
        <h2 className="text-3xl font-bold flex items-center gap-2">
          <Sparkles className="animate-pulse" /> Chef IA Inteligente
        </h2>
        <p className="opacity-90 mt-2">
          Tu asistente experto para creatividad, gestión y análisis de negocio.
        </p>
      </div>

      <div className="flex gap-4 border-b border-slate-200">
        <button
          onClick={() => { setActiveTab('recipe'); setResponse(''); setErrorMsg(null); }}
          className={`pb-2 px-4 font-medium transition-colors ${activeTab === 'recipe' ? 'border-b-2 border-indigo-500 text-indigo-600' : 'text-slate-500'}`}
        >
          Consultas & Recetas
        </button>
        <button
          onClick={() => { setActiveTab('analysis'); setResponse(''); setErrorMsg(null); }}
          className={`pb-2 px-4 font-medium transition-colors ${activeTab === 'analysis' ? 'border-b-2 border-indigo-500 text-indigo-600' : 'text-slate-500'}`}
        >
          Análisis de Negocio
        </button>
      </div>

      <div className="flex-1 bg-white rounded-xl shadow-sm border border-slate-100 p-6 min-h-[400px]">
        {activeTab === 'recipe' ? (
          <div className="space-y-4">
            <label className="block text-slate-700 font-medium">¿Qué necesitas hoy?</label>
            <div className="flex gap-2">
              <input
                type="text"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="Ej. Tengo muchas manzanas, ¿qué puedo hacer? o Dame un consejo para merengue perfecto."
                className="flex-1 p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-300 outline-none"
                onKeyDown={(e) => e.key === 'Enter' && handleRecipeSuggest()}
              />
              <button
                onClick={handleRecipeSuggest}
                disabled={loading}
                className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 rounded-lg disabled:opacity-50 flex items-center"
              >
                {loading ? <Loader2 className="animate-spin" /> : <MessageSquare size={20} />}
              </button>
            </div>
          </div>
        ) : (
          <div className="space-y-4 text-center">
            <p className="text-slate-600">Genera un reporte inteligente basado en tus pedidos actuales y niveles de stock.</p>
            <button
              onClick={handleAnalysis}
              disabled={loading}
              className="bg-purple-600 hover:bg-purple-700 text-white px-8 py-3 rounded-lg shadow-md disabled:opacity-50 inline-flex items-center gap-2"
            >
              {loading ? <Loader2 className="animate-spin" /> : <BarChart2 size={20} />}
              Generar Análisis de Negocio
            </button>
          </div>
        )}

        {/* Error Message Area */}
        {errorMsg && (
          <div className="mt-8 p-4 bg-red-50 text-red-700 rounded-lg border border-red-200 flex items-center gap-2">
            <AlertCircle size={20} />
            <span>{errorMsg}</span>
          </div>
        )}

        {/* Response Area */}
        {(response || loading) && !errorMsg && (
          <div className="mt-8 p-6 bg-slate-50 rounded-xl border border-slate-200">
            {loading ? (
              <div className="flex flex-col items-center justify-center py-8 text-slate-500">
                <Loader2 className="animate-spin mb-2 w-8 h-8 text-indigo-500" />
                <p>El Chef está pensando...</p>
              </div>
            ) : (
              <div className="prose prose-indigo max-w-none text-slate-700 whitespace-pre-wrap">
                {response}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

