// Enums for Units to ensure consistency
export enum UnitType {
  GRAMS = 'g',
  KILOGRAMS = 'kg',
  MILLILITERS = 'ml',
  LITERS = 'L',
  UNITS = 'u'
}

// Entity: Ingrediente (Raw Material)
export interface Ingredient {
  id: string;
  name: string;
  currentStock: number; // Stored in base units (g, ml, u)
  unit: UnitType; // Preferred display unit, though storage is normalized
  costPerUnit: number;
  minStock: number; // Reorder point
}

// Entity: Receta (Recipe Line Item)
export interface RecipeItem {
  ingredientId: string;
  quantity: number; // Amount needed for 1 unit of product
  unit: UnitType;
}

// Entity: Producto (Final Product)
export interface Product {
  id: string;
  name: string;
  price: number;
  description?: string;
  recipe: RecipeItem[];
}

// Entity: Cliente
export interface Customer {
  id: string;
  name: string;
  phone?: string;
  email?: string;
  address?: string;
  notes?: string;
}

// Entity: Pedido (Order)
export interface OrderItem {
  productId: string;
  quantity: number;
}

export type OrderStatus = 'Pendiente' | 'En Proceso' | 'Completado' | 'Entregado' | 'Pagado';

export interface Order {
  id: string;
  customerId: string; // Link to Customer ID if available
  customerName: string; // Fallback or snapshot name
  deliveryDate: string; // ISO Date string YYYY-MM-DD
  status: OrderStatus;
  items: OrderItem[];
  totalPrice: number;
}

// Helper type for Production Planning
export interface ProductionRequirement {
  ingredientName: string;
  ingredientId: string;
  totalNeeded: number;
  currentStock: number;
  unit: UnitType;
  missing: number; // If totalNeeded > currentStock
}

// Chat Message for AI Chef
export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

// Inventory Item for Display
export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  threshold: number;
  category: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Ingredient, Product, Order, UnitType, ChatMessage } from "../types";
import { formatStock } from "../utils/conversions";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const suggestRecipe = async (availableIngredients: Ingredient[], prompt: string) => {
  const ingredientList = availableIngredients.map(i => `${i.name} (${formatStock(i.currentStock, i.unit)})`).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Soy un pastelero con los siguientes ingredientes en stock: ${ingredientList}. ${prompt}`,
      config: {
        systemInstruction: "Eres un Chef Pastelero experto y creativo. Sugiere recetas detalladas o consejos basados en el inventario disponible. Sé conciso y profesional.",
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error (suggestRecipe):", error);
    throw error;
  }
};

export const parseOrderFromText = async (text: string, products: Product[]): Promise<any> => {
  const productNames = products.map(p => p.name).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Texto del pedido: "${text}"`,
      config: {
        systemInstruction: `Extrae la información del pedido en formato JSON.
        Los productos disponibles son: ${productNames}.
        Intenta coincidir el nombre del producto.
        `,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            customerName: { type: Type.STRING },
            items: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  productName: { type: Type.STRING },
                  quantity: { type: Type.NUMBER }
                }
              }
            },
          }
        }
      }
    });

    // Handle potential markdown code blocks in response
    let cleanText = response.text || "{}";
    cleanText = cleanText.replace(/```json/g, '').replace(/```/g, '').trim();

    return JSON.parse(cleanText);
  } catch (e) {
    console.error("Gemini API Error (parseOrderFromText):", e);
    return null;
  }
};

export const analyzeProductionData = async (orders: Order[], inventory: Ingredient[]) => {
    // Simplify orders for prompt
    const orderSummary = JSON.stringify(orders.map(o => ({
        customer: o.customerName,
        status: o.status,
        items: o.items.length,
        total: o.totalPrice
    })));

    const inventorySummary = JSON.stringify(inventory.map(i => ({ 
        name: i.name, 
        stock: i.currentStock, 
        unit: i.unit, 
        min: i.minStock 
    })));

    try {
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `Analiza estos datos de producción. 
          Pedidos pendientes: ${orderSummary}
          Inventario actual: ${inventorySummary}

          Dame un resumen ejecutivo de 3 puntos:
          1. Estado de riesgo del inventario.
          2. Eficiencia de producción sugerida.
          3. Una idea creativa para vender el excedente de stock (si lo hay) o mejorar ventas.`,
          config: {
              systemInstruction: "Eres un consultor de negocios de pastelería.",
          }
      });
      return response.text;
    } catch (error) {
      console.error("Gemini API Error (analyzeProductionData):", error);
      throw error;
    }
}

export const getChefResponse = async (history: ChatMessage[], newMessage: string) => {
  try {
    const formattedHistory = history.map(msg => ({
      role: msg.role,
      parts: [{ text: msg.text }]
    }));

    const chat = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction: "Eres Chef Pierre, un experto pastelero francés amigable y servicial. Ayudas con recetas, consejos técnicos y gestión de pastelería. Tus respuestas son breves, útiles y con un toque de personalidad francesa.",
      },
      history: formattedHistory
    });

    const result = await chat.sendMessage({ message: newMessage });
    return result.text;
  } catch (error) {
    console.error("Gemini API Error (getChefResponse):", error);
    throw error;
  }
};

