import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus } from '../types';
import { STATUS_COLORS } from '../constants';
import { Plus, X, Clock, AlertCircle, User, ArrowRight, Check, Archive, LayoutGrid, List as ListIcon, Calendar } from 'lucide-react';
import { formatCurrency } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrderStatus } = useBakery();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'kanban' | 'list'>('kanban');
  const [showHistory, setShowHistory] = useState(false);

  // Mobile Tab State
  const [activeTab, setActiveTab] = useState<OrderStatus>('Pendiente');

  // New Order State
  const [customerId, setCustomerId] = useState('');
  const [customerNameInput, setCustomerNameInput] = useState('');
  const [isExistingCustomer, setIsExistingCustomer] = useState(true);
  const [date, setDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  // --- Filtering Logic ---
  const activeOrders = useMemo(() => orders.filter(o => o.status !== 'Pagado' && o.status !== 'Entregado'), [orders]);
  const historyOrders = useMemo(() => orders.filter(o => o.status === 'Pagado' || o.status === 'Entregado'), [orders]);

  const currentOrders = showHistory ? historyOrders : activeOrders;

  // --- Actions ---
  const advanceStatus = (order: Order) => {
    const statusFlow: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];
    const currentIndex = statusFlow.indexOf(order.status);
    if (currentIndex < statusFlow.length - 1) {
      updateOrderStatus(order.id, statusFlow[currentIndex + 1]);
    }
  };

  const isUrgent = (dateStr: string) => {
    const today = new Date().toISOString().split('T')[0];
    return dateStr <= today;
  };

  // --- Modal Handlers ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    setSelectedProduct('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrder = () => {
    setError('');
    let finalCustomerName = '';
    let finalCustomerId = '';

    if (isExistingCustomer) {
        if (!customerId) { setError('Selecciona un cliente.'); return; }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) { setError('Ingresa el nombre.'); return; }
        finalCustomerName = customerNameInput;
        finalCustomerId = 'temp_' + Date.now(); 
    }

    if(!date) { setError('Selecciona fecha.'); return; }
    if(cart.length === 0) { setError('Agrega productos.'); return; }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const newOrder: Order = {
      id: Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: 'Pendiente',
      items: cart,
      totalPrice: total
    };

    addOrder(newOrder);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
  };

  // --- Components ---

  const KanbanCard: React.FC<{ order: Order }> = ({ order }) => {
    const urgent = isUrgent(order.deliveryDate) && order.status !== 'Pagado' && order.status !== 'Entregado';

    return (
      <div className={`bg-white p-3 rounded-lg shadow-sm border-l-4 mb-3 transition-all hover:shadow-md flex flex-col gap-2 ${urgent ? 'border-l-red-500 ring-1 ring-red-100' : 'border-l-indigo-500 border-slate-200'}`}>
        <div className="flex justify-between items-start">
          <div>
            <h4 className="font-bold text-slate-800 text-sm">{order.customerName}</h4>
            <div className={`flex items-center gap-1 text-[10px] ${urgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
              <Calendar size={10} /> {order.deliveryDate} {urgent && '(URGENTE)'}
            </div>
          </div>
          <span className="font-bold text-slate-700 text-sm">{formatCurrency(order.totalPrice)}</span>
        </div>

        <div className="bg-slate-50 p-2 rounded text-xs text-slate-600 space-y-1">
           {order.items.slice(0, 2).map((item, i) => {
             const pName = products.find(p => p.id === item.productId)?.name;
             return <div key={i} className="flex justify-between"><span>{item.quantity}x {pName}</span></div>;
           })}
           {order.items.length > 2 && <span className="text-[10px] text-slate-400">+{order.items.length - 2} más...</span>}
        </div>

        <div className="flex justify-end gap-2 mt-1">
           {order.status !== 'Pagado' && (
             <button 
               onClick={() => advanceStatus(order)}
               className="flex items-center gap-1 bg-indigo-50 text-indigo-700 hover:bg-indigo-100 px-2 py-1 rounded text-xs font-bold transition-colors"
             >
               {order.status === 'Entregado' ? 'Marcar Pagado' : 'Avanzar'} <ArrowRight size={12} />
             </button>
           )}
        </div>
      </div>
    );
  };

  const KanbanColumn: React.FC<{ title: string, status: OrderStatus, items: Order[] }> = ({ title, status, items }) => (
    <div className="flex-1 min-w-[280px] bg-slate-100 rounded-xl p-3 h-full flex flex-col">
      <div className="flex items-center justify-between mb-3 px-1">
        <h3 className="font-bold text-slate-700 flex items-center gap-2">
          <span className={`w-2 h-2 rounded-full ${status === 'Pendiente' ? 'bg-yellow-400' : status === 'En Proceso' ? 'bg-orange-400' : status === 'Completado' ? 'bg-indigo-500' : 'bg-green-500'}`}></span>
          {title}
        </h3>
        <span className="bg-white px-2 py-0.5 rounded-full text-xs font-bold text-slate-500">{items.length}</span>
      </div>
      <div className="overflow-y-auto flex-1 pr-1 custom-scrollbar">
        {items.length === 0 && <div className="text-center text-slate-400 text-xs py-10 border-2 border-dashed border-slate-200 rounded-lg">Sin pedidos</div>}
        {items.map(order => <KanbanCard key={order.id} order={order} />)}
      </div>
    </div>
  );

  return (
    <div className="h-[calc(100vh-8rem)] flex flex-col space-y-4">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 shrink-0">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            Gestión de Pedidos
            {showHistory && <span className="bg-slate-200 text-slate-600 text-xs px-2 py-1 rounded-full font-normal">Historial</span>}
          </h2>
          <p className="text-slate-500 text-sm hidden md:block">Arrastra el flujo de trabajo de tu cocina.</p>
        </div>

        <div className="flex items-center gap-2 w-full md:w-auto">
          <div className="flex bg-white rounded-lg border border-slate-200 p-1 mr-2">
             <button 
                onClick={() => setShowHistory(false)}
                className={`px-3 py-1.5 rounded text-xs font-medium transition-all ${!showHistory ? 'bg-indigo-100 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}
             >
               Tablero Activo
             </button>
             <button 
                onClick={() => setShowHistory(true)}
                className={`px-3 py-1.5 rounded text-xs font-medium transition-all ${showHistory ? 'bg-indigo-100 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}
             >
               Historial
             </button>
          </div>

          <button 
            onClick={() => setIsModalOpen(true)}
            className="flex-1 md:flex-none bg-indigo-600 text-white px-4 py-2 rounded-lg items-center justify-center gap-2 hover:bg-indigo-700 shadow-sm flex text-sm font-bold"
          >
            <Plus size={18} /> <span className="md:hidden">Nuevo</span> <span className="hidden md:inline">Nuevo Pedido</span>
          </button>
        </div>
      </div>

      {/* Kanban View (Active) */}
      {!showHistory && (
        <>
          {/* Mobile Tabs */}
          <div className="md:hidden flex gap-2 overflow-x-auto pb-2 shrink-0 no-scrollbar">
            {['Pendiente', 'En Proceso', 'Completado'].map((status) => (
              <button
                key={status}
                onClick={() => setActiveTab(status as OrderStatus)}
                className={`whitespace-nowrap px-4 py-2 rounded-full text-sm font-bold border transition-colors ${
                  activeTab === status 
                    ? 'bg-indigo-600 text-white border-indigo-600' 
                    : 'bg-white text-slate-600 border-slate-200'
                }`}
              >
                {status} ({activeOrders.filter(o => o.status === status).length})
              </button>
            ))}
          </div>

          {/* Desktop Board / Mobile Tab Content */}
          <div className="flex-1 overflow-hidden">
             {/* Desktop Grid */}
             <div className="hidden md:flex gap-4 h-full">
                <KanbanColumn title="Por Hacer" status="Pendiente" items={activeOrders.filter(o => o.status === 'Pendiente')} />
                <KanbanColumn title="En Horno/Prep" status="En Proceso" items={activeOrders.filter(o => o.status === 'En Proceso')} />
                <KanbanColumn title="Listo para Entregar" status="Completado" items={activeOrders.filter(o => o.status === 'Completado')} />
             </div>

             {/* Mobile Single Column */}
             <div className="md:hidden h-full">
                <KanbanColumn 
                  title={activeTab} 
                  status={activeTab} 
                  items={activeOrders.filter(o => o.status === activeTab)} 
                />
             </div>
          </div>
        </>
      )}

      {/* History List View */}
      {showHistory && (
        <div className="flex-1 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
           <div className="p-4 bg-slate-50 border-b border-slate-100 font-bold text-slate-700 text-sm">
              Pedidos Entregados y Pagados
           </div>
           <div className="overflow-y-auto flex-1 p-4 space-y-2">
              {historyOrders.length === 0 && <p className="text-center text-slate-400 py-8">No hay historial reciente.</p>}
              {historyOrders.map(order => (
                 <div key={order.id} className="flex justify-between items-center p-3 border border-slate-100 rounded-lg bg-slate-50 opacity-75">
                    <div>
                       <span className="font-bold text-slate-700 text-sm">{order.customerName}</span>
                       <span className="text-xs text-slate-500 block">{order.deliveryDate}</span>
                    </div>
                    <div className="text-right">
                       <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
                       <span className={`text-[10px] px-2 py-0.5 rounded-full border ${STATUS_COLORS[order.status]}`}>{order.status}</span>
                    </div>
                 </div>
              ))}
           </div>
        </div>
      )}

      {/* CREATE MODAL */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white">
              <h3 className="font-bold">Nuevo Pedido</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex gap-2 mb-2 text-xs">
                      <button onClick={() => setIsExistingCustomer(true)} className={`flex-1 py-1.5 rounded ${isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Seleccionar</button>
                      <button onClick={() => setIsExistingCustomer(false)} className={`flex-1 py-1.5 rounded ${!isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Nuevo</button>
                  </div>
                  {isExistingCustomer ? (
                      <select className="w-full p-2 border rounded text-sm bg-white" value={customerId} onChange={e => setCustomerId(e.target.value)}>
                          <option value="">-- Buscar Cliente --</option>
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                  ) : (
                      <input className="w-full p-2 border rounded text-sm" value={customerNameInput} onChange={e => setCustomerNameInput(e.target.value)} placeholder="Nombre del cliente" />
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700">Entrega</label>
                  <input type="date" className="w-full p-2 border rounded text-sm" value={date} onChange={e => setDate(e.target.value)} />
