               </div>

               {error && <div className="bg-red-50 text-red-600 p-2 rounded text-xs flex items-center gap-2"><AlertCircle size={14}/>{error}</div>}

               <button onClick={handleCreateOrder} className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 shadow-md">Crear Pedido</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus } from '../types';
import { STATUS_COLORS } from '../constants';
import { Plus, Search, Calendar, ChevronDown, ChevronRight, AlertCircle, CheckCircle2, Clock, MapPin, Phone } from 'lucide-react';
import { formatCurrency } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrderStatus } = useBakery();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // State for collapsible sections
  const [collapsedSections, setCollapsedSections] = useState<Record<string, boolean>>({});

  // New Order Form State
  const [customerId, setCustomerId] = useState('');
  const [customerNameInput, setCustomerNameInput] = useState('');
  const [isExistingCustomer, setIsExistingCustomer] = useState(true);
  const [date, setDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  // --- Logic: Group by Date ---
  const groupedOrders = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const groups: Record<string, Order[]> = {
      'overdue': [],
      'today': [],
      'tomorrow': [],
      'future': [],
      'completed': [] // History
    };

    // Filter by search
    const filtered = orders.filter(o => 
      o.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      o.id.toLowerCase().includes(searchTerm.toLowerCase())
    );

    filtered.forEach(order => {
      // If completed/delivered/paid, goes to history unless searching
      if (['Entregado', 'Pagado'].includes(order.status)) {
        groups['completed'].push(order);
        return;
      }

      if (order.deliveryDate < today) {
        groups['overdue'].push(order);
      } else if (order.deliveryDate === today) {
        groups['today'].push(order);
      } else {
        // Check if tomorrow
        const tmrw = new Date();
        tmrw.setDate(tmrw.getDate() + 1);
        const tmrwStr = tmrw.toISOString().split('T')[0];

        if (order.deliveryDate === tmrwStr) {
          groups['tomorrow'].push(order);
        } else {
          groups['future'].push(order);
        }
      }
    });

    // Sort future orders by date
    groups['future'].sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
    // Sort completed by date desc
    groups['completed'].sort((a, b) => b.deliveryDate.localeCompare(a.deliveryDate));

    return groups;
  }, [orders, searchTerm]);

  const toggleSection = (section: string) => {
    setCollapsedSections(prev => ({ ...prev, [section]: !prev[section] }));
  };

  // --- Helpers ---
  const getStatusBadge = (status: OrderStatus) => {
    const styles = {
      'Pendiente': 'bg-yellow-100 text-yellow-800',
      'En Proceso': 'bg-orange-100 text-orange-800',
      'Completado': 'bg-green-100 text-green-800',
      'Entregado': 'bg-slate-100 text-slate-600',
      'Pagado': 'bg-emerald-50 text-emerald-600 border border-emerald-100',
    };
    return styles[status] || 'bg-gray-100';
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    setSelectedProduct('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrder = () => {
    setError('');
    let finalCustomerName = '';
    let finalCustomerId = '';

    if (isExistingCustomer) {
        if (!customerId) { setError('Selecciona un cliente.'); return; }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) { setError('Ingresa el nombre.'); return; }
        finalCustomerName = customerNameInput;
        finalCustomerId = 'temp_' + Date.now(); 
    }

    if(!date) { setError('Selecciona fecha.'); return; }
    if(cart.length === 0) { setError('Agrega productos.'); return; }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const newOrder: Order = {
      id: Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: 'Pendiente',
      items: cart,
      totalPrice: total
    };

    addOrder(newOrder);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
  };

  // --- Sub-components ---

  const OrderRow: React.FC<{ order: Order }> = ({ order }) => {
    const customer = customers.find(c => c.id === order.customerId);

    return (
      <div className="group bg-white p-4 rounded-xl border border-slate-100 shadow-sm hover:shadow-md hover:border-indigo-100 transition-all flex flex-col md:flex-row gap-4 items-start md:items-center">
        {/* Date/Time Indicator */}
        <div className="flex flex-row md:flex-col items-center md:items-start gap-2 md:gap-0 min-w-[80px]">
           <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden md:block">Entrega</span>
           <div className="flex items-center gap-1 text-slate-700 font-medium">
              <Calendar size={14} className="text-indigo-500" />
              <span className="text-sm">{order.deliveryDate.split('-').slice(1).reverse().join('/')}</span>
           </div>
        </div>

        {/* Info */}
        <div className="flex-1">
           <div className="flex items-center gap-2 mb-1">
              <h4 className="font-bold text-slate-800 text-lg">{order.customerName}</h4>
              {customer?.phone && (
                <a href={`tel:${customer.phone}`} className="text-slate-400 hover:text-green-600" title="Llamar">
                  <Phone size={14} />
                </a>
              )}
           </div>
           <div className="text-sm text-slate-600 mb-2">
              {order.items.map((item, idx) => {
                 const p = products.find(p => p.id === item.productId);
                 return (
                   <span key={idx} className="inline-block mr-3 bg-slate-50 px-2 py-0.5 rounded text-xs border border-slate-200">
                     {item.quantity}x {p?.name}
                   </span>
                 )
              })}
           </div>
           <div className="text-xs text-slate-400 flex gap-4">
              {customer?.address && <span className="flex items-center gap-1"><MapPin size={12}/> {customer.address}</span>}
              <span className="font-semibold text-slate-500">Total: {formatCurrency(order.totalPrice)}</span>
           </div>
        </div>

        {/* Action / Status */}
        <div className="w-full md:w-auto flex items-center justify-between md:justify-end gap-3 pt-3 md:pt-0 border-t md:border-t-0 border-slate-100">
           <select 
             value={order.status}
             onChange={(e) => updateOrderStatus(order.id, e.target.value as OrderStatus)}
             className={`px-3 py-1.5 rounded-lg text-sm font-medium border-0 cursor-pointer outline-none ring-1 ring-inset ring-black/5 focus:ring-2 focus:ring-indigo-600 ${getStatusBadge(order.status)}`}
           >
             <option value="Pendiente">Pendiente</option>
             <option value="En Proceso">En Proceso</option>
             <option value="Completado">Listo</option>
             <option value="Entregado">Entregado</option>
             <option value="Pagado">Pagado</option>
           </select>
        </div>
      </div>
    );
  };

  const SectionHeader: React.FC<{ title: string, count: number, id: string, color?: string }> = ({ title, count, id, color = "text-slate-800" }) => (
    <div 
      onClick={() => toggleSection(id)}
      className="flex items-center gap-2 cursor-pointer py-4 select-none"
    >
      {collapsedSections[id] ? <ChevronRight size={18} className="text-slate-400"/> : <ChevronDown size={18} className="text-slate-400"/>}
      <h3 className={`text-lg font-bold ${color}`}>{title}</h3>
      <span className="px-2 py-0.5 bg-slate-100 text-slate-600 text-xs rounded-full font-bold">{count}</span>
      <div className="h-px bg-slate-200 flex-1 ml-4"></div>
    </div>
  );

  return (
    <div className="space-y-2 pb-20">
      {/* Header & Controls */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 sticky top-0 z-10">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
           <h2 className="text-2xl font-bold text-slate-800 self-start md:self-center">Agenda de Pedidos</h2>

           <div className="flex w-full md:w-auto gap-3">
              <div className="relative flex-1 md:w-64">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Buscar cliente..."
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                   className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                 />
              </div>
              <button 
                onClick={() => setIsModalOpen(true)}
                className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap"
              >
                <Plus size={18} /> <span className="hidden sm:inline">Nuevo</span>
              </button>
           </div>
        </div>
      </div>

      {/* Agenda Content */}
      <div className="space-y-1">

        {/* OVERDUE */}
        {groupedOrders.overdue.length > 0 && (
          <div className="animate-in slide-in-from-top-2 fade-in">
            <SectionHeader title="¡Atrasados! (Requiere Atención)" count={groupedOrders.overdue.length} id="overdue" color="text-red-600" />
            {!collapsedSections['overdue'] && (
              <div className="space-y-2 pl-2 md:pl-4 border-l-2 border-red-100">
                {groupedOrders.overdue.map(order => <OrderRow key={order.id} order={order} />)}
              </div>
            )}
          </div>
        )}

        {/* TODAY */}
        <div className="animate-in slide-in-from-top-4 fade-in duration-500">
          <SectionHeader title="Para Hoy" count={groupedOrders.today.length} id="today" color="text-indigo-700" />
          {!collapsedSections['today'] && (
            <div className="space-y-3 pl-2 md:pl-4 border-l-2 border-indigo-100 min-h-[100px]">
              {groupedOrders.today.length === 0 ? (
                <div className="text-slate-400 italic py-4 text-sm flex items-center gap-2">
                  <CheckCircle2 size={16} /> ¡Todo listo para hoy! No hay entregas pendientes.
                </div>
              ) : (
                groupedOrders.today.map(order => <OrderRow key={order.id} order={order} />)
              )}
            </div>
          )}
        </div>

        {/* TOMORROW */}
        <div className="opacity-90">
          <SectionHeader title="Mañana" count={groupedOrders.tomorrow.length} id="tomorrow" />
          {!collapsedSections['tomorrow'] && (
            <div className="space-y-2 pl-2 md:pl-4 border-l-2 border-slate-100">
              {groupedOrders.tomorrow.map(order => <OrderRow key={order.id} order={order} />)}
              {groupedOrders.tomorrow.length === 0 && <p className="text-slate-400 text-xs py-2">Nada programado para mañana.</p>}
            </div>
          )}
        </div>

        {/* FUTURE */}
        {groupedOrders.future.length > 0 && (
          <div className="opacity-75 hover:opacity-100 transition-opacity">
            <SectionHeader title="Próximos Días" count={groupedOrders.future.length} id="future" />
            {!collapsedSections['future'] && (
              <div className="space-y-2 pl-2 md:pl-4 border-l-2 border-slate-100">
                {groupedOrders.future.map(order => <OrderRow key={order.id} order={order} />)}
              </div>
            )}
          </div>
        )}

        {/* HISTORY (Collapsed by default usually, but we manage state manually) */}
        <div className="pt-8 opacity-60">
           <SectionHeader title="Historial Completado" count={groupedOrders.completed.length} id="completed" />
           {!collapsedSections['completed'] && (
              <div className="space-y-2 pl-2 md:pl-4 border-l-2 border-slate-100">
                 {groupedOrders.completed.map(order => <OrderRow key={order.id} order={order} />)}
              </div>
           )}
        </div>

      </div>

      {/* New Order Modal (Reused) */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0">
              <h3 className="font-bold">Nuevo Pedido</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex gap-2 mb-2 text-xs">
                      <button onClick={() => setIsExistingCustomer(true)} className={`flex-1 py-1.5 rounded ${isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Seleccionar</button>
                      <button onClick={() => setIsExistingCustomer(false)} className={`flex-1 py-1.5 rounded ${!isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Nuevo</button>
                  </div>
                  {isExistingCustomer ? (
                      <select className="w-full p-2 border rounded text-sm bg-white" value={customerId} onChange={e => setCustomerId(e.target.value)}>
                          <option value="">-- Buscar Cliente --</option>
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                  ) : (
                      <input className="w-full p-2 border rounded text-sm" value={customerNameInput} onChange={e => setCustomerNameInput(e.target.value)} placeholder="Nombre del cliente" />
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700">Entrega</label>
                  <input type="date" className="w-full p-2 border rounded text-sm" value={date} onChange={e => setDate(e.target.value)} />
               </div>

               <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                 <h4 className="font-bold text-slate-700 text-xs mb-2 uppercase">Productos</h4>
                 <div className="flex gap-2 mb-2">
                    <select className="flex-1 p-2 border rounded text-sm bg-white" value={selectedProduct} onChange={e => setSelectedProduct(e.target.value)}>
                        <option value="">Seleccionar...</option>
                        {products.map(p => <option key={p.id} value={p.id}>{p.name} ({formatCurrency(p.price)})</option>)}
                    </select>
                    <input type="number" min="1" className="w-16 p-2 border rounded text-sm text-center" value={qty} onChange={e => setQty(Number(e.target.value))} />
                    <button onClick={addToCart} className="bg-indigo-600 text-white p-2 rounded hover:bg-indigo-700" disabled={!selectedProduct}><Plus size={18} /></button>
                 </div>
                 <div className="space-y-1 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between text-sm bg-white p-2 rounded border border-slate-100">
                            <span>{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-500"><X size={14}/></button>
                        </div>
                    ))}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-2 rounded text-xs flex items-center gap-2"><AlertCircle size={14}/>{error}</div>}

               <button onClick={handleCreateOrder} className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 shadow-md">Crear Pedido</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

