        if (!customerId) { setError('Selecciona un cliente.'); return; }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) { setError('Ingresa el nombre.'); return; }
        finalCustomerName = customerNameInput;
        finalCustomerId = 'temp_' + Date.now(); 
    }

    if(!date) { setError('Selecciona fecha.'); return; }
    if(cart.length === 0) { setError('Agrega productos.'); return; }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const newOrder: Order = {
      id: Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: 'Pendiente',
      items: cart,
      totalPrice: total
    };

    addOrder(newOrder);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
  };

  // --- Sub-components ---

  const OrderRow: React.FC<{ order: Order }> = ({ order }) => {
    const customer = customers.find(c => c.id === order.customerId);

    return (
      <div className="group bg-white p-4 rounded-xl border border-slate-100 shadow-sm hover:shadow-md hover:border-indigo-100 transition-all flex flex-col md:flex-row gap-4 items-start md:items-center">
        {/* Date/Time Indicator */}
        <div className="flex flex-row md:flex-col items-center md:items-start gap-2 md:gap-0 min-w-[80px]">
           <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden md:block">Entrega</span>
           <div className="flex items-center gap-1 text-slate-700 font-medium">
              <Calendar size={14} className="text-indigo-500" />
              <span className="text-sm">{order.deliveryDate.split('-').slice(1).reverse().join('/')}</span>
           </div>
        </div>

        {/* Info */}
        <div className="flex-1">
           <div className="flex items-center gap-2 mb-1">
              <h4 className="font-bold text-slate-800 text-lg">{order.customerName}</h4>
              {customer?.phone && (
                <a href={`tel:${customer.phone}`} className="text-slate-400 hover:text-green-600" title="Llamar">
                  <Phone size={14} />
                </a>
              )}
           </div>
           <div className="text-sm text-slate-600 mb-2">
              {order.items.map((item, idx) => {
                 const p = products.find(p => p.id === item.productId);
                 return (
                   <span key={idx} className="inline-block mr-3 bg-slate-50 px-2 py-0.5 rounded text-xs border border-slate-200">
                     {item.quantity}x {p?.name}
                   </span>
                 )
              })}
           </div>
           <div className="text-xs text-slate-400 flex gap-4">
              {customer?.address && <span className="flex items-center gap-1"><MapPin size={12}/> {customer.address}</span>}
              <span className="font-semibold text-slate-500">Total: {formatCurrency(order.totalPrice)}</span>
           </div>
        </div>

        {/* Action / Status */}
        <div className="w-full md:w-auto flex items-center justify-between md:justify-end gap-3 pt-3 md:pt-0 border-t md:border-t-0 border-slate-100">
           <select 
             value={order.status}
             onChange={(e) => updateOrderStatus(order.id, e.target.value as OrderStatus)}
             className={`px-3 py-1.5 rounded-lg text-sm font-medium border-0 cursor-pointer outline-none ring-1 ring-inset ring-black/5 focus:ring-2 focus:ring-indigo-600 ${getStatusBadge(order.status)}`}
           >
             <option value="Pendiente">Pendiente</option>
             <option value="En Proceso">En Proceso</option>
             <option value="Completado">Listo</option>
             <option value="Entregado">Entregado</option>
             <option value="Pagado">Pagado</option>
           </select>
        </div>
      </div>
    );
  };

  const SectionHeader: React.FC<{ title: string, count: number, id: string, color?: string }> = ({ title, count, id, color = "text-slate-800" }) => (
    <div 
      onClick={() => toggleSection(id)}
      className="flex items-center gap-2 cursor-pointer py-4 select-none"
    >
      {collapsedSections[id] ? <ChevronRight size={18} className="text-slate-400"/> : <ChevronDown size={18} className="text-slate-400"/>}
      <h3 className={`text-lg font-bold ${color}`}>{title}</h3>
      <span className="px-2 py-0.5 bg-slate-100 text-slate-600 text-xs rounded-full font-bold">{count}</span>
      <div className="h-px bg-slate-200 flex-1 ml-4"></div>
    </div>
  );

  return (
    <div className="space-y-2 pb-20">
      {/* Header & Controls */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 sticky top-0 z-10">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
           <h2 className="text-2xl font-bold text-slate-800 self-start md:self-center">Agenda de Pedidos</h2>

           <div className="flex w-full md:w-auto gap-3">
              <div className="relative flex-1 md:w-64">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Buscar cliente..."
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                   className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                 />
              </div>
              <button 
                onClick={() => setIsModalOpen(true)}
                className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap"
              >
                <Plus size={18} /> <span className="hidden sm:inline">Nuevo</span>
              </button>
           </div>
        </div>
      </div>

      {/* Agenda Content */}
      <div className="space-y-1">

        {/* OVERDUE */}
        {groupedOrders.overdue.length > 0 && (
          <div className="animate-in slide-in-from-top-2 fade-in">
            <SectionHeader title="¡Atrasados! (Requiere Atención)" count={groupedOrders.overdue.length} id="overdue" color="text-red-600" />
            {!collapsedSections['overdue'] && (
              <div className="space-y-2 pl-2 md:pl-4 border-l-2 border-red-100">
                {groupedOrders.overdue.map(order => <OrderRow key={order.id} order={order} />)}
              </div>
            )}
          </div>
        )}

        {/* TODAY */}
        <div className="animate-in slide-in-from-top-4 fade-in duration-500">
          <SectionHeader title="Para Hoy" count={groupedOrders.today.length} id="today" color="text-indigo-700" />
          {!collapsedSections['today'] && (
            <div className="space-y-3 pl-2 md:pl-4 border-l-2 border-indigo-100 min-h-[100px]">
              {groupedOrders.today.length === 0 ? (
                <div className="text-slate-400 italic py-4 text-sm flex items-center gap-2">
                  <CheckCircle2 size={16} /> ¡Todo listo para hoy! No hay entregas pendientes.
                </div>
              ) : (
                groupedOrders.today.map(order => <OrderRow key={order.id} order={order} />)
              )}
            </div>
          )}
        </div>

        {/* TOMORROW */}
        <div className="opacity-90">
          <SectionHeader title="Mañana" count={groupedOrders.tomorrow.length} id="tomorrow" />
          {!collapsedSections['tomorrow'] && (
            <div className="space-y-2 pl-2 md:pl-4 border-l-2 border-slate-100">
              {groupedOrders.tomorrow.map(order => <OrderRow key={order.id} order={order} />)}
              {groupedOrders.tomorrow.length === 0 && <p className="text-slate-400 text-xs py-2">Nada programado para mañana.</p>}
            </div>
          )}
        </div>

        {/* FUTURE */}
        {groupedOrders.future.length > 0 && (
          <div className="opacity-75 hover:opacity-100 transition-opacity">
            <SectionHeader title="Próximos Días" count={groupedOrders.future.length} id="future" />
            {!collapsedSections['future'] && (
              <div className="space-y-2 pl-2 md:pl-4 border-l-2 border-slate-100">
                {groupedOrders.future.map(order => <OrderRow key={order.id} order={order} />)}
              </div>
            )}
          </div>
        )}

        {/* HISTORY (Collapsed by default usually, but we manage state manually) */}
        <div className="pt-8 opacity-60">
           <SectionHeader title="Historial Completado" count={groupedOrders.completed.length} id="completed" />
           {!collapsedSections['completed'] && (
              <div className="space-y-2 pl-2 md:pl-4 border-l-2 border-slate-100">
                 {groupedOrders.completed.map(order => <OrderRow key={order.id} order={order} />)}
              </div>
           )}
        </div>

      </div>

      {/* New Order Modal (Reused) */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0">
              <h3 className="font-bold">Nuevo Pedido</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex gap-2 mb-2 text-xs">
                      <button onClick={() => setIsExistingCustomer(true)} className={`flex-1 py-1.5 rounded ${isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Seleccionar</button>
                      <button onClick={() => setIsExistingCustomer(false)} className={`flex-1 py-1.5 rounded ${!isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Nuevo</button>
                  </div>
                  {isExistingCustomer ? (
                      <select className="w-full p-2 border rounded text-sm bg-white" value={customerId} onChange={e => setCustomerId(e.target.value)}>
                          <option value="">-- Buscar Cliente --</option>
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                  ) : (
                      <input className="w-full p-2 border rounded text-sm" value={customerNameInput} onChange={e => setCustomerNameInput(e.target.value)} placeholder="Nombre del cliente" />
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700">Entrega</label>
                  <input type="date" className="w-full p-2 border rounded text-sm" value={date} onChange={e => setDate(e.target.value)} />
               </div>

               <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                 <h4 className="font-bold text-slate-700 text-xs mb-2 uppercase">Productos</h4>
                 <div className="flex gap-2 mb-2">
                    <select className="flex-1 p-2 border rounded text-sm bg-white" value={selectedProduct} onChange={e => setSelectedProduct(e.target.value)}>
                        <option value="">Seleccionar...</option>
                        {products.map(p => <option key={p.id} value={p.id}>{p.name} ({formatCurrency(p.price)})</option>)}
                    </select>
                    <input type="number" min="1" className="w-16 p-2 border rounded text-sm text-center" value={qty} onChange={e => setQty(Number(e.target.value))} />
                    <button onClick={addToCart} className="bg-indigo-600 text-white p-2 rounded hover:bg-indigo-700" disabled={!selectedProduct}><Plus size={18} /></button>
                 </div>
                 <div className="space-y-1 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between text-sm bg-white p-2 rounded border border-slate-100">
                            <span>{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-500"><X size={14}/></button>
                        </div>
                    ))}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-2 rounded text-xs flex items-center gap-2"><AlertCircle size={14}/>{error}</div>}

               <button onClick={handleCreateOrder} className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 shadow-md">Crear Pedido</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, MapPin, Phone, X, History, Flame, PackageCheck, ChefHat } from 'lucide-react';
import { formatCurrency } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrderStatus } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New Order Form State
  const [customerId, setCustomerId] = useState('');
  const [customerNameInput, setCustomerNameInput] = useState('');
  const [isExistingCustomer, setIsExistingCustomer] = useState(true);
  const [date, setDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  // --- Constants ---
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado'];
  const HISTORY_STEPS: OrderStatus[] = ['Entregado', 'Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const flow: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];
    const currentIndex = flow.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < flow.length - 1) {
      updateOrderStatus(order.id, flow[currentIndex + 1]);
    }
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    setSelectedProduct('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrder = () => {
    setError('');
    let finalCustomerName = '';
    let finalCustomerId = '';

    if (isExistingCustomer) {
        if (!customerId) { setError('Selecciona un cliente.'); return; }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) { setError('Ingresa el nombre.'); return; }
        finalCustomerName = customerNameInput;
        finalCustomerId = 'temp_' + Date.now(); 
    }

    if(!date) { setError('Selecciona fecha.'); return; }
    if(cart.length === 0) { setError('Agrega productos.'); return; }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const newOrder: Order = {
      id: Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: 'Pendiente',
      items: cart,
      totalPrice: total
    };

    addOrder(newOrder);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendientes', next: 'Cocinar' };
      case 'En Proceso': return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: Flame, label: 'En Horno', next: 'Terminar' };
      case 'Completado': return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: PackageCheck, label: 'Listos', next: 'Entregar' };
      default: return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Administra el ciclo de vida de cada orden.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial de Entregas
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Finalizados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div>
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {order.deliveryDate}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>
                <div className="text-right">
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block mt-1 ${config.color}`}>
                     {order.status}
                  </span>
                </div>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <button 
                  onClick={() => advanceOrder(order)}
                  className="w-full py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                >
                  {config.next === 'Cocinar' && <Flame size={16} />}
                  {config.next === 'Terminar' && <CheckCircle2 size={16} />}
                  {config.next === 'Entregar' && <PackageCheck size={16} />}
                  Avanzar a {config.next} 
                  <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
                </button>
              ) : (
                <div className="text-center text-xs text-slate-400 italic">
                  {order.status === 'Pagado' ? 'Pedido cerrado' : 'Esperando pago'}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* New Order Modal (Preserved) */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0">
              <h3 className="font-bold">Nuevo Pedido</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex gap-2 mb-2 text-xs">
                      <button onClick={() => setIsExistingCustomer(true)} className={`flex-1 py-1.5 rounded ${isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Seleccionar</button>
                      <button onClick={() => setIsExistingCustomer(false)} className={`flex-1 py-1.5 rounded ${!isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Nuevo</button>
                  </div>
                  {isExistingCustomer ? (
                      <select className="w-full p-2 border rounded text-sm bg-white" value={customerId} onChange={e => setCustomerId(e.target.value)}>
                          <option value="">-- Buscar Cliente --</option>
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                  ) : (
                      <input className="w-full p-2 border rounded text-sm" value={customerNameInput} onChange={e => setCustomerNameInput(e.target.value)} placeholder="Nombre del cliente" />
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700">Entrega</label>
                  <input type="date" className="w-full p-2 border rounded text-sm" value={date} onChange={e => setDate(e.target.value)} />
               </div>

               <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                 <h4 className="font-bold text-slate-700 text-xs mb-2 uppercase">Productos</h4>
                 <div className="flex gap-2 mb-2">
                    <select className="flex-1 p-2 border rounded text-sm bg-white" value={selectedProduct} onChange={e => setSelectedProduct(e.target.value)}>
                        <option value="">Seleccionar...</option>
                        {products.map(p => <option key={p.id} value={p.id}>{p.name} ({formatCurrency(p.price)})</option>)}
                    </select>
                    <input type="number" min="1" className="w-16 p-2 border rounded text-sm text-center" value={qty} onChange={e => setQty(Number(e.target.value))} />
                    <button onClick={addToCart} className="bg-indigo-600 text-white p-2 rounded hover:bg-indigo-700" disabled={!selectedProduct}><Plus size={18} /></button>
                 </div>
                 <div className="space-y-1 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between text-sm bg-white p-2 rounded border border-slate-100">
                            <span>{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-500"><X size={14}/></button>
                        </div>
                    ))}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-2 rounded text-xs flex items-center gap-2"><AlertCircle size={14}/>{error}</div>}

               <button onClick={handleCreateOrder} className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 shadow-md">Crear Pedido</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, MapPin, PackageCheck, ChefHat, Truck, DollarSign, History, X } from 'lucide-react';
import { formatCurrency } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrderStatus } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New Order Form State
  const [customerId, setCustomerId] = useState('');
  const [customerNameInput, setCustomerNameInput] = useState('');
  const [isExistingCustomer, setIsExistingCustomer] = useState(true);
  const [date, setDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  // --- Constants ---
  // "Pagado" is treated as the final "Archived/Cancelled" state from the workflow view.
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado'];
  const HISTORY_STEPS: OrderStatus[] = ['Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const flow: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];
    const currentIndex = flow.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < flow.length - 1) {
      updateOrderStatus(order.id, flow[currentIndex + 1]);
    }
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    setSelectedProduct('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrder = () => {
    setError('');
    let finalCustomerName = '';
    let finalCustomerId = '';

    if (isExistingCustomer) {
        if (!customerId) { setError('Selecciona un cliente.'); return; }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) { setError('Ingresa el nombre.'); return; }
        finalCustomerName = customerNameInput;
        finalCustomerId = 'temp_' + Date.now(); 
    }

    if(!date) { setError('Selecciona fecha.'); return; }
    if(cart.length === 0) { setError('Agrega productos.'); return; }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const newOrder: Order = {
      id: Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: 'Pendiente',
      items: cart,
      totalPrice: total
    };

    addOrder(newOrder);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': 
        return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendiente', next: 'En Proceso' };
      case 'En Proceso': 
        return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: ChefHat, label: 'En Proceso', next: 'Completado' };
      case 'Completado': 
        return { color: 'bg-indigo-100 text-indigo-800 border-indigo-200', icon: PackageCheck, label: 'Completado', next: 'Entregado' };
      case 'Entregado': 
        return { color: 'bg-blue-100 text-blue-800 border-blue-200', icon: Truck, label: 'Entregado', next: 'Pagado' };
      case 'Pagado': 
        return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: DollarSign, label: 'Pagado', next: '' };
      default: 
        return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Controla el flujo desde Pendiente hasta Pagado.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial (Pagados)
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Cerrados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div>
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {order.deliveryDate}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>
                <div className="text-right">
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block mt-1 ${config.color}`}>
                     {order.status}
                  </span>
                </div>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <button 
                  onClick={() => advanceOrder(order)}
                  className="w-full py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                >
                  {/* Dynamic Icon based on next step */}
                  {config.next === 'En Proceso' && <ChefHat size={16} />}
                  {config.next === 'Completado' && <PackageCheck size={16} />}
                  {config.next === 'Entregado' && <Truck size={16} />}
                  {config.next === 'Pagado' && <DollarSign size={16} />}

                  {config.next === 'Pagado' ? 'Confirmar Pago (Cerrar)' : `Avanzar a ${config.next}`}

                  <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
                </button>
              ) : (
                <div className="text-center text-xs text-slate-400 italic flex items-center justify-center gap-1">
                  <CheckCircle2 size={14} /> Pedido cerrado y archivado
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* New Order Modal (Preserved) */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0">
              <h3 className="font-bold">Nuevo Pedido</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex gap-2 mb-2 text-xs">
                      <button onClick={() => setIsExistingCustomer(true)} className={`flex-1 py-1.5 rounded ${isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Seleccionar</button>
                      <button onClick={() => setIsExistingCustomer(false)} className={`flex-1 py-1.5 rounded ${!isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Nuevo</button>
                  </div>
                  {isExistingCustomer ? (
                      <select className="w-full p-2 border rounded text-sm bg-white" value={customerId} onChange={e => setCustomerId(e.target.value)}>
                          <option value="">-- Buscar Cliente --</option>
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                  ) : (
                      <input className="w-full p-2 border rounded text-sm" value={customerNameInput} onChange={e => setCustomerNameInput(e.target.value)} placeholder="Nombre del cliente" />
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700">Entrega</label>
                  <input type="date" className="w-full p-2 border rounded text-sm" value={date} onChange={e => setDate(e.target.value)} />
               </div>

               <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                 <h4 className="font-bold text-slate-700 text-xs mb-2 uppercase">Productos</h4>
                 <div className="flex gap-2 mb-2">
                    <select className="flex-1 p-2 border rounded text-sm bg-white" value={selectedProduct} onChange={e => setSelectedProduct(e.target.value)}>
                        <option value="">Seleccionar...</option>
                        {products.map(p => <option key={p.id} value={p.id}>{p.name} ({formatCurrency(p.price)})</option>)}
                    </select>
                    <input type="number" min="1" className="w-16 p-2 border rounded text-sm text-center" value={qty} onChange={e => setQty(Number(e.target.value))} />
                    <button onClick={addToCart} className="bg-indigo-600 text-white p-2 rounded hover:bg-indigo-700" disabled={!selectedProduct}><Plus size={18} /></button>
                 </div>
                 <div className="space-y-1 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between text-sm bg-white p-2 rounded border border-slate-100">
                            <span>{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-500"><X size={14}/></button>
                        </div>
                    ))}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-2 rounded text-xs flex items-center gap-2"><AlertCircle size={14}/>{error}</div>}

               <button onClick={handleCreateOrder} className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 shadow-md">Crear Pedido</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Ingredient, Product, Order, ChatMessage } from "../types";
import { formatStock } from "../utils/conversions";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const suggestRecipe = async (availableIngredients: Ingredient[], prompt: string) => {
  const ingredientList = availableIngredients.map(i => `${i.name} (${formatStock(i.currentStock, i.unit)})`).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Soy un pastelero con los siguientes ingredientes en stock: ${ingredientList}. ${prompt}`,
      config: {
        systemInstruction: "Eres un Chef Pastelero experto y creativo. Sugiere recetas detalladas o consejos basados en el inventario disponible. Sé conciso y profesional.",
      }
    });
    return response.text || "No pude generar una respuesta.";
  } catch (error) {
    console.error("Gemini API Error (suggestRecipe):", error);
    throw error;
  }
};

export const parseOrderFromText = async (text: string, products: Product[]): Promise<any> => {
  const productNames = products.map(p => p.name).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Texto del pedido: "${text}"`,
      config: {
        systemInstruction: `Extrae la información del pedido en formato JSON.
        Los productos disponibles son: ${productNames}.
        Intenta coincidir el nombre del producto.
        `,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            customerName: { type: Type.STRING },
            items: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  productName: { type: Type.STRING },
                  quantity: { type: Type.NUMBER }
                }
              }
            },
          }
        }
      }
    });

    // Handle potential markdown code blocks in response
    let cleanText = response.text || "{}";
    cleanText = cleanText.replace(/```json/g, '').replace(/```/g, '').trim();

    return JSON.parse(cleanText);
  } catch (e) {
    console.error("Gemini API Error (parseOrderFromText):", e);
    return null;
  }
};

export const analyzeProductionData = async (orders: Order[], inventory: Ingredient[]) => {
    // Simplify orders for prompt
    const orderSummary = JSON.stringify(orders.map(o => ({
        customer: o.customerName,
        status: o.status,
        items: o.items.length,
        total: o.totalPrice
    })));

    const inventorySummary = JSON.stringify(inventory.map(i => ({ 
        name: i.name, 
        stock: i.currentStock, 
        unit: i.unit, 
        min: i.minStock 
    })));

    try {
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `Analiza estos datos de producción. 
          Pedidos pendientes: ${orderSummary}
          Inventario actual: ${inventorySummary}

          Dame un resumen ejecutivo de 3 puntos:
          1. Estado de riesgo del inventario.
          2. Eficiencia de producción sugerida.
          3. Una idea creativa para vender el excedente de stock (si lo hay) o mejorar ventas.`,
          config: {
              systemInstruction: "Eres un consultor de negocios de pastelería.",
          }
      });
      return response.text;
    } catch (error) {
      console.error("Gemini API Error (analyzeProductionData):", error);
      throw error;
    }
}

export const getChefResponse = async (history: ChatMessage[], newMessage: string): Promise<string> => {
  try {
    const formattedHistory = history.map(msg => ({
      role: msg.role,
      parts: [{ text: msg.text }]
    }));

    const chat = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
