interface BakeryContextType {
  ingredients: Ingredient[];
  products: Product[];
  orders: Order[];
  customers: Customer[];
  loading: boolean;

  addIngredient: (ing: Ingredient) => void;
  updateIngredientStock: (id: string, newAmount: number, newUnitCost?: number) => void;
  deleteIngredient: (id: string) => void;

  addProduct: (prod: Product) => void;
  updateProduct: (prod: Product) => void;
  deleteProduct: (id: string) => void;

  addOrder: (order: Order) => void;
  updateOrderStatus: (orderId: string, status: OrderStatus) => void;
  deleteOrder: (orderId: string) => void;

  addCustomer: (customer: Customer) => void;
  updateCustomer: (customer: Customer) => void;
  deleteCustomer: (id: string) => void;

  restoreDatabase: (data: any) => void;
}

const BakeryContext = createContext<BakeryContextType | undefined>(undefined);

export const BakeryProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [loading, setLoading] = useState(true);

  // Sync with Firestore
  useEffect(() => {
    const unsubIngredients = onSnapshot(collection(db, 'ingredients'), (snap) => {
      const data = snap.docs.map(d => ({ ...d.data(), id: d.id } as Ingredient));
      setIngredients(data);
      // Seed if empty on first load
      if (data.length === 0 && !localStorage.getItem('db_seeded')) {
        seedDatabase();
      }
    });

    const unsubProducts = onSnapshot(collection(db, 'products'), (snap) => {
      setProducts(snap.docs.map(d => ({ ...d.data(), id: d.id } as Product)));
    });

    const unsubOrders = onSnapshot(collection(db, 'orders'), (snap) => {
      setOrders(snap.docs.map(d => ({ ...d.data(), id: d.id } as Order)));
    });

    const unsubCustomers = onSnapshot(collection(db, 'customers'), (snap) => {
      setCustomers(snap.docs.map(d => ({ ...d.data(), id: d.id } as Customer)));
    });

    setLoading(false);

    return () => {
      unsubIngredients();
      unsubProducts();
      unsubOrders();
      unsubCustomers();
    };
  }, []);

  const seedDatabase = async () => {
    try {
      localStorage.setItem('db_seeded', 'true'); // Prevent loop
      const batch = writeBatch(db);

      // We need to maintain ID relationships for recipes.
      // Firestore creates random IDs on add(), so we use set() with specific IDs for seeding to keep relationships intact.

      INITIAL_INGREDIENTS.forEach(ing => {
        const ref = doc(db, 'ingredients', ing.id);
        batch.set(ref, ing);
      });

      INITIAL_PRODUCTS.forEach(prod => {
        const ref = doc(db, 'products', prod.id);
        batch.set(ref, prod);
      });

      INITIAL_CUSTOMERS.forEach(cust => {
        const ref = doc(db, 'customers', cust.id);
        batch.set(ref, cust);
      });

      INITIAL_ORDERS.forEach(ord => {
        const ref = doc(db, 'orders', ord.id);
        batch.set(ref, ord);
      });

      await batch.commit();
      console.log('Database seeded with initial data');
    } catch (e) {
      console.error('Error seeding database:', e);
    }
  };

  /* --- INGREDIENTS --- */
  const addIngredient = async (ing: Ingredient) => {
    const { id, ...rest } = ing; // Let Firestore handle ID or use addDoc
    await addDoc(collection(db, 'ingredients'), rest);
  };

  const updateIngredientStock = async (id: string, newAmount: number, newUnitCost?: number) => {
    const ing = ingredients.find(i => i.id === id);
    if (!ing) return;

    let updates: Partial<Ingredient> = { currentStock: newAmount };

    // Weighted Average Cost Logic
    if (newAmount > ing.currentStock && newUnitCost !== undefined && newUnitCost > 0) {
      const addedAmountBase = newAmount - ing.currentStock;
      const currentStockDisplay = fromBaseUnit(ing.currentStock, ing.unit);
      const addedAmountDisplay = fromBaseUnit(addedAmountBase, ing.unit);
      const newTotalDisplay = fromBaseUnit(newAmount, ing.unit);

      const oldValue = currentStockDisplay * ing.costPerUnit;
      const newValue = addedAmountDisplay * newUnitCost;

      const newAverageCost = newTotalDisplay > 0 ? (oldValue + newValue) / newTotalDisplay : ing.costPerUnit;
      updates.costPerUnit = Math.round(newAverageCost);
    }

    const ref = doc(db, 'ingredients', id);
    await updateDoc(ref, updates);
  };

  const deleteIngredient = async (id: string) => {
    await deleteDoc(doc(db, 'ingredients', id));
  };

  /* --- PRODUCTS --- */
  const addProduct = async (prod: Product) => {
    const { id, ...rest } = prod;
    await addDoc(collection(db, 'products'), rest);
  };

  const updateProduct = async (updated: Product) => {
    const { id, ...rest } = updated;
    await updateDoc(doc(db, 'products', id), rest);
  };

  const deleteProduct = async (id: string) => {
    await deleteDoc(doc(db, 'products', id));
  };

  /* --- CUSTOMERS --- */
  const addCustomer = async (customer: Customer) => {
    const { id, ...rest } = customer;
    await addDoc(collection(db, 'customers'), rest);
  };

  const updateCustomer = async (updated: Customer) => {
    const { id, ...rest } = updated;
    await updateDoc(doc(db, 'customers', id), rest);
  };

  const deleteCustomer = async (id: string) => {
    await deleteDoc(doc(db, 'customers', id));
  };

  /* --- ORDERS --- */
  const addOrder = async (order: Order) => {
    const { id, ...rest } = order;
    await addDoc(collection(db, 'orders'), rest);
  };

  const deleteOrder = async (id: string) => {
    await deleteDoc(doc(db, 'orders', id));
  };

  const updateOrderStatus = useCallback(async (orderId: string, newStatus: OrderStatus) => {
    const order = orders.find(o => o.id === orderId);
    if (!order) return;

    const oldStatus = order.status;

    // Deduct stock only when moving TO Completed from a non-completed state
    if (newStatus === 'Completado' && oldStatus !== 'Completado') {
      await deductStockForOrder(order);
    }

    await updateDoc(doc(db, 'orders', orderId), { status: newStatus });
  }, [orders, products, ingredients]); 

  const deductStockForOrder = async (order: Order) => {
    const usageMap = new Map<string, number>(); 

    order.items.forEach(item => {
      const product = products.find(p => p.id === item.productId);
      if (!product) return;

      product.recipe.forEach(recipeItem => {
        const amountPerProduct = toBaseUnit(recipeItem.quantity, recipeItem.unit);
        const totalAmount = amountPerProduct * item.quantity;

        const currentUsage = usageMap.get(recipeItem.ingredientId) || 0;
        usageMap.set(recipeItem.ingredientId, currentUsage + totalAmount);
      });
    });

    const batch = writeBatch(db);

    usageMap.forEach((amountToDeduct, ingId) => {
      const ing = ingredients.find(i => i.id === ingId);
      if (ing) {
        const newStock = Math.max(0, ing.currentStock - amountToDeduct);
        const ref = doc(db, 'ingredients', ingId);
        batch.update(ref, { currentStock: newStock });
      }
    });

    await batch.commit();
  };

  /* --- DATABASE RESTORE --- */
  const restoreDatabase = async (data: any) => {
    const batch = writeBatch(db);

    // Helper to batch adds. 
    // Note: This replaces data by adding new docs. 
    // Ideally, one would clear the collection first, but that requires listing all docs.
    // For simplicity in this context, we will add/merge.

    if (data.ingredients) {
      data.ingredients.forEach((item: any) => {
         // Create a new ref to avoid ID collision or use existing ID if provided
         const ref = item.id ? doc(db, 'ingredients', item.id) : doc(collection(db, 'ingredients'));
         batch.set(ref, item);
      });
    }
    if (data.products) {
      data.products.forEach((item: any) => {
         const ref = item.id ? doc(db, 'products', item.id) : doc(collection(db, 'products'));
         batch.set(ref, item);
      });
    }
    if (data.orders) {
      data.orders.forEach((item: any) => {
         const ref = item.id ? doc(db, 'orders', item.id) : doc(collection(db, 'orders'));
         batch.set(ref, item);
      });
    }
    if (data.customers) {
      data.customers.forEach((item: any) => {
         const ref = item.id ? doc(db, 'customers', item.id) : doc(collection(db, 'customers'));
         batch.set(ref, item);
      });
    }

    await batch.commit();
  };

  return (
    <BakeryContext.Provider value={{
      ingredients,
      products,
      orders,
      customers,
      loading,
      addIngredient,
      updateIngredientStock,
      deleteIngredient,
      addProduct,
      updateProduct,
      deleteProduct,
      addOrder,
      updateOrderStatus,
      deleteOrder,
      addCustomer,
      updateCustomer,
      deleteCustomer,
      restoreDatabase
    }}>
      {children}
    </BakeryContext.Provider>
  );
};

export const useBakery = () => {
  const context = useContext(BakeryContext);
  if (!context) throw new Error("useBakery must be used within BakeryProvider");
  return context;
};

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Ingredient, UnitType } from '../types';
import { UNIT_OPTIONS, BASE_UNITS } from '../constants';
import { formatStock, toBaseUnit, fromBaseUnit, formatCurrency } from '../utils/conversions';
import { Plus, Search, Edit2, X, RefreshCw, TrendingUp, Trash2 } from 'lucide-react';

// Local interface to handle form inputs allowing empty strings
interface IngredientForm {
  name: string;
  unit: UnitType;
  currentStock: number | '';
  minStock: number | '';
  costPerUnit: number | '';
}

export const Inventory: React.FC = () => {
  const { ingredients, addIngredient, updateIngredientStock, deleteIngredient } = useBakery();

  // State for Create Modal
  const [isModalOpen, setIsModalOpen] = useState(false);

  // State for Edit (Adjust) Modal
  const [editingItem, setEditingItem] = useState<Ingredient | null>(null);
  const [editStockValue, setEditStockValue] = useState<string>('');
  const [newPurchasePrice, setNewPurchasePrice] = useState<string>(''); // For WAC

  const [searchTerm, setSearchTerm] = useState('');

  // Form State for New Ingredient - Initialized with empty strings for numbers
  const [newIng, setNewIng] = useState<IngredientForm>({
    name: '',
    unit: UnitType.GRAMS,
    currentStock: '',
    minStock: '',
    costPerUnit: ''
  });

  // Handler: Create New
  const handleAdd = () => {
    if (!newIng.name || newIng.currentStock === '') return;

    // Default to 0 if empty string (though validation above checks currentStock)
    // Note: TypeScript narrows currentStock to 'number' due to the check above, so strict comparison with '' is invalid.
    const stockVal = newIng.currentStock;
    const minStockVal = newIng.minStock === '' ? 0 : newIng.minStock;
    const costVal = newIng.costPerUnit === '' ? 0 : newIng.costPerUnit;

    const stockInBase = toBaseUnit(stockVal, newIng.unit);
    const minStockInBase = toBaseUnit(minStockVal, newIng.unit);

    const ingredient: Ingredient = {
      id: Date.now().toString(),
      name: newIng.name,
      unit: newIng.unit,
      currentStock: stockInBase,
      minStock: minStockInBase,
      costPerUnit: costVal
    };

    addIngredient(ingredient);
    setIsModalOpen(false);
    // Reset form
    setNewIng({ name: '', unit: UnitType.GRAMS, currentStock: '', minStock: '', costPerUnit: '' });
  };

  // Handler: Open Edit Modal
  const handleEditClick = (ing: Ingredient) => {
    setEditingItem(ing);
    // Show value in preferred unit
    const val = fromBaseUnit(ing.currentStock, ing.unit);
    setEditStockValue(val.toString());
    setNewPurchasePrice(''); // Reset price
  };

  // Handler: Delete
  const handleDelete = (id: string, name: string) => {
    if (window.confirm(`¿Estás seguro que deseas eliminar "${name}" del inventario? Esto podría afectar las recetas que lo utilizan.`)) {
      deleteIngredient(id);
    }
  };

  // Handler: Save Edit
  const handleSaveEdit = () => {
    if (!editingItem) return;
    const val = parseFloat(editStockValue);
    if (isNaN(val) || val < 0) return;

    // Convert back to base unit for storage
    const newStockBase = toBaseUnit(val, editingItem.unit);

    // Check if price is provided for WAC
    const priceVal = newPurchasePrice ? parseFloat(newPurchasePrice) : undefined;

    updateIngredientStock(editingItem.id, newStockBase, priceVal);

    setEditingItem(null);
    setEditStockValue('');
    setNewPurchasePrice('');
  };

  const filtered = ingredients.filter(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()));

  // Calculate if we are adding stock (to show price input)
  const isAddingStock = editingItem && !isNaN(parseFloat(editStockValue)) 
    ? toBaseUnit(parseFloat(editStockValue), editingItem.unit) > editingItem.currentStock 
    : false;

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Inventario</h2>
        {/* Desktop Button */}
        <button 
          onClick={() => setIsModalOpen(true)}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 transition-colors shadow-sm"
        >
          <Plus size={18} /> Nuevo Ingrediente
        </button>
      </div>

      {/* Mobile Floating Action Button (FAB) */}
      <button 
        onClick={() => setIsModalOpen(true)}
        className="md:hidden fixed bottom-20 right-4 bg-indigo-600 text-white p-4 rounded-full shadow-lg z-40 hover:bg-indigo-700 transition-colors"
        aria-label="Nuevo Ingrediente"
      >
        <Plus size={24} />
      </button>

      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="text" 
          placeholder="Buscar materia prima..." 
          className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-600 text-xs uppercase font-semibold">
              <tr>
                <th className="px-6 py-4">Ingrediente</th>
                <th className="px-6 py-4">Stock Actual</th>
                <th className="px-6 py-4">Costo Prom. Unit</th>
                <th className="px-6 py-4">Unidad Base</th>
                <th className="px-6 py-4 text-center">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filtered.map(ing => {
                const isLow = ing.currentStock <= ing.minStock;
                return (
                  <tr key={ing.id} className={`hover:bg-slate-50 ${isLow ? 'bg-red-50' : ''}`}>
                    <td className="px-6 py-4 font-medium text-slate-800">{ing.name}</td>
