          onClick={() => setViewDetails('today')}
          className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col items-center justify-center text-center hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer group"
        >
          <div className="p-2 bg-blue-100 rounded-full text-blue-600 mb-2 group-hover:scale-110 transition-transform"><Clock size={20} /></div>
          <span className="text-xs text-slate-500 font-medium group-hover:text-indigo-600">Para Hoy</span>
          <p className="text-xl font-bold text-slate-800">{todayOrdersCount}</p>
          <span className="text-[10px] text-indigo-500 mt-1 opacity-0 group-hover:opacity-100 flex items-center">Ver lista <ChevronRight size={10}/></span>
        </button>

        <button 
          onClick={() => setViewDetails('lowStock')}
          className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col items-center justify-center text-center hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer group"
        >
          <div className="p-2 bg-red-100 rounded-full text-red-600 mb-2 group-hover:scale-110 transition-transform"><AlertTriangle size={20} /></div>
          <span className="text-xs text-slate-500 font-medium group-hover:text-indigo-600">Stock Bajo</span>
          <p className="text-xl font-bold text-slate-800">{lowStockItems.length}</p>
          <span className="text-[10px] text-indigo-500 mt-1 opacity-0 group-hover:opacity-100 flex items-center">Ver lista <ChevronRight size={10}/></span>
        </button>
      </div>

      {/* Low Stock Alerts Section (Inline Preview) */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex items-center justify-between">
          <h3 className="font-semibold text-slate-800 flex items-center gap-2">
            <AlertTriangle size={18} className="text-red-500" />
            Alertas de Stock
          </h3>
          {lowStockItems.length > 0 && (
            <span className="text-xs bg-red-100 text-red-700 px-2 py-1 rounded-full font-bold">
              {lowStockItems.length}
            </span>
          )}
        </div>
        <div className="divide-y divide-slate-100">
          {lowStockItems.length === 0 ? (
            <div className="p-8 text-center flex flex-col items-center text-slate-400">
              <CheckCircle2 size={32} className="mb-2 text-emerald-100" />
              <p>Todo el inventario está bajo control.</p>
            </div>
          ) : (
            // Only show top 5 here to encourage using the detail view if list is long
            lowStockItems.slice(0, 5).map(item => {
               const max = item.minStock * 2;
               const pct = Math.min(100, (item.currentStock / max) * 100);
               return (
                <div key={item.id} className="p-4 hover:bg-slate-50 transition-colors">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-medium text-slate-800">{item.name}</span>
                    <span className="font-bold text-red-600">{formatStock(item.currentStock, item.unit)}</span>
                  </div>
                  <div className="flex justify-between items-center text-xs text-slate-500 mb-1">
                    <span>Mínimo requerido: {formatStock(item.minStock, item.unit)}</span>
                  </div>
                  <div className="w-full bg-slate-100 rounded-full h-2">
                    <div 
                      className="bg-red-500 h-2 rounded-full transition-all duration-500" 
                      style={{ width: `${Math.max(5, pct)}%` }}
                    ></div>
                  </div>
                </div>
               );
            })
          )}
          {lowStockItems.length > 5 && (
             <button 
               onClick={() => setViewDetails('lowStock')}
               className="w-full py-3 text-sm text-indigo-600 font-medium hover:bg-slate-50"
             >
                Ver todos ({lowStockItems.length})
             </button>
          )}
        </div>
      </div>

      {/* Detail Modal */}
      {viewDetails && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50 animate-in fade-in duration-200">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-md max-h-[80vh] flex flex-col">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white rounded-t-xl">
              <h3 className="font-bold">{getModalTitle()}</h3>
              <button onClick={() => setViewDetails(null)} className="hover:bg-white/20 rounded-full p-1"><X size={20} /></button>
            </div>

            <div className="p-4 overflow-y-auto">
              {renderDetailContent()}
            </div>

            {viewDetails !== 'closing' && (
              <div className="p-3 border-t border-slate-100 bg-slate-50 rounded-b-xl">
                <button 
                  onClick={() => setViewDetails(null)}
                  className="w-full py-2 bg-white border border-slate-300 text-slate-700 font-medium rounded-lg hover:bg-slate-100"
                >
                  Cerrar
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus, Customer } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, PackageCheck, ChefHat, Truck, DollarSign, History, X } from 'lucide-react';
import { formatCurrency } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrderStatus, addCustomer } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New Order Form State
  const [customerId, setCustomerId] = useState('');
  const [customerNameInput, setCustomerNameInput] = useState('');
  const [isExistingCustomer, setIsExistingCustomer] = useState(true);
  const [date, setDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  // --- Constants ---
  // "Pagado" is treated as the final "Archived/Cancelled" state from the workflow view.
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado'];
  const HISTORY_STEPS: OrderStatus[] = ['Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const flow: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];
    const currentIndex = flow.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < flow.length - 1) {
      updateOrderStatus(order.id, flow[currentIndex + 1]);
    }
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    setSelectedProduct('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrder = async () => {
    setError('');
    let finalCustomerName = '';
    let finalCustomerId = '';

    if (isExistingCustomer) {
        if (!customerId) { setError('Selecciona un cliente.'); return; }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) { setError('Ingresa el nombre.'); return; }
        // Create new Customer in DB
        const newCustomerData: Customer = {
          id: '', // Generated by firestore in addCustomer
          name: customerNameInput.trim()
        };
        try {
          // addCustomer now returns the new ID
          finalCustomerId = await addCustomer(newCustomerData);
          finalCustomerName = customerNameInput.trim();
        } catch (e) {
          setError('Error guardando cliente nuevo.');
          return;
        }
    }

    if(!date) { setError('Selecciona fecha.'); return; }
    if(cart.length === 0) { setError('Agrega productos.'); return; }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const newOrder: Order = {
      id: Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: 'Pendiente',
      items: cart,
      totalPrice: total
    };

    addOrder(newOrder);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': 
        return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendiente', next: 'En Proceso' };
      case 'En Proceso': 
        return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: ChefHat, label: 'En Proceso', next: 'Completado' };
      case 'Completado': 
        return { color: 'bg-indigo-100 text-indigo-800 border-indigo-200', icon: PackageCheck, label: 'Completado', next: 'Entregado' };
      case 'Entregado': 
        return { color: 'bg-blue-100 text-blue-800 border-blue-200', icon: Truck, label: 'Entregado', next: 'Pagado' };
      case 'Pagado': 
        return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: DollarSign, label: 'Pagado', next: '' };
      default: 
        return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Controla el flujo desde Pendiente hasta Pagado.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial (Pagados)
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Cerrados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div>
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {order.deliveryDate}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>
                <div className="text-right">
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block mt-1 ${config.color}`}>
                     {order.status}
                  </span>
                </div>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <button 
                  onClick={() => advanceOrder(order)}
                  className="w-full py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                >
                  {/* Dynamic Icon based on next step */}
                  {config.next === 'En Proceso' && <ChefHat size={16} />}
                  {config.next === 'Completado' && <PackageCheck size={16} />}
                  {config.next === 'Entregado' && <Truck size={16} />}
                  {config.next === 'Pagado' && <DollarSign size={16} />}

                  {config.next === 'Pagado' ? 'Confirmar Pago (Cerrar)' : `Avanzar a ${config.next}`}

                  <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
                </button>
              ) : (
                <div className="text-center text-xs text-slate-400 italic flex items-center justify-center gap-1">
                  <CheckCircle2 size={14} /> Pedido cerrado y archivado
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* New Order Modal (Preserved) */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0">
              <h3 className="font-bold">Nuevo Pedido</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex gap-2 mb-2 text-xs">
                      <button onClick={() => setIsExistingCustomer(true)} className={`flex-1 py-1.5 rounded ${isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Seleccionar</button>
                      <button onClick={() => setIsExistingCustomer(false)} className={`flex-1 py-1.5 rounded ${!isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Nuevo</button>
                  </div>
                  {isExistingCustomer ? (
                      <select className="w-full p-2 border rounded text-sm bg-white" value={customerId} onChange={e => setCustomerId(e.target.value)}>
                          <option value="">-- Buscar Cliente --</option>
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                  ) : (
                      <input className="w-full p-2 border rounded text-sm" value={customerNameInput} onChange={e => setCustomerNameInput(e.target.value)} placeholder="Nombre del cliente" />
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700">Entrega</label>
                  <input type="date" className="w-full p-2 border rounded text-sm" value={date} onChange={e => setDate(e.target.value)} />
               </div>

               <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                 <h4 className="font-bold text-slate-700 text-xs mb-2 uppercase">Productos</h4>
                 <div className="flex gap-2 mb-2">
                    <select className="flex-1 p-2 border rounded text-sm bg-white" value={selectedProduct} onChange={e => setSelectedProduct(e.target.value)}>
                        <option value="">Seleccionar...</option>
                        {products.map(p => <option key={p.id} value={p.id}>{p.name} ({formatCurrency(p.price)})</option>)}
                    </select>
                    <input type="number" min="1" className="w-16 p-2 border rounded text-sm text-center" value={qty} onChange={e => setQty(Number(e.target.value))} />
                    <button onClick={addToCart} className="bg-indigo-600 text-white p-2 rounded hover:bg-indigo-700" disabled={!selectedProduct}><Plus size={18} /></button>
                 </div>
                 <div className="space-y-1 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between text-sm bg-white p-2 rounded border border-slate-100">
                            <span>{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-500"><X size={14}/></button>
                        </div>
                    ))}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-2 rounded text-xs flex items-center gap-2"><AlertCircle size={14}/>{error}</div>}

               <button onClick={handleCreateOrder} className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 shadow-md">Crear Pedido</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { UnitType } from '../types';

/**
 * Converts a value TO the base unit for storage/calculation.
 * Base units: Grams, Milliliters, Units.
 */
export const toBaseUnit = (amount: number, unit: UnitType): number => {
  switch (unit) {
    case UnitType.KILOGRAMS: return amount * 1000;
    case UnitType.LITERS: return amount * 1000;
    default: return amount;
  }
};

/**
 * Converts a value FROM the base unit to a display unit.
 */
export const fromBaseUnit = (amount: number, targetUnit: UnitType): number => {
  switch (targetUnit) {
    case UnitType.KILOGRAMS: return amount / 1000;
    case UnitType.LITERS: return amount / 1000;
    default: return amount;
  }
};

/**
 * Smart formatter: e.g. 1500g -> "1.5 kg"
 */
export const formatStock = (amount: number, preferredUnit: UnitType): string => {
  // If the unit is grams but amount >= 1000, show as kg
  if (preferredUnit === UnitType.GRAMS && amount >= 1000) {
    return `${(amount / 1000).toFixed(2)} kg`;
  }
  // If unit is ml but amount >= 1000, show as L
  if (preferredUnit === UnitType.MILLILITERS && amount >= 1000) {
    return `${(amount / 1000).toFixed(2)} L`;
  }

  // Otherwise respect the preferred unit but handle the scaling if needed
  const val = fromBaseUnit(amount, preferredUnit);
  return `${val.toFixed(preferredUnit === UnitType.UNITS ? 0 : 1)} ${preferredUnit}`;
};

/**
 * Formats currency for Chile (CLP): No decimals, uses dots for thousands.
 * e.g. 1500 -> "$1.500"
 */
export const formatCurrency = (amount: number): string => {
  return new Intl.NumberFormat('es-CL', {
    style: 'currency',
    currency: 'CLP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount);
};

/**
 * Formats a YYYY-MM-DD date string to dd/mm/yyyy
 */
export const formatDate = (dateString: string): string => {
  if (!dateString) return '';
  // Handle YYYY-MM-DD
  const parts = dateString.split('-');
  if (parts.length === 3) {
    return `${parts[2]}/${parts[1]}/${parts[0]}`;
  }
  return dateString;
};

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { AlertTriangle, ShoppingBag, Clock, DollarSign, CheckCircle2, X, ChevronRight, CreditCard, Banknote, Lock, Archive } from 'lucide-react';
import { formatStock, formatCurrency, formatDate } from '../utils/conversions';
import { STATUS_COLORS } from '../constants';

type DetailViewType = 'pending' | 'today' | 'lowStock' | 'closing' | null;

export const Dashboard: React.FC = () => {
  const { ingredients, orders, products, performMonthClose } = useBakery();
  const [viewDetails, setViewDetails] = useState<DetailViewType>(null);

  // Low Stock Logic
  const lowStockItems = ingredients.filter(ing => ing.currentStock <= ing.minStock);

  // Order Stats
  const pendingOrdersList = orders.filter(o => o.status === 'Pendiente');
  const pendingOrdersCount = pendingOrdersList.length;

  const today = new Date().toISOString().split('T')[0];
  const todayOrdersList = orders.filter(o => o.deliveryDate === today);
  const todayOrdersCount = todayOrdersList.length;

  // Financial Stats (CASH BASIS ADJUSTED)
  // 1. Pagado (Caja Actual): Solo pedidos Pagados que NO han sido cerrados administrativamente.
  const paidOrdersOpen = orders.filter(o => o.status === 'Pagado' && !o.accountingClosed);
  const revenueCollectedOpen = paidOrdersOpen.reduce((acc, order) => acc + order.totalPrice, 0);

  // 2. Entregado (Por Cobrar): Producto entregado pero no marcado como pagado aún.
  // IMPORTANTE: Estos no se ven afectados por el cierre de mes. Siguen siendo deuda viva.
  const deliveredOrders = orders.filter(o => o.status === 'Entregado');
  const revenueReceivable = deliveredOrders.reduce((acc, order) => acc + order.totalPrice, 0);

  // Total Active Value
  const totalActiveValue = revenueCollectedOpen + revenueReceivable;

  // Progress Bar
  const collectionRate = totalActiveValue > 0 ? (revenueCollectedOpen / totalActiveValue) * 100 : 0;

  const handlePerformClose = async () => {
    if (window.confirm(`¿Estás seguro que deseas realizar el CIERRE DE MES?\n\nSe archivarán ${paidOrdersOpen.length} pedidos pagados por un total de ${formatCurrency(revenueCollectedOpen)}.\n\nLos pedidos 'Por Cobrar' NO se verán afectados hasta que se paguen.`)) {
      await performMonthClose();
      setViewDetails(null);
    }
  };

  const renderDetailContent = () => {
    if (viewDetails === 'closing') {
      return (
        <div className="space-y-4">
           <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 text-sm text-amber-800">
             <div className="flex items-center gap-2 font-bold mb-2">
               <AlertTriangle size={18} /> Atención
             </div>
             <p className="mb-2">El <strong>Cierre de Mes</strong> archivará los ingresos actuales para iniciar un nuevo periodo contable.</p>
             <ul className="list-disc list-inside space-y-1 ml-1 opacity-90">
               <li>Se archivarán <strong>{paidOrdersOpen.length}</strong> pedidos pagados.</li>
               <li>Monto a cerrar: <strong>{formatCurrency(revenueCollectedOpen)}</strong>.</li>
               <li>El contador de "Caja Actual" volverá a $0.</li>
               <li>Los pedidos <strong>"Por Cobrar" ({deliveredOrders.length})</strong> se mantendrán abiertos.</li>
             </ul>
           </div>

           <div className="flex gap-2">
             <button 
               onClick={() => setViewDetails(null)}
               className="flex-1 py-3 border border-slate-300 rounded-lg font-medium text-slate-600 hover:bg-slate-50"
             >
               Cancelar
             </button>
             <button 
               onClick={handlePerformClose}
               disabled={paidOrdersOpen.length === 0}
               className="flex-1 py-3 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
             >
               <Lock size={18} /> Confirmar Cierre
             </button>
           </div>
        </div>
      );
    }

    if (viewDetails === 'lowStock') {
      return (
        <div className="space-y-3">
          {lowStockItems.length === 0 ? (
            <p className="text-center text-slate-500 py-4">No hay ítems con stock bajo.</p>
          ) : (
            lowStockItems.map(item => {
              const max = item.minStock * 2;
              const pct = Math.min(100, (item.currentStock / max) * 100);
              return (
                <div key={item.id} className="p-3 border border-slate-100 rounded-lg hover:bg-slate-50">
                  <div className="flex justify-between items-center mb-1">
                    <span className="font-semibold text-slate-800">{item.name}</span>
                    <span className="font-bold text-red-600">{formatStock(item.currentStock, item.unit)}</span>
                  </div>
                  <div className="text-xs text-slate-500 mb-2">Mínimo: {formatStock(item.minStock, item.unit)}</div>
                  <div className="w-full bg-slate-100 rounded-full h-1.5">
                    <div className="bg-red-500 h-1.5 rounded-full" style={{ width: `${Math.max(5, pct)}%` }}></div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      );
    }

    const orderList = viewDetails === 'pending' ? pendingOrdersList : todayOrdersList;
    const emptyMsg = viewDetails === 'pending' ? 'No hay pedidos pendientes.' : 'No hay pedidos para hoy.';

    return (
      <div className="space-y-3">
        {orderList.length === 0 ? (
          <p className="text-center text-slate-500 py-4">{emptyMsg}</p>
        ) : (
          orderList.map(order => (
            <div key={order.id} className="p-3 border border-slate-100 rounded-lg hover:bg-slate-50">
              <div className="flex justify-between items-start mb-2">
                <div>
                  <h4 className="font-bold text-slate-800">{order.customerName}</h4>
                  <p className="text-xs text-slate-500 flex items-center gap-1">
                    <Clock size={12} /> Entrega: {formatDate(order.deliveryDate)}
                  </p>
                </div>
                <span className={`text-[10px] px-2 py-1 rounded-full border ${STATUS_COLORS[order.status]}`}>
                  {order.status}
                </span>
              </div>
              <ul className="text-sm text-slate-600 space-y-1 mb-2 bg-slate-50 p-2 rounded">
                {order.items.map((item, idx) => {
                  const pName = products.find(p => p.id === item.productId)?.name || 'Producto';
                  return (
                    <li key={idx} className="flex justify-between">
                      <span>{item.quantity}x {pName}</span>
                    </li>
                  );
                })}
              </ul>
              <div className="text-right font-bold text-slate-800 text-sm">
                Total: {formatCurrency(order.totalPrice)}
              </div>
            </div>
          ))
        )}
      </div>
    );
  };

  const getModalTitle = () => {
    switch (viewDetails) {
      case 'pending': return 'Pedidos Pendientes';
      case 'today': return 'Pedidos Para Hoy';
      case 'lowStock': return 'Alertas de Stock Bajo';
      case 'closing': return 'Cierre de Mes';
      default: return '';
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Panel de Control</h2>
          <p className="text-slate-500">Resumen operativo y financiero.</p>
        </div>

        {/* Main Action Button for Closing Month */}
        <button 
          onClick={() => setViewDetails('closing')}
          className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-900 transition-colors shadow-sm text-sm font-medium"
        >
          <Archive size={16} /> Cerrar Mes
        </button>
      </header>

      {/* Financial Summary Section */}
      <div className="bg-gradient-to-br from-indigo-900 to-slate-900 rounded-xl p-6 text-white shadow-lg relative overflow-hidden">

        <div className="flex items-center gap-3 mb-4 opacity-80">
          <DollarSign className="text-emerald-400" />
          <span className="uppercase tracking-wider text-sm font-semibold">Caja Actual (Abierta)</span>
        </div>

        <div className="grid grid-cols-2 gap-8">
          <div>
             <p className="text-sm text-slate-300 mb-1">Total Pagado</p>
             <p className="text-3xl font-bold text-emerald-400">{formatCurrency(revenueCollectedOpen)}</p>
             <div className="flex items-center gap-1 mt-1 text-xs text-emerald-200/70">
                <Banknote size={12} /> {paidOrdersOpen.length} pedidos sin cerrar
             </div>
          </div>

          <div className="border-l border-white/10 pl-8">
             <p className="text-sm text-slate-300 mb-1">Por Cobrar (Entregados)</p>
             <p className="text-2xl font-bold text-slate-200">{formatCurrency(revenueReceivable)}</p>
             <div className="flex items-center gap-1 mt-1 text-xs text-slate-400">
                <CreditCard size={12} /> {deliveredOrders.length} pendientes de pago
             </div>
          </div>
        </div>

        <div className="mt-4 pt-4 border-t border-white/10">
          <div className="flex justify-between text-xs mb-1">
            <span>Flujo de Caja Activo</span>
            <span>{collectionRate.toFixed(0)}% cobrado</span>
          </div>
          <div className="w-full bg-white/10 rounded-full h-1.5 flex overflow-hidden">
            <div 
              className="bg-emerald-500 h-1.5 transition-all"
              style={{ width: `${collectionRate}%` }}
            ></div>
          </div>
        </div>
      </div>

      {/* Operational KPI Cards - Clickable */}
      <div className="grid grid-cols-3 gap-3 md:gap-4">
        <button 
          onClick={() => setViewDetails('pending')}
          className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col items-center justify-center text-center hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer group"
        >
          <div className="p-2 bg-yellow-100 rounded-full text-yellow-600 mb-2 group-hover:scale-110 transition-transform"><ShoppingBag size={20} /></div>
          <span className="text-xs text-slate-500 font-medium group-hover:text-indigo-600">Pendientes</span>
          <p className="text-xl font-bold text-slate-800">{pendingOrdersCount}</p>
          <span className="text-[10px] text-indigo-500 mt-1 opacity-0 group-hover:opacity-100 flex items-center">Ver lista <ChevronRight size={10}/></span>
        </button>

        <button 
          onClick={() => setViewDetails('today')}
          className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col items-center justify-center text-center hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer group"
        >
          <div className="p-2 bg-blue-100 rounded-full text-blue-600 mb-2 group-hover:scale-110 transition-transform"><Clock size={20} /></div>
          <span className="text-xs text-slate-500 font-medium group-hover:text-indigo-600">Para Hoy</span>
          <p className="text-xl font-bold text-slate-800">{todayOrdersCount}</p>
          <span className="text-[10px] text-indigo-500 mt-1 opacity-0 group-hover:opacity-100 flex items-center">Ver lista <ChevronRight size={10}/></span>
        </button>

        <button 
          onClick={() => setViewDetails('lowStock')}
          className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col items-center justify-center text-center hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer group"
        >
          <div className="p-2 bg-red-100 rounded-full text-red-600 mb-2 group-hover:scale-110 transition-transform"><AlertTriangle size={20} /></div>
          <span className="text-xs text-slate-500 font-medium group-hover:text-indigo-600">Stock Bajo</span>
          <p className="text-xl font-bold text-slate-800">{lowStockItems.length}</p>
          <span className="text-[10px] text-indigo-500 mt-1 opacity-0 group-hover:opacity-100 flex items-center">Ver lista <ChevronRight size={10}/></span>
        </button>
      </div>

      {/* Low Stock Alerts Section (Inline Preview) */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex items-center justify-between">
          <h3 className="font-semibold text-slate-800 flex items-center gap-2">
            <AlertTriangle size={18} className="text-red-500" />
            Alertas de Stock
          </h3>
          {lowStockItems.length > 0 && (
            <span className="text-xs bg-red-100 text-red-700 px-2 py-1 rounded-full font-bold">
              {lowStockItems.length}
            </span>
          )}
        </div>
        <div className="divide-y divide-slate-100">
          {lowStockItems.length === 0 ? (
            <div className="p-8 text-center flex flex-col items-center text-slate-400">
              <CheckCircle2 size={32} className="mb-2 text-emerald-100" />
              <p>Todo el inventario está bajo control.</p>
            </div>
          ) : (
            // Only show top 5 here to encourage using the detail view if list is long
            lowStockItems.slice(0, 5).map(item => {
               const max = item.minStock * 2;
               const pct = Math.min(100, (item.currentStock / max) * 100);
               return (
                <div key={item.id} className="p-4 hover:bg-slate-50 transition-colors">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-medium text-slate-800">{item.name}</span>
                    <span className="font-bold text-red-600">{formatStock(item.currentStock, item.unit)}</span>
                  </div>
                  <div className="flex justify-between items-center text-xs text-slate-500 mb-1">
                    <span>Mínimo requerido: {formatStock(item.minStock, item.unit)}</span>
                  </div>
                  <div className="w-full bg-slate-100 rounded-full h-2">
                    <div 
                      className="bg-red-500 h-2 rounded-full transition-all duration-500" 
                      style={{ width: `${Math.max(5, pct)}%` }}
                    ></div>
                  </div>
                </div>
               );
            })
          )}
          {lowStockItems.length > 5 && (
             <button 
               onClick={() => setViewDetails('lowStock')}
               className="w-full py-3 text-sm text-indigo-600 font-medium hover:bg-slate-50"
             >
                Ver todos ({lowStockItems.length})
             </button>
          )}
        </div>
      </div>

      {/* Detail Modal */}
      {viewDetails && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50 animate-in fade-in duration-200">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-md max-h-[80vh] flex flex-col">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white rounded-t-xl">
              <h3 className="font-bold">{getModalTitle()}</h3>
              <button onClick={() => setViewDetails(null)} className="hover:bg-white/20 rounded-full p-1"><X size={20} /></button>
            </div>

            <div className="p-4 overflow-y-auto">
              {renderDetailContent()}
            </div>

            {viewDetails !== 'closing' && (
              <div className="p-3 border-t border-slate-100 bg-slate-50 rounded-b-xl">
                <button 
                  onClick={() => setViewDetails(null)}
                  className="w-full py-2 bg-white border border-slate-300 text-slate-700 font-medium rounded-lg hover:bg-slate-100"
                >
                  Cerrar
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus, Customer } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, PackageCheck, ChefHat, Truck, DollarSign, History, X } from 'lucide-react';
import { formatCurrency, formatDate } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrderStatus, addCustomer } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New Order Form State
  const [customerId, setCustomerId] = useState('');
  const [customerNameInput, setCustomerNameInput] = useState('');
  const [isExistingCustomer, setIsExistingCustomer] = useState(true);
  const [date, setDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  // --- Constants ---
  // "Pagado" is treated as the final "Archived/Cancelled" state from the workflow view.
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado'];
  const HISTORY_STEPS: OrderStatus[] = ['Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const flow: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];
    const currentIndex = flow.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < flow.length - 1) {
      updateOrderStatus(order.id, flow[currentIndex + 1]);
    }
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    setSelectedProduct('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrder = async () => {
    setError('');
    let finalCustomerName = '';
    let finalCustomerId = '';

    if (isExistingCustomer) {
        if (!customerId) { setError('Selecciona un cliente.'); return; }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) { setError('Ingresa el nombre.'); return; }
        // Create new Customer in DB
        const newCustomerData: Customer = {
          id: '', // Generated by firestore in addCustomer
          name: customerNameInput.trim()
        };
        try {
          // addCustomer now returns the new ID
          finalCustomerId = await addCustomer(newCustomerData);
          finalCustomerName = customerNameInput.trim();
        } catch (e) {
          setError('Error guardando cliente nuevo.');
          return;
        }
    }

    if(!date) { setError('Selecciona fecha.'); return; }
    if(cart.length === 0) { setError('Agrega productos.'); return; }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const newOrder: Order = {
      id: Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: 'Pendiente',
      items: cart,
      totalPrice: total
    };

    addOrder(newOrder);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': 
        return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendiente', next: 'En Proceso' };
      case 'En Proceso': 
        return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: ChefHat, label: 'En Proceso', next: 'Completado' };
      case 'Completado': 
        return { color: 'bg-indigo-100 text-indigo-800 border-indigo-200', icon: PackageCheck, label: 'Completado', next: 'Entregado' };
      case 'Entregado': 
        return { color: 'bg-blue-100 text-blue-800 border-blue-200', icon: Truck, label: 'Entregado', next: 'Pagado' };
      case 'Pagado': 
        return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: DollarSign, label: 'Pagado', next: '' };
      default: 
        return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Controla el flujo desde Pendiente hasta Pagado.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial (Pagados)
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Cerrados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div>
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {formatDate(order.deliveryDate)}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>
                <div className="text-right">
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block mt-1 ${config.color}`}>
                     {order.status}
                  </span>
                </div>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <button 
                  onClick={() => advanceOrder(order)}
                  className="w-full py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                >
                  {/* Dynamic Icon based on next step */}
                  {config.next === 'En Proceso' && <ChefHat size={16} />}
                  {config.next === 'Completado' && <PackageCheck size={16} />}
                  {config.next === 'Entregado' && <Truck size={16} />}
                  {config.next === 'Pagado' && <DollarSign size={16} />}

                  {config.next === 'Pagado' ? 'Confirmar Pago (Cerrar)' : `Avanzar a ${config.next}`}

                  <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
