interface BakeryContextType {
  ingredients: Ingredient[];
  products: Product[];
  orders: Order[];
  customers: Customer[];
  monthClosures: MonthClosure[];
  loading: boolean;

  addIngredient: (ing: Ingredient) => void;
  updateIngredientStock: (id: string, newAmount: number, newUnitCost?: number) => void;
  deleteIngredient: (id: string) => void;

  addProduct: (prod: Product) => void;
  updateProduct: (prod: Product) => void;
  deleteProduct: (id: string) => void;

  addOrder: (order: Order) => void;
  updateOrder: (order: Order) => void; // Added for editing full order details
  updateOrderStatus: (orderId: string, status: OrderStatus) => void;
  deleteOrder: (orderId: string) => void;

  addCustomer: (customer: Customer) => Promise<string>; // Returns the new ID
  updateCustomer: (customer: Customer) => void;
  deleteCustomer: (id: string) => void;

  performMonthClose: () => Promise<void>;
  restoreDatabase: (data: any) => void;
}

const BakeryContext = createContext<BakeryContextType | undefined>(undefined);

export const BakeryProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [monthClosures, setMonthClosures] = useState<MonthClosure[]>([]);
  const [loading, setLoading] = useState(true);

  // Sync with Firestore
  useEffect(() => {
    const unsubIngredients = onSnapshot(collection(db, 'ingredients'), (snap) => {
      const data = snap.docs.map(d => ({ ...d.data(), id: d.id } as Ingredient));
      setIngredients(data);
      // Seed if empty on first load
      if (data.length === 0 && !localStorage.getItem('db_seeded')) {
        seedDatabase();
      }
    });

    const unsubProducts = onSnapshot(collection(db, 'products'), (snap) => {
      setProducts(snap.docs.map(d => ({ ...d.data(), id: d.id } as Product)));
    });

    const unsubOrders = onSnapshot(collection(db, 'orders'), (snap) => {
      setOrders(snap.docs.map(d => ({ ...d.data(), id: d.id } as Order)));
    });

    const unsubCustomers = onSnapshot(collection(db, 'customers'), (snap) => {
      setCustomers(snap.docs.map(d => ({ ...d.data(), id: d.id } as Customer)));
    });

    const qClosures = query(collection(db, 'month_closures'), orderBy('date', 'desc'));
    const unsubClosures = onSnapshot(qClosures, (snap) => {
      setMonthClosures(snap.docs.map(d => ({ ...d.data(), id: d.id } as MonthClosure)));
    });

    setLoading(false);

    return () => {
      unsubIngredients();
      unsubProducts();
      unsubOrders();
      unsubCustomers();
      unsubClosures();
    };
  }, []);

  const seedDatabase = async () => {
    try {
      localStorage.setItem('db_seeded', 'true'); // Prevent loop
      const batch = writeBatch(db);

      INITIAL_INGREDIENTS.forEach(ing => {
        const ref = doc(db, 'ingredients', ing.id);
        batch.set(ref, ing);
      });

      INITIAL_PRODUCTS.forEach(prod => {
        const ref = doc(db, 'products', prod.id);
        batch.set(ref, prod);
      });

      INITIAL_CUSTOMERS.forEach(cust => {
        const ref = doc(db, 'customers', cust.id);
        batch.set(ref, cust);
      });

      INITIAL_ORDERS.forEach(ord => {
        const ref = doc(db, 'orders', ord.id);
        batch.set(ref, ord);
      });

      await batch.commit();
      console.log('Database seeded with initial data');
    } catch (e) {
      console.error('Error seeding database:', e);
    }
  };

  /* --- INGREDIENTS --- */
  const addIngredient = async (ing: Ingredient) => {
    const { id, ...rest } = ing; // Let Firestore handle ID or use addDoc
    await addDoc(collection(db, 'ingredients'), rest);
  };

  const updateIngredientStock = async (id: string, newAmount: number, newUnitCost?: number) => {
    const ing = ingredients.find(i => i.id === id);
    if (!ing) return;

    let updates: Partial<Ingredient> = { currentStock: newAmount };

    // Weighted Average Cost Logic
    if (newAmount > ing.currentStock && newUnitCost !== undefined && newUnitCost > 0) {
      const addedAmountBase = newAmount - ing.currentStock;
      const currentStockDisplay = fromBaseUnit(ing.currentStock, ing.unit);
      const addedAmountDisplay = fromBaseUnit(addedAmountBase, ing.unit);
      const newTotalDisplay = fromBaseUnit(newAmount, ing.unit);

      const oldValue = currentStockDisplay * ing.costPerUnit;
      const newValue = addedAmountDisplay * newUnitCost;

      const newAverageCost = newTotalDisplay > 0 ? (oldValue + newValue) / newTotalDisplay : ing.costPerUnit;
      updates.costPerUnit = Math.round(newAverageCost);
    }

    const ref = doc(db, 'ingredients', id);
    await updateDoc(ref, updates);
  };

  const deleteIngredient = async (id: string) => {
    await deleteDoc(doc(db, 'ingredients', id));
  };

  /* --- PRODUCTS --- */
  const addProduct = async (prod: Product) => {
    const { id, ...rest } = prod;
    await addDoc(collection(db, 'products'), rest);
  };

  const updateProduct = async (updated: Product) => {
    const { id, ...rest } = updated;
    await updateDoc(doc(db, 'products', id), rest);
  };

  const deleteProduct = async (id: string) => {
    await deleteDoc(doc(db, 'products', id));
  };

  /* --- CUSTOMERS --- */
  const addCustomer = async (customer: Customer): Promise<string> => {
    const { id, ...rest } = customer;
    // We ignore the passed ID and let Firestore generate one, then return it.
    const docRef = await addDoc(collection(db, 'customers'), rest);
    return docRef.id;
  };

  const updateCustomer = async (updated: Customer) => {
    const { id, ...rest } = updated;
    await updateDoc(doc(db, 'customers', id), rest);
  };

  const deleteCustomer = async (id: string) => {
    await deleteDoc(doc(db, 'customers', id));
  };

  /* --- ORDERS --- */
  const addOrder = async (order: Order) => {
    const { id, ...rest } = order;
    await addDoc(collection(db, 'orders'), rest);
  };

  const updateOrder = async (updatedOrder: Order) => {
    const { id, ...rest } = updatedOrder;
    await updateDoc(doc(db, 'orders', id), rest);
  };

  const deleteOrder = async (id: string) => {
    await deleteDoc(doc(db, 'orders', id));
  };

  const updateOrderStatus = useCallback(async (orderId: string, newStatus: OrderStatus) => {
    const order = orders.find(o => o.id === orderId);
    if (!order) return;

    const oldStatus = order.status;

    // Deduct stock only when moving TO Completed from a non-completed state
    if (newStatus === 'Completado' && oldStatus !== 'Completado') {
      await deductStockForOrder(order);
    }

    await updateDoc(doc(db, 'orders', orderId), { status: newStatus });
  }, [orders, products, ingredients]); 

  const deductStockForOrder = async (order: Order) => {
    const usageMap = new Map<string, number>(); 

    order.items.forEach(item => {
      const product = products.find(p => p.id === item.productId);
      if (!product) return;

      product.recipe.forEach(recipeItem => {
        const amountPerProduct = toBaseUnit(recipeItem.quantity, recipeItem.unit);
        const totalAmount = amountPerProduct * item.quantity;

        const currentUsage = usageMap.get(recipeItem.ingredientId) || 0;
        usageMap.set(recipeItem.ingredientId, currentUsage + totalAmount);
      });
    });

    const batch = writeBatch(db);

    usageMap.forEach((amountToDeduct, ingId) => {
      const ing = ingredients.find(i => i.id === ingId);
      if (ing) {
        const newStock = Math.max(0, ing.currentStock - amountToDeduct);
        const ref = doc(db, 'ingredients', ingId);
        batch.update(ref, { currentStock: newStock });
      }
    });

    await batch.commit();
  };

  /* --- MONTH CLOSURE (CIERRE DE CAJA) --- */
  const performMonthClose = async () => {
    // 1. Filter Orders: Status "Pagado" AND NOT already closed.
    const openPaidOrders = orders.filter(o => o.status === 'Pagado' && !o.accountingClosed);

    if (openPaidOrders.length === 0) return;

    const batch = writeBatch(db);

    // 2. Calculate Totals
    const totalRevenue = openPaidOrders.reduce((acc, o) => acc + o.totalPrice, 0);
    const totalOrders = openPaidOrders.length;
    const now = new Date();

    // 3. Create Closure Record
    const closureData: Omit<MonthClosure, 'id'> = {
      date: now.toISOString(),
      periodLabel: `${now.toLocaleString('es-CL', { month: 'long', year: 'numeric' })} - Corte ${now.getDate()}`,
      totalRevenue,
      totalOrders
    };

    const closureRef = doc(collection(db, 'month_closures'));
    batch.set(closureRef, closureData);

    // 4. Update Orders to accountingClosed: true
    openPaidOrders.forEach(order => {
      const orderRef = doc(db, 'orders', order.id);
      batch.update(orderRef, { accountingClosed: true });
    });

    await batch.commit();
  };


  /* --- DATABASE RESTORE --- */
  const restoreDatabase = async (data: any) => {
    const batch = writeBatch(db);

    if (data.ingredients) {
      data.ingredients.forEach((item: any) => {
         const ref = item.id ? doc(db, 'ingredients', item.id) : doc(collection(db, 'ingredients'));
         batch.set(ref, item);
      });
    }
    if (data.products) {
      data.products.forEach((item: any) => {
         const ref = item.id ? doc(db, 'products', item.id) : doc(collection(db, 'products'));
         batch.set(ref, item);
      });
    }
    if (data.orders) {
      data.orders.forEach((item: any) => {
         const ref = item.id ? doc(db, 'orders', item.id) : doc(collection(db, 'orders'));
         batch.set(ref, item);
      });
    }
    if (data.customers) {
      data.customers.forEach((item: any) => {
         const ref = item.id ? doc(db, 'customers', item.id) : doc(collection(db, 'customers'));
         batch.set(ref, item);
      });
    }

    await batch.commit();
  };

  return (
    <BakeryContext.Provider value={{
      ingredients,
      products,
      orders,
      customers,
      monthClosures,
      loading,
      addIngredient,
      updateIngredientStock,
      deleteIngredient,
      addProduct,
      updateProduct,
      deleteProduct,
      addOrder,
      updateOrder,
      updateOrderStatus,
      deleteOrder,
      addCustomer,
      updateCustomer,
      deleteCustomer,
      performMonthClose,
      restoreDatabase
    }}>
      {children}
    </BakeryContext.Provider>
  );
};

export const useBakery = () => {
  const context = useContext(BakeryContext);
  if (!context) throw new Error("useBakery must be used within BakeryProvider");
  return context;
};

import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus, Customer } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, PackageCheck, ChefHat, Truck, DollarSign, History, X, Edit2, Trash2 } from 'lucide-react';
import { formatCurrency, formatDate } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrder, updateOrderStatus, addCustomer, deleteOrder } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New/Edit Order Form State
  const [editingOrderId, setEditingOrderId] = useState<string | null>(null);
  const [customerId, setCustomerId] = useState('');
  const [customerNameInput, setCustomerNameInput] = useState('');
  const [isExistingCustomer, setIsExistingCustomer] = useState(true);
  const [date, setDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  // --- Constants ---
  // "Pagado" is treated as the final "Archived/Cancelled" state from the workflow view.
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado'];
  const HISTORY_STEPS: OrderStatus[] = ['Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const flow: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];
    const currentIndex = flow.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < flow.length - 1) {
      updateOrderStatus(order.id, flow[currentIndex + 1]);
    }
  };

  const handleDeleteOrder = (order: Order) => {
    if (window.confirm(`¿Estás seguro de eliminar el pedido de ${order.customerName}?`)) {
        if(order.status === 'Completado' || order.status === 'Entregado' || order.status === 'Pagado') {
            alert('Atención: Al eliminar este pedido que ya fue procesado, el stock de ingredientes NO se repondrá automáticamente.');
        }
        deleteOrder(order.id);
    }
  };

  const handleEditOrder = (order: Order) => {
    setEditingOrderId(order.id);
    setCustomerId(order.customerId);
    setCustomerNameInput(order.customerName);
    setIsExistingCustomer(!!order.customerId && customers.some(c => c.id === order.customerId));
    setDate(order.deliveryDate);
    setCart(order.items.map(i => ({...i}))); // Clone items
    setError('');
    setIsModalOpen(true);
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    // Check if product already in cart
    const existingIndex = cart.findIndex(i => i.productId === selectedProduct);
    if (existingIndex >= 0) {
        const newCart = [...cart];
        newCart[existingIndex].quantity += finalQty;
        setCart(newCart);
    } else {
        setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    }

    setSelectedProduct('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrUpdateOrder = async () => {
    setError('');
    let finalCustomerName = '';
    let finalCustomerId = '';

    if (isExistingCustomer) {
        if (!customerId) { setError('Selecciona un cliente.'); return; }
        const c = customers.find(c => c.id === customerId);
        finalCustomerName = c ? c.name : 'Cliente';
        finalCustomerId = customerId;
    } else {
        if (!customerNameInput.trim()) { setError('Ingresa el nombre.'); return; }
        // Create new Customer in DB only if we are creating new order or changing customer
        const newCustomerData: Customer = {
          id: '', // Generated by firestore in addCustomer
          name: customerNameInput.trim()
        };
        try {
          finalCustomerId = await addCustomer(newCustomerData);
          finalCustomerName = customerNameInput.trim();
        } catch (e) {
          setError('Error guardando cliente nuevo.');
          return;
        }
    }

    if(!date) { setError('Selecciona fecha.'); return; }
    if(cart.length === 0) { setError('Agrega productos.'); return; }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const orderData: Order = {
      id: editingOrderId || Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: editingOrderId ? (orders.find(o => o.id === editingOrderId)?.status || 'Pendiente') : 'Pendiente',
      items: cart,
      totalPrice: total
    };

    if (editingOrderId) {
        updateOrder(orderData);
    } else {
        addOrder(orderData);
    }
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    setCustomerId('');
    setCustomerNameInput('');
    setIsExistingCustomer(true);
    setDate('');
    setError('');
    setSelectedProduct('');
    setQty(1);
    setEditingOrderId(null);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': 
        return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendiente', next: 'En Proceso' };
      case 'En Proceso': 
        return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: ChefHat, label: 'En Proceso', next: 'Completado' };
      case 'Completado': 
        return { color: 'bg-indigo-100 text-indigo-800 border-indigo-200', icon: PackageCheck, label: 'Completado', next: 'Entregado' };
      case 'Entregado': 
        return { color: 'bg-blue-100 text-blue-800 border-blue-200', icon: Truck, label: 'Entregado', next: 'Pagado' };
      case 'Pagado': 
        return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: DollarSign, label: 'Pagado', next: '' };
      default: 
        return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Controla el flujo desde Pendiente hasta Pagado.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial (Pagados)
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Cerrados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div className="flex-1 min-w-0">
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {formatDate(order.deliveryDate)}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>

                {/* Edit/Delete Controls */}
                <div className="flex gap-1 ml-2">
                    <button 
                        onClick={() => handleEditOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-indigo-600 rounded hover:bg-indigo-50 transition-colors"
                        title="Editar Pedido"
                    >
                        <Edit2 size={16} />
                    </button>
                    <button 
                        onClick={() => handleDeleteOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-red-600 rounded hover:bg-red-50 transition-colors"
                        title="Eliminar Pedido"
                    >
                        <Trash2 size={16} />
                    </button>
                </div>
              </div>

              {/* Status & Price Row */}
              <div className="flex justify-between items-center mb-3">
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block ${config.color}`}>
                     {order.status}
                  </span>
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <button 
                  onClick={() => advanceOrder(order)}
                  className="w-full py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                >
                  {/* Dynamic Icon based on next step */}
                  {config.next === 'En Proceso' && <ChefHat size={16} />}
                  {config.next === 'Completado' && <PackageCheck size={16} />}
                  {config.next === 'Entregado' && <Truck size={16} />}
                  {config.next === 'Pagado' && <DollarSign size={16} />}

                  {config.next === 'Pagado' ? 'Confirmar Pago (Cerrar)' : `Avanzar a ${config.next}`}

                  <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
                </button>
              ) : (
                <div className="text-center text-xs text-slate-400 italic flex items-center justify-center gap-1">
                  <CheckCircle2 size={14} /> Pedido cerrado y archivado
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* New/Edit Order Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0">
              <h3 className="font-bold">{editingOrderId ? 'Editar Pedido' : 'Nuevo Pedido'}</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex gap-2 mb-2 text-xs">
                      <button onClick={() => setIsExistingCustomer(true)} className={`flex-1 py-1.5 rounded ${isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Seleccionar</button>
                      <button onClick={() => setIsExistingCustomer(false)} className={`flex-1 py-1.5 rounded ${!isExistingCustomer ? 'bg-indigo-100 text-indigo-700 font-bold' : 'bg-slate-100'}`}>Nuevo</button>
                  </div>
                  {isExistingCustomer ? (
                      <select className="w-full p-2 border rounded text-sm bg-white" value={customerId} onChange={e => setCustomerId(e.target.value)}>
                          <option value="">-- Buscar Cliente --</option>
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                  ) : (
                      <input className="w-full p-2 border rounded text-sm" value={customerNameInput} onChange={e => setCustomerNameInput(e.target.value)} placeholder="Nombre del cliente" />
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700">Entrega</label>
                  <input type="date" className="w-full p-2 border rounded text-sm" value={date} onChange={e => setDate(e.target.value)} />
               </div>

               <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                 <h4 className="font-bold text-slate-700 text-xs mb-2 uppercase">Productos</h4>
                 <div className="flex gap-2 mb-2">
                    <select className="flex-1 p-2 border rounded text-sm bg-white" value={selectedProduct} onChange={e => setSelectedProduct(e.target.value)}>
                        <option value="">Seleccionar...</option>
                        {products.map(p => <option key={p.id} value={p.id}>{p.name} ({formatCurrency(p.price)})</option>)}
                    </select>
                    <input type="number" min="1" className="w-16 p-2 border rounded text-sm text-center" value={qty} onChange={e => setQty(Number(e.target.value))} />
                    <button onClick={addToCart} className="bg-indigo-600 text-white p-2 rounded hover:bg-indigo-700" disabled={!selectedProduct}><Plus size={18} /></button>
                 </div>
                 <div className="space-y-1 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between text-sm bg-white p-2 rounded border border-slate-100">
                            <span>{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-500"><X size={14}/></button>
                        </div>
                    ))}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-2 rounded text-xs flex items-center gap-2"><AlertCircle size={14}/>{error}</div>}

               <button onClick={handleCreateOrUpdateOrder} className="w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 shadow-md">
                   {editingOrderId ? 'Guardar Cambios' : 'Crear Pedido'}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
