export const Customers: React.FC = () => {
  const { customers, addCustomer, updateCustomer, deleteCustomer, orders } = useBakery();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Customer>>({
    name: '',
    phone: '',
    email: '',
    address: '',
    notes: ''
  });

  const handleEdit = (customer: Customer) => {
    setEditingId(customer.id);
    setFormData(customer);
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    setEditingId(null);
    setFormData({ name: '', phone: '', email: '', address: '', notes: '' });
    setIsModalOpen(true);
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation(); 
    if (window.confirm('¿Seguro que deseas eliminar este cliente? Se mantendrá el historial de pedidos, pero el cliente ya no aparecerá en la lista.')) {
      deleteCustomer(id);
    }
