import React, { useState, useRef, useEffect } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Product, RecipeItem, UnitType, Ingredient } from '../types';
import { UNIT_OPTIONS } from '../constants';
import { Plus, Trash2, ChevronDown, ChevronUp, Calculator, DollarSign, Edit2, Save, X, Search, CheckCircle2 } from 'lucide-react';
import { fromBaseUnit, formatCurrency } from '../utils/conversions';

export const Recipes: React.FC = () => {
  const { products, ingredients, addProduct, updateProduct } = useBakery();
  const [isCreating, setIsCreating] = useState(false);

  // State to track if we are editing an existing product
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [productName, setProductName] = useState('');
  const [productPrice, setProductPrice] = useState<number | ''>('');
  const [recipeItems, setRecipeItems] = useState<RecipeItem[]>([]);

  // Costing Calculator State
  const [fixedCosts, setFixedCosts] = useState<number | ''>('');
  const [estimatedUnits, setEstimatedUnits] = useState<number | ''>('');

  // Ingredient Search & Add State
  const [selectedIngId, setSelectedIngId] = useState('');
  const [ingSearchTerm, setIngSearchTerm] = useState('');
  const [showIngSuggestions, setShowIngSuggestions] = useState(false);
  const [amount, setAmount] = useState<number | ''>('');
  const [selectedUnit, setSelectedUnit] = useState<UnitType>(UnitType.GRAMS);

  const suggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (suggestionsRef.current && !suggestionsRef.current.contains(event.target as Node)) {
        setShowIngSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Filtered ingredients for autocomplete
  const ingredientSuggestions = ingredients.filter(i => 
    i.name.toLowerCase().includes(ingSearchTerm.toLowerCase())
  );

  const handleSelectIngredient = (ing: Ingredient) => {
    setSelectedIngId(ing.id);
    setIngSearchTerm(ing.name);
    setSelectedUnit(ing.unit);
    setShowIngSuggestions(false);
  };

  const handleAddIngredient = () => {
    if(!selectedIngId) {
        alert("Por favor selecciona un ingrediente de la lista.");
        return;
    }
    if(!amount || Number(amount) <= 0) {
        alert("Ingresa una cantidad válida.");
        return;
    }

    setRecipeItems([...recipeItems, {
      ingredientId: selectedIngId,
      quantity: Number(amount),
      unit: selectedUnit
    }]);

    // Reset inputs
    setAmount('');
    setSelectedIngId('');
    setIngSearchTerm('');
  };

  const handleUpdateItemQuantity = (index: number, newQty: string) => {
    const val = newQty === '' ? 0 : parseFloat(newQty);
    const updatedItems = [...recipeItems];
    updatedItems[index].quantity = val;
    setRecipeItems(updatedItems);
  };

  const handleDeleteItem = (index: number) => {
    const updatedItems = recipeItems.filter((_, i) => i !== index);
    setRecipeItems(updatedItems);
  };

  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setProductName(product.name);
    setProductPrice(product.price);
    // Clone array to allow editing without mutating original until save
    setRecipeItems(product.recipe.map(item => ({...item}))); 

    // Reset calculator fields as they are transient
    setFixedCosts('');
    setEstimatedUnits('');

    setIsCreating(true);
  };

  const handleSaveProduct = () => {
    // Validation Feedback
    if(!productName.trim()) {
        alert("El nombre del producto es obligatorio.");
        return;
    }
    if(recipeItems.length === 0) {
        alert("Debes agregar al menos un ingrediente a la receta.");
        return;
    }
    if(productPrice === '' || Number(productPrice) < 0) {
        alert("El precio de venta no es válido.");
        return;
    }

    // Filter out items with 0 quantity just in case
    const validItems = recipeItems.filter(item => item.quantity > 0);

    if (editingProduct) {
        // Update Existing
        const updatedProd: Product = {
            ...editingProduct,
            name: productName,
            price: Number(productPrice),
            recipe: validItems
        };
        updateProduct(updatedProd);
    } else {
        // Create New
        const newProd: Product = {
            id: Date.now().toString(),
            name: productName,
            price: Number(productPrice),
            recipe: validItems
        };
        addProduct(newProd);
    }

    closeForm();
  };

  const closeForm = () => {
    setIsCreating(false);
    setEditingProduct(null);
    resetForm();
  };

  const resetForm = () => {
    setProductName('');
    setProductPrice('');
    setRecipeItems([]);
    setFixedCosts('');
    setEstimatedUnits('');
    setEditingProduct(null);
    setIngSearchTerm('');
    setSelectedIngId('');
    setAmount('');
  };

  // Cost Estimation
  const calculateVariableCost = (items: RecipeItem[]) => {
    return items.reduce((acc, item) => {
      const ing = ingredients.find(i => i.id === item.ingredientId);
      if(!ing) return acc;

      // Cost is stored per ing.unit (Display unit).
      // We need to match item.quantity (item.unit) to ing.unit.

      // Case 1: Same unit
      if (item.unit === ing.unit) {
          return acc + (item.quantity * ing.costPerUnit);
      }

      // Case 2: Different units (e.g. g vs kg)

      // 1. Get Base Quantity of Item
      let itemBase = 0;
      switch(item.unit) {
          case UnitType.KILOGRAMS: itemBase = item.quantity * 1000; break;
          case UnitType.LITERS: itemBase = item.quantity * 1000; break;
          default: itemBase = item.quantity;
      }

      // 2. Convert Base Quantity to Ing Unit
      const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);

      return acc + (itemQtyInIngUnit * ing.costPerUnit);
    }, 0);
  };

  const cvu = calculateVariableCost(recipeItems);

  // Suggested Price Formula
  // Price = (CVU + (CFT / Q)) / (1 - 0.60)
  // Margin 60%
  const calculateSuggestedPrice = () => {
      const cft = Number(fixedCosts) || 0;
      const q = Number(estimatedUnits) || 1; // avoid div by 0

      const fixedCostPerUnit = cft / q;
      const totalUnitCost = cvu + fixedCostPerUnit;

      // Margin 60% -> Cost is 40% of price
      const price = totalUnitCost / (1 - 0.60);
      return Math.round(price); // Round to integer for CLP
  };

  const suggestedPrice = calculateSuggestedPrice();

  const toggleCreate = () => {
    if(isCreating) {
        closeForm();
    } else {
        resetForm();
        setIsCreating(true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Recetas y Productos</h2>
        {/* Desktop Button */}
        <button 
          onClick={toggleCreate}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          {isCreating ? 'Cancelar' : <><Plus size={18} /> Nuevo Producto</>}
        </button>
      </div>

      {/* Mobile Floating Action Button (FAB) */}
      <button 
        onClick={toggleCreate}
        className={`md:hidden fixed bottom-20 right-4 p-4 rounded-full shadow-lg z-40 transition-colors ${isCreating ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white`}
        aria-label={isCreating ? "Cancelar" : "Nuevo Producto"}
      >
        {isCreating ? <X size={24} /> : <Plus size={24} />}
      </button>

      {isCreating && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-lg space-y-6 animate-in fade-in slide-in-from-top-4">
          <h3 className="font-bold text-lg text-slate-800 border-b pb-2">
              {editingProduct ? 'Editar Receta' : 'Crear Nueva Receta'}
          </h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1">Nombre del Producto</label>
                  <input 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={productName} 
                    onChange={e => setProductName(e.target.value)} 
                    placeholder="Ej: Tarta de Frutilla"
                  />
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                    <h4 className="font-medium text-slate-700 mb-3 text-sm uppercase tracking-wide">Ingredientes (Costo Variable)</h4>

                    <div className="flex flex-col gap-2 mb-4 bg-white p-3 rounded border border-slate-200 shadow-sm relative" ref={suggestionsRef}>
                      <label className="text-xs font-bold text-slate-500">Agregar Ingrediente</label>
                      <div className="grid grid-cols-12 gap-2 items-end">

                          {/* Autocomplete Input */}
                          <div className="col-span-12 sm:col-span-5 relative">
                             <div className="flex items-center border rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500 focus-within:border-indigo-500">
                                <Search size={16} className="ml-2 text-slate-400" />
                                <input 
                                    className="w-full p-2 text-sm outline-none"
                                    placeholder="Buscar ingrediente..."
                                    value={ingSearchTerm}
                                    onChange={e => {
                                        setIngSearchTerm(e.target.value);
                                        setSelectedIngId(''); // Reset selection when typing
                                        setShowIngSuggestions(true);
                                    }}
                                    onFocus={() => setShowIngSuggestions(true)}
                                />
                             </div>

                             {/* Suggestions Dropdown */}
                             {showIngSuggestions && ingredientSuggestions.length > 0 && (
                                 <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 max-h-48 overflow-y-auto">
                                    {ingredientSuggestions.map(ing => (
                                        <button
                                            key={ing.id}
                                            onClick={() => handleSelectIngredient(ing)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span>{ing.name}</span>
                                            <span className="text-xs text-slate-400">{formatCurrency(ing.costPerUnit)}/{ing.unit}</span>
                                        </button>
                                    ))}
                                 </div>
                             )}
                             {/* No results */}
                             {showIngSuggestions && ingSearchTerm && ingredientSuggestions.length === 0 && (
                                <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 p-2 text-xs text-slate-400">
                                    No se encontraron ingredientes.
                                </div>
                             )}
                          </div>

                          <div className="col-span-4 sm:col-span-3">
                              <input 
                                type="number" 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500" 
                                placeholder="Cant."
                                value={amount}
                                onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))}
                                onKeyDown={(e) => { if(e.key === 'Enter') handleAddIngredient() }}
                              />
                          </div>

                          <div className="col-span-6 sm:col-span-3">
                              <select 
                                className="w-full p-2 border rounded text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={selectedUnit}
                                onChange={e => setSelectedUnit(e.target.value as UnitType)}
                              >
                                {/* Show all units to allow flexibility */}
                                {UNIT_OPTIONS.map(u => (
                                  <option key={u.value} value={u.value}>{u.label}</option>
                                ))}
                              </select>
                          </div>

                          <div className="col-span-2 sm:col-span-1">
                              <button 
                                onClick={handleAddIngredient}
                                className={`w-full text-white p-2 rounded flex items-center justify-center transition-colors h-[38px] ${selectedIngId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-300 cursor-not-allowed'}`}
                                disabled={!selectedIngId}
                              >
                                <Plus size={18} />
                              </button>
                          </div>
                      </div>
                    </div>

                    {recipeItems.length > 0 ? (
                       <div className="space-y-2 mb-2">
                         <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 px-2">
                            <div className="col-span-5">Ingrediente</div>
                            <div className="col-span-5 text-right">Cantidad</div>
                            <div className="col-span-2 text-center"></div>
                         </div>
                         {recipeItems.map((item, idx) => {
                           const ingName = ingredients.find(i => i.id === item.ingredientId)?.name || 'Ingrediente eliminado';
                           return (
                             <div key={idx} className="grid grid-cols-12 gap-2 items-center bg-white p-2 border rounded shadow-sm text-sm">
                               <div className="col-span-5 truncate font-medium text-slate-700" title={ingName}>
                                 {ingName}
                                </div>
                               <div className="col-span-5 flex justify-end items-center gap-1">
                                 <input 
                                    type="number"
                                    min="0"
                                    step="any"
                                    className="w-20 p-1 border border-slate-200 rounded text-right focus:border-indigo-500 outline-none"
                                    value={item.quantity === 0 ? '' : item.quantity}
                                    onChange={(e) => handleUpdateItemQuantity(idx, e.target.value)}
                                 />
                                 <span className="text-xs text-slate-500 w-8">{item.unit}</span>
                               </div>
                               <div className="col-span-2 text-center">
                                 <button 
                                    onClick={() => handleDeleteItem(idx)} 
                                    className="text-red-400 hover:text-red-600 p-1 rounded-full hover:bg-red-50"
                                 >
                                    <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                           )
                         })}
                         <div className="flex justify-between items-center pt-3 border-t border-slate-200 mt-3">
                            <span className="text-slate-500 font-medium text-sm">Costo Variable Total (CVU):</span>
                            <span className="text-slate-800 font-bold text-lg">{formatCurrency(cvu)}</span>
                         </div>
                       </div>
                    ) : (
                        <p className="text-xs text-slate-400 italic text-center py-4">Agrega ingredientes para calcular el costo.</p>
                    )}
                </div>
            </div>

            <div className="space-y-4">
               {/* Pricing Calculator */}
               <div className="bg-indigo-50 p-5 rounded-xl border border-indigo-100">
                  <div className="flex items-center gap-2 mb-4 text-indigo-800">
                     <Calculator size={20} />
                     <h4 className="font-bold">Calculadora de Precios</h4>
                  </div>

                  <div className="space-y-3 mb-4">
                      <div className="grid grid-cols-2 gap-3">
                        <div>
                           <label className="text-xs font-semibold text-slate-500 block mb-1">Costos Fijos Asignados (CFT)</label>
                           <div className="relative">
                               <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400 text-xs">$</span>
                               <input 
                                 type="number" 
                                 className="w-full pl-5 p-2 border border-indigo-200 rounded text-sm focus:ring-1 focus:ring-indigo-500"
                                 placeholder="0"
                                 value={fixedCosts}
                                 onChange={e => setFixedCosts(e.target.value === '' ? '' : Number(e.target.value))}
                               />
                           </div>
                        </div>
                        <div>
                           <label className="text-xs font-semibold text-slate-500 block mb-1">Ventas Estimadas (Q)</label>
                           <input 
                             type="number" 
                             className="w-full p-2 border border-indigo-200 rounded text-sm focus:ring-1 focus:ring-indigo-500"
                             placeholder="Unidades/mes"
                             value={estimatedUnits}
                             onChange={e => setEstimatedUnits(e.target.value === '' ? '' : Number(e.target.value))}
                           />
                        </div>
                      </div>

                      <div className="bg-white p-3 rounded-lg border border-indigo-100 space-y-1">
                          <div className="flex justify-between text-xs text-slate-500">
                              <span>Costo Variable (CVU):</span>
                              <span>{formatCurrency(cvu)}</span>
                          </div>
                          <div className="flex justify-between text-xs text-slate-500">
                              <span>Costo Fijo Unitario (CFT/Q):</span>
                              <span>{formatCurrency((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0)}</span>
                          </div>
                          <div className="flex justify-between text-xs text-slate-800 font-semibold pt-1 border-t border-slate-100">
                              <span>Costo Total Unitario:</span>
                              <span>{formatCurrency(cvu + ((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0))}</span>
                          </div>
                      </div>

                      <div className="flex justify-between items-center bg-indigo-100 p-3 rounded-lg">
                          <div>
                              <span className="text-xs text-indigo-600 font-bold uppercase block">Precio Sugerido</span>
                              <span className="text-[10px] text-indigo-400">Margen 60%</span>
                          </div>
                          <div className="text-xl font-bold text-indigo-800">
                              {formatCurrency(suggestedPrice)}
                          </div>
                      </div>

                      <button 
                        onClick={() => setProductPrice(suggestedPrice)}
                        disabled={!isFinite(suggestedPrice) || suggestedPrice <= 0}
                        className="w-full py-1.5 text-xs bg-indigo-200 text-indigo-800 rounded font-semibold hover:bg-indigo-300 transition-colors disabled:opacity-50"
                      >
                         Usar Precio Sugerido
                      </button>
                  </div>

                  <div>
                    <label className="label text-sm font-bold text-slate-700 mb-1 block">Precio de Venta Final</label>
                    <div className="relative">
                        <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input 
                            type="number" 
                            className="w-full pl-9 p-3 border border-slate-300 rounded-lg text-lg font-bold text-slate-800" 
                            value={productPrice} 
                            onChange={e => setProductPrice(e.target.value === '' ? '' : Number(e.target.value))} 
                            placeholder="0"
                        />
                    </div>
                  </div>
               </div>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
             <button 
                onClick={handleSaveProduct}
                className="bg-green-600 text-white py-3 px-8 rounded-lg font-bold hover:bg-green-700 shadow-md flex items-center gap-2"
             >
                {editingProduct ? 'Actualizar Producto' : 'Guardar Producto'} <Save size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Product List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {products.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            ingredients={ingredients} 
            onEdit={handleEditClick}
          />
        ))}
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ 
    product: Product, 
    ingredients: Ingredient[], 
    onEdit: (p: Product) => void 
}> = ({ product, ingredients, onEdit }) => {
    const [expanded, setExpanded] = useState(false);
    const { deleteProduct } = useBakery();

    const handleDelete = (e: React.MouseEvent) => {
        // e.stopPropagation() is less critical now that buttons are structurally separated, 
        // but kept for safety.
        e.stopPropagation();
        if(window.confirm(`¿Estás seguro que deseas eliminar "${product.name}"? Esta acción no se puede deshacer.`)) {
            deleteProduct(product.id);
        }
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow">
            <div className="p-4 flex justify-between items-center hover:bg-slate-50">
                <div 
                    className="flex-1 cursor-pointer"
                    onClick={() => setExpanded(!expanded)}
                >
                    <h3 className="font-bold text-slate-800 text-lg">{product.name}</h3>
                    <p className="text-slate-500 text-sm flex items-center gap-2">
                        {product.recipe.length} ingredientes
                    </p>
                </div>
                <div className="flex items-center gap-3 pl-4">
                    <span className="font-bold text-emerald-600 text-lg bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100 whitespace-nowrap">
                        {formatCurrency(product.price)}
                    </span>
                    <button 
                        onClick={(e) => { e.stopPropagation(); onEdit(product); }}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                        title="Editar receta"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={handleDelete}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                        title="Eliminar receta"
                    >
                        <Trash2 size={18} />
                    </button>
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="p-1 text-slate-400"
                    >
                        {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </button>
                </div>
            </div>
            {expanded && (
                <div className="p-4 bg-slate-50 border-t border-slate-100 animate-in fade-in slide-in-from-top-1">
                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Fórmula (Unitario)</h4>
                    <ul className="space-y-2 text-sm">
                        {product.recipe.map((r, i) => {
                            const ing = ingredients.find(ing => ing.id === r.ingredientId);
                            // Calculate simple cost share for display
                            let costShare = 0;
                            if(ing) {
                                let itemBase = 0;
                                switch(r.unit) {
                                    case UnitType.KILOGRAMS: itemBase = r.quantity * 1000; break;
                                    case UnitType.LITERS: itemBase = r.quantity * 1000; break;
                                    default: itemBase = r.quantity;
                                }
                                const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);
                                costShare = itemQtyInIngUnit * ing.costPerUnit;
                            }

                            return (
                                <li key={i} className="flex justify-between items-center text-slate-700 p-2 bg-white rounded border border-slate-100">
                                    <span className="font-medium">{ing?.name || 'Desconocido'}</span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-600">{r.quantity} {r.unit}</div>
                                        <div className="text-[10px] text-slate-400">~{formatCurrency(costShare)}</div>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Ingredient, UnitType } from '../types';
import { UNIT_OPTIONS, BASE_UNITS } from '../constants';
import { formatStock, toBaseUnit, fromBaseUnit, formatCurrency } from '../utils/conversions';
import { Plus, Search, Edit2, X, RefreshCw, TrendingUp, Trash2 } from 'lucide-react';

// Local interface to handle form inputs allowing empty strings
interface IngredientForm {
  name: string;
  unit: UnitType;
  currentStock: number | '';
  minStock: number | '';
  costPerUnit: number | '';
}

export const Inventory: React.FC = () => {
  const { ingredients, addIngredient, updateIngredientStock, deleteIngredient } = useBakery();

  // State for Create Modal
  const [isModalOpen, setIsModalOpen] = useState(false);

  // State for Edit (Adjust) Modal
  const [editingItem, setEditingItem] = useState<Ingredient | null>(null);
  const [editStockValue, setEditStockValue] = useState<string>('');
  const [newPurchasePrice, setNewPurchasePrice] = useState<string>(''); // For WAC

  const [searchTerm, setSearchTerm] = useState('');

  // Form State for New Ingredient - Initialized with empty strings for numbers
  const [newIng, setNewIng] = useState<IngredientForm>({
    name: '',
    unit: UnitType.GRAMS,
    currentStock: '',
    minStock: '',
    costPerUnit: ''
  });

  // Handler: Create New
  const handleAdd = () => {
    if (!newIng.name || newIng.currentStock === '') return;

    // Default to 0 if empty string (though validation above checks currentStock)
    // Note: TypeScript narrows currentStock to 'number' due to the check above, so strict comparison with '' is invalid.
    const stockVal = newIng.currentStock;
    const minStockVal = newIng.minStock === '' ? 0 : newIng.minStock;
    const costVal = newIng.costPerUnit === '' ? 0 : newIng.costPerUnit;

    const stockInBase = toBaseUnit(stockVal, newIng.unit);
    const minStockInBase = toBaseUnit(minStockVal, newIng.unit);

    const ingredient: Ingredient = {
      id: Date.now().toString(),
      name: newIng.name,
      unit: newIng.unit,
      currentStock: stockInBase,
      minStock: minStockInBase,
      costPerUnit: costVal
    };

    addIngredient(ingredient);
    setIsModalOpen(false);
    // Reset form
    setNewIng({ name: '', unit: UnitType.GRAMS, currentStock: '', minStock: '', costPerUnit: '' });
  };

  // Handler: Open Edit Modal
  const handleEditClick = (ing: Ingredient) => {
    setEditingItem(ing);
    // Show value in preferred unit
    const val = fromBaseUnit(ing.currentStock, ing.unit);
    setEditStockValue(val.toString());
    setNewPurchasePrice(''); // Reset price
  };

  // Handler: Delete
  const handleDelete = (id: string, name: string) => {
    if (window.confirm(`¿Estás seguro que deseas eliminar "${name}" del inventario? Esto podría afectar las recetas que lo utilizan.`)) {
      deleteIngredient(id);
    }
  };

  // Handler: Save Edit
  const handleSaveEdit = () => {
    if (!editingItem) return;
    const val = parseFloat(editStockValue);
    if (isNaN(val) || val < 0) return;

    // Convert back to base unit for storage
    const newStockBase = toBaseUnit(val, editingItem.unit);

    // Check if price is provided for WAC
    const priceVal = newPurchasePrice ? parseFloat(newPurchasePrice) : undefined;

    updateIngredientStock(editingItem.id, newStockBase, priceVal);

    setEditingItem(null);
    setEditStockValue('');
    setNewPurchasePrice('');
  };

  const filtered = ingredients
    .filter(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()))
    .sort((a, b) => a.name.localeCompare(b.name));

  // Calculate if we are adding stock (to show price input)
  const isAddingStock = editingItem && !isNaN(parseFloat(editStockValue)) 
    ? toBaseUnit(parseFloat(editStockValue), editingItem.unit) > editingItem.currentStock 
    : false;

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Inventario</h2>
        {/* Desktop Button */}
        <button 
          onClick={() => setIsModalOpen(true)}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 transition-colors shadow-sm"
        >
          <Plus size={18} /> Nuevo Ingrediente
        </button>
      </div>

      {/* Mobile Floating Action Button (FAB) */}
      <button 
        onClick={() => setIsModalOpen(true)}
        className="md:hidden fixed bottom-20 right-4 bg-indigo-600 text-white p-4 rounded-full shadow-lg z-40 hover:bg-indigo-700 transition-colors"
        aria-label="Nuevo Ingrediente"
      >
        <Plus size={24} />
      </button>

      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="text" 
          placeholder="Buscar materia prima..." 
          className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-600 text-xs uppercase font-semibold">
              <tr>
                <th className="px-6 py-4">Ingrediente</th>
                <th className="px-6 py-4">Stock Actual</th>
                <th className="px-6 py-4">Costo Prom. Unit</th>
                <th className="px-6 py-4">Unidad Base</th>
                <th className="px-6 py-4 text-center">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filtered.map(ing => {
                const isLow = ing.currentStock <= ing.minStock;
                return (
                  <tr key={ing.id} className={`hover:bg-slate-50 ${isLow ? 'bg-red-50' : ''}`}>
                    <td className="px-6 py-4 font-medium text-slate-800">{ing.name}</td>
                    <td className={`px-6 py-4 font-bold ${isLow ? 'text-red-600' : 'text-slate-700'}`}>
                      {formatStock(ing.currentStock, ing.unit)}
                    </td>
                    <td className="px-6 py-4 text-slate-500">
                      {formatCurrency(ing.costPerUnit)} / {ing.unit}
                    </td>
                    <td className="px-6 py-4 text-slate-500 text-sm">
                      {BASE_UNITS[ing.unit]}
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center justify-center gap-2">
                        <button 
                          onClick={() => handleEditClick(ing)}
                          className="text-indigo-600 hover:text-indigo-800 p-2 rounded hover:bg-indigo-50 transition-colors"
                          title="Ajustar Stock"
                        >
                          <Edit2 size={18} />
                        </button>
                        <button 
                          onClick={() => handleDelete(ing.id, ing.name)}
                          className="text-red-400 hover:text-red-600 p-2 rounded hover:bg-red-50 transition-colors"
                          title="Eliminar Ingrediente"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Create Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white">
              <h3 className="font-bold">Nuevo Ingrediente</h3>
              <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Nombre</label>
                <input 
                  className="w-full p-2 border border-slate-300 rounded-lg"
                  value={newIng.name}
                  onChange={e => setNewIng({...newIng, name: e.target.value})}
                  placeholder="Ej: Harina 0000"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Unidad de Medida</label>
                  <select 
                    className="w-full p-2 border border-slate-300 rounded-lg"
                    value={newIng.unit}
                    onChange={e => setNewIng({...newIng, unit: e.target.value as UnitType})}
                  >
                    {UNIT_OPTIONS.map(opt => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Costo Unitario ($)</label>
                   <input 
                    type="number"
                    className="w-full p-2 border border-slate-300 rounded-lg"
                    value={newIng.costPerUnit}
                    onChange={e => setNewIng({...newIng, costPerUnit: e.target.value === '' ? '' : Number(e.target.value)})}
                    placeholder="0"
                  />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Stock Inicial</label>
                  <input 
                    type="number"
                    className="w-full p-2 border border-slate-300 rounded-lg"
                    value={newIng.currentStock}
                    onChange={e => setNewIng({...newIng, currentStock: e.target.value === '' ? '' : Number(e.target.value)})}
                    placeholder="0"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Punto Reposición</label>
                  <input 
                    type="number"
                    className="w-full p-2 border border-slate-300 rounded-lg"
                    value={newIng.minStock}
                    onChange={e => setNewIng({...newIng, minStock: e.target.value === '' ? '' : Number(e.target.value)})}
                    placeholder="0"
                  />
                </div>
              </div>
              <div className="pt-2 text-xs text-slate-500">
                * Las cantidades ingresadas se guardarán en la unidad seleccionada y se convertirán internamente si es necesario.
              </div>
              <button 
                onClick={handleAdd}
                className="w-full py-3 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 mt-2"
              >
                Guardar Ingrediente
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Adjust Stock Modal */}
      {editingItem && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-sm overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-800 text-white">
              <h3 className="font-bold flex items-center gap-2">
                <RefreshCw size={18} /> Ajustar Stock
              </h3>
              <button onClick={() => setEditingItem(null)}><X size={20} /></button>
            </div>

            <div className="p-6 space-y-4">
              <div className="text-center mb-2">
                <h4 className="text-lg font-semibold text-slate-800">{editingItem.name}</h4>
                <p className="text-sm text-slate-500">Actualiza la cantidad física disponible</p>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  Nuevo Stock Total ({editingItem.unit})
                </label>
                <div className="relative">
                  <input 
                    type="number"
                    step="any"
                    className="w-full p-3 border border-slate-300 rounded-lg text-lg font-bold text-center focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={editStockValue}
                    onChange={e => setEditStockValue(e.target.value)}
                    autoFocus
                  />
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-medium">
                    {editingItem.unit}
                  </span>
                </div>
              </div>

              {/* Purchase Price Input (Conditional) */}
              {isAddingStock && (
                <div className="bg-green-50 p-3 rounded-lg border border-green-100 animate-in fade-in slide-in-from-top-2">
                  <div className="flex items-start gap-2 mb-2">
                     <TrendingUp className="text-green-600 mt-0.5" size={16} />
                     <label className="block text-sm font-medium text-green-800 leading-tight">
                       Detectamos una entrada de stock.<br/>
                       <span className="text-xs font-normal opacity-80">¿A qué precio compraste las nuevas unidades?</span>
                     </label>
                  </div>
                  <div className="relative">
                     <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">$</span>
                     <input 
                      type="number"
                      step="1"
                      placeholder={`Costo por ${editingItem.unit}`}
                      className="w-full pl-7 pr-3 py-2 border border-green-200 rounded-md focus:outline-none focus:ring-1 focus:ring-green-500 text-sm"
                      value={newPurchasePrice}
                      onChange={e => setNewPurchasePrice(e.target.value)}
                    />
                  </div>
                  <p className="text-[10px] text-green-700 mt-1">
                    Esto actualizará el costo promedio ponderado.
                  </p>
                </div>
              )}

              <div className="flex gap-3 mt-4">
                <button 
                  onClick={() => setEditingItem(null)}
                  className="flex-1 py-2 text-slate-600 font-medium hover:bg-slate-100 rounded-lg"
                >
                  Cancelar
                </button>
                <button 
                  onClick={handleSaveEdit}
                  className="flex-1 py-2 bg-indigo-600 text-white font-bold rounded-lg hover:bg-indigo-700 shadow-md"
                >
                  Confirmar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Product, RecipeItem, UnitType, Ingredient } from '../types';
import { UNIT_OPTIONS } from '../constants';
import { Plus, Trash2, ChevronDown, ChevronUp, Calculator, DollarSign, Edit2, Save, X, Search, CheckCircle2 } from 'lucide-react';
import { fromBaseUnit, formatCurrency } from '../utils/conversions';

export const Recipes: React.FC = () => {
  const { products, ingredients, addProduct, updateProduct } = useBakery();
  const [isCreating, setIsCreating] = useState(false);

  // State to track if we are editing an existing product
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [productName, setProductName] = useState('');
  const [productPrice, setProductPrice] = useState<number | ''>('');
  const [recipeItems, setRecipeItems] = useState<RecipeItem[]>([]);

  // Costing Calculator State
  const [fixedCosts, setFixedCosts] = useState<number | ''>('');
  const [estimatedUnits, setEstimatedUnits] = useState<number | ''>('');

  // Ingredient Search & Add State
  const [selectedIngId, setSelectedIngId] = useState('');
  const [ingSearchTerm, setIngSearchTerm] = useState('');
  const [showIngSuggestions, setShowIngSuggestions] = useState(false);
  const [amount, setAmount] = useState<number | ''>('');
  const [selectedUnit, setSelectedUnit] = useState<UnitType>(UnitType.GRAMS);

  const suggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (suggestionsRef.current && !suggestionsRef.current.contains(event.target as Node)) {
        setShowIngSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Filtered ingredients for autocomplete (SORTED A-Z)
  const ingredientSuggestions = ingredients
    .filter(i => i.name.toLowerCase().includes(ingSearchTerm.toLowerCase()))
    .sort((a, b) => a.name.localeCompare(b.name));

  const handleSelectIngredient = (ing: Ingredient) => {
    setSelectedIngId(ing.id);
    setIngSearchTerm(ing.name);
    setSelectedUnit(ing.unit);
    setShowIngSuggestions(false);
  };

  const handleAddIngredient = () => {
    if(!selectedIngId) {
        alert("Por favor selecciona un ingrediente de la lista.");
        return;
    }
    if(!amount || Number(amount) <= 0) {
        alert("Ingresa una cantidad válida.");
        return;
    }

    setRecipeItems([...recipeItems, {
      ingredientId: selectedIngId,
      quantity: Number(amount),
      unit: selectedUnit
    }]);

    // Reset inputs
    setAmount('');
    setSelectedIngId('');
    setIngSearchTerm('');
  };

  const handleUpdateItemQuantity = (index: number, newQty: string) => {
    const val = newQty === '' ? 0 : parseFloat(newQty);
    const updatedItems = [...recipeItems];
    updatedItems[index].quantity = val;
    setRecipeItems(updatedItems);
  };

  const handleDeleteItem = (index: number) => {
    const updatedItems = recipeItems.filter((_, i) => i !== index);
    setRecipeItems(updatedItems);
  };

  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setProductName(product.name);
    setProductPrice(product.price);
    // Clone array to allow editing without mutating original until save
    setRecipeItems(product.recipe.map(item => ({...item}))); 

    // Reset calculator fields as they are transient
    setFixedCosts('');
    setEstimatedUnits('');

    setIsCreating(true);
  };

  const handleSaveProduct = async () => {
    // Validation Feedback
    if(!productName.trim()) {
        alert("El nombre del producto es obligatorio.");
        return;
    }
    if(recipeItems.length === 0) {
        alert("Debes agregar al menos un ingrediente a la receta.");
        return;
    }
    if(productPrice === '' || Number(productPrice) < 0) {
        alert("El precio de venta no es válido. Debe ser mayor o igual a 0.");
        return;
    }

    try {
        // Filter out items with 0 quantity just in case
        const validItems = recipeItems.filter(item => item.quantity > 0);

        if (editingProduct) {
            // Update Existing
            const updatedProd: Product = {
                ...editingProduct,
                name: productName,
                price: Number(productPrice),
                recipe: validItems
            };
            await updateProduct(updatedProd);
        } else {
            // Create New
            const newProd: Product = {
                id: Date.now().toString(),
                name: productName,
                price: Number(productPrice),
                recipe: validItems
            };
            await addProduct(newProd);
        }

        closeForm();
    } catch (error) {
        console.error("Error al guardar producto:", error);
        alert("Hubo un error al guardar el producto. Por favor intenta nuevamente.");
    }
  };

  const closeForm = () => {
    setIsCreating(false);
    setEditingProduct(null);
    resetForm();
  };

  const resetForm = () => {
    setProductName('');
    setProductPrice('');
    setRecipeItems([]);
    setFixedCosts('');
    setEstimatedUnits('');
    setEditingProduct(null);
    setIngSearchTerm('');
    setSelectedIngId('');
    setAmount('');
  };

  // Cost Estimation
  const calculateVariableCost = (items: RecipeItem[]) => {
    return items.reduce((acc, item) => {
      const ing = ingredients.find(i => i.id === item.ingredientId);
      if(!ing) return acc;

      // Cost is stored per ing.unit (Display unit).
      // We need to match item.quantity (item.unit) to ing.unit.

      // Case 1: Same unit
      if (item.unit === ing.unit) {
          return acc + (item.quantity * ing.costPerUnit);
      }

      // Case 2: Different units (e.g. g vs kg)

      // 1. Get Base Quantity of Item
      let itemBase = 0;
      switch(item.unit) {
          case UnitType.KILOGRAMS: itemBase = item.quantity * 1000; break;
          case UnitType.LITERS: itemBase = item.quantity * 1000; break;
          default: itemBase = item.quantity;
      }

      // 2. Convert Base Quantity to Ing Unit
      const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);

      return acc + (itemQtyInIngUnit * ing.costPerUnit);
    }, 0);
  };

  const cvu = calculateVariableCost(recipeItems);

  // Suggested Price Formula
  // Price = (CVU + (CFT / Q)) / (1 - 0.60)
  // Margin 60%
  const calculateSuggestedPrice = () => {
      const cft = Number(fixedCosts) || 0;
      const q = Number(estimatedUnits) || 1; // avoid div by 0

      const fixedCostPerUnit = cft / q;
      const totalUnitCost = cvu + fixedCostPerUnit;

      // Margin 60% -> Cost is 40% of price
      const price = totalUnitCost / (1 - 0.60);
      return Math.round(price); // Round to integer for CLP
  };

  const suggestedPrice = calculateSuggestedPrice();

  const toggleCreate = () => {
    if(isCreating) {
        closeForm();
    } else {
        resetForm();
        setIsCreating(true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Recetas y Productos</h2>
        {/* Desktop Button */}
        <button 
          onClick={toggleCreate}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          {isCreating ? 'Cancelar' : <><Plus size={18} /> Nuevo Producto</>}
        </button>
      </div>

      {/* Mobile Floating Action Button (FAB) */}
      <button 
        onClick={toggleCreate}
        className={`md:hidden fixed bottom-20 right-4 p-4 rounded-full shadow-lg z-40 transition-colors ${isCreating ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white`}
        aria-label={isCreating ? "Cancelar" : "Nuevo Producto"}
      >
        {isCreating ? <X size={24} /> : <Plus size={24} />}
      </button>

      {isCreating && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-lg space-y-6 animate-in fade-in slide-in-from-top-4">
          <h3 className="font-bold text-lg text-slate-800 border-b pb-2">
              {editingProduct ? 'Editar Receta' : 'Crear Nueva Receta'}
          </h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1">Nombre del Producto</label>
                  <input 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={productName} 
                    onChange={e => setProductName(e.target.value)} 
                    placeholder="Ej: Tarta de Frutilla"
                  />
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                    <h4 className="font-medium text-slate-700 mb-3 text-sm uppercase tracking-wide">Ingredientes (Costo Variable)</h4>

                    <div className="flex flex-col gap-2 mb-4 bg-white p-3 rounded border border-slate-200 shadow-sm relative" ref={suggestionsRef}>
                      <label className="text-xs font-bold text-slate-500">Agregar Ingrediente</label>
                      <div className="grid grid-cols-12 gap-2 items-end">

                          {/* Autocomplete Input */}
                          <div className="col-span-12 sm:col-span-5 relative">
                             <div className="flex items-center border rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500 focus-within:border-indigo-500">
                                <Search size={16} className="ml-2 text-slate-400" />
                                <input 
                                    className="w-full p-2 text-sm outline-none"
                                    placeholder="Buscar ingrediente..."
                                    value={ingSearchTerm}
                                    onChange={e => {
                                        setIngSearchTerm(e.target.value);
                                        setSelectedIngId(''); // Reset selection when typing
                                        setShowIngSuggestions(true);
                                    }}
                                    onFocus={() => setShowIngSuggestions(true)}
                                />
                             </div>

                             {/* Suggestions Dropdown */}
                             {showIngSuggestions && ingredientSuggestions.length > 0 && (
                                 <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 max-h-48 overflow-y-auto">
                                    {ingredientSuggestions.map(ing => (
                                        <button
                                            key={ing.id}
                                            onClick={() => handleSelectIngredient(ing)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span>{ing.name}</span>
                                            <span className="text-xs text-slate-400">{formatCurrency(ing.costPerUnit)}/{ing.unit}</span>
                                        </button>
                                    ))}
                                 </div>
                             )}
                             {/* No results */}
                             {showIngSuggestions && ingSearchTerm && ingredientSuggestions.length === 0 && (
                                <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 p-2 text-xs text-slate-400">
                                    No se encontraron ingredientes.
                                </div>
                             )}
                          </div>

                          <div className="col-span-4 sm:col-span-3">
                              <input 
                                type="number" 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500" 
                                placeholder="Cant."
                                value={amount}
                                onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))}
                                onKeyDown={(e) => { if(e.key === 'Enter') handleAddIngredient() }}
                              />
                          </div>

                          <div className="col-span-6 sm:col-span-3">
                              <select 
                                className="w-full p-2 border rounded text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={selectedUnit}
                                onChange={e => setSelectedUnit(e.target.value as UnitType)}
                              >
                                {/* Show all units to allow flexibility */}
                                {UNIT_OPTIONS.map(u => (
                                  <option key={u.value} value={u.value}>{u.label}</option>
                                ))}
                              </select>
                          </div>

                          <div className="col-span-2 sm:col-span-1">
                              <button 
                                onClick={handleAddIngredient}
                                className={`w-full text-white p-2 rounded flex items-center justify-center transition-colors h-[38px] ${selectedIngId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-300 cursor-not-allowed'}`}
                                disabled={!selectedIngId}
                              >
                                <Plus size={18} />
                              </button>
                          </div>
                      </div>
                    </div>

                    {recipeItems.length > 0 ? (
                       <div className="space-y-2 mb-2">
                         <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 px-2">
                            <div className="col-span-5">Ingrediente</div>
                            <div className="col-span-5 text-right">Cantidad</div>
                            <div className="col-span-2 text-center"></div>
                         </div>
                         {recipeItems.map((item, idx) => {
                           const ingName = ingredients.find(i => i.id === item.ingredientId)?.name || 'Ingrediente eliminado';
                           return (
                             <div key={idx} className="grid grid-cols-12 gap-2 items-center bg-white p-2 border rounded shadow-sm text-sm">
                               <div className="col-span-5 truncate font-medium text-slate-700" title={ingName}>
                                 {ingName}
                                </div>
                               <div className="col-span-5 flex justify-end items-center gap-1">
                                 <input 
                                    type="number"
                                    min="0"
                                    step="any"
                                    className="w-20 p-1 border border-slate-200 rounded text-right focus:border-indigo-500 outline-none"
                                    value={item.quantity === 0 ? '' : item.quantity}
                                    onChange={(e) => handleUpdateItemQuantity(idx, e.target.value)}
                                 />
                                 <span className="text-xs text-slate-500 w-8">{item.unit}</span>
                               </div>
                               <div className="col-span-2 text-center">
                                 <button 
                                    onClick={() => handleDeleteItem(idx)} 
                                    className="text-red-400 hover:text-red-600 p-1 rounded-full hover:bg-red-50"
                                 >
                                    <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                           )
                         })}
                         <div className="flex justify-between items-center pt-3 border-t border-slate-200 mt-3">
                            <span className="text-slate-500 font-medium text-sm">Costo Variable Total (CVU):</span>
                            <span className="text-slate-800 font-bold text-lg">{formatCurrency(cvu)}</span>
                         </div>
                       </div>
                    ) : (
                        <p className="text-xs text-slate-400 italic text-center py-4">Agrega ingredientes para calcular el costo.</p>
                    )}
                </div>
            </div>

            <div className="space-y-4">
               {/* Pricing Calculator */}
               <div className="bg-indigo-50 p-5 rounded-xl border border-indigo-100">
                  <div className="flex items-center gap-2 mb-4 text-indigo-800">
                     <Calculator size={20} />
                     <h4 className="font-bold">Calculadora de Precios</h4>
                  </div>

                  <div className="space-y-3 mb-4">
                      <div className="grid grid-cols-2 gap-3">
                        <div>
                           <label className="text-xs font-semibold text-slate-500 block mb-1">Costos Fijos Asignados (CFT)</label>
                           <div className="relative">
                               <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400 text-xs">$</span>
                               <input 
                                 type="number" 
                                 className="w-full pl-5 p-2 border border-indigo-200 rounded text-sm focus:ring-1 focus:ring-indigo-500"
                                 placeholder="0"
                                 value={fixedCosts}
                                 onChange={e => setFixedCosts(e.target.value === '' ? '' : Number(e.target.value))}
                               />
                           </div>
                        </div>
                        <div>
                           <label className="text-xs font-semibold text-slate-500 block mb-1">Ventas Estimadas (Q)</label>
                           <input 
                             type="number" 
                             className="w-full p-2 border border-indigo-200 rounded text-sm focus:ring-1 focus:ring-indigo-500"
                             placeholder="Unidades/mes"
                             value={estimatedUnits}
                             onChange={e => setEstimatedUnits(e.target.value === '' ? '' : Number(e.target.value))}
                           />
                        </div>
                      </div>

                      <div className="bg-white p-3 rounded-lg border border-indigo-100 space-y-1">
                          <div className="flex justify-between text-xs text-slate-500">
                              <span>Costo Variable (CVU):</span>
                              <span>{formatCurrency(cvu)}</span>
                          </div>
                          <div className="flex justify-between text-xs text-slate-500">
                              <span>Costo Fijo Unitario (CFT/Q):</span>
                              <span>{formatCurrency((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0)}</span>
                          </div>
                          <div className="flex justify-between text-xs text-slate-800 font-semibold pt-1 border-t border-slate-100">
                              <span>Costo Total Unitario:</span>
                              <span>{formatCurrency(cvu + ((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0))}</span>
                          </div>
                      </div>

                      <div className="flex justify-between items-center bg-indigo-100 p-3 rounded-lg">
                          <div>
                              <span className="text-xs text-indigo-600 font-bold uppercase block">Precio Sugerido</span>
                              <span className="text-[10px] text-indigo-400">Margen 60%</span>
                          </div>
                          <div className="text-xl font-bold text-indigo-800">
                              {formatCurrency(suggestedPrice)}
                          </div>
                      </div>

                      <button 
                        onClick={() => setProductPrice(suggestedPrice)}
                        disabled={!isFinite(suggestedPrice) || suggestedPrice <= 0}
                        className="w-full py-1.5 text-xs bg-indigo-200 text-indigo-800 rounded font-semibold hover:bg-indigo-300 transition-colors disabled:opacity-50"
                      >
                         Usar Precio Sugerido
                      </button>
                  </div>

                  <div>
                    <label className="label text-sm font-bold text-slate-700 mb-1 block">Precio de Venta Final</label>
                    <div className="relative">
                        <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input 
                            type="number" 
                            className="w-full pl-9 p-3 border border-slate-300 rounded-lg text-lg font-bold text-slate-800" 
                            value={productPrice} 
                            onChange={e => setProductPrice(e.target.value === '' ? '' : Number(e.target.value))} 
                            placeholder="0"
                        />
                    </div>
                  </div>
               </div>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
             <button 
                type="button"
                onClick={handleSaveProduct}
                className="bg-green-600 text-white py-3 px-8 rounded-lg font-bold hover:bg-green-700 shadow-md flex items-center gap-2"
             >
                {editingProduct ? 'Actualizar Producto' : 'Guardar Producto'} <Save size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Product List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {products.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            ingredients={ingredients} 
            onEdit={handleEditClick}
          />
        ))}
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ 
    product: Product, 
    ingredients: Ingredient[], 
    onEdit: (p: Product) => void 
}> = ({ product, ingredients, onEdit }) => {
    const [expanded, setExpanded] = useState(false);
    const { deleteProduct } = useBakery();

    const handleDelete = (e: React.MouseEvent) => {
        // e.stopPropagation() is less critical now that buttons are structurally separated, 
        // but kept for safety.
        e.stopPropagation();
        if(window.confirm(`¿Estás seguro que deseas eliminar "${product.name}"? Esta acción no se puede deshacer.`)) {
            deleteProduct(product.id);
        }
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow">
            <div className="p-4 flex justify-between items-center hover:bg-slate-50">
                <div 
                    className="flex-1 cursor-pointer"
                    onClick={() => setExpanded(!expanded)}
                >
                    <h3 className="font-bold text-slate-800 text-lg">{product.name}</h3>
                    <p className="text-slate-500 text-sm flex items-center gap-2">
                        {product.recipe.length} ingredientes
                    </p>
                </div>
                <div className="flex items-center gap-3 pl-4">
                    <span className="font-bold text-emerald-600 text-lg bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100 whitespace-nowrap">
                        {formatCurrency(product.price)}
                    </span>
                    <button 
                        onClick={(e) => { e.stopPropagation(); onEdit(product); }}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                        title="Editar receta"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={handleDelete}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                        title="Eliminar receta"
                    >
                        <Trash2 size={18} />
                    </button>
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="p-1 text-slate-400"
                    >
                        {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </button>
                </div>
            </div>
            {expanded && (
                <div className="p-4 bg-slate-50 border-t border-slate-100 animate-in fade-in slide-in-from-top-1">
                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Fórmula (Unitario)</h4>
                    <ul className="space-y-2 text-sm">
                        {product.recipe.map((r, i) => {
                            const ing = ingredients.find(ing => ing.id === r.ingredientId);
                            // Calculate simple cost share for display
                            let costShare = 0;
                            if(ing) {
                                let itemBase = 0;
                                switch(r.unit) {
                                    case UnitType.KILOGRAMS: itemBase = r.quantity * 1000; break;
                                    case UnitType.LITERS: itemBase = r.quantity * 1000; break;
                                    default: itemBase = r.quantity;
                                }
                                const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);
                                costShare = itemQtyInIngUnit * ing.costPerUnit;
                            }

                            return (
                                <li key={i} className="flex justify-between items-center text-slate-700 p-2 bg-white rounded border border-slate-100">
                                    <span className="font-medium">{ing?.name || 'Desconocido'}</span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-600">{r.quantity} {r.unit}</div>
                                        <div className="text-[10px] text-slate-400">~{formatCurrency(costShare)}</div>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus, Customer, Product } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, PackageCheck, ChefHat, Truck, DollarSign, History, X, Edit2, Trash2, User } from 'lucide-react';
import { formatCurrency, formatDate } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrder, updateOrderStatus, addCustomer, deleteOrder } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New/Edit Order Form State
  const [editingOrderId, setEditingOrderId] = useState<string | null>(null);

  // Customer Smart Search State
  const [customerSearchInput, setCustomerSearchInput] = useState('');
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | null>(null); // If null, means new customer
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);

  // Product Smart Search State
  const [productSearchInput, setProductSearchInput] = useState('');
  const [selectedProduct, setSelectedProduct] = useState(''); // Stores ID
  const [showProductSuggestions, setShowProductSuggestions] = useState(false);

  const [date, setDate] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  const customerSuggestionsRef = useRef<HTMLDivElement>(null);
  const productSuggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // Customer Dropdown
      if (customerSuggestionsRef.current && !customerSuggestionsRef.current.contains(event.target as Node)) {
        setShowCustomerSuggestions(false);
      }
      // Product Dropdown
      if (productSuggestionsRef.current && !productSuggestionsRef.current.contains(event.target as Node)) {
        setShowProductSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Filtered customers for autocomplete
  const customerSuggestions = useMemo(() => {
    if (!customerSearchInput) return [];
    return customers.filter(c => 
      c.name.toLowerCase().includes(customerSearchInput.toLowerCase())
    ).slice(0, 5); // Limit to 5
  }, [customers, customerSearchInput]);

  // Filtered products for autocomplete (Sorted Alphabetically)
  const productSuggestions = useMemo(() => {
    return products
      .filter(p => p.name.toLowerCase().includes(productSearchInput.toLowerCase()))
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [products, productSearchInput]);

  const handleSelectCustomer = (c: Customer) => {
    setCustomerSearchInput(c.name);
    setSelectedCustomerId(c.id);
    setShowCustomerSuggestions(false);
  };

  const handleCustomerInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setCustomerSearchInput(e.target.value);
    setSelectedCustomerId(null); // Reset ID implies potentially new customer
    setShowCustomerSuggestions(true);
  };

  const handleSelectProduct = (p: Product) => {
    setProductSearchInput(p.name);
    setSelectedProduct(p.id);
    setShowProductSuggestions(false);
  };

  // --- Constants ---
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado'];
  const HISTORY_STEPS: OrderStatus[] = ['Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const flow: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];
    const currentIndex = flow.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < flow.length - 1) {
      updateOrderStatus(order.id, flow[currentIndex + 1]);
    }
  };

  const handleDeleteOrder = (order: Order) => {
    if (window.confirm(`¿Estás seguro de eliminar el pedido de ${order.customerName}? Esto devolverá los ingredientes al inventario.`)) {
        deleteOrder(order.id);
    }
  };

  const handleEditOrder = (order: Order) => {
    setEditingOrderId(order.id);

    // Setup Customer Field
    setCustomerSearchInput(order.customerName);
    setSelectedCustomerId(order.customerId || null); // Keep ID if valid

    setDate(order.deliveryDate);
    setCart(order.items.map(i => ({...i})));
    setError('');
    setIsModalOpen(true);
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    const existingIndex = cart.findIndex(i => i.productId === selectedProduct);
    if (existingIndex >= 0) {
        const newCart = [...cart];
        newCart[existingIndex].quantity += finalQty;
        setCart(newCart);
    } else {
        setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    }

    // Reset Product Selection
    setSelectedProduct('');
    setProductSearchInput('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrUpdateOrder = async () => {
    setError('');

    if (!customerSearchInput.trim()) { setError('Ingresa el nombre del cliente.'); return; }
    if(!date) { setError('Selecciona fecha de entrega.'); return; }
    if(cart.length === 0) { setError('Agrega al menos un producto.'); return; }

    let finalCustomerId = selectedCustomerId;
    let finalCustomerName = customerSearchInput.trim();

    // Logic: If no ID is selected, but name exists in text, create new customer
    if (!finalCustomerId) {
        // Double check if name matches an existing one exactly to avoid dupe
        const existingExact = customers.find(c => c.name.toLowerCase() === finalCustomerName.toLowerCase());
        if (existingExact) {
            finalCustomerId = existingExact.id;
        } else {
            // Create completely new customer
            try {
                finalCustomerId = await addCustomer({
                    id: '',
                    name: finalCustomerName
                });
            } catch (e) {
                setError('Error al crear nuevo cliente.');
                return;
            }
        }
    }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const orderData: Order = {
      id: editingOrderId || Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: editingOrderId ? (orders.find(o => o.id === editingOrderId)?.status || 'Pendiente') : 'Pendiente',
      items: cart,
      totalPrice: total
    };

    if (editingOrderId) {
        updateOrder(orderData);
    } else {
        addOrder(orderData);
    }
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    // Customer Reset
    setCustomerSearchInput('');
    setSelectedCustomerId(null);
    setShowCustomerSuggestions(false);
    // Product Reset
    setProductSearchInput('');
    setSelectedProduct('');
    setShowProductSuggestions(false);

    setDate('');
    setError('');
    setQty(1);
    setEditingOrderId(null);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': 
        return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendiente', next: 'En Proceso' };
      case 'En Proceso': 
        return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: ChefHat, label: 'En Proceso', next: 'Completado' };
      case 'Completado': 
        return { color: 'bg-indigo-100 text-indigo-800 border-indigo-200', icon: PackageCheck, label: 'Completado', next: 'Entregado' };
      case 'Entregado': 
        return { color: 'bg-blue-100 text-blue-800 border-blue-200', icon: Truck, label: 'Entregado', next: 'Pagado' };
      case 'Pagado': 
        return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: DollarSign, label: 'Pagado', next: '' };
      default: 
        return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Controla el flujo desde Pendiente hasta Pagado.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial (Pagados)
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Cerrados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div className="flex-1 min-w-0">
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {formatDate(order.deliveryDate)}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>

                {/* Edit/Delete Controls */}
                <div className="flex gap-1 ml-2">
                    <button 
                        onClick={() => handleEditOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-indigo-600 rounded hover:bg-indigo-50 transition-colors"
                        title="Editar Pedido"
                    >
                        <Edit2 size={16} />
                    </button>
                    <button 
                        onClick={() => handleDeleteOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-red-600 rounded hover:bg-red-50 transition-colors"
                        title="Eliminar Pedido"
                    >
                        <Trash2 size={16} />
                    </button>
                </div>
              </div>

              {/* Status & Price Row */}
              <div className="flex justify-between items-center mb-3">
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block ${config.color}`}>
                     {order.status}
                  </span>
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <button 
                  onClick={() => advanceOrder(order)}
                  className="w-full py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                >
                  {/* Dynamic Icon based on next step */}
                  {config.next === 'En Proceso' && <ChefHat size={16} />}
                  {config.next === 'Completado' && <PackageCheck size={16} />}
                  {config.next === 'Entregado' && <Truck size={16} />}
                  {config.next === 'Pagado' && <DollarSign size={16} />}

                  {config.next === 'Pagado' ? 'Confirmar Pago (Cerrar)' : `Avanzar a ${config.next}`}

                  <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
                </button>
              ) : (
                <div className="text-center text-xs text-slate-400 italic flex items-center justify-center gap-1">
                  <CheckCircle2 size={14} /> Pedido cerrado y archivado
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* New/Edit Order Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto flex flex-col">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0 z-10">
              <h3 className="font-bold">{editingOrderId ? 'Editar Pedido' : 'Nuevo Pedido'}</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-5 flex-1 overflow-y-auto">

               {/* Smart Customer Search */}
               <div className="relative" ref={customerSuggestionsRef}>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex items-center border border-slate-300 rounded-lg overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500 focus-within:border-indigo-500">
                    <div className="pl-3 text-slate-400"><User size={18} /></div>
                    <input 
                      className="w-full p-2.5 text-sm outline-none" 
                      value={customerSearchInput} 
                      onChange={handleCustomerInputChange} 
                      onFocus={() => setShowCustomerSuggestions(true)}
                      placeholder="Buscar o crear nuevo cliente..."
                      autoComplete="off"
                    />
                    {selectedCustomerId && (
                        <div className="pr-3 text-green-500"><CheckCircle2 size={18} /></div>
                    )}
                  </div>

                  {/* Autocomplete Dropdown */}
                  {showCustomerSuggestions && customerSuggestions.length > 0 && (
                    <div className="absolute z-20 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-lg max-h-48 overflow-y-auto">
                        <div className="text-[10px] uppercase text-slate-400 font-semibold px-3 py-1 bg-slate-50">Sugerencias</div>
                        {customerSuggestions.map(c => (
                            <button
                                key={c.id}
                                onClick={() => handleSelectCustomer(c)}
                                className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none"
                            >
                                {c.name}
                            </button>
                        ))}
                    </div>
                  )}
                  {showCustomerSuggestions && customerSearchInput && customerSuggestions.length === 0 && (
                     <div className="absolute z-20 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-lg p-3 text-xs text-slate-500">
                        <p>No se encontraron coincidencias. Se creará como <strong>nuevo cliente</strong>.</p>
                     </div>
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Fecha de Entrega</label>
                  <input 
                    type="date" 
                    className="w-full p-2.5 border border-slate-300 rounded-lg text-sm" 
                    value={date} 
                    onChange={e => setDate(e.target.value)} 
                  />
                  <p className="text-[10px] text-slate-400 mt-1">Formato interno: dd/mm/yyyy (visualización automática por navegador)</p>
               </div>

               <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                 <h4 className="font-bold text-slate-700 text-xs mb-3 uppercase flex items-center gap-2">
                    <PackageCheck size={14}/> Productos
                 </h4>
                 <div className="flex flex-col gap-2 mb-3">
                    <div className="flex gap-2" ref={productSuggestionsRef}>

                        {/* Product Search Input (Autocomplete) */}
                        <div className="relative flex-1">
                          <div className="flex items-center border border-slate-300 rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500">
                            <Search size={16} className="ml-2 text-slate-400" />
                            <input 
                                className="w-full p-2 text-sm outline-none"
                                placeholder="Buscar producto..."
                                value={productSearchInput}
                                onChange={e => {
                                    setProductSearchInput(e.target.value);
                                    setSelectedProduct(''); // Clear selection on type
                                    setShowProductSuggestions(true);
                                }}
                                onFocus={() => setShowProductSuggestions(true)}
                            />
                          </div>

                          {/* Product Suggestions Dropdown */}
                          {showProductSuggestions && (
                            <div className="absolute z-30 w-full bg-white border border-slate-200 rounded-lg shadow-xl mt-1 max-h-48 overflow-y-auto left-0">
                                {productSuggestions.length > 0 ? (
                                    productSuggestions.map(p => (
                                        <button
                                            key={p.id}
                                            onClick={() => handleSelectProduct(p)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span>{p.name}</span>
                                            <span className="text-xs text-slate-500 font-medium">{formatCurrency(p.price)}</span>
                                        </button>
                                    ))
                                ) : (
                                    <div className="p-2 text-xs text-slate-400 text-center">No encontrado</div>
                                )}
                            </div>
                          )}
                        </div>

                        <input 
                          type="number" 
                          min="1" 
                          className="w-16 p-2 border border-slate-300 rounded text-sm text-center outline-none focus:border-indigo-500" 
                          value={qty} 
                          onChange={e => setQty(Number(e.target.value))} 
                        />
                    </div>
                    <button 
                      onClick={addToCart} 
                      className={`w-full text-white p-2 rounded flex items-center justify-center gap-1 text-sm font-medium transition-colors ${selectedProduct ? 'bg-slate-800 hover:bg-slate-900' : 'bg-slate-300 cursor-not-allowed'}`}
                      disabled={!selectedProduct}
                    >
                        <Plus size={16} /> Agregar al Pedido
                    </button>
                 </div>

                 <div className="space-y-2 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between items-center text-sm bg-white p-2 rounded border border-slate-200 shadow-sm">
                            <span className="font-medium text-slate-700">{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-400 hover:text-red-600 p-1 rounded hover:bg-red-50"><X size={16}/></button>
                        </div>
                    ))}
                    {cart.length === 0 && <p className="text-xs text-slate-400 text-center py-2">Lista vacía</p>}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-3 rounded-lg text-xs flex items-center gap-2 border border-red-100"><AlertCircle size={16}/>{error}</div>}

               <button onClick={handleCreateOrUpdateOrder} className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all">
                   {editingOrderId ? 'Guardar Cambios' : 'Confirmar Pedido'}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Product, RecipeItem, UnitType, Ingredient } from '../types';
import { UNIT_OPTIONS } from '../constants';
import { Plus, Trash2, ChevronDown, ChevronUp, Calculator, DollarSign, Edit2, Save, X, Search } from 'lucide-react';
import { fromBaseUnit, formatCurrency } from '../utils/conversions';

export const Recipes: React.FC = () => {
  const { products, ingredients, addProduct, updateProduct } = useBakery();
  const [isCreating, setIsCreating] = useState(false);

  // State to track if we are editing an existing product
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [productName, setProductName] = useState('');
  const [productPrice, setProductPrice] = useState<number | ''>('');
  const [recipeItems, setRecipeItems] = useState<RecipeItem[]>([]);

  // Costing Calculator State
  const [fixedCosts, setFixedCosts] = useState<number | ''>('');
  const [estimatedUnits, setEstimatedUnits] = useState<number | ''>('');

  // Ingredient Search & Add State
  const [selectedIngId, setSelectedIngId] = useState('');
  const [ingSearchTerm, setIngSearchTerm] = useState('');
  const [showIngSuggestions, setShowIngSuggestions] = useState(false);
  const [amount, setAmount] = useState<number | ''>('');
  const [selectedUnit, setSelectedUnit] = useState<UnitType>(UnitType.GRAMS);

  const suggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (suggestionsRef.current && !suggestionsRef.current.contains(event.target as Node)) {
        setShowIngSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Filtered ingredients for autocomplete (SORTED A-Z)
  const ingredientSuggestions = ingredients
    .filter(i => i.name.toLowerCase().includes(ingSearchTerm.toLowerCase()))
    .sort((a, b) => a.name.localeCompare(b.name));

  const handleSelectIngredient = (ing: Ingredient) => {
    setSelectedIngId(ing.id);
    setIngSearchTerm(ing.name);
    setSelectedUnit(ing.unit);
    setShowIngSuggestions(false);
  };

  const handleAddIngredient = () => {
    if(!selectedIngId) {
        alert("Por favor selecciona un ingrediente de la lista.");
        return;
    }
    if(!amount || Number(amount) <= 0) {
        alert("Ingresa una cantidad válida.");
        return;
    }

    setRecipeItems([...recipeItems, {
      ingredientId: selectedIngId,
      quantity: Number(amount),
      unit: selectedUnit
    }]);

    // Reset inputs
    setAmount('');
    setSelectedIngId('');
    setIngSearchTerm('');
  };

  const handleUpdateItemQuantity = (index: number, newQty: string) => {
    const val = newQty === '' ? 0 : parseFloat(newQty);
    const updatedItems = [...recipeItems];
    updatedItems[index].quantity = val;
    setRecipeItems(updatedItems);
  };

  const handleDeleteItem = (index: number) => {
    const updatedItems = recipeItems.filter((_, i) => i !== index);
    setRecipeItems(updatedItems);
  };

  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setProductName(product.name);
    setProductPrice(product.price);
    // Clone array to allow editing without mutating original until save
    setRecipeItems(product.recipe.map(item => ({...item}))); 

    // Reset calculator fields as they are transient
    setFixedCosts('');
    setEstimatedUnits('');

    setIsCreating(true);
  };

  const handleSaveProduct = async () => {
    // Validation Feedback
    if(!productName.trim()) {
        alert("El nombre del producto es obligatorio.");
        return;
    }
    if(recipeItems.length === 0) {
        alert("Debes agregar al menos un ingrediente a la receta.");
        return;
    }
    if(productPrice === '' || Number(productPrice) < 0) {
        alert("El precio de venta no es válido. Debe ser mayor o igual a 0.");
        return;
    }

    try {
        // Filter out items with 0 quantity just in case
        const validItems = recipeItems.filter(item => item.quantity > 0);

        if (editingProduct) {
            // Update Existing
            const updatedProd: Product = {
                ...editingProduct,
                name: productName,
                price: Number(productPrice),
                recipe: validItems
            };
            await updateProduct(updatedProd);
        } else {
            // Create New
            const newProd: Product = {
                id: Date.now().toString(),
                name: productName,
                price: Number(productPrice),
                recipe: validItems
            };
            await addProduct(newProd);
        }

        closeForm();
    } catch (error) {
        console.error("Error al guardar producto:", error);
        alert("Hubo un error al guardar el producto. Por favor intenta nuevamente.");
    }
  };

  const closeForm = () => {
    setIsCreating(false);
    setEditingProduct(null);
    resetForm();
  };

  const resetForm = () => {
    setProductName('');
    setProductPrice('');
    setRecipeItems([]);
    setFixedCosts('');
    setEstimatedUnits('');
    setEditingProduct(null);
    setIngSearchTerm('');
    setSelectedIngId('');
    setAmount('');
  };

  // Cost Estimation
  const calculateVariableCost = (items: RecipeItem[]) => {
    return items.reduce((acc, item) => {
      const ing = ingredients.find(i => i.id === item.ingredientId);
      if(!ing) return acc;

      // Cost is stored per ing.unit (Display unit).
      // We need to match item.quantity (item.unit) to ing.unit.

      // Case 1: Same unit
      if (item.unit === ing.unit) {
          return acc + (item.quantity * ing.costPerUnit);
      }

      // Case 2: Different units (e.g. g vs kg)

      // 1. Get Base Quantity of Item
      let itemBase = 0;
      switch(item.unit) {
          case UnitType.KILOGRAMS: itemBase = item.quantity * 1000; break;
          case UnitType.LITERS: itemBase = item.quantity * 1000; break;
          default: itemBase = item.quantity;
      }

      // 2. Convert Base Quantity to Ing Unit
      const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);

      return acc + (itemQtyInIngUnit * ing.costPerUnit);
    }, 0);
  };

  const cvu = calculateVariableCost(recipeItems);

  // Suggested Price Formula
  // Price = (CVU + (CFT / Q)) / (1 - 0.60)
  // Margin 60%
  const calculateSuggestedPrice = () => {
      const cft = Number(fixedCosts) || 0;
      const q = Number(estimatedUnits) || 1; // avoid div by 0

      const fixedCostPerUnit = cft / q;
      const totalUnitCost = cvu + fixedCostPerUnit;

      // Margin 60% -> Cost is 40% of price
      const price = totalUnitCost / (1 - 0.60);
      return Math.round(price); // Round to integer for CLP
  };

  const suggestedPrice = calculateSuggestedPrice();

  const toggleCreate = () => {
    if(isCreating) {
        closeForm();
    } else {
        resetForm();
        setIsCreating(true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Recetas y Productos</h2>
        {/* Desktop Button */}
        <button 
          onClick={toggleCreate}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          {isCreating ? 'Cancelar' : <><Plus size={18} /> Nuevo Producto</>}
        </button>
      </div>

      {/* Mobile Floating Action Button (FAB) */}
      <button 
        onClick={toggleCreate}
        className={`md:hidden fixed bottom-20 right-4 p-4 rounded-full shadow-lg z-40 transition-colors ${isCreating ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white`}
        aria-label={isCreating ? "Cancelar" : "Nuevo Producto"}
      >
        {isCreating ? <X size={24} /> : <Plus size={24} />}
      </button>

      {isCreating && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-lg space-y-6 animate-in fade-in slide-in-from-top-4">
          <h3 className="font-bold text-lg text-slate-800 border-b pb-2">
              {editingProduct ? 'Editar Receta' : 'Crear Nueva Receta'}
          </h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1">Nombre del Producto</label>
                  <input 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={productName} 
                    onChange={e => setProductName(e.target.value)} 
                    placeholder="Ej: Tarta de Frutilla"
                  />
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                    <h4 className="font-medium text-slate-700 mb-3 text-sm uppercase tracking-wide">Ingredientes (Costo Variable)</h4>

                    <div className="flex flex-col gap-2 mb-4 bg-white p-3 rounded border border-slate-200 shadow-sm relative" ref={suggestionsRef}>
                      <label className="text-xs font-bold text-slate-500">Agregar Ingrediente</label>
                      <div className="grid grid-cols-12 gap-2 items-end">

                          {/* Autocomplete Input */}
                          <div className="col-span-12 sm:col-span-5 relative">
                             <div className="flex items-center border rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500 focus-within:border-indigo-500">
                                <Search size={16} className="ml-2 text-slate-400" />
                                <input 
                                    className="w-full p-2 text-sm outline-none"
                                    placeholder="Buscar ingrediente..."
                                    value={ingSearchTerm}
                                    onChange={e => {
                                        setIngSearchTerm(e.target.value);
                                        setSelectedIngId(''); // Reset selection when typing
                                        setShowIngSuggestions(true);
                                    }}
                                    onFocus={() => setShowIngSuggestions(true)}
                                />
                             </div>

                             {/* Suggestions Dropdown */}
                             {showIngSuggestions && ingredientSuggestions.length > 0 && (
                                 <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 max-h-48 overflow-y-auto">
                                    {ingredientSuggestions.map(ing => (
                                        <button
                                            key={ing.id}
                                            onClick={() => handleSelectIngredient(ing)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span>{ing.name}</span>
                                            <span className="text-xs text-slate-400">{formatCurrency(ing.costPerUnit)}/{ing.unit}</span>
                                        </button>
                                    ))}
                                 </div>
                             )}
                             {/* No results */}
                             {showIngSuggestions && ingSearchTerm && ingredientSuggestions.length === 0 && (
                                <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 p-2 text-xs text-slate-400">
                                    No se encontraron ingredientes.
                                </div>
                             )}
                          </div>

                          <div className="col-span-4 sm:col-span-3">
                              <input 
                                type="number" 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500" 
                                placeholder="Cant."
                                value={amount}
                                onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))}
                                onKeyDown={(e) => { if(e.key === 'Enter') handleAddIngredient() }}
                              />
                          </div>

                          <div className="col-span-6 sm:col-span-3">
                              <select 
                                className="w-full p-2 border rounded text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={selectedUnit}
                                onChange={e => setSelectedUnit(e.target.value as UnitType)}
                              >
                                {/* Show all units to allow flexibility */}
                                {UNIT_OPTIONS.map(u => (
                                  <option key={u.value} value={u.value}>{u.label}</option>
                                ))}
                              </select>
                          </div>

                          <div className="col-span-2 sm:col-span-1">
                              <button 
                                onClick={handleAddIngredient}
                                className={`w-full text-white p-2 rounded flex items-center justify-center transition-colors h-[38px] ${selectedIngId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-300 cursor-not-allowed'}`}
                                disabled={!selectedIngId}
                              >
                                <Plus size={18} />
                              </button>
                          </div>
                      </div>
                    </div>

                    {recipeItems.length > 0 ? (
                       <div className="space-y-2 mb-2">
                         <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 px-2">
                            <div className="col-span-5">Ingrediente</div>
                            <div className="col-span-5 text-right">Cantidad</div>
                            <div className="col-span-2 text-center"></div>
                         </div>
                         {recipeItems.map((item, idx) => {
                           const ingName = ingredients.find(i => i.id === item.ingredientId)?.name || 'Ingrediente eliminado';
                           return (
                             <div key={idx} className="grid grid-cols-12 gap-2 items-center bg-white p-2 border rounded shadow-sm text-sm">
                               <div className="col-span-5 truncate font-medium text-slate-700" title={ingName}>
                                 {ingName}
                                </div>
                               <div className="col-span-5 flex justify-end items-center gap-1">
                                 <input 
                                    type="number"
                                    min="0"
                                    step="any"
                                    className="w-20 p-1 border border-slate-200 rounded text-right focus:border-indigo-500 outline-none"
                                    value={item.quantity === 0 ? '' : item.quantity}
                                    onChange={(e) => handleUpdateItemQuantity(idx, e.target.value)}
                                 />
                                 <span className="text-xs text-slate-500 w-8">{item.unit}</span>
                               </div>
                               <div className="col-span-2 text-center">
                                 <button 
                                    onClick={() => handleDeleteItem(idx)} 
                                    className="text-red-400 hover:text-red-600 p-1 rounded-full hover:bg-red-50"
                                 >
                                    <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                           )
                         })}
                         <div className="flex justify-between items-center pt-3 border-t border-slate-200 mt-3">
                            <span className="text-slate-500 font-medium text-sm">Costo Variable Total (CVU):</span>
                            <span className="text-slate-800 font-bold text-lg">{formatCurrency(cvu)}</span>
                         </div>
                       </div>
                    ) : (
                        <p className="text-xs text-slate-400 italic text-center py-4">Agrega ingredientes para calcular el costo.</p>
                    )}
                </div>
            </div>

            <div className="space-y-4">
               {/* Pricing Calculator */}
               <div className="bg-indigo-50 p-5 rounded-xl border border-indigo-100">
                  <div className="flex items-center gap-2 mb-4 text-indigo-800">
                     <Calculator size={20} />
                     <h4 className="font-bold">Calculadora de Precios</h4>
                  </div>

                  <div className="space-y-3 mb-4">
                      <div className="grid grid-cols-2 gap-3">
                        <div>
                           <label className="text-xs font-semibold text-slate-500 block mb-1">Costos Fijos Asignados (CFT)</label>
                           <div className="relative">
                               <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400 text-xs">$</span>
                               <input 
                                 type="number" 
                                 className="w-full pl-5 p-2 border border-indigo-200 rounded text-sm focus:ring-1 focus:ring-indigo-500"
                                 placeholder="0"
                                 value={fixedCosts}
                                 onChange={e => setFixedCosts(e.target.value === '' ? '' : Number(e.target.value))}
                               />
                           </div>
                        </div>
                        <div>
                           <label className="text-xs font-semibold text-slate-500 block mb-1">Ventas Estimadas (Q)</label>
                           <input 
                             type="number" 
                             className="w-full p-2 border border-indigo-200 rounded text-sm focus:ring-1 focus:ring-indigo-500"
                             placeholder="Unidades/mes"
                             value={estimatedUnits}
                             onChange={e => setEstimatedUnits(e.target.value === '' ? '' : Number(e.target.value))}
                           />
                        </div>
                      </div>

                      <div className="bg-white p-3 rounded-lg border border-indigo-100 space-y-1">
                          <div className="flex justify-between text-xs text-slate-500">
                              <span>Costo Variable (CVU):</span>
                              <span>{formatCurrency(cvu)}</span>
                          </div>
                          <div className="flex justify-between text-xs text-slate-500">
                              <span>Costo Fijo Unitario (CFT/Q):</span>
                              <span>{formatCurrency((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0)}</span>
                          </div>
                          <div className="flex justify-between text-xs text-slate-800 font-semibold pt-1 border-t border-slate-100">
                              <span>Costo Total Unitario:</span>
                              <span>{formatCurrency(cvu + ((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0))}</span>
                          </div>
                      </div>

                      <div className="flex justify-between items-center bg-indigo-100 p-3 rounded-lg">
                          <div>
                              <span className="text-xs text-indigo-600 font-bold uppercase block">Precio Sugerido</span>
                              <span className="text-[10px] text-indigo-400">Margen 60%</span>
                          </div>
                          <div className="text-xl font-bold text-indigo-800">
                              {formatCurrency(suggestedPrice)}
                          </div>
                      </div>

                      <button 
                        onClick={() => setProductPrice(suggestedPrice)}
                        disabled={!isFinite(suggestedPrice) || suggestedPrice <= 0}
                        className="w-full py-1.5 text-xs bg-indigo-200 text-indigo-800 rounded font-semibold hover:bg-indigo-300 transition-colors disabled:opacity-50"
                      >
                         Usar Precio Sugerido
                      </button>
                  </div>

                  <div>
                    <label className="label text-sm font-bold text-slate-700 mb-1 block">Precio de Venta Final</label>
                    <div className="relative">
                        <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input 
                            type="number" 
                            className="w-full pl-9 p-3 border border-slate-300 rounded-lg text-lg font-bold text-slate-800" 
                            value={productPrice} 
                            onChange={e => setProductPrice(e.target.value === '' ? '' : Number(e.target.value))} 
                            placeholder="0"
                        />
                    </div>
                  </div>
               </div>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
             <button 
                type="button"
                onClick={handleSaveProduct}
                className="bg-green-600 text-white py-3 px-8 rounded-lg font-bold hover:bg-green-700 shadow-md flex items-center gap-2"
             >
                {editingProduct ? 'Actualizar Producto' : 'Guardar Producto'} <Save size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Product List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {products.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            ingredients={ingredients} 
            onEdit={handleEditClick}
          />
        ))}
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ 
    product: Product, 
    ingredients: Ingredient[], 
    onEdit: (p: Product) => void 
}> = ({ product, ingredients, onEdit }) => {
    const [expanded, setExpanded] = useState(false);
    const { deleteProduct } = useBakery();

    const handleDelete = (e: React.MouseEvent) => {
        // e.stopPropagation() is less critical now that buttons are structurally separated, 
        // but kept for safety.
        e.stopPropagation();
        if(window.confirm(`¿Estás seguro que deseas eliminar "${product.name}"? Esta acción no se puede deshacer.`)) {
            deleteProduct(product.id);
        }
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow">
            <div className="p-4 flex justify-between items-center hover:bg-slate-50">
                <div 
                    className="flex-1 cursor-pointer"
                    onClick={() => setExpanded(!expanded)}
                >
                    <h3 className="font-bold text-slate-800 text-lg">{product.name}</h3>
                    <p className="text-slate-500 text-sm flex items-center gap-2">
                        {product.recipe.length} ingredientes
                    </p>
                </div>
                <div className="flex items-center gap-3 pl-4">
                    <span className="font-bold text-emerald-600 text-lg bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100 whitespace-nowrap">
                        {formatCurrency(product.price)}
                    </span>
                    <button 
                        onClick={(e) => { e.stopPropagation(); onEdit(product); }}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                        title="Editar receta"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={handleDelete}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                        title="Eliminar receta"
                    >
                        <Trash2 size={18} />
                    </button>
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="p-1 text-slate-400"
                    >
                        {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </button>
                </div>
            </div>
            {expanded && (
                <div className="p-4 bg-slate-50 border-t border-slate-100 animate-in fade-in slide-in-from-top-1">
                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Fórmula (Unitario)</h4>
                    <ul className="space-y-2 text-sm">
                        {product.recipe.map((r, i) => {
                            const ing = ingredients.find(ing => ing.id === r.ingredientId);
                            // Calculate simple cost share for display
                            let costShare = 0;
                            if(ing) {
                                let itemBase = 0;
                                switch(r.unit) {
                                    case UnitType.KILOGRAMS: itemBase = r.quantity * 1000; break;
                                    case UnitType.LITERS: itemBase = r.quantity * 1000; break;
                                    default: itemBase = r.quantity;
                                }
                                const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);
                                costShare = itemQtyInIngUnit * ing.costPerUnit;
                            }

                            return (
                                <li key={i} className="flex justify-between items-center text-slate-700 p-2 bg-white rounded border border-slate-100">
                                    <span className="font-medium">{ing?.name || 'Desconocido'}</span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-600">{r.quantity} {r.unit}</div>
                                        <div className="text-[10px] text-slate-400">~{formatCurrency(costShare)}</div>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus, Customer, Product } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, PackageCheck, ChefHat, Truck, DollarSign, History, X, Edit2, Trash2, User } from 'lucide-react';
import { formatCurrency, formatDate } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrder, updateOrderStatus, addCustomer, deleteOrder } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New/Edit Order Form State
  const [editingOrderId, setEditingOrderId] = useState<string | null>(null);

  // Customer Smart Search State
  const [customerSearchInput, setCustomerSearchInput] = useState('');
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | null>(null); // If null, means new customer
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);

  // Product Smart Search State
  const [productSearchInput, setProductSearchInput] = useState('');
  const [selectedProduct, setSelectedProduct] = useState(''); // Stores ID
  const [showProductSuggestions, setShowProductSuggestions] = useState(false);

  const [date, setDate] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  const customerSuggestionsRef = useRef<HTMLDivElement>(null);
  const productSuggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // Customer Dropdown
      if (customerSuggestionsRef.current && !customerSuggestionsRef.current.contains(event.target as Node)) {
        setShowCustomerSuggestions(false);
      }
      // Product Dropdown
      if (productSuggestionsRef.current && !productSuggestionsRef.current.contains(event.target as Node)) {
        setShowProductSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Filtered customers for autocomplete
  const customerSuggestions = useMemo(() => {
    if (!customerSearchInput) return [];
    return customers.filter(c => 
      c.name.toLowerCase().includes(customerSearchInput.toLowerCase())
    ).slice(0, 5); // Limit to 5
  }, [customers, customerSearchInput]);

  // Filtered products for autocomplete (Sorted Alphabetically)
  const productSuggestions = useMemo(() => {
    return products
      .filter(p => p.name.toLowerCase().includes(productSearchInput.toLowerCase()))
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [products, productSearchInput]);

  const handleSelectCustomer = (c: Customer) => {
    setCustomerSearchInput(c.name);
    setSelectedCustomerId(c.id);
    setShowCustomerSuggestions(false);
  };

  const handleCustomerInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setCustomerSearchInput(e.target.value);
    setSelectedCustomerId(null); // Reset ID implies potentially new customer
    setShowCustomerSuggestions(true);
  };

  const handleSelectProduct = (p: Product) => {
    setProductSearchInput(p.name);
    setSelectedProduct(p.id);
    setShowProductSuggestions(false);
  };

  // --- Constants ---
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado'];
  const HISTORY_STEPS: OrderStatus[] = ['Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const flow: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];
    const currentIndex = flow.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < flow.length - 1) {
      updateOrderStatus(order.id, flow[currentIndex + 1]);
    }
  };

  const handleDeleteOrder = (order: Order) => {
    if (window.confirm(`¿Estás seguro de eliminar el pedido de ${order.customerName}? Esto devolverá los ingredientes al inventario.`)) {
        deleteOrder(order.id);
    }
  };

  const handleEditOrder = (order: Order) => {
    setEditingOrderId(order.id);

    // Setup Customer Field
    setCustomerSearchInput(order.customerName);
    setSelectedCustomerId(order.customerId || null); // Keep ID if valid

    setDate(order.deliveryDate);
    setCart(order.items.map(i => ({...i})));
    setError('');
    setIsModalOpen(true);
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    const existingIndex = cart.findIndex(i => i.productId === selectedProduct);
    if (existingIndex >= 0) {
        const newCart = [...cart];
        newCart[existingIndex].quantity += finalQty;
        setCart(newCart);
    } else {
        setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    }

    // Reset Product Selection
    setSelectedProduct('');
    setProductSearchInput('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrUpdateOrder = async () => {
    setError('');

    if (!customerSearchInput.trim()) { setError('Ingresa el nombre del cliente.'); return; }
    if(!date) { setError('Selecciona fecha de entrega.'); return; }
    if(cart.length === 0) { setError('Agrega al menos un producto.'); return; }

    let finalCustomerId = selectedCustomerId;
    let finalCustomerName = customerSearchInput.trim();

    // Logic: If no ID is selected, but name exists in text, create new customer
    if (!finalCustomerId) {
        // Double check if name matches an existing one exactly to avoid dupe
        const existingExact = customers.find(c => c.name.toLowerCase() === finalCustomerName.toLowerCase());
        if (existingExact) {
            finalCustomerId = existingExact.id;
        } else {
            // Create completely new customer
            try {
                finalCustomerId = await addCustomer({
                    id: '',
                    name: finalCustomerName
                });
            } catch (e) {
                setError('Error al crear nuevo cliente.');
                return;
            }
        }
    }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const orderData: Order = {
      id: editingOrderId || Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: editingOrderId ? (orders.find(o => o.id === editingOrderId)?.status || 'Pendiente') : 'Pendiente',
      items: cart,
      totalPrice: total
    };

    if (editingOrderId) {
        updateOrder(orderData);
    } else {
        addOrder(orderData);
    }
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    // Customer Reset
    setCustomerSearchInput('');
    setSelectedCustomerId(null);
    setShowCustomerSuggestions(false);
    // Product Reset
    setProductSearchInput('');
    setSelectedProduct('');
    setShowProductSuggestions(false);

    setDate('');
    setError('');
    setQty(1);
    setEditingOrderId(null);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': 
        return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendiente', next: 'En Proceso' };
      case 'En Proceso': 
        return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: ChefHat, label: 'En Proceso', next: 'Completado' };
      case 'Completado': 
        return { color: 'bg-indigo-100 text-indigo-800 border-indigo-200', icon: PackageCheck, label: 'Completado', next: 'Entregado' };
      case 'Entregado': 
        return { color: 'bg-blue-100 text-blue-800 border-blue-200', icon: Truck, label: 'Entregado', next: 'Pagado' };
      case 'Pagado': 
        return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: DollarSign, label: 'Pagado', next: '' };
      default: 
        return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Controla el flujo desde Pendiente hasta Pagado.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial (Pagados)
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Cerrados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div className="flex-1 min-w-0">
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {formatDate(order.deliveryDate)}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>

                {/* Edit/Delete Controls */}
                <div className="flex gap-1 ml-2">
                    <button 
                        onClick={() => handleEditOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-indigo-600 rounded hover:bg-indigo-50 transition-colors"
                        title="Editar Pedido"
                    >
                        <Edit2 size={16} />
                    </button>
                    <button 
                        onClick={() => handleDeleteOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-red-600 rounded hover:bg-red-50 transition-colors"
                        title="Eliminar Pedido"
                    >
                        <Trash2 size={16} />
                    </button>
                </div>
              </div>

              {/* Status & Price Row */}
              <div className="flex justify-between items-center mb-3">
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block ${config.color}`}>
                     {order.status}
                  </span>
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <button 
                  onClick={() => advanceOrder(order)}
                  className="w-full py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                >
                  {/* Dynamic Icon based on next step */}
                  {config.next === 'En Proceso' && <ChefHat size={16} />}
                  {config.next === 'Completado' && <PackageCheck size={16} />}
                  {config.next === 'Entregado' && <Truck size={16} />}
                  {config.next === 'Pagado' && <DollarSign size={16} />}

                  {config.next === 'Pagado' ? 'Confirmar Pago (Cerrar)' : `Avanzar a ${config.next}`}

                  <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
                </button>
              ) : (
                <div className="text-center text-xs text-slate-400 italic flex items-center justify-center gap-1">
                  <CheckCircle2 size={14} /> Pedido cerrado y archivado
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* New/Edit Order Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto flex flex-col">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0 z-10">
              <h3 className="font-bold">{editingOrderId ? 'Editar Pedido' : 'Nuevo Pedido'}</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-5 flex-1 overflow-y-auto">

               {/* Smart Customer Search */}
               <div className="relative" ref={customerSuggestionsRef}>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex items-center border border-slate-300 rounded-lg overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500 focus-within:border-indigo-500">
                    <div className="pl-3 text-slate-400"><User size={18} /></div>
                    <input 
                      className="w-full p-2.5 text-sm outline-none" 
                      value={customerSearchInput} 
                      onChange={handleCustomerInputChange} 
                      onFocus={() => setShowCustomerSuggestions(true)}
                      placeholder="Buscar o crear nuevo cliente..."
                      autoComplete="off"
                    />
                    {selectedCustomerId && (
                        <div className="pr-3 text-green-500"><CheckCircle2 size={18} /></div>
                    )}
                  </div>

                  {/* Autocomplete Dropdown */}
                  {showCustomerSuggestions && customerSuggestions.length > 0 && (
                    <div className="absolute z-20 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-lg max-h-48 overflow-y-auto">
                        <div className="text-[10px] uppercase text-slate-400 font-semibold px-3 py-1 bg-slate-50">Sugerencias</div>
                        {customerSuggestions.map(c => (
                            <button
                                key={c.id}
                                onClick={() => handleSelectCustomer(c)}
                                className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none"
                            >
                                {c.name}
                            </button>
                        ))}
                    </div>
                  )}
                  {showCustomerSuggestions && customerSearchInput && customerSuggestions.length === 0 && (
                     <div className="absolute z-20 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-lg p-3 text-xs text-slate-500">
                        <p>No se encontraron coincidencias. Se creará como <strong>nuevo cliente</strong>.</p>
                     </div>
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Fecha de Entrega</label>
                  <input 
                    type="date" 
                    className="w-full p-2.5 border border-slate-300 rounded-lg text-sm" 
                    value={date} 
                    onChange={e => setDate(e.target.value)} 
                  />
                  <p className="text-[10px] text-slate-400 mt-1">Formato interno: dd/mm/yyyy (visualización automática por navegador)</p>
               </div>

               <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                 <h4 className="font-bold text-slate-700 text-xs mb-3 uppercase flex items-center gap-2">
                    <PackageCheck size={14}/> Productos
                 </h4>
                 <div className="flex flex-col gap-2 mb-3">
                    <div className="flex gap-2" ref={productSuggestionsRef}>

                        {/* Product Search Input (Autocomplete) */}
                        <div className="relative flex-1">
                          <div className="flex items-center border border-slate-300 rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500">
                            <Search size={16} className="ml-2 text-slate-400" />
                            <input 
                                className="w-full p-2 text-sm outline-none"
                                placeholder="Buscar producto..."
                                value={productSearchInput}
                                onChange={e => {
                                    setProductSearchInput(e.target.value);
                                    setSelectedProduct(''); // Clear selection on type
                                    setShowProductSuggestions(true);
                                }}
                                onFocus={() => setShowProductSuggestions(true)}
                            />
                          </div>

                          {/* Product Suggestions Dropdown */}
                          {showProductSuggestions && (
                            <div className="absolute z-30 w-full bg-white border border-slate-200 rounded-lg shadow-xl mt-1 max-h-48 overflow-y-auto left-0">
                                {productSuggestions.length > 0 ? (
                                    productSuggestions.map(p => (
                                        <button
                                            key={p.id}
                                            onClick={() => handleSelectProduct(p)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span>{p.name}</span>
                                            <span className="text-xs text-slate-500 font-medium">{formatCurrency(p.price)}</span>
                                        </button>
                                    ))
                                ) : (
                                    <div className="p-2 text-xs text-slate-400 text-center">No encontrado</div>
                                )}
                            </div>
                          )}
                        </div>

                        <input 
                          type="number" 
                          min="1" 
                          className="w-16 p-2 border border-slate-300 rounded text-sm text-center outline-none focus:border-indigo-500" 
                          value={qty} 
                          onChange={e => setQty(Number(e.target.value))} 
                        />
                    </div>
                    <button 
                      onClick={addToCart} 
                      className={`w-full text-white p-2 rounded flex items-center justify-center gap-1 text-sm font-medium transition-colors ${selectedProduct ? 'bg-slate-800 hover:bg-slate-900' : 'bg-slate-300 cursor-not-allowed'}`}
                      disabled={!selectedProduct}
                    >
                        <Plus size={16} /> Agregar al Pedido
                    </button>
                 </div>

                 <div className="space-y-2 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between items-center text-sm bg-white p-2 rounded border border-slate-200 shadow-sm">
                            <span className="font-medium text-slate-700">{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-400 hover:text-red-600 p-1 rounded hover:bg-red-50"><X size={16}/></button>
                        </div>
                    ))}
                    {cart.length === 0 && <p className="text-xs text-slate-400 text-center py-2">Lista vacía</p>}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-3 rounded-lg text-xs flex items-center gap-2 border border-red-100"><AlertCircle size={16}/>{error}</div>}

               <button onClick={handleCreateOrUpdateOrder} className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all">
                   {editingOrderId ? 'Guardar Cambios' : 'Confirmar Pedido'}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// Enums for Units to ensure consistency
export enum UnitType {
  GRAMS = 'g',
  KILOGRAMS = 'kg',
  MILLILITERS = 'ml',
  LITERS = 'L',
  UNITS = 'u'
}

// Entity: Ingrediente (Raw Material)
export interface Ingredient {
  id: string;
  name: string;
  currentStock: number; // Stored in base units (g, ml, u)
  unit: UnitType; // Preferred display unit, though storage is normalized
  costPerUnit: number;
  minStock: number; // Reorder point
}

// Entity: Receta (Recipe Line Item)
export interface RecipeItem {
  ingredientId: string; // Can be IngredientID OR ProductID (if sub-recipe)
  type?: 'INGREDIENT' | 'PRODUCT'; // Discriminator. Defaults to INGREDIENT for legacy data.
  quantity: number; // Amount needed for 1 unit of product
  unit: UnitType;
}

// Entity: Producto (Final Product)
export interface Product {
  id: string;
  name: string;
  price: number;
  description?: string;
  recipe: RecipeItem[];
  isIntermediate?: boolean; // NEW: If true, it's a base/pre-mix (e.g. Pie Crust) not for direct sale usually
}

// Entity: Cliente
export interface Customer {
  id: string;
  name: string;
  phone?: string;
  email?: string;
  address?: string;
  notes?: string;
}

// Entity: Pedido (Order)
export interface OrderItem {
  productId: string;
  quantity: number;
}

export type OrderStatus = 'Pendiente' | 'En Proceso' | 'Completado' | 'Entregado' | 'Pagado';

export interface Order {
  id: string;
  customerId: string; // Link to Customer ID if available
  customerName: string; // Fallback or snapshot name
  deliveryDate: string; // ISO Date string YYYY-MM-DD
  status: OrderStatus;
  items: OrderItem[];
  totalPrice: number;
  accountingClosed?: boolean; // If true, this order has been included in a month close
}

export interface MonthClosure {
  id: string;
  date: string; // ISO Timestamp of closure
  totalRevenue: number;
  totalOrders: number;
  periodLabel: string; // e.g., "Octubre 2023 - Corte 1"
}

// Helper type for Production Planning
export interface ProductionRequirement {
  ingredientName: string;
  ingredientId: string;
  totalNeeded: number;
  currentStock: number;
  unit: UnitType;
  missing: number; // If totalNeeded > currentStock
}

// Chat Message for AI Chef
export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

// Inventory Item for Display
export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  threshold: number;
  category: string;
}

