  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (suggestionsRef.current && !suggestionsRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Combined Suggestions: Ingredients + Intermediate Products
  // SORTED A-Z
  const combinedSuggestions = useMemo(() => {
     const rawIngs = ingredients.map(i => ({
         id: i.id,
         name: i.name,
         type: 'INGREDIENT' as const,
         unit: i.unit,
         cost: i.costPerUnit,
         isIntermediate: false
     }));

     // Only show products that ARE intermediate (Sub-recipes)
     // Prevent circular dependency (simplistic check: don't show self if editing)
     const subProds = products
        .filter(p => p.isIntermediate && p.id !== editingProduct?.id)
        .map(p => ({
            id: p.id,
            name: p.name,
            type: 'PRODUCT' as const,
            unit: UnitType.UNITS, // Default for sub-recipes usually
            cost: 0, // Calculated dynamically later
            isIntermediate: true
        }));

     return [...rawIngs, ...subProds]
        .filter(item => item.name.toLowerCase().includes(searchQuery.toLowerCase()))
        .sort((a, b) => a.name.localeCompare(b.name));
  }, [ingredients, products, searchQuery, editingProduct]);

  const handleSelectItem = (item: typeof combinedSuggestions[0]) => {
    setSelectedItemId(item.id);
    setSelectedItemType(item.type);
    setSearchQuery(item.name);
    setSelectedUnit(item.unit);
    setShowSuggestions(false);
  };

  const handleAddItem = () => {
    if(!selectedItemId) {
        alert("Por favor selecciona un ingrediente o base.");
        return;
    }
    if(!amount || Number(amount) <= 0) {
        alert("Ingresa una cantidad válida.");
        return;
    }

    setRecipeItems([...recipeItems, {
      ingredientId: selectedItemId, // This stores either Ing ID or Prod ID
      type: selectedItemType,
      quantity: Number(amount),
      unit: selectedUnit
    }]);

    // Reset inputs
    setAmount('');
    setSelectedItemId('');
    setSelectedItemType('INGREDIENT');
    setSearchQuery('');
  };

  const handleUpdateItemQuantity = (index: number, newQty: string) => {
    const val = newQty === '' ? 0 : parseFloat(newQty);
    const updatedItems = [...recipeItems];
    updatedItems[index].quantity = val;
    setRecipeItems(updatedItems);
  };

  const handleDeleteItem = (index: number) => {
    const updatedItems = recipeItems.filter((_, i) => i !== index);
    setRecipeItems(updatedItems);
  };

  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setProductName(product.name);
    setProductPrice(product.price);
    setIsIntermediate(!!product.isIntermediate);

    // Normalize recipe items (handle legacy data missing 'type')
    const normalizedItems = product.recipe.map(item => ({
        ...item,
        type: item.type || 'INGREDIENT' // Default for old data
    }));
    setRecipeItems(normalizedItems.map(item => ({...item}))); 

    setFixedCosts('');
    setEstimatedUnits('');

    setIsCreating(true);
  };

  const handleSaveProduct = async () => {
    // Validation
    if(!productName.trim()) {
        alert("El nombre del producto es obligatorio.");
        return;
    }
    if(recipeItems.length === 0) {
        alert("Debes agregar al menos un ingrediente a la receta.");
        return;
    }

    // If it's NOT intermediate, it needs a price. 
    // If it IS intermediate, price is optional (usually 0/internal).
    if(!isIntermediate && (productPrice === '' || Number(productPrice) < 0)) {
        alert("El precio de venta no es válido.");
        return;
    }

    try {
        const validItems = recipeItems.filter(item => item.quantity > 0);
        const finalPrice = productPrice === '' ? 0 : Number(productPrice);

        const prodData: Product = {
            id: editingProduct ? editingProduct.id : Date.now().toString(),
            name: productName,
            price: finalPrice,
            recipe: validItems,
            isIntermediate: isIntermediate
        };

        if (editingProduct) {
            await updateProduct(prodData);
        } else {
            await addProduct(prodData);
        }

        closeForm();
    } catch (error) {
        console.error("Error al guardar producto:", error);
        alert("Hubo un error al guardar el producto.");
    }
  };

  const closeForm = () => {
    setIsCreating(false);
    setEditingProduct(null);
    resetForm();
  };

  const resetForm = () => {
    setProductName('');
    setProductPrice('');
    setRecipeItems([]);
    setFixedCosts('');
    setEstimatedUnits('');
    setEditingProduct(null);
    setSearchQuery('');
    setSelectedItemId('');
    setAmount('');
    setIsIntermediate(false);
  };

  // --- RECURSIVE COST CALCULATOR ---
  const getProductCost = (prodId: string): number => {
      const prod = products.find(p => p.id === prodId);
      if(!prod) return 0;
      return calculateVariableCost(prod.recipe);
  };

  const calculateVariableCost = (items: RecipeItem[]) => {
    return items.reduce((acc, item) => {
      const type = item.type || 'INGREDIENT';

      if (type === 'INGREDIENT') {
          const ing = ingredients.find(i => i.id === item.ingredientId);
          if(!ing) return acc;

          if (item.unit === ing.unit) {
              return acc + (item.quantity * ing.costPerUnit);
          }
          let itemBase = 0;
          switch(item.unit) {
              case UnitType.KILOGRAMS: itemBase = item.quantity * 1000; break;
              case UnitType.LITERS: itemBase = item.quantity * 1000; break;
              default: itemBase = item.quantity;
          }
          const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);
          return acc + (itemQtyInIngUnit * ing.costPerUnit);

      } else {
          // It's a SUB-PRODUCT (Intermediate)
          // Assumption: Cost is calculated per 1 Unit of that recipe (Batch)
          // Ideally we need yield, but for now we assume 1 Unit = 1 Batch Cost.
          const subCost = getProductCost(item.ingredientId);

          // If unit is UNITS, it's a direct multiplier. 
          // If unit is Weight, we are in trouble without yield. We fallback to direct multiplier logic.
          // Usually sub-recipes are added as "0.5 Units" (half batch).

          let multiplier = item.quantity;
          // Very simple fallback if they try to measure a recipe in grams (assuming 1 unit = 1 kg for lack of better data)
          // Ideally: Prevent non-unit measures for sub-products in UI, or assume 1 Unit.

          return acc + (subCost * multiplier);
      }
    }, 0);
  };

  const cvu = calculateVariableCost(recipeItems);

  // Suggested Price Formula
  const calculateSuggestedPrice = () => {
      const cft = Number(fixedCosts) || 0;
      const q = Number(estimatedUnits) || 1; 
      const fixedCostPerUnit = cft / q;
      const totalUnitCost = cvu + fixedCostPerUnit;
      const price = totalUnitCost / (1 - 0.60);
      return Math.round(price);
  };

  const suggestedPrice = calculateSuggestedPrice();

  const toggleCreate = () => {
    if(isCreating) {
        closeForm();
    } else {
        resetForm();
        setIsCreating(true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Recetas y Productos</h2>
        <button 
          onClick={toggleCreate}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          {isCreating ? 'Cancelar' : <><Plus size={18} /> Nuevo Producto</>}
        </button>
      </div>

      <button 
        onClick={toggleCreate}
        className={`md:hidden fixed bottom-20 right-4 p-4 rounded-full shadow-lg z-40 transition-colors ${isCreating ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white`}
      >
        {isCreating ? <X size={24} /> : <Plus size={24} />}
      </button>

      {isCreating && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-lg space-y-6 animate-in fade-in slide-in-from-top-4">
          <div className="flex justify-between items-start border-b pb-2">
            <h3 className="font-bold text-lg text-slate-800">
                {editingProduct ? 'Editar Receta' : 'Crear Nueva Receta'}
            </h3>
            {/* Intermediate Switch */}
            <div className="flex items-center gap-2 bg-amber-50 px-3 py-1.5 rounded-full border border-amber-100">
               <input 
                 type="checkbox" 
                 id="isIntermediate"
                 checked={isIntermediate}
                 onChange={e => setIsIntermediate(e.target.checked)}
                 className="w-4 h-4 text-amber-600 rounded focus:ring-amber-500"
               />
               <label htmlFor="isIntermediate" className="text-xs font-bold text-amber-800 cursor-pointer select-none">
                 Es Preparado Base / Intermedio
               </label>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1">Nombre {isIntermediate ? 'del Preparado' : 'del Producto'}</label>
                  <input 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={productName} 
                    onChange={e => setProductName(e.target.value)} 
                    placeholder={isIntermediate ? "Ej: Masa Madre, Relleno de Limón" : "Ej: Tarta de Frutilla"}
                  />
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                    <h4 className="font-medium text-slate-700 mb-3 text-sm uppercase tracking-wide">Fórmula (Ingredientes y Bases)</h4>

                    <div className="flex flex-col gap-2 mb-4 bg-white p-3 rounded border border-slate-200 shadow-sm relative" ref={suggestionsRef}>
                      <label className="text-xs font-bold text-slate-500">Agregar Ítem</label>
                      <div className="grid grid-cols-12 gap-2 items-end">

                          {/* Autocomplete Input */}
                          <div className="col-span-12 sm:col-span-5 relative">
                             <div className="flex items-center border rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500">
                                <Search size={16} className="ml-2 text-slate-400" />
                                <input 
                                    className="w-full p-2 text-sm outline-none"
                                    placeholder="Buscar ingrediente o base..."
                                    value={searchQuery}
                                    onChange={e => {
                                        setSearchQuery(e.target.value);
                                        setSelectedItemId(''); 
                                        setShowSuggestions(true);
                                    }}
                                    onFocus={() => setShowSuggestions(true)}
                                />
                             </div>

                             {/* Combined Suggestions Dropdown */}
                             {showSuggestions && combinedSuggestions.length > 0 && (
                                 <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 max-h-48 overflow-y-auto">
                                    {combinedSuggestions.map(item => (
                                        <button
                                            key={item.id}
                                            onClick={() => handleSelectItem(item)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span className="flex items-center gap-2">
                                                {item.isIntermediate && <Layers size={12} className="text-amber-500" />}
                                                {item.name}
                                            </span>
                                            <span className="text-xs text-slate-400">
                                                {item.isIntermediate ? 'Receta' : `${formatCurrency(item.cost)}/${item.unit}`}
                                            </span>
                                        </button>
                                    ))}
                                 </div>
                             )}
                          </div>

                          <div className="col-span-4 sm:col-span-3">
                              <input 
                                type="number" 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500" 
                                placeholder="Cant."
                                value={amount}
                                onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))}
                                onKeyDown={(e) => { if(e.key === 'Enter') handleAddItem() }}
                              />
                          </div>

                          <div className="col-span-6 sm:col-span-3">
                              <select 
                                className="w-full p-2 border rounded text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={selectedUnit}
                                onChange={e => setSelectedUnit(e.target.value as UnitType)}
                              >
                                {UNIT_OPTIONS.map(u => (
                                  <option key={u.value} value={u.value}>{u.label}</option>
                                ))}
                              </select>
                          </div>

                          <div className="col-span-2 sm:col-span-1">
                              <button 
                                onClick={handleAddItem}
                                className={`w-full text-white p-2 rounded flex items-center justify-center transition-colors h-[38px] ${selectedItemId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-300 cursor-not-allowed'}`}
                                disabled={!selectedItemId}
                              >
                                <Plus size={18} />
                              </button>
                          </div>
                      </div>
                    </div>

                    {recipeItems.length > 0 ? (
                       <div className="space-y-2 mb-2">
                         <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 px-2">
                            <div className="col-span-5">Ítem</div>
                            <div className="col-span-5 text-right">Cantidad</div>
                            <div className="col-span-2 text-center"></div>
                         </div>
                         {recipeItems.map((item, idx) => {
                           let name = 'Desconocido';
                           let isSub = false;

                           if (item.type === 'PRODUCT') {
                               name = products.find(p => p.id === item.ingredientId)?.name || 'Base eliminada';
                               isSub = true;
                           } else {
                               name = ingredients.find(i => i.id === item.ingredientId)?.name || 'Ingrediente eliminado';
                           }

                           return (
                             <div key={idx} className={`grid grid-cols-12 gap-2 items-center p-2 border rounded shadow-sm text-sm ${isSub ? 'bg-amber-50 border-amber-100' : 'bg-white border-slate-200'}`}>
                               <div className="col-span-5 truncate font-medium text-slate-700 flex items-center gap-1" title={name}>
                                 {isSub && <Layers size={12} className="text-amber-500 flex-shrink-0" />}
                                 {name}
                                </div>
                               <div className="col-span-5 flex justify-end items-center gap-1">
                                 <input 
                                    type="number"
                                    min="0"
                                    step="any"
                                    className="w-20 p-1 border border-slate-200 rounded text-right focus:border-indigo-500 outline-none bg-white"
                                    value={item.quantity === 0 ? '' : item.quantity}
                                    onChange={(e) => handleUpdateItemQuantity(idx, e.target.value)}
                                 />
                                 <span className="text-xs text-slate-500 w-8">{item.unit}</span>
                               </div>
                               <div className="col-span-2 text-center">
                                 <button 
                                    onClick={() => handleDeleteItem(idx)} 
                                    className="text-red-400 hover:text-red-600 p-1 rounded-full hover:bg-red-50"
                                 >
                                    <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                           )
                         })}
                         <div className="flex justify-between items-center pt-3 border-t border-slate-200 mt-3">
                            <span className="text-slate-500 font-medium text-sm">Costo Variable Total (CVU):</span>
                            <span className="text-slate-800 font-bold text-lg">{formatCurrency(cvu)}</span>
                         </div>
                       </div>
                    ) : (
                        <p className="text-xs text-slate-400 italic text-center py-4">Agrega ingredientes o bases para calcular el costo.</p>
                    )}
                </div>
            </div>

            <div className="space-y-4">
               {/* Pricing Calculator - Hide/Dim if Intermediate */}
               <div className={`bg-indigo-50 p-5 rounded-xl border border-indigo-100 ${isIntermediate ? 'opacity-60 grayscale' : ''}`}>
                  <div className="flex items-center gap-2 mb-4 text-indigo-800">
                     <Calculator size={20} />
                     <h4 className="font-bold">Calculadora {isIntermediate ? '(No requerida)' : 'de Precios'}</h4>
                  </div>

                  {!isIntermediate && (
                    <div className="space-y-3 mb-4">
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                            <label className="text-xs font-semibold text-slate-500 block mb-1">Costos Fijos Asignados (CFT)</label>
                            <input 
                                type="number" 
                                className="w-full p-2 border border-indigo-200 rounded text-sm"
                                placeholder="0"
                                value={fixedCosts}
                                onChange={e => setFixedCosts(e.target.value === '' ? '' : Number(e.target.value))}
                            />
                            </div>
                            <div>
                            <label className="text-xs font-semibold text-slate-500 block mb-1">Ventas Estimadas (Q)</label>
                            <input 
                                type="number" 
                                className="w-full p-2 border border-indigo-200 rounded text-sm"
                                placeholder="Unidades/mes"
                                value={estimatedUnits}
                                onChange={e => setEstimatedUnits(e.target.value === '' ? '' : Number(e.target.value))}
                            />
                            </div>
                        </div>

                        <div className="bg-white p-3 rounded-lg border border-indigo-100 space-y-1">
                            <div className="flex justify-between text-xs text-slate-500">
                                <span>Costo Variable (CVU):</span>
                                <span>{formatCurrency(cvu)}</span>
                            </div>
                            <div className="flex justify-between text-xs text-slate-800 font-semibold pt-1 border-t border-slate-100">
                                <span>Costo Total Unitario:</span>
                                <span>{formatCurrency(cvu + ((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0))}</span>
                            </div>
                        </div>

                        <div className="flex justify-between items-center bg-indigo-100 p-3 rounded-lg">
                            <div>
                                <span className="text-xs text-indigo-600 font-bold uppercase block">Precio Sugerido</span>
                                <span className="text-[10px] text-indigo-400">Margen 60%</span>
                            </div>
                            <div className="text-xl font-bold text-indigo-800">
                                {formatCurrency(suggestedPrice)}
                            </div>
                        </div>

                        <button 
                            onClick={() => setProductPrice(suggestedPrice)}
                            disabled={!isFinite(suggestedPrice) || suggestedPrice <= 0}
                            className="w-full py-1.5 text-xs bg-indigo-200 text-indigo-800 rounded font-semibold hover:bg-indigo-300 transition-colors disabled:opacity-50"
                        >
                            Usar Precio Sugerido
                        </button>
                    </div>
                  )}

                  <div>
                    <label className="label text-sm font-bold text-slate-700 mb-1 block">
                        {isIntermediate ? 'Costo/Valor Interno (Opcional)' : 'Precio de Venta Final'}
                    </label>
                    <div className="relative">
                        <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input 
                            type="number" 
                            className="w-full pl-9 p-3 border border-slate-300 rounded-lg text-lg font-bold text-slate-800" 
                            value={productPrice} 
                            onChange={e => setProductPrice(e.target.value === '' ? '' : Number(e.target.value))} 
                            placeholder={isIntermediate ? "0" : "0"}
                        />
                    </div>
                  </div>
               </div>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
             <button 
                type="button"
                onClick={handleSaveProduct}
                className="bg-green-600 text-white py-3 px-8 rounded-lg font-bold hover:bg-green-700 shadow-md flex items-center gap-2"
             >
                {editingProduct ? 'Actualizar' : 'Guardar'} {isIntermediate ? 'Base' : 'Producto'} <Save size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Product List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {products.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            ingredients={ingredients} 
            products={products}
            onEdit={handleEditClick}
          />
        ))}
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ 
    product: Product, 
    ingredients: Ingredient[], 
    products: Product[],
    onEdit: (p: Product) => void 
}> = ({ product, ingredients, products, onEdit }) => {
    const [expanded, setExpanded] = useState(false);
    const { deleteProduct } = useBakery();

    const handleDelete = (e: React.MouseEvent) => {
        e.stopPropagation();
        if(window.confirm(`¿Estás seguro que deseas eliminar "${product.name}"?`)) {
            deleteProduct(product.id);
        }
    };

    return (
        <div className={`rounded-xl shadow-sm border overflow-hidden hover:shadow-md transition-shadow ${product.isIntermediate ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-200'}`}>
            <div className="p-4 flex justify-between items-center hover:bg-opacity-80">
                <div 
                    className="flex-1 cursor-pointer"
                    onClick={() => setExpanded(!expanded)}
                >
                    <div className="flex items-center gap-2">
                        {product.isIntermediate && <Layers size={18} className="text-amber-600" />}
                        <h3 className="font-bold text-slate-800 text-lg">{product.name}</h3>
                    </div>
                    <p className="text-slate-500 text-sm flex items-center gap-2">
                        {product.isIntermediate ? 'Receta Base / Preparado' : `${product.recipe.length} componentes`}
                    </p>
                </div>
                <div className="flex items-center gap-3 pl-4">
                    {!product.isIntermediate && (
                        <span className="font-bold text-emerald-600 text-lg bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100 whitespace-nowrap">
                            {formatCurrency(product.price)}
                        </span>
                    )}
                    <button 
                        onClick={(e) => { e.stopPropagation(); onEdit(product); }}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={handleDelete}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                    >
                        <Trash2 size={18} />
                    </button>
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="p-1 text-slate-400"
                    >
                        {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </button>
                </div>
            </div>
            {expanded && (
                <div className="p-4 border-t border-slate-100 animate-in fade-in slide-in-from-top-1 bg-white/50">
                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Fórmula</h4>
                    <ul className="space-y-2 text-sm">
                        {product.recipe.map((r, i) => {
                            const isSub = r.type === 'PRODUCT';
                            let name = 'Desconocido';

                            if (isSub) {
                                name = products.find(p => p.id === r.ingredientId)?.name || 'Base eliminada';
                            } else {
                                name = ingredients.find(ing => ing.id === r.ingredientId)?.name || 'Ingrediente desconocido';
                            }

                            return (
                                <li key={i} className="flex justify-between items-center text-slate-700 p-2 bg-white rounded border border-slate-100">
                                    <span className="font-medium flex items-center gap-2">
                                        {isSub && <Layers size={12} className="text-amber-500" />}
                                        {name}
                                    </span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-600">{r.quantity} {r.unit}</div>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Product, RecipeItem, UnitType, Ingredient } from '../types';
import { UNIT_OPTIONS } from '../constants';
import { Plus, Trash2, ChevronDown, ChevronUp, Calculator, DollarSign, Edit2, Save, X, Search, Layers } from 'lucide-react';
import { fromBaseUnit, formatCurrency } from '../utils/conversions';

export const Recipes: React.FC = () => {
  const { products, ingredients, addProduct, updateProduct } = useBakery();
  const [isCreating, setIsCreating] = useState(false);

  // State to track if we are editing an existing product
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [productName, setProductName] = useState('');
  const [productPrice, setProductPrice] = useState<number | ''>('');
  const [recipeItems, setRecipeItems] = useState<RecipeItem[]>([]);
  const [isIntermediate, setIsIntermediate] = useState(false);

  // Costing Calculator State
  const [fixedCosts, setFixedCosts] = useState<number | ''>('');
  const [estimatedUnits, setEstimatedUnits] = useState<number | ''>('');

  // Ingredient Search & Add State
  // Search Logic now includes BOTH Ingredients AND Intermediate Products
  const [selectedItemId, setSelectedItemId] = useState('');
  const [selectedItemType, setSelectedItemType] = useState<'INGREDIENT' | 'PRODUCT'>('INGREDIENT');
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuggestions, setShowSuggestions] = useState(false);

  const [amount, setAmount] = useState<number | ''>('');
  const [selectedUnit, setSelectedUnit] = useState<UnitType>(UnitType.GRAMS);

  const suggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (suggestionsRef.current && !suggestionsRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Combined Suggestions: Ingredients + Intermediate Products
  // SORTED A-Z
  const combinedSuggestions = useMemo(() => {
     const rawIngs = ingredients.map(i => ({
         id: i.id,
         name: i.name,
         type: 'INGREDIENT' as const,
         unit: i.unit,
         cost: i.costPerUnit,
         isIntermediate: false
     }));

     // Only show products that ARE intermediate (Sub-recipes)
     // Prevent circular dependency (simplistic check: don't show self if editing)
     const subProds = products
        .filter(p => p.isIntermediate && p.id !== editingProduct?.id)
        .map(p => ({
            id: p.id,
            name: p.name,
            type: 'PRODUCT' as const,
            unit: UnitType.UNITS, // Default for sub-recipes usually
            cost: 0, // Calculated dynamically later
            isIntermediate: true
        }));

     return [...rawIngs, ...subProds]
        .filter(item => item.name.toLowerCase().includes(searchQuery.toLowerCase()))
        .sort((a, b) => a.name.localeCompare(b.name));
  }, [ingredients, products, searchQuery, editingProduct]);

  const handleSelectItem = (item: typeof combinedSuggestions[0]) => {
    setSelectedItemId(item.id);
    setSelectedItemType(item.type);
    setSearchQuery(item.name);
    setSelectedUnit(item.unit);
    setShowSuggestions(false);
  };

  const handleAddItem = () => {
    if(!selectedItemId) {
        alert("Por favor selecciona un ingrediente o base.");
        return;
    }
    if(!amount || Number(amount) <= 0) {
        alert("Ingresa una cantidad válida.");
        return;
    }

    setRecipeItems([...recipeItems, {
      ingredientId: selectedItemId, // This stores either Ing ID or Prod ID
      type: selectedItemType,
      quantity: Number(amount),
      unit: selectedUnit
    }]);

    // Reset inputs
    setAmount('');
    setSelectedItemId('');
    setSelectedItemType('INGREDIENT');
    setSearchQuery('');
  };

  const handleUpdateItemQuantity = (index: number, newQty: string) => {
    const val = newQty === '' ? 0 : parseFloat(newQty);
    const updatedItems = [...recipeItems];
    updatedItems[index].quantity = val;
    setRecipeItems(updatedItems);
  };

  const handleDeleteItem = (index: number) => {
    const updatedItems = recipeItems.filter((_, i) => i !== index);
    setRecipeItems(updatedItems);
  };

  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setProductName(product.name);
    setProductPrice(product.price);
    setIsIntermediate(!!product.isIntermediate);

    // Normalize recipe items (handle legacy data missing 'type')
    const normalizedItems = product.recipe.map(item => ({
        ...item,
        type: item.type || 'INGREDIENT' // Default for old data
    }));
    setRecipeItems(normalizedItems.map(item => ({...item}))); 

    setFixedCosts('');
    setEstimatedUnits('');

    setIsCreating(true);
  };

  const handleSaveProduct = async () => {
    // Validation
    if(!productName.trim()) {
        alert("El nombre del producto es obligatorio.");
        return;
    }
    if(recipeItems.length === 0) {
        alert("Debes agregar al menos un ingrediente a la receta.");
        return;
    }

    // If it's NOT intermediate, it needs a price. 
    // If it IS intermediate, price is optional (usually 0/internal).
    if(!isIntermediate && (productPrice === '' || Number(productPrice) < 0)) {
        alert("El precio de venta no es válido.");
        return;
    }

    try {
        const validItems = recipeItems.filter(item => item.quantity > 0);
        const finalPrice = productPrice === '' ? 0 : Number(productPrice);

        const prodData: Product = {
            id: editingProduct ? editingProduct.id : Date.now().toString(),
            name: productName,
            price: finalPrice,
            recipe: validItems,
            isIntermediate: isIntermediate
        };

        if (editingProduct) {
            await updateProduct(prodData);
        } else {
            await addProduct(prodData);
        }

        closeForm();
    } catch (error) {
        console.error("Error al guardar producto:", error);
        alert("Hubo un error al guardar el producto.");
    }
  };

  const closeForm = () => {
    setIsCreating(false);
    setEditingProduct(null);
    resetForm();
  };

  const resetForm = () => {
    setProductName('');
    setProductPrice('');
    setRecipeItems([]);
    setFixedCosts('');
    setEstimatedUnits('');
    setEditingProduct(null);
    setSearchQuery('');
    setSelectedItemId('');
    setAmount('');
    setIsIntermediate(false);
  };

  // --- RECURSIVE COST CALCULATOR ---
  const getProductCost = (prodId: string): number => {
      const prod = products.find(p => p.id === prodId);
      if(!prod) return 0;
      return calculateVariableCost(prod.recipe);
  };

  const calculateVariableCost = (items: RecipeItem[]) => {
    return items.reduce((acc, item) => {
      const type = item.type || 'INGREDIENT';

      if (type === 'INGREDIENT') {
          const ing = ingredients.find(i => i.id === item.ingredientId);
          if(!ing) return acc;

          if (item.unit === ing.unit) {
              return acc + (item.quantity * ing.costPerUnit);
          }
          let itemBase = 0;
          switch(item.unit) {
              case UnitType.KILOGRAMS: itemBase = item.quantity * 1000; break;
              case UnitType.LITERS: itemBase = item.quantity * 1000; break;
              default: itemBase = item.quantity;
          }
          const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);
          return acc + (itemQtyInIngUnit * ing.costPerUnit);

      } else {
          // It's a SUB-PRODUCT (Intermediate)
          // Assumption: Cost is calculated per 1 Unit of that recipe (Batch)
          // Ideally we need yield, but for now we assume 1 Unit = 1 Batch Cost.
          const subCost = getProductCost(item.ingredientId);

          // If unit is UNITS, it's a direct multiplier. 
          // If unit is Weight, we are in trouble without yield. We fallback to direct multiplier logic.
          // Usually sub-recipes are added as "0.5 Units" (half batch).

          let multiplier = item.quantity;
          // Very simple fallback if they try to measure a recipe in grams (assuming 1 unit = 1 kg for lack of better data)
          // Ideally: Prevent non-unit measures for sub-products in UI, or assume 1 Unit.

          return acc + (subCost * multiplier);
      }
    }, 0);
  };

  const cvu = calculateVariableCost(recipeItems);

  // Suggested Price Formula
  const calculateSuggestedPrice = () => {
      const cft = Number(fixedCosts) || 0;
      const q = Number(estimatedUnits) || 1; 
      const fixedCostPerUnit = cft / q;
      const totalUnitCost = cvu + fixedCostPerUnit;
      const price = totalUnitCost / (1 - 0.60);
      return Math.round(price);
  };

  const suggestedPrice = calculateSuggestedPrice();

  const toggleCreate = () => {
    if(isCreating) {
        closeForm();
    } else {
        resetForm();
        setIsCreating(true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Recetas y Productos</h2>
        <button 
          onClick={toggleCreate}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          {isCreating ? 'Cancelar' : <><Plus size={18} /> Nuevo Producto</>}
        </button>
      </div>

      <button 
        onClick={toggleCreate}
        className={`md:hidden fixed bottom-20 right-4 p-4 rounded-full shadow-lg z-40 transition-colors ${isCreating ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white`}
      >
        {isCreating ? <X size={24} /> : <Plus size={24} />}
      </button>

      {isCreating && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-lg space-y-6 animate-in fade-in slide-in-from-top-4">
          <div className="flex justify-between items-start border-b pb-2">
            <h3 className="font-bold text-lg text-slate-800">
                {editingProduct ? 'Editar Receta' : 'Crear Nueva Receta'}
            </h3>
            {/* Intermediate Switch */}
            <div className="flex items-center gap-2 bg-amber-50 px-3 py-1.5 rounded-full border border-amber-100">
               <input 
                 type="checkbox" 
                 id="isIntermediate"
                 checked={isIntermediate}
                 onChange={e => setIsIntermediate(e.target.checked)}
                 className="w-4 h-4 text-amber-600 rounded focus:ring-amber-500"
               />
               <label htmlFor="isIntermediate" className="text-xs font-bold text-amber-800 cursor-pointer select-none">
                 Es Preparado Base / Intermedio
               </label>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1">Nombre {isIntermediate ? 'del Preparado' : 'del Producto'}</label>
                  <input 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={productName} 
                    onChange={e => setProductName(e.target.value)} 
                    placeholder={isIntermediate ? "Ej: Masa Madre, Relleno de Limón" : "Ej: Tarta de Frutilla"}
                  />
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                    <h4 className="font-medium text-slate-700 mb-3 text-sm uppercase tracking-wide">Fórmula (Ingredientes y Bases)</h4>

                    <div className="flex flex-col gap-2 mb-4 bg-white p-3 rounded border border-slate-200 shadow-sm relative" ref={suggestionsRef}>
                      <label className="text-xs font-bold text-slate-500">Agregar Ítem</label>
                      <div className="grid grid-cols-12 gap-2 items-end">

                          {/* Autocomplete Input */}
                          <div className="col-span-12 sm:col-span-5 relative">
                             <div className="flex items-center border rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500">
                                <Search size={16} className="ml-2 text-slate-400" />
                                <input 
                                    className="w-full p-2 text-sm outline-none"
                                    placeholder="Buscar ingrediente o base..."
                                    value={searchQuery}
                                    onChange={e => {
                                        setSearchQuery(e.target.value);
                                        setSelectedItemId(''); 
                                        setShowSuggestions(true);
                                    }}
                                    onFocus={() => setShowSuggestions(true)}
                                />
                             </div>

                             {/* Combined Suggestions Dropdown */}
                             {showSuggestions && combinedSuggestions.length > 0 && (
                                 <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 max-h-48 overflow-y-auto">
                                    {combinedSuggestions.map(item => (
                                        <button
                                            key={item.id}
                                            onClick={() => handleSelectItem(item)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span className="flex items-center gap-2">
                                                {item.isIntermediate && <Layers size={12} className="text-amber-500" />}
                                                {item.name}
                                            </span>
                                            <span className="text-xs text-slate-400">
                                                {item.isIntermediate ? 'Receta' : `${formatCurrency(item.cost)}/${item.unit}`}
                                            </span>
                                        </button>
                                    ))}
                                 </div>
                             )}
                          </div>

                          <div className="col-span-4 sm:col-span-3">
                              <input 
                                type="number" 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500" 
                                placeholder="Cant."
                                value={amount}
                                onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))}
                                onKeyDown={(e) => { if(e.key === 'Enter') handleAddItem() }}
                              />
                          </div>

                          <div className="col-span-6 sm:col-span-3">
                              <select 
                                className="w-full p-2 border rounded text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={selectedUnit}
                                onChange={e => setSelectedUnit(e.target.value as UnitType)}
                              >
                                {UNIT_OPTIONS.map(u => (
                                  <option key={u.value} value={u.value}>{u.label}</option>
                                ))}
                              </select>
                          </div>

                          <div className="col-span-2 sm:col-span-1">
                              <button 
                                onClick={handleAddItem}
                                className={`w-full text-white p-2 rounded flex items-center justify-center transition-colors h-[38px] ${selectedItemId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-300 cursor-not-allowed'}`}
                                disabled={!selectedItemId}
                              >
                                <Plus size={18} />
                              </button>
                          </div>
                      </div>
                    </div>

                    {recipeItems.length > 0 ? (
                       <div className="space-y-2 mb-2">
                         <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 px-2">
                            <div className="col-span-5">Ítem</div>
                            <div className="col-span-5 text-right">Cantidad</div>
                            <div className="col-span-2 text-center"></div>
                         </div>
                         {recipeItems.map((item, idx) => {
                           let name = 'Desconocido';
                           let isSub = false;

                           if (item.type === 'PRODUCT') {
                               name = products.find(p => p.id === item.ingredientId)?.name || 'Base eliminada';
                               isSub = true;
                           } else {
                               name = ingredients.find(i => i.id === item.ingredientId)?.name || 'Ingrediente eliminado';
                           }

                           return (
                             <div key={idx} className={`grid grid-cols-12 gap-2 items-center p-2 border rounded shadow-sm text-sm ${isSub ? 'bg-amber-50 border-amber-100' : 'bg-white border-slate-200'}`}>
                               <div className="col-span-5 truncate font-medium text-slate-700 flex items-center gap-1" title={name}>
                                 {isSub && <Layers size={12} className="text-amber-500 flex-shrink-0" />}
                                 {name}
                                </div>
                               <div className="col-span-5 flex justify-end items-center gap-1">
                                 <input 
                                    type="number"
                                    min="0"
                                    step="any"
                                    className="w-20 p-1 border border-slate-200 rounded text-right focus:border-indigo-500 outline-none bg-white"
                                    value={item.quantity === 0 ? '' : item.quantity}
                                    onChange={(e) => handleUpdateItemQuantity(idx, e.target.value)}
                                 />
                                 <span className="text-xs text-slate-500 w-8">{item.unit}</span>
                               </div>
                               <div className="col-span-2 text-center">
                                 <button 
                                    onClick={() => handleDeleteItem(idx)} 
                                    className="text-red-400 hover:text-red-600 p-1 rounded-full hover:bg-red-50"
                                 >
                                    <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                           )
                         })}
                         <div className="flex justify-between items-center pt-3 border-t border-slate-200 mt-3">
                            <span className="text-slate-500 font-medium text-sm">Costo Variable Total (CVU):</span>
                            <span className="text-slate-800 font-bold text-lg">{formatCurrency(cvu)}</span>
                         </div>
                       </div>
                    ) : (
                        <p className="text-xs text-slate-400 italic text-center py-4">Agrega ingredientes o bases para calcular el costo.</p>
                    )}
                </div>
            </div>

            <div className="space-y-4">
               {/* Pricing Calculator - Hide/Dim if Intermediate */}
               <div className={`bg-indigo-50 p-5 rounded-xl border border-indigo-100 ${isIntermediate ? 'opacity-60 grayscale' : ''}`}>
                  <div className="flex items-center gap-2 mb-4 text-indigo-800">
                     <Calculator size={20} />
                     <h4 className="font-bold">Calculadora {isIntermediate ? '(No requerida)' : 'de Precios'}</h4>
                  </div>

                  {!isIntermediate && (
                    <div className="space-y-3 mb-4">
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                            <label className="text-xs font-semibold text-slate-500 block mb-1">Costos Fijos Asignados (CFT)</label>
                            <input 
                                type="number" 
                                className="w-full p-2 border border-indigo-200 rounded text-sm"
                                placeholder="0"
                                value={fixedCosts}
                                onChange={e => setFixedCosts(e.target.value === '' ? '' : Number(e.target.value))}
                            />
                            </div>
                            <div>
                            <label className="text-xs font-semibold text-slate-500 block mb-1">Ventas Estimadas (Q)</label>
                            <input 
                                type="number" 
                                className="w-full p-2 border border-indigo-200 rounded text-sm"
                                placeholder="Unidades/mes"
                                value={estimatedUnits}
                                onChange={e => setEstimatedUnits(e.target.value === '' ? '' : Number(e.target.value))}
                            />
                            </div>
                        </div>

                        <div className="bg-white p-3 rounded-lg border border-indigo-100 space-y-1">
                            <div className="flex justify-between text-xs text-slate-500">
                                <span>Costo Variable (CVU):</span>
                                <span>{formatCurrency(cvu)}</span>
                            </div>
                            <div className="flex justify-between text-xs text-slate-800 font-semibold pt-1 border-t border-slate-100">
                                <span>Costo Total Unitario:</span>
                                <span>{formatCurrency(cvu + ((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0))}</span>
                            </div>
                        </div>

                        <div className="flex justify-between items-center bg-indigo-100 p-3 rounded-lg">
                            <div>
                                <span className="text-xs text-indigo-600 font-bold uppercase block">Precio Sugerido</span>
                                <span className="text-[10px] text-indigo-400">Margen 60%</span>
                            </div>
                            <div className="text-xl font-bold text-indigo-800">
                                {formatCurrency(suggestedPrice)}
                            </div>
                        </div>

                        <button 
                            onClick={() => setProductPrice(suggestedPrice)}
                            disabled={!isFinite(suggestedPrice) || suggestedPrice <= 0}
                            className="w-full py-1.5 text-xs bg-indigo-200 text-indigo-800 rounded font-semibold hover:bg-indigo-300 transition-colors disabled:opacity-50"
                        >
                            Usar Precio Sugerido
                        </button>
                    </div>
                  )}

                  <div>
                    <label className="label text-sm font-bold text-slate-700 mb-1 block">
                        {isIntermediate ? 'Costo/Valor Interno (Opcional)' : 'Precio de Venta Final'}
                    </label>
                    <div className="relative">
                        <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input 
                            type="number" 
                            className="w-full pl-9 p-3 border border-slate-300 rounded-lg text-lg font-bold text-slate-800" 
                            value={productPrice} 
                            onChange={e => setProductPrice(e.target.value === '' ? '' : Number(e.target.value))} 
                            placeholder={isIntermediate ? "0" : "0"}
                        />
                    </div>
                  </div>
               </div>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
             <button 
                type="button"
                onClick={handleSaveProduct}
                className="bg-green-600 text-white py-3 px-8 rounded-lg font-bold hover:bg-green-700 shadow-md flex items-center gap-2"
             >
                {editingProduct ? 'Actualizar' : 'Guardar'} {isIntermediate ? 'Base' : 'Producto'} <Save size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Product List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {products.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            ingredients={ingredients} 
            products={products}
            onEdit={handleEditClick}
          />
        ))}
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ 
    product: Product, 
    ingredients: Ingredient[], 
    products: Product[],
    onEdit: (p: Product) => void 
}> = ({ product, ingredients, products, onEdit }) => {
    const [expanded, setExpanded] = useState(false);
    const { deleteProduct } = useBakery();

    const handleDelete = (e: React.MouseEvent) => {
        e.stopPropagation();
        if(window.confirm(`¿Estás seguro que deseas eliminar "${product.name}"?`)) {
            deleteProduct(product.id);
        }
    };

    return (
        <div className={`rounded-xl shadow-sm border overflow-hidden hover:shadow-md transition-shadow ${product.isIntermediate ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-200'}`}>
            <div className="p-4 flex justify-between items-center hover:bg-opacity-80">
                <div 
                    className="flex-1 cursor-pointer"
                    onClick={() => setExpanded(!expanded)}
                >
                    <div className="flex items-center gap-2">
                        {product.isIntermediate && <Layers size={18} className="text-amber-600" />}
                        <h3 className="font-bold text-slate-800 text-lg">{product.name}</h3>
                    </div>
                    <p className="text-slate-500 text-sm flex items-center gap-2">
                        {product.isIntermediate ? 'Receta Base / Preparado' : `${product.recipe.length} componentes`}
                    </p>
                </div>
                <div className="flex items-center gap-3 pl-4">
                    {!product.isIntermediate && (
                        <span className="font-bold text-emerald-600 text-lg bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100 whitespace-nowrap">
                            {formatCurrency(product.price)}
                        </span>
                    )}
                    <button 
                        onClick={(e) => { e.stopPropagation(); onEdit(product); }}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={handleDelete}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                    >
                        <Trash2 size={18} />
                    </button>
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="p-1 text-slate-400"
                    >
                        {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </button>
                </div>
            </div>
            {expanded && (
                <div className="p-4 border-t border-slate-100 animate-in fade-in slide-in-from-top-1 bg-white/50">
                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Fórmula</h4>
                    <ul className="space-y-2 text-sm">
                        {product.recipe.map((r, i) => {
                            const isSub = r.type === 'PRODUCT';
                            let name = 'Desconocido';

                            if (isSub) {
                                name = products.find(p => p.id === r.ingredientId)?.name || 'Base eliminada';
                            } else {
                                name = ingredients.find(ing => ing.id === r.ingredientId)?.name || 'Ingrediente desconocido';
                            }

                            return (
                                <li key={i} className="flex justify-between items-center text-slate-700 p-2 bg-white rounded border border-slate-100">
                                    <span className="font-medium flex items-center gap-2">
                                        {isSub && <Layers size={12} className="text-amber-500" />}
                                        {name}
                                    </span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-600">{r.quantity} {r.unit}</div>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
}

// Enums for Units to ensure consistency
export enum UnitType {
  GRAMS = 'g',
  KILOGRAMS = 'kg',
  MILLILITERS = 'ml',
  LITERS = 'L',
  UNITS = 'u'
}

// Entity: Ingrediente (Raw Material)
export interface Ingredient {
  id: string;
  name: string;
  currentStock: number; // Stored in base units (g, ml, u)
  unit: UnitType; // Preferred display unit, though storage is normalized
  costPerUnit: number;
  minStock: number; // Reorder point
}

// Entity: Receta (Recipe Line Item)
export interface RecipeItem {
  ingredientId: string; // Can be IngredientID OR ProductID (if sub-recipe)
  type?: 'INGREDIENT' | 'PRODUCT'; // Discriminator. Defaults to INGREDIENT for legacy data.
  quantity: number; // Amount needed for 1 unit of product
  unit: UnitType;
}

// Entity: Producto (Final Product)
export interface Product {
  id: string;
  name: string;
  price: number;
  description?: string;
  recipe: RecipeItem[];
  isIntermediate?: boolean; // NEW: If true, it's a base/pre-mix (e.g. Pie Crust) not for direct sale usually
  observations?: string; // NEW: Notes or specific instructions
}

// Entity: Cliente
export interface Customer {
  id: string;
  name: string;
  phone?: string;
  email?: string;
  address?: string;
  notes?: string;
}

// Entity: Pedido (Order)
export interface OrderItem {
  productId: string;
  quantity: number;
}

export type OrderStatus = 'Pendiente' | 'En Proceso' | 'Completado' | 'Entregado' | 'Pagado';

export interface Order {
  id: string;
  customerId: string; // Link to Customer ID if available
  customerName: string; // Fallback or snapshot name
  deliveryDate: string; // ISO Date string YYYY-MM-DD
  status: OrderStatus;
  items: OrderItem[];
  totalPrice: number;
  accountingClosed?: boolean; // If true, this order has been included in a month close
}

export interface MonthClosure {
  id: string;
  date: string; // ISO Timestamp of closure
  totalRevenue: number;
  totalOrders: number;
  periodLabel: string; // e.g., "Octubre 2023 - Corte 1"
}

// Helper type for Production Planning
export interface ProductionRequirement {
  ingredientName: string;
  ingredientId: string;
  totalNeeded: number;
  currentStock: number;
  unit: UnitType;
  missing: number; // If totalNeeded > currentStock
}

// Chat Message for AI Chef
export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

// Inventory Item for Display
export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  threshold: number;
  category: string;
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Product, RecipeItem, UnitType, Ingredient } from '../types';
import { UNIT_OPTIONS } from '../constants';
import { Plus, Trash2, ChevronDown, ChevronUp, Calculator, DollarSign, Edit2, Save, X, Search, Layers, StickyNote } from 'lucide-react';
import { fromBaseUnit, formatCurrency } from '../utils/conversions';

export const Recipes: React.FC = () => {
  const { products, ingredients, addProduct, updateProduct } = useBakery();
  const [isCreating, setIsCreating] = useState(false);

  // State to track if we are editing an existing product
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [productName, setProductName] = useState('');
  const [productObservations, setProductObservations] = useState('');
  const [productPrice, setProductPrice] = useState<number | ''>('');
  const [recipeItems, setRecipeItems] = useState<RecipeItem[]>([]);
  const [isIntermediate, setIsIntermediate] = useState(false);

  // Costing Calculator State
  const [fixedCosts, setFixedCosts] = useState<number | ''>('');
  const [estimatedUnits, setEstimatedUnits] = useState<number | ''>('');

  // Ingredient Search & Add State
  // Search Logic now includes BOTH Ingredients AND Intermediate Products
  const [selectedItemId, setSelectedItemId] = useState('');
  const [selectedItemType, setSelectedItemType] = useState<'INGREDIENT' | 'PRODUCT'>('INGREDIENT');
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuggestions, setShowSuggestions] = useState(false);

  const [amount, setAmount] = useState<number | ''>('');
  const [selectedUnit, setSelectedUnit] = useState<UnitType>(UnitType.GRAMS);

  const suggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (suggestionsRef.current && !suggestionsRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Combined Suggestions: Ingredients + Intermediate Products
  // SORTED A-Z
  const combinedSuggestions = useMemo(() => {
     const rawIngs = ingredients.map(i => ({
         id: i.id,
         name: i.name,
         type: 'INGREDIENT' as const,
         unit: i.unit,
         cost: i.costPerUnit,
         isIntermediate: false
     }));

     // Only show products that ARE intermediate (Sub-recipes)
     // Prevent circular dependency (simplistic check: don't show self if editing)
     const subProds = products
        .filter(p => p.isIntermediate && p.id !== editingProduct?.id)
        .map(p => ({
            id: p.id,
            name: p.name,
            type: 'PRODUCT' as const,
            unit: UnitType.UNITS, // Default for sub-recipes usually
            cost: 0, // Calculated dynamically later
            isIntermediate: true
        }));

     return [...rawIngs, ...subProds]
        .filter(item => item.name.toLowerCase().includes(searchQuery.toLowerCase()))
        .sort((a, b) => a.name.localeCompare(b.name));
  }, [ingredients, products, searchQuery, editingProduct]);

  const handleSelectItem = (item: typeof combinedSuggestions[0]) => {
    setSelectedItemId(item.id);
    setSelectedItemType(item.type);
    setSearchQuery(item.name);
    setSelectedUnit(item.unit);
    setShowSuggestions(false);
  };

  const handleAddItem = () => {
    if(!selectedItemId) {
        alert("Por favor selecciona un ingrediente o base.");
        return;
    }
    if(!amount || Number(amount) <= 0) {
        alert("Ingresa una cantidad válida.");
        return;
    }

    setRecipeItems([...recipeItems, {
      ingredientId: selectedItemId, // This stores either Ing ID or Prod ID
      type: selectedItemType,
      quantity: Number(amount),
      unit: selectedUnit
    }]);

    // Reset inputs
    setAmount('');
    setSelectedItemId('');
    setSelectedItemType('INGREDIENT');
    setSearchQuery('');
  };

  const handleUpdateItemQuantity = (index: number, newQty: string) => {
    const val = newQty === '' ? 0 : parseFloat(newQty);
    const updatedItems = [...recipeItems];
    updatedItems[index].quantity = val;
    setRecipeItems(updatedItems);
  };

  const handleDeleteItem = (index: number) => {
    const updatedItems = recipeItems.filter((_, i) => i !== index);
    setRecipeItems(updatedItems);
  };

  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setProductName(product.name);
    setProductObservations(product.observations || '');
    setProductPrice(product.price);
    setIsIntermediate(!!product.isIntermediate);

    // Normalize recipe items (handle legacy data missing 'type')
    const normalizedItems = product.recipe.map(item => ({
        ...item,
        type: item.type || 'INGREDIENT' // Default for old data
    }));
    setRecipeItems(normalizedItems.map(item => ({...item}))); 

    setFixedCosts('');
    setEstimatedUnits('');

    setIsCreating(true);
  };

  const handleSaveProduct = async () => {
    // Validation
    if(!productName.trim()) {
        alert("El nombre del producto es obligatorio.");
        return;
    }
    if(recipeItems.length === 0) {
        alert("Debes agregar al menos un ingrediente a la receta.");
        return;
    }

    // If it's NOT intermediate, it needs a price. 
    // If it IS intermediate, price is optional (usually 0/internal).
    if(!isIntermediate && (productPrice === '' || Number(productPrice) < 0)) {
        alert("El precio de venta no es válido.");
        return;
    }

    try {
        const validItems = recipeItems.filter(item => item.quantity > 0);
        const finalPrice = productPrice === '' ? 0 : Number(productPrice);

        const prodData: Product = {
            id: editingProduct ? editingProduct.id : Date.now().toString(),
            name: productName,
            price: finalPrice,
            recipe: validItems,
            isIntermediate: isIntermediate,
            observations: productObservations
        };

        if (editingProduct) {
            await updateProduct(prodData);
        } else {
            await addProduct(prodData);
        }

        closeForm();
    } catch (error) {
        console.error("Error al guardar producto:", error);
        alert("Hubo un error al guardar el producto.");
    }
  };

  const closeForm = () => {
    setIsCreating(false);
    setEditingProduct(null);
    resetForm();
  };

  const resetForm = () => {
    setProductName('');
    setProductObservations('');
    setProductPrice('');
    setRecipeItems([]);
    setFixedCosts('');
    setEstimatedUnits('');
    setEditingProduct(null);
    setSearchQuery('');
    setSelectedItemId('');
    setAmount('');
    setIsIntermediate(false);
  };

  // --- RECURSIVE COST CALCULATOR ---
  const getProductCost = (prodId: string): number => {
      const prod = products.find(p => p.id === prodId);
      if(!prod) return 0;
      return calculateVariableCost(prod.recipe);
  };

  const calculateVariableCost = (items: RecipeItem[]) => {
    return items.reduce((acc, item) => {
      const type = item.type || 'INGREDIENT';

      if (type === 'INGREDIENT') {
          const ing = ingredients.find(i => i.id === item.ingredientId);
          if(!ing) return acc;

          if (item.unit === ing.unit) {
              return acc + (item.quantity * ing.costPerUnit);
          }
          let itemBase = 0;
          switch(item.unit) {
              case UnitType.KILOGRAMS: itemBase = item.quantity * 1000; break;
              case UnitType.LITERS: itemBase = item.quantity * 1000; break;
              default: itemBase = item.quantity;
          }
          const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);
          return acc + (itemQtyInIngUnit * ing.costPerUnit);

      } else {
          // It's a SUB-PRODUCT (Intermediate)
          // Assumption: Cost is calculated per 1 Unit of that recipe (Batch)
          // Ideally we need yield, but for now we assume 1 Unit = 1 Batch Cost.
          const subCost = getProductCost(item.ingredientId);

          // If unit is UNITS, it's a direct multiplier. 
          // If unit is Weight, we are in trouble without yield. We fallback to direct multiplier logic.
          // Usually sub-recipes are added as "0.5 Units" (half batch).

          let multiplier = item.quantity;
          // Very simple fallback if they try to measure a recipe in grams (assuming 1 unit = 1 kg for lack of better data)
          // Ideally: Prevent non-unit measures for sub-products in UI, or assume 1 Unit.

          return acc + (subCost * multiplier);
      }
    }, 0);
  };

  const cvu = calculateVariableCost(recipeItems);

  // Suggested Price Formula
  const calculateSuggestedPrice = () => {
      const cft = Number(fixedCosts) || 0;
      const q = Number(estimatedUnits) || 1; 
      const fixedCostPerUnit = cft / q;
      const totalUnitCost = cvu + fixedCostPerUnit;
      const price = totalUnitCost / (1 - 0.60);
      return Math.round(price);
  };

  const suggestedPrice = calculateSuggestedPrice();

  const toggleCreate = () => {
    if(isCreating) {
        closeForm();
    } else {
        resetForm();
        setIsCreating(true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Recetas y Productos</h2>
        <button 
          onClick={toggleCreate}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          {isCreating ? 'Cancelar' : <><Plus size={18} /> Nuevo Producto</>}
        </button>
      </div>

      <button 
        onClick={toggleCreate}
        className={`md:hidden fixed bottom-20 right-4 p-4 rounded-full shadow-lg z-40 transition-colors ${isCreating ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white`}
      >
        {isCreating ? <X size={24} /> : <Plus size={24} />}
      </button>

      {isCreating && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-lg space-y-6 animate-in fade-in slide-in-from-top-4">
          <div className="flex justify-between items-start border-b pb-2">
            <h3 className="font-bold text-lg text-slate-800">
                {editingProduct ? 'Editar Receta' : 'Crear Nueva Receta'}
            </h3>
            {/* Intermediate Switch */}
            <div className="flex items-center gap-2 bg-amber-50 px-3 py-1.5 rounded-full border border-amber-100">
               <input 
                 type="checkbox" 
                 id="isIntermediate"
                 checked={isIntermediate}
                 onChange={e => setIsIntermediate(e.target.checked)}
                 className="w-4 h-4 text-amber-600 rounded focus:ring-amber-500"
               />
               <label htmlFor="isIntermediate" className="text-xs font-bold text-amber-800 cursor-pointer select-none">
                 Es Preparado Base / Intermedio
               </label>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1">Nombre {isIntermediate ? 'del Preparado' : 'del Producto'}</label>
                  <input 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={productName} 
                    onChange={e => setProductName(e.target.value)} 
                    placeholder={isIntermediate ? "Ej: Masa Madre, Relleno de Limón" : "Ej: Tarta de Frutilla"}
                  />
                </div>

                {/* Observation Field */}
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1 flex items-center gap-1">
                     <StickyNote size={14} className="text-slate-400" /> Observaciones (Opcional)
                  </label>
                  <textarea 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm" 
                    value={productObservations} 
                    onChange={e => setProductObservations(e.target.value)} 
                    placeholder="Ej: Instrucciones especiales de preparación, tiempo de horno, etc."
                    rows={2}
                  />
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                    <h4 className="font-medium text-slate-700 mb-3 text-sm uppercase tracking-wide">Fórmula (Ingredientes y Bases)</h4>

                    <div className="flex flex-col gap-2 mb-4 bg-white p-3 rounded border border-slate-200 shadow-sm relative" ref={suggestionsRef}>
                      <label className="text-xs font-bold text-slate-500">Agregar Ítem</label>
                      <div className="grid grid-cols-12 gap-2 items-end">

                          {/* Autocomplete Input */}
                          <div className="col-span-12 sm:col-span-5 relative">
                             <div className="flex items-center border rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500">
                                <Search size={16} className="ml-2 text-slate-400" />
                                <input 
                                    className="w-full p-2 text-sm outline-none"
                                    placeholder="Buscar ingrediente o base..."
                                    value={searchQuery}
                                    onChange={e => {
                                        setSearchQuery(e.target.value);
                                        setSelectedItemId(''); 
                                        setShowSuggestions(true);
                                    }}
                                    onFocus={() => setShowSuggestions(true)}
                                />
                             </div>

                             {/* Combined Suggestions Dropdown */}
                             {showSuggestions && combinedSuggestions.length > 0 && (
                                 <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 max-h-48 overflow-y-auto">
                                    {combinedSuggestions.map(item => (
                                        <button
                                            key={item.id}
                                            onClick={() => handleSelectItem(item)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span className="flex items-center gap-2">
                                                {item.isIntermediate && <Layers size={12} className="text-amber-500" />}
                                                {item.name}
                                            </span>
                                            <span className="text-xs text-slate-400">
                                                {item.isIntermediate ? 'Receta' : `${formatCurrency(item.cost)}/${item.unit}`}
                                            </span>
                                        </button>
                                    ))}
                                 </div>
                             )}
                          </div>

                          <div className="col-span-4 sm:col-span-3">
                              <input 
                                type="number" 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500" 
                                placeholder="Cant."
                                value={amount}
                                onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))}
                                onKeyDown={(e) => { if(e.key === 'Enter') handleAddItem() }}
                              />
                          </div>

                          <div className="col-span-6 sm:col-span-3">
                              <select 
                                className="w-full p-2 border rounded text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={selectedUnit}
                                onChange={e => setSelectedUnit(e.target.value as UnitType)}
                              >
                                {UNIT_OPTIONS.map(u => (
                                  <option key={u.value} value={u.value}>{u.label}</option>
                                ))}
                              </select>
                          </div>

                          <div className="col-span-2 sm:col-span-1">
                              <button 
                                onClick={handleAddItem}
                                className={`w-full text-white p-2 rounded flex items-center justify-center transition-colors h-[38px] ${selectedItemId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-300 cursor-not-allowed'}`}
                                disabled={!selectedItemId}
                              >
                                <Plus size={18} />
                              </button>
                          </div>
                      </div>
                    </div>

                    {recipeItems.length > 0 ? (
                       <div className="space-y-2 mb-2">
                         <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 px-2">
                            <div className="col-span-5">Ítem</div>
                            <div className="col-span-5 text-right">Cantidad</div>
                            <div className="col-span-2 text-center"></div>
                         </div>
                         {recipeItems.map((item, idx) => {
                           let name = 'Desconocido';
                           let isSub = false;

                           if (item.type === 'PRODUCT') {
                               name = products.find(p => p.id === item.ingredientId)?.name || 'Base eliminada';
                               isSub = true;
                           } else {
                               name = ingredients.find(i => i.id === item.ingredientId)?.name || 'Ingrediente eliminado';
                           }

                           return (
                             <div key={idx} className={`grid grid-cols-12 gap-2 items-center p-2 border rounded shadow-sm text-sm ${isSub ? 'bg-amber-50 border-amber-100' : 'bg-white border-slate-200'}`}>
                               <div className="col-span-5 truncate font-medium text-slate-700 flex items-center gap-1" title={name}>
                                 {isSub && <Layers size={12} className="text-amber-500 flex-shrink-0" />}
                                 {name}
                                </div>
                               <div className="col-span-5 flex justify-end items-center gap-1">
                                 <input 
                                    type="number"
                                    min="0"
                                    step="any"
                                    className="w-20 p-1 border border-slate-200 rounded text-right focus:border-indigo-500 outline-none bg-white"
                                    value={item.quantity === 0 ? '' : item.quantity}
                                    onChange={(e) => handleUpdateItemQuantity(idx, e.target.value)}
                                 />
                                 <span className="text-xs text-slate-500 w-8">{item.unit}</span>
                               </div>
                               <div className="col-span-2 text-center">
                                 <button 
                                    onClick={() => handleDeleteItem(idx)} 
                                    className="text-red-400 hover:text-red-600 p-1 rounded-full hover:bg-red-50"
                                 >
                                    <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                           )
                         })}
                         <div className="flex justify-between items-center pt-3 border-t border-slate-200 mt-3">
                            <span className="text-slate-500 font-medium text-sm">Costo Variable Total (CVU):</span>
                            <span className="text-slate-800 font-bold text-lg">{formatCurrency(cvu)}</span>
                         </div>
                       </div>
                    ) : (
                        <p className="text-xs text-slate-400 italic text-center py-4">Agrega ingredientes o bases para calcular el costo.</p>
                    )}
                </div>
            </div>

            <div className="space-y-4">
               {/* Pricing Calculator - Hide/Dim if Intermediate */}
               <div className={`bg-indigo-50 p-5 rounded-xl border border-indigo-100 ${isIntermediate ? 'opacity-60 grayscale' : ''}`}>
                  <div className="flex items-center gap-2 mb-4 text-indigo-800">
                     <Calculator size={20} />
                     <h4 className="font-bold">Calculadora {isIntermediate ? '(No requerida)' : 'de Precios'}</h4>
                  </div>

                  {!isIntermediate && (
                    <div className="space-y-3 mb-4">
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                            <label className="text-xs font-semibold text-slate-500 block mb-1">Costos Fijos Asignados (CFT)</label>
                            <input 
                                type="number" 
                                className="w-full p-2 border border-indigo-200 rounded text-sm"
                                placeholder="0"
                                value={fixedCosts}
                                onChange={e => setFixedCosts(e.target.value === '' ? '' : Number(e.target.value))}
                            />
                            </div>
                            <div>
                            <label className="text-xs font-semibold text-slate-500 block mb-1">Ventas Estimadas (Q)</label>
                            <input 
                                type="number" 
                                className="w-full p-2 border border-indigo-200 rounded text-sm"
                                placeholder="Unidades/mes"
                                value={estimatedUnits}
                                onChange={e => setEstimatedUnits(e.target.value === '' ? '' : Number(e.target.value))}
                            />
                            </div>
                        </div>

                        <div className="bg-white p-3 rounded-lg border border-indigo-100 space-y-1">
                            <div className="flex justify-between text-xs text-slate-500">
                                <span>Costo Variable (CVU):</span>
                                <span>{formatCurrency(cvu)}</span>
                            </div>
                            <div className="flex justify-between text-xs text-slate-800 font-semibold pt-1 border-t border-slate-100">
                                <span>Costo Total Unitario:</span>
                                <span>{formatCurrency(cvu + ((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0))}</span>
                            </div>
                        </div>

                        <div className="flex justify-between items-center bg-indigo-100 p-3 rounded-lg">
                            <div>
                                <span className="text-xs text-indigo-600 font-bold uppercase block">Precio Sugerido</span>
                                <span className="text-[10px] text-indigo-400">Margen 60%</span>
                            </div>
                            <div className="text-xl font-bold text-indigo-800">
                                {formatCurrency(suggestedPrice)}
                            </div>
                        </div>

                        <button 
                            onClick={() => setProductPrice(suggestedPrice)}
                            disabled={!isFinite(suggestedPrice) || suggestedPrice <= 0}
                            className="w-full py-1.5 text-xs bg-indigo-200 text-indigo-800 rounded font-semibold hover:bg-indigo-300 transition-colors disabled:opacity-50"
                        >
                            Usar Precio Sugerido
                        </button>
                    </div>
                  )}

                  <div>
                    <label className="label text-sm font-bold text-slate-700 mb-1 block">
                        {isIntermediate ? 'Costo/Valor Interno (Opcional)' : 'Precio de Venta Final'}
                    </label>
                    <div className="relative">
                        <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input 
                            type="number" 
                            className="w-full pl-9 p-3 border border-slate-300 rounded-lg text-lg font-bold text-slate-800" 
                            value={productPrice} 
                            onChange={e => setProductPrice(e.target.value === '' ? '' : Number(e.target.value))} 
                            placeholder={isIntermediate ? "0" : "0"}
                        />
                    </div>
                  </div>
               </div>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
             <button 
                type="button"
                onClick={handleSaveProduct}
                className="bg-green-600 text-white py-3 px-8 rounded-lg font-bold hover:bg-green-700 shadow-md flex items-center gap-2"
             >
                {editingProduct ? 'Actualizar' : 'Guardar'} {isIntermediate ? 'Base' : 'Producto'} <Save size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Product List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {products.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            ingredients={ingredients} 
            products={products}
            onEdit={handleEditClick}
          />
        ))}
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ 
    product: Product, 
    ingredients: Ingredient[], 
    products: Product[],
    onEdit: (p: Product) => void 
}> = ({ product, ingredients, products, onEdit }) => {
    const [expanded, setExpanded] = useState(false);
    const { deleteProduct } = useBakery();

    const handleDelete = (e: React.MouseEvent) => {
        e.stopPropagation();
        if(window.confirm(`¿Estás seguro que deseas eliminar "${product.name}"?`)) {
            deleteProduct(product.id);
        }
    };

    return (
        <div className={`rounded-xl shadow-sm border overflow-hidden hover:shadow-md transition-shadow ${product.isIntermediate ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-200'}`}>
            <div className="p-4 flex justify-between items-center hover:bg-opacity-80">
                <div 
                    className="flex-1 cursor-pointer"
                    onClick={() => setExpanded(!expanded)}
                >
                    <div className="flex items-center gap-2">
                        {product.isIntermediate && <Layers size={18} className="text-amber-600" />}
                        <h3 className="font-bold text-slate-800 text-lg">{product.name}</h3>
                    </div>
                    <p className="text-slate-500 text-sm flex items-center gap-2">
                        {product.isIntermediate ? 'Receta Base / Preparado' : `${product.recipe.length} componentes`}
                    </p>
                </div>
                <div className="flex items-center gap-3 pl-4">
                    {!product.isIntermediate && (
                        <span className="font-bold text-emerald-600 text-lg bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100 whitespace-nowrap">
                            {formatCurrency(product.price)}
                        </span>
                    )}
                    <button 
                        onClick={(e) => { e.stopPropagation(); onEdit(product); }}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={handleDelete}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                    >
                        <Trash2 size={18} />
                    </button>
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="p-1 text-slate-400"
                    >
                        {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </button>
                </div>
            </div>
            {expanded && (
                <div className="p-4 border-t border-slate-100 animate-in fade-in slide-in-from-top-1 bg-white/50">

                    {/* Observations Display */}
                    {product.observations && (
                        <div className="mb-4 bg-yellow-50 p-2 rounded text-xs text-yellow-800 border border-yellow-100 flex gap-2">
                            <StickyNote size={14} className="flex-shrink-0 mt-0.5" />
                            <p className="whitespace-pre-wrap">{product.observations}</p>
                        </div>
                    )}

                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Fórmula</h4>
                    <ul className="space-y-2 text-sm">
                        {product.recipe.map((r, i) => {
                            const isSub = r.type === 'PRODUCT';
                            let name = 'Desconocido';

                            if (isSub) {
                                name = products.find(p => p.id === r.ingredientId)?.name || 'Base eliminada';
                            } else {
                                name = ingredients.find(ing => ing.id === r.ingredientId)?.name || 'Ingrediente desconocido';
                            }

                            return (
                                <li key={i} className="flex justify-between items-center text-slate-700 p-2 bg-white rounded border border-slate-100">
                                    <span className="font-medium flex items-center gap-2">
                                        {isSub && <Layers size={12} className="text-amber-500" />}
                                        {name}
                                    </span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-600">{r.quantity} {r.unit}</div>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus, Customer, Product } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, PackageCheck, ChefHat, Truck, DollarSign, History, X, Edit2, Trash2, User, RotateCcw } from 'lucide-react';
import { formatCurrency, formatDate } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrder, updateOrderStatus, addCustomer, deleteOrder } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New/Edit Order Form State
  const [editingOrderId, setEditingOrderId] = useState<string | null>(null);

  // Customer Smart Search State
  const [customerSearchInput, setCustomerSearchInput] = useState('');
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | null>(null); // If null, means new customer
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);

  // Product Smart Search State
  const [productSearchInput, setProductSearchInput] = useState('');
  const [selectedProduct, setSelectedProduct] = useState(''); // Stores ID
  const [showProductSuggestions, setShowProductSuggestions] = useState(false);

  const [date, setDate] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  const customerSuggestionsRef = useRef<HTMLDivElement>(null);
  const productSuggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // Customer Dropdown
      if (customerSuggestionsRef.current && !customerSuggestionsRef.current.contains(event.target as Node)) {
        setShowCustomerSuggestions(false);
      }
      // Product Dropdown
      if (productSuggestionsRef.current && !productSuggestionsRef.current.contains(event.target as Node)) {
        setShowProductSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Filtered customers for autocomplete
  const customerSuggestions = useMemo(() => {
    if (!customerSearchInput) return [];
    return customers.filter(c => 
      c.name.toLowerCase().includes(customerSearchInput.toLowerCase())
    ).slice(0, 5); // Limit to 5
  }, [customers, customerSearchInput]);

  // Filtered products for autocomplete (Sorted Alphabetically)
  const productSuggestions = useMemo(() => {
    return products
      .filter(p => p.name.toLowerCase().includes(productSearchInput.toLowerCase()))
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [products, productSearchInput]);

  const handleSelectCustomer = (c: Customer) => {
    setCustomerSearchInput(c.name);
    setSelectedCustomerId(c.id);
    setShowCustomerSuggestions(false);
  };

  const handleCustomerInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setCustomerSearchInput(e.target.value);
    setSelectedCustomerId(null); // Reset ID implies potentially new customer
    setShowCustomerSuggestions(true);
  };

  const handleSelectProduct = (p: Product) => {
    setProductSearchInput(p.name);
    setSelectedProduct(p.id);
    setShowProductSuggestions(false);
  };

  // --- Constants ---
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado'];
  const HISTORY_STEPS: OrderStatus[] = ['Pagado'];
  const FULL_FLOW: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const currentIndex = FULL_FLOW.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < FULL_FLOW.length - 1) {
      updateOrderStatus(order.id, FULL_FLOW[currentIndex + 1]);
    }
  };

  const revertOrder = (order: Order) => {
    const currentIndex = FULL_FLOW.indexOf(order.status);
    if (currentIndex > 0) {
      updateOrderStatus(order.id, FULL_FLOW[currentIndex - 1]);
    }
  };

  const handleDeleteOrder = (order: Order) => {
    if (window.confirm(`¿Estás seguro de eliminar el pedido de ${order.customerName}? Esto devolverá los ingredientes al inventario.`)) {
        deleteOrder(order.id);
    }
  };

  const handleEditOrder = (order: Order) => {
    setEditingOrderId(order.id);

    // Setup Customer Field
    setCustomerSearchInput(order.customerName);
    setSelectedCustomerId(order.customerId || null); // Keep ID if valid

    setDate(order.deliveryDate);
    setCart(order.items.map(i => ({...i})));
    setError('');
    setIsModalOpen(true);
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    const existingIndex = cart.findIndex(i => i.productId === selectedProduct);
    if (existingIndex >= 0) {
        const newCart = [...cart];
        newCart[existingIndex].quantity += finalQty;
        setCart(newCart);
    } else {
        setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    }

    // Reset Product Selection
    setSelectedProduct('');
    setProductSearchInput('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrUpdateOrder = async () => {
    setError('');

    if (!customerSearchInput.trim()) { setError('Ingresa el nombre del cliente.'); return; }
    if(!date) { setError('Selecciona fecha de entrega.'); return; }
    if(cart.length === 0) { setError('Agrega al menos un producto.'); return; }

    let finalCustomerId = selectedCustomerId;
    let finalCustomerName = customerSearchInput.trim();

    // Logic: If no ID is selected, but name exists in text, create new customer
    if (!finalCustomerId) {
        // Double check if name matches an existing one exactly to avoid dupe
        const existingExact = customers.find(c => c.name.toLowerCase() === finalCustomerName.toLowerCase());
        if (existingExact) {
            finalCustomerId = existingExact.id;
        } else {
            // Create completely new customer
            try {
                finalCustomerId = await addCustomer({
                    id: '',
                    name: finalCustomerName
                });
            } catch (e) {
                setError('Error al crear nuevo cliente.');
                return;
            }
        }
    }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const orderData: Order = {
      id: editingOrderId || Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: editingOrderId ? (orders.find(o => o.id === editingOrderId)?.status || 'Pendiente') : 'Pendiente',
      items: cart,
      totalPrice: total
    };

    if (editingOrderId) {
        updateOrder(orderData);
    } else {
        addOrder(orderData);
    }
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    // Customer Reset
    setCustomerSearchInput('');
    setSelectedCustomerId(null);
    setShowCustomerSuggestions(false);
    // Product Reset
    setProductSearchInput('');
    setSelectedProduct('');
    setShowProductSuggestions(false);

    setDate('');
    setError('');
    setQty(1);
    setEditingOrderId(null);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': 
        return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendiente', next: 'En Proceso' };
      case 'En Proceso': 
        return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: ChefHat, label: 'En Proceso', next: 'Completado' };
      case 'Completado': 
        return { color: 'bg-indigo-100 text-indigo-800 border-indigo-200', icon: PackageCheck, label: 'Completado', next: 'Entregado' };
      case 'Entregado': 
        return { color: 'bg-blue-100 text-blue-800 border-blue-200', icon: Truck, label: 'Entregado', next: 'Pagado' };
      case 'Pagado': 
        return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: DollarSign, label: 'Pagado', next: '' };
      default: 
        return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Controla el flujo desde Pendiente hasta Pagado.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial (Pagados)
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Cerrados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          // Check if it's possible to revert (index > 0)
          const flowIndex = FULL_FLOW.indexOf(order.status);
          const canRevert = flowIndex > 0;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div className="flex-1 min-w-0">
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {formatDate(order.deliveryDate)}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>

                {/* Edit/Delete Controls */}
                <div className="flex gap-1 ml-2">
                    <button 
                        onClick={() => handleEditOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-indigo-600 rounded hover:bg-indigo-50 transition-colors"
                        title="Editar Pedido"
                    >
                        <Edit2 size={16} />
                    </button>
                    <button 
                        onClick={() => handleDeleteOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-red-600 rounded hover:bg-red-50 transition-colors"
                        title="Eliminar Pedido"
                    >
                        <Trash2 size={16} />
                    </button>
                </div>
              </div>

              {/* Status & Price Row */}
              <div className="flex justify-between items-center mb-3">
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block ${config.color}`}>
                     {order.status}
                  </span>
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <div className="flex gap-2">
                   {canRevert && (
                      <button 
                         onClick={() => revertOrder(order)}
                         className="p-2.5 rounded-lg border border-slate-200 text-slate-400 hover:bg-slate-100 hover:text-slate-600 transition-colors"
                         title="Volver al estado anterior"
                      >
                         <RotateCcw size={16} />
                      </button>
                   )}
                   <button 
                    onClick={() => advanceOrder(order)}
                    className="flex-1 py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                   >
                    {/* Dynamic Icon based on next step */}
                    {config.next === 'En Proceso' && <ChefHat size={16} />}
                    {config.next === 'Completado' && <PackageCheck size={16} />}
                    {config.next === 'Entregado' && <Truck size={16} />}
                    {config.next === 'Pagado' && <DollarSign size={16} />}

                    {config.next === 'Pagado' ? 'Confirmar Pago' : `Avanzar a ${config.next}`}

                    <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
                   </button>
                </div>
              ) : (
                <div className="text-center text-xs text-slate-400 italic flex items-center justify-center gap-1">
                  <CheckCircle2 size={14} /> Pedido cerrado y archivado
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* New/Edit Order Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto flex flex-col">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0 z-10">
              <h3 className="font-bold">{editingOrderId ? 'Editar Pedido' : 'Nuevo Pedido'}</h3>
              <button onClick={closeModal}><X size={20} /></button>
            </div>
            <div className="p-6 space-y-5 flex-1 overflow-y-auto">

               {/* Smart Customer Search */}
               <div className="relative" ref={customerSuggestionsRef}>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cliente</label>
                  <div className="flex items-center border border-slate-300 rounded-lg overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500 focus-within:border-indigo-500">
                    <div className="pl-3 text-slate-400"><User size={18} /></div>
                    <input 
                      className="w-full p-2.5 text-sm outline-none" 
                      value={customerSearchInput} 
                      onChange={handleCustomerInputChange} 
                      onFocus={() => setShowCustomerSuggestions(true)}
                      placeholder="Buscar o crear nuevo cliente..."
                      autoComplete="off"
                    />
                    {selectedCustomerId && (
                        <div className="pr-3 text-green-500"><CheckCircle2 size={18} /></div>
                    )}
                  </div>

                  {/* Autocomplete Dropdown */}
                  {showCustomerSuggestions && customerSuggestions.length > 0 && (
                    <div className="absolute z-20 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-lg max-h-48 overflow-y-auto">
                        <div className="text-[10px] uppercase text-slate-400 font-semibold px-3 py-1 bg-slate-50">Sugerencias</div>
                        {customerSuggestions.map(c => (
                            <button
                                key={c.id}
                                onClick={() => handleSelectCustomer(c)}
                                className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none"
                            >
                                {c.name}
                            </button>
                        ))}
                    </div>
                  )}
                  {showCustomerSuggestions && customerSearchInput && customerSuggestions.length === 0 && (
                     <div className="absolute z-20 w-full bg-white mt-1 border border-slate-200 rounded-lg shadow-lg p-3 text-xs text-slate-500">
                        <p>No se encontraron coincidencias. Se creará como <strong>nuevo cliente</strong>.</p>
                     </div>
                  )}
               </div>

               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Fecha de Entrega</label>
                  <input 
                    type="date" 
                    className="w-full p-2.5 border border-slate-300 rounded-lg text-sm" 
                    value={date} 
                    onChange={e => setDate(e.target.value)} 
                  />
                  <p className="text-[10px] text-slate-400 mt-1">Formato interno: dd/mm/yyyy (visualización automática por navegador)</p>
               </div>

               <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                 <h4 className="font-bold text-slate-700 text-xs mb-3 uppercase flex items-center gap-2">
                    <PackageCheck size={14}/> Productos
                 </h4>
                 <div className="flex flex-col gap-2 mb-3">
                    <div className="flex gap-2" ref={productSuggestionsRef}>

                        {/* Product Search Input (Autocomplete) */}
                        <div className="relative flex-1">
                          <div className="flex items-center border border-slate-300 rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500">
                            <Search size={16} className="ml-2 text-slate-400" />
                            <input 
                                className="w-full p-2 text-sm outline-none"
                                placeholder="Buscar producto..."
                                value={productSearchInput}
                                onChange={e => {
                                    setProductSearchInput(e.target.value);
                                    setSelectedProduct(''); // Clear selection on type
                                    setShowProductSuggestions(true);
                                }}
                                onFocus={() => setShowProductSuggestions(true)}
                            />
                          </div>

                          {/* Product Suggestions Dropdown */}
                          {showProductSuggestions && (
                            <div className="absolute z-30 w-full bg-white border border-slate-200 rounded-lg shadow-xl mt-1 max-h-48 overflow-y-auto left-0">
                                {productSuggestions.length > 0 ? (
                                    productSuggestions.map(p => (
                                        <button
                                            key={p.id}
                                            onClick={() => handleSelectProduct(p)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span>{p.name}</span>
                                            <span className="text-xs text-slate-500 font-medium">{formatCurrency(p.price)}</span>
                                        </button>
                                    ))
                                ) : (
                                    <div className="p-2 text-xs text-slate-400 text-center">No encontrado</div>
                                )}
                            </div>
                          )}
                        </div>

                        <input 
                          type="number" 
                          min="1" 
                          className="w-16 p-2 border border-slate-300 rounded text-sm text-center outline-none focus:border-indigo-500" 
                          value={qty} 
                          onChange={e => setQty(Number(e.target.value))} 
                        />
                    </div>
                    <button 
                      onClick={addToCart} 
                      className={`w-full text-white p-2 rounded flex items-center justify-center gap-1 text-sm font-medium transition-colors ${selectedProduct ? 'bg-slate-800 hover:bg-slate-900' : 'bg-slate-300 cursor-not-allowed'}`}
                      disabled={!selectedProduct}
                    >
                        <Plus size={16} /> Agregar al Pedido
                    </button>
                 </div>

                 <div className="space-y-2 max-h-32 overflow-y-auto">
                    {cart.map((item, i) => (
                        <div key={i} className="flex justify-between items-center text-sm bg-white p-2 rounded border border-slate-200 shadow-sm">
                            <span className="font-medium text-slate-700">{item.quantity}x {products.find(p => p.id === item.productId)?.name}</span>
                            <button onClick={() => removeFromCart(i)} className="text-red-400 hover:text-red-600 p-1 rounded hover:bg-red-50"><X size={16}/></button>
                        </div>
                    ))}
                    {cart.length === 0 && <p className="text-xs text-slate-400 text-center py-2">Lista vacía</p>}
                 </div>
               </div>

               {error && <div className="bg-red-50 text-red-600 p-3 rounded-lg text-xs flex items-center gap-2 border border-red-100"><AlertCircle size={16}/>{error}</div>}

               <button onClick={handleCreateOrUpdateOrder} className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all">
                   {editingOrderId ? 'Guardar Cambios' : 'Confirmar Pedido'}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Order, OrderStatus, Customer, Product } from '../types';
import { Plus, Search, Calendar, AlertCircle, ArrowRight, CheckCircle2, Clock, PackageCheck, ChefHat, Truck, DollarSign, History, X, Edit2, Trash2, User, RotateCcw, Lock } from 'lucide-react';
import { formatCurrency, formatDate } from '../utils/conversions';

export const Orders: React.FC = () => {
  const { orders, products, customers, addOrder, updateOrder, updateOrderStatus, addCustomer, deleteOrder } = useBakery();

  // State
  const [activeStatus, setActiveStatus] = useState<OrderStatus>('Pendiente');
  const [showHistory, setShowHistory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New/Edit Order Form State
  const [editingOrderId, setEditingOrderId] = useState<string | null>(null);

  // Customer Smart Search State
  const [customerSearchInput, setCustomerSearchInput] = useState('');
  const [selectedCustomerId, setSelectedCustomerId] = useState<string | null>(null); // If null, means new customer
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);

  // Product Smart Search State
  const [productSearchInput, setProductSearchInput] = useState('');
  const [selectedProduct, setSelectedProduct] = useState(''); // Stores ID
  const [showProductSuggestions, setShowProductSuggestions] = useState(false);

  const [date, setDate] = useState('');
  const [qty, setQty] = useState<number | ''>(1);
  const [cart, setCart] = useState<{productId: string, quantity: number}[]>([]);
  const [error, setError] = useState('');

  const customerSuggestionsRef = useRef<HTMLDivElement>(null);
  const productSuggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // Customer Dropdown
      if (customerSuggestionsRef.current && !customerSuggestionsRef.current.contains(event.target as Node)) {
        setShowCustomerSuggestions(false);
      }
      // Product Dropdown
      if (productSuggestionsRef.current && !productSuggestionsRef.current.contains(event.target as Node)) {
        setShowProductSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Filtered customers for autocomplete
  const customerSuggestions = useMemo(() => {
    if (!customerSearchInput) return [];
    return customers.filter(c => 
      c.name.toLowerCase().includes(customerSearchInput.toLowerCase())
    ).slice(0, 5); // Limit to 5
  }, [customers, customerSearchInput]);

  // Filtered products for autocomplete (Sorted Alphabetically)
  const productSuggestions = useMemo(() => {
    return products
      .filter(p => p.name.toLowerCase().includes(productSearchInput.toLowerCase()))
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [products, productSearchInput]);

  const handleSelectCustomer = (c: Customer) => {
    setCustomerSearchInput(c.name);
    setSelectedCustomerId(c.id);
    setShowCustomerSuggestions(false);
  };

  const handleCustomerInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setCustomerSearchInput(e.target.value);
    setSelectedCustomerId(null); // Reset ID implies potentially new customer
    setShowCustomerSuggestions(true);
  };

  const handleSelectProduct = (p: Product) => {
    setProductSearchInput(p.name);
    setSelectedProduct(p.id);
    setShowProductSuggestions(false);
  };

  // --- Constants ---
  const WORKFLOW_STEPS: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado'];
  const HISTORY_STEPS: OrderStatus[] = ['Pagado'];
  const FULL_FLOW: OrderStatus[] = ['Pendiente', 'En Proceso', 'Completado', 'Entregado', 'Pagado'];

  // --- Data Logic ---
  const counts = useMemo(() => {
    const c: Record<string, number> = {};
    orders.forEach(o => {
      c[o.status] = (c[o.status] || 0) + 1;
    });
    return c;
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders;

    // 1. Filter by Mode (Active Workflow vs History)
    if (showHistory) {
      result = result.filter(o => HISTORY_STEPS.includes(o.status));
    } else {
      result = result.filter(o => o.status === activeStatus);
    }

    // 2. Filter by Search
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(o => 
        o.customerName.toLowerCase().includes(lower) || 
        o.id.toLowerCase().includes(lower)
      );
    }

    // 3. Sort by Date
    return result.sort((a, b) => a.deliveryDate.localeCompare(b.deliveryDate));
  }, [orders, activeStatus, showHistory, searchTerm]);

  // --- Actions ---
  const advanceOrder = (order: Order) => {
    const currentIndex = FULL_FLOW.indexOf(order.status);
    if (currentIndex >= 0 && currentIndex < FULL_FLOW.length - 1) {
      updateOrderStatus(order.id, FULL_FLOW[currentIndex + 1]);
    }
  };

  const revertOrder = (order: Order) => {
    const currentIndex = FULL_FLOW.indexOf(order.status);
    // Safety check: Cannot revert if accounting is closed for this order
    if (order.accountingClosed) {
        alert("No se puede deshacer un pedido que ya forma parte de un Cierre de Mes contable.");
        return;
    }

    if (currentIndex > 0) {
      updateOrderStatus(order.id, FULL_FLOW[currentIndex - 1]);
    }
  };

  const handleDeleteOrder = (order: Order) => {
    if (window.confirm(`¿Estás seguro de eliminar el pedido de ${order.customerName}? Esto devolverá los ingredientes al inventario.`)) {
        deleteOrder(order.id);
    }
  };

  const handleEditOrder = (order: Order) => {
    setEditingOrderId(order.id);

    // Setup Customer Field
    setCustomerSearchInput(order.customerName);
    setSelectedCustomerId(order.customerId || null); // Keep ID if valid

    setDate(order.deliveryDate);
    setCart(order.items.map(i => ({...i})));
    setError('');
    setIsModalOpen(true);
  };

  // --- Modal Logic ---
  const addToCart = () => {
    if(!selectedProduct) return;
    const finalQty = qty === '' ? 1 : qty;
    const existingIndex = cart.findIndex(i => i.productId === selectedProduct);
    if (existingIndex >= 0) {
        const newCart = [...cart];
        newCart[existingIndex].quantity += finalQty;
        setCart(newCart);
    } else {
        setCart([...cart, { productId: selectedProduct, quantity: finalQty }]);
    }

    // Reset Product Selection
    setSelectedProduct('');
    setProductSearchInput('');
    setQty(1);
    setError('');
  };

  const removeFromCart = (index: number) => {
    setCart(cart.filter((_, idx) => idx !== index));
  };

  const handleCreateOrUpdateOrder = async () => {
    setError('');

    if (!customerSearchInput.trim()) { setError('Ingresa el nombre del cliente.'); return; }
    if(!date) { setError('Selecciona fecha de entrega.'); return; }
    if(cart.length === 0) { setError('Agrega al menos un producto.'); return; }

    let finalCustomerId = selectedCustomerId;
    let finalCustomerName = customerSearchInput.trim();

    // Logic: If no ID is selected, but name exists in text, create new customer
    if (!finalCustomerId) {
        // Double check if name matches an existing one exactly to avoid dupe
        const existingExact = customers.find(c => c.name.toLowerCase() === finalCustomerName.toLowerCase());
        if (existingExact) {
            finalCustomerId = existingExact.id;
        } else {
            // Create completely new customer
            try {
                finalCustomerId = await addCustomer({
                    id: '',
                    name: finalCustomerName
                });
            } catch (e) {
                setError('Error al crear nuevo cliente.');
                return;
            }
        }
    }

    let total = 0;
    cart.forEach(item => {
      const p = products.find(prod => prod.id === item.productId);
      if(p) total += p.price * item.quantity;
    });

    const orderData: Order = {
      id: editingOrderId || Date.now().toString(),
      customerId: finalCustomerId,
      customerName: finalCustomerName,
      deliveryDate: date,
      status: editingOrderId ? (orders.find(o => o.id === editingOrderId)?.status || 'Pendiente') : 'Pendiente',
      items: cart,
      totalPrice: total
    };

    if (editingOrderId) {
        updateOrder(orderData);
    } else {
        addOrder(orderData);
    }
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setCart([]);
    // Customer Reset
    setCustomerSearchInput('');
    setSelectedCustomerId(null);
    setShowCustomerSuggestions(false);
    // Product Reset
    setProductSearchInput('');
    setSelectedProduct('');
    setShowProductSuggestions(false);

    setDate('');
    setError('');
    setQty(1);
    setEditingOrderId(null);
  };

  // --- UI Helpers ---
  const getStatusConfig = (status: OrderStatus) => {
    switch (status) {
      case 'Pendiente': 
        return { color: 'bg-yellow-100 text-yellow-800 border-yellow-200', icon: Clock, label: 'Pendiente', next: 'En Proceso' };
      case 'En Proceso': 
        return { color: 'bg-orange-100 text-orange-800 border-orange-200', icon: ChefHat, label: 'En Proceso', next: 'Completado' };
      case 'Completado': 
        return { color: 'bg-indigo-100 text-indigo-800 border-indigo-200', icon: PackageCheck, label: 'Completado', next: 'Entregado' };
      case 'Entregado': 
        return { color: 'bg-blue-100 text-blue-800 border-blue-200', icon: Truck, label: 'Entregado', next: 'Pagado' };
      case 'Pagado': 
        return { color: 'bg-emerald-100 text-emerald-800 border-emerald-200', icon: DollarSign, label: 'Pagado', next: '' };
      default: 
        return { color: 'bg-slate-100', icon: CheckCircle2, label: status, next: '' };
    }
  };

  return (
    <div className="space-y-6 pb-24 md:pb-0">
      {/* 1. Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <ChefHat className="text-indigo-600" /> Gestión de Pedidos
           </h2>
           <p className="text-slate-500 text-sm">Controla el flujo desde Pendiente hasta Pagado.</p>
        </div>

        <div className="flex w-full md:w-auto gap-3">
           <div className="relative flex-1 md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
           </div>
           <button 
             onClick={() => setIsModalOpen(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm whitespace-nowrap font-medium text-sm"
           >
             <Plus size={18} /> <span className="hidden sm:inline">Crear Pedido</span>
           </button>
        </div>
      </div>

      {/* 2. Dynamic Status Tabs */}
      <div className="flex flex-col sm:flex-row gap-4 items-center justify-between border-b border-slate-200 pb-1">

        {/* Active Workflow Tabs */}
        <div className="flex gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0 no-scrollbar">
          {!showHistory && WORKFLOW_STEPS.map((status) => {
            const config = getStatusConfig(status);
            const isActive = activeStatus === status;
            const count = counts[status] || 0;
            const Icon = config.icon;

            return (
              <button
                key={status}
                onClick={() => setActiveStatus(status)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap border ${
                  isActive 
                    ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm ring-1 ring-indigo-50' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Icon size={16} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />
                {config.label}
                <span className={`ml-1 px-2 py-0.5 rounded-full text-xs ${isActive ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                  {count}
                </span>
              </button>
            );
          })}

          {/* History Mode Title Override */}
          {showHistory && (
             <div className="flex items-center gap-2 px-4 py-2 text-slate-800 font-bold">
                <History size={18} /> Historial (Pagados)
             </div>
          )}
        </div>

        {/* Toggle History */}
        <button
          onClick={() => setShowHistory(!showHistory)}
          className={`text-xs font-medium flex items-center gap-2 px-3 py-1.5 rounded-full transition-colors ${
            showHistory ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {showHistory ? <X size={14}/> : <History size={14}/>}
          {showHistory ? 'Volver al Flujo' : 'Ver Cerrados'}
        </button>
      </div>

      {/* 3. Order List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredOrders.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl">
             <PackageCheck size={48} className="mx-auto mb-3 opacity-20" />
             <p>No hay pedidos en esta sección.</p>
          </div>
        )}

        {filteredOrders.map(order => {
          const config = getStatusConfig(order.status);
          const isUrgent = order.deliveryDate <= new Date().toISOString().split('T')[0] && !showHistory;

          // Check if it's possible to revert (index > 0)
          const flowIndex = FULL_FLOW.indexOf(order.status);
          const canRevert = flowIndex > 0;
          const isClosed = order.accountingClosed;

          return (
            <div key={order.id} className={`bg-white rounded-xl p-5 shadow-sm border transition-all hover:shadow-md ${isUrgent ? 'border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100' : 'border-slate-200'}`}>

              {/* Header */}
              <div className="flex justify-between items-start mb-3">
                <div className="flex-1 min-w-0">
                   <h3 className="font-bold text-slate-800 truncate pr-2">{order.customerName}</h3>
                   <div className={`flex items-center gap-1 text-xs mt-1 ${isUrgent ? 'text-red-600 font-bold' : 'text-slate-500'}`}>
                      <Calendar size={12} /> {formatDate(order.deliveryDate)}
                      {isUrgent && <span className="bg-red-100 text-red-600 px-1.5 rounded text-[10px] ml-1">HOY</span>}
                   </div>
                </div>

                {/* Edit/Delete Controls */}
                <div className="flex gap-1 ml-2">
                    <button 
                        onClick={() => handleEditOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-indigo-600 rounded hover:bg-indigo-50 transition-colors"
                        title="Editar Pedido"
                    >
                        <Edit2 size={16} />
                    </button>
                    <button 
                        onClick={() => handleDeleteOrder(order)} 
                        className="p-1.5 text-slate-400 hover:text-red-600 rounded hover:bg-red-50 transition-colors"
                        title="Eliminar Pedido"
                    >
                        <Trash2 size={16} />
                    </button>
                </div>
              </div>

              {/* Status & Price Row */}
              <div className="flex justify-between items-center mb-3">
                  <span className={`text-[10px] px-2 py-0.5 rounded-full inline-block ${config.color}`}>
                     {order.status}
                  </span>
                  <span className="block font-bold text-slate-700">{formatCurrency(order.totalPrice)}</span>
              </div>

              {/* Items */}
              <div className="bg-slate-50 rounded-lg p-3 text-sm text-slate-600 space-y-1 mb-4 border border-slate-100">
                 {order.items.slice(0, 3).map((item, idx) => {
                   const p = products.find(prod => prod.id === item.productId);
                   return (
                     <div key={idx} className="flex justify-between">
                       <span>{item.quantity}x {p?.name}</span>
                     </div>
                   );
                 })}
                 {order.items.length > 3 && (
                   <div className="text-xs text-slate-400 pt-1 text-center">+ {order.items.length - 3} ítems más...</div>
                 )}
              </div>

              {/* Action Footer */}
              {!showHistory ? (
                <div className="flex gap-2">
                   {canRevert && (
                      <button 
                         onClick={() => revertOrder(order)}
                         className="p-2.5 rounded-lg border border-slate-200 text-slate-400 hover:bg-slate-100 hover:text-slate-600 transition-colors"
                         title="Volver al estado anterior"
                      >
                         <RotateCcw size={16} />
                      </button>
                   )}
                   <button 
                    onClick={() => advanceOrder(order)}
                    className="flex-1 py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-colors bg-indigo-50 text-indigo-700 hover:bg-indigo-600 hover:text-white group"
                   >
                    {/* Dynamic Icon based on next step */}
                    {config.next === 'En Proceso' && <ChefHat size={16} />}
                    {config.next === 'Completado' && <PackageCheck size={16} />}
                    {config.next === 'Entregado' && <Truck size={16} />}
                    {config.next === 'Pagado' && <DollarSign size={16} />}

                    {config.next === 'Pagado' ? 'Confirmar Pago' : `Avanzar a ${config.next}`}

                    <ArrowRight size={16} className="transition-transform group-hover:translate-x-1" />
                   </button>
                </div>
              ) : (
                <div className="flex items-center justify-between pt-2 border-t border-slate-100 mt-2">
                    <div className="text-xs text-slate-400 italic flex items-center gap-1">
                        {isClosed ? (
                            <><Lock size={12} /> Contabilidad Cerrada</>
                        ) : (
                            <><CheckCircle2 size={12} /> Pago Registrado</>
                        )}
                    </div>

                    {!isClosed && (
                         <button 
                            onClick={() => revertOrder(order)}
                            className="flex items-center gap-1 px-3 py-1.5 text-xs font-medium text-slate-500 bg-slate-100 hover:bg-slate-200 hover:text-slate-700 rounded-lg transition-colors"
                            title="Revertir a Entregado (Por Cobrar)"
                         >
                            <RotateCcw size={12} /> Deshacer Pago
                         </button>
                    )}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* New/Edit Order Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto flex flex-col">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white sticky top-0 z-10">
