  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Ingredient, Product, Order, ChatMessage } from "../types";
import { formatStock } from "../utils/conversions";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Define the interface for the AI response locally for typing
export interface AiRecipeResult {
  name: string;
  description: string;
  ingredients: {
    name: string;
    quantity: number;
    unit: string;
  }[];
}

export const suggestRecipe = async (availableIngredients: Ingredient[], prompt: string): Promise<AiRecipeResult[]> => {
  const ingredientList = availableIngredients.map(i => `${i.name} (${formatStock(i.currentStock, i.unit)})`).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Inventario disponible: ${ingredientList}. Solicitud del usuario: "${prompt}"`,
      config: {
        systemInstruction: `Eres un Chef Pastelero experto. Genera 3 recetas diferentes basadas en la solicitud.
        REGLAS CRÍTICAS PARA INTEGRACIÓN DE DATOS:
        1. Devuelve un JSON con un array de 3 recetas.
        2. Para las unidades ('unit'), usa EXCLUSIVAMENTE: 'g', 'kg', 'ml', 'L', o 'u'. Convierte tazas o cucharadas a gramos/ml.
        3. En 'ingredients', intenta usar nombres de ingredientes que coincidan con el inventario provisto si es posible, pero si la receta necesita algo nuevo, inclúyelo.
        4. 'description' debe ser un resumen corto de la preparación (pasos clave).`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              ingredients: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    quantity: { type: Type.NUMBER },
                    unit: { type: Type.STRING }
                  }
                }
              }
            }
          }
        }
      }
    });

    const text = response.text || "[]";
    return JSON.parse(text) as AiRecipeResult[];
  } catch (error) {
    console.error("Gemini API Error (suggestRecipe):", error);
    throw error;
  }
};

export const parseOrderFromText = async (text: string, products: Product[]): Promise<any> => {
  const productNames = products.map(p => p.name).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Texto del pedido: "${text}"`,
      config: {
        systemInstruction: `Extrae la información del pedido en formato JSON.
        Los productos disponibles son: ${productNames}.
        Intenta coincidir el nombre del producto.
        `,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            customerName: { type: Type.STRING },
            items: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  productName: { type: Type.STRING },
                  quantity: { type: Type.NUMBER }
                }
              }
            },
          }
        }
      }
    });

    // Handle potential markdown code blocks in response
    let cleanText = response.text || "{}";
    cleanText = cleanText.replace(/```json/g, '').replace(/```/g, '').trim();

    return JSON.parse(cleanText);
  } catch (e) {
    console.error("Gemini API Error (parseOrderFromText):", e);
    return null;
  }
};

export const analyzeProductionData = async (orders: Order[], inventory: Ingredient[]) => {
    // Simplify orders for prompt
    const orderSummary = JSON.stringify(orders.map(o => ({
        customer: o.customerName,
        status: o.status,
        items: o.items.length,
        total: o.totalPrice
    })));

    const inventorySummary = JSON.stringify(inventory.map(i => ({ 
        name: i.name, 
        stock: i.currentStock, 
        unit: i.unit, 
        min: i.minStock 
    })));

    try {
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `Analiza estos datos de producción. 
          Pedidos pendientes: ${orderSummary}
          Inventario actual: ${inventorySummary}

          Dame un resumen ejecutivo de 3 puntos:
          1. Estado de riesgo del inventario.
          2. Eficiencia de producción sugerida.
          3. Una idea creativa para vender el excedente de stock (si lo hay) o mejorar ventas.`,
          config: {
              systemInstruction: "Eres un consultor de negocios de pastelería.",
          }
      });
      return response.text;
    } catch (error) {
      console.error("Gemini API Error (analyzeProductionData):", error);
      throw error;
    }
}

export const getChefResponse = async (history: ChatMessage[], newMessage: string): Promise<string> => {
  try {
    const formattedHistory = history.map(msg => ({
      role: msg.role,
      parts: [{ text: msg.text }]
    }));

    const chat = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction: "Eres Chef Pierre, un experto pastelero francés amigable y servicial. Ayudas con recetas, consejos técnicos y gestión de pastelería. Tus respuestas son breves, útiles y con un toque de personalidad francesa.",
      },
      history: formattedHistory
    });

    const result = await chat.sendMessage({ message: newMessage });
    return result.text || "";
  } catch (error) {
    console.error("Gemini API Error (getChefResponse):", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { suggestRecipe, analyzeProductionData, AiRecipeResult } from '../services/geminiService';
import { Sparkles, MessageSquare, Loader2, BarChart2, AlertCircle, ChevronLeft, ChevronRight, Save, CheckCircle2, AlertTriangle, Layers } from 'lucide-react';
import { UnitType, Product } from '../types';

export const AiAssistant: React.FC = () => {
  const { ingredients, orders, addProduct } = useBakery();
  const [activeTab, setActiveTab] = useState<'recipe' | 'analysis'>('recipe');

  // Recipe State
  const [prompt, setPrompt] = useState('');
  const [recipeSuggestions, setRecipeSuggestions] = useState<AiRecipeResult[]>([]);
  const [currentRecipeIndex, setCurrentRecipeIndex] = useState(0);

  // Analysis State
  const [analysisResponse, setAnalysisResponse] = useState('');

  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [saveSuccess, setSaveSuccess] = useState(false);

  const handleRecipeSuggest = async () => {
    if (!prompt) return;
    setLoading(true);
    setErrorMsg(null);
    setRecipeSuggestions([]);
    setSaveSuccess(false);

    try {
      const results = await suggestRecipe(ingredients, prompt);
      if (results && results.length > 0) {
        setRecipeSuggestions(results);
        setCurrentRecipeIndex(0);
      } else {
        setErrorMsg('El Chef no pudo generar recetas válidas. Intenta ser más específico.');
      }
    } catch (error: any) {
      console.error(error);
      setErrorMsg(`Error: ${error.message || 'No se pudo conectar con el Chef IA.'}`);
    } finally {
      setLoading(false);
    }
  };

  const handleAnalysis = async () => {
    setLoading(true);
    setErrorMsg(null);
    setAnalysisResponse('');
    try {
      const result = await analyzeProductionData(orders, ingredients);
      setAnalysisResponse(result || 'Sin datos suficientes.');
    } catch (error: any) {
      console.error(error);
      setErrorMsg(`Error: ${error.message || 'Error analizando datos.'}`);
    } finally {
      setLoading(false);
    }
  };

  // --- Recipe Matching Logic ---

  // Helper to normalize strings for comparison
  const normalize = (str: string) => str.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();

  // Logic to check if recipe ingredients exist in DB
  const validateIngredients = (recipe: AiRecipeResult) => {
    const missing: string[] = [];
    const matched = recipe.ingredients.map(aiIng => {
      // Find match in DB
      const dbIng = ingredients.find(i => 
        normalize(i.name).includes(normalize(aiIng.name)) || 
        normalize(aiIng.name).includes(normalize(i.name))
      );

      if (!dbIng) {
        missing.push(aiIng.name);
        return null;
      }

      // Map Unit string to Enum
      let unit = UnitType.GRAMS; // Default
      const u = aiIng.unit.toLowerCase();
      if (u === 'kg') unit = UnitType.KILOGRAMS;
      if (u === 'ml') unit = UnitType.MILLILITERS;
      if (u === 'l') unit = UnitType.LITERS;
      if (u === 'u' || u.includes('unid')) unit = UnitType.UNITS;

      return {
        ingredientId: dbIng.id,
        quantity: aiIng.quantity,
        unit: unit,
        type: 'INGREDIENT' as const, // For now, AI only suggests raw ingredients
        originalName: aiIng.name // Keep for display if needed
      };
    });

    return { missing, matchedItems: matched.filter((i): i is NonNullable<typeof i> => i !== null) };
  };

  const currentRecipe = recipeSuggestions[currentRecipeIndex];
  const { missing, matchedItems } = currentRecipe ? validateIngredients(currentRecipe) : { missing: [], matchedItems: [] };
  const canSave = currentRecipe && missing.length === 0;

  const handleSaveRecipe = async () => {
    if (!canSave || !currentRecipe) return;

    try {
      const newProduct: Product = {
        id: Date.now().toString(),
        name: currentRecipe.name,
        price: 0, // Needs to be set manually later
        description: "Receta generada por Chef IA",
        observations: currentRecipe.description,
        isIntermediate: false, // Default to product, user can change later
        recipe: matchedItems
      };

      await addProduct(newProduct);
      setSaveSuccess(true);
      setTimeout(() => setSaveSuccess(false), 3000);
    } catch (e) {
      setErrorMsg('Error al guardar la receta en la base de datos.');
    }
  };

  const nextRecipe = () => {
    if (recipeSuggestions.length > 0) {
      setCurrentRecipeIndex((prev) => (prev + 1) % recipeSuggestions.length);
      setSaveSuccess(false);
    }
  };

  const prevRecipe = () => {
    if (recipeSuggestions.length > 0) {
      setCurrentRecipeIndex((prev) => (prev - 1 + recipeSuggestions.length) % recipeSuggestions.length);
      setSaveSuccess(false);
    }
  };

  return (
    <div className="h-full flex flex-col space-y-4 max-w-4xl mx-auto pb-20 md:pb-0">
      <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl p-6 text-white shadow-lg">
        <h2 className="text-3xl font-bold flex items-center gap-2">
          <Sparkles className="animate-pulse" /> Chef IA Inteligente
        </h2>
        <p className="opacity-90 mt-2">
          Tu asistente experto para creatividad, gestión y análisis de negocio.
        </p>
      </div>

      <div className="flex gap-4 border-b border-slate-200 overflow-x-auto">
        <button
          onClick={() => { setActiveTab('recipe'); setAnalysisResponse(''); setErrorMsg(null); }}
          className={`pb-2 px-4 font-medium transition-colors whitespace-nowrap ${activeTab === 'recipe' ? 'border-b-2 border-indigo-500 text-indigo-600' : 'text-slate-500'}`}
        >
          Consultas & Recetas
        </button>
        <button
          onClick={() => { setActiveTab('analysis'); setRecipeSuggestions([]); setErrorMsg(null); }}
          className={`pb-2 px-4 font-medium transition-colors whitespace-nowrap ${activeTab === 'analysis' ? 'border-b-2 border-indigo-500 text-indigo-600' : 'text-slate-500'}`}
        >
          Análisis de Negocio
        </button>
      </div>

      <div className="flex-1 bg-white rounded-xl shadow-sm border border-slate-100 p-6 min-h-[400px]">
        {activeTab === 'recipe' ? (
          <div className="space-y-6">
            {/* Search Input */}
            <div className="space-y-2">
              <label className="block text-slate-700 font-medium">¿Qué deseas preparar hoy?</label>
              <div className="flex gap-2">
                <input
                  type="text"
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Ej. Tengo muchas manzanas, ¿qué puedo hacer? o Dame 3 variantes de Cheesecake."
                  className="flex-1 p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-300 outline-none"
                  onKeyDown={(e) => e.key === 'Enter' && handleRecipeSuggest()}
                />
                <button
                  onClick={handleRecipeSuggest}
                  disabled={loading}
                  className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 rounded-lg disabled:opacity-50 flex items-center justify-center min-w-[60px]"
                >
                  {loading ? <Loader2 className="animate-spin" /> : <MessageSquare size={20} />}
                </button>
              </div>
            </div>

            {/* Suggestions Display */}
            {recipeSuggestions.length > 0 && (
               <div className="animate-in fade-in slide-in-from-bottom-4">
                  <div className="flex items-center justify-between mb-4">
                     <h3 className="text-lg font-bold text-slate-800">Sugerencia {currentRecipeIndex + 1} de {recipeSuggestions.length}</h3>
                     <div className="flex gap-2">
                        <button onClick={prevRecipe} className="p-2 border rounded-full hover:bg-slate-100"><ChevronLeft size={20}/></button>
                        <button onClick={nextRecipe} className="p-2 border rounded-full hover:bg-slate-100"><ChevronRight size={20}/></button>
                     </div>
                  </div>

                  <div className="border border-slate-200 rounded-xl p-5 bg-slate-50">
                     <h4 className="text-xl font-bold text-indigo-700 mb-2">{currentRecipe.name}</h4>
                     <p className="text-slate-600 italic mb-4 text-sm">{currentRecipe.description}</p>

                     <div className="bg-white rounded-lg p-4 border border-slate-200 mb-4">
                        <h5 className="font-semibold text-slate-700 mb-2 flex items-center gap-2"><Layers size={16}/> Ingredientes</h5>
                        <ul className="space-y-2 text-sm">
                           {currentRecipe.ingredients.map((ing, i) => {
                              // Check locally if this specific ingredient is matched
                              const dbMatch = ingredients.find(db => 
                                normalize(db.name).includes(normalize(ing.name)) || 
                                normalize(ing.name).includes(normalize(db.name))
                              );

                              return (
                                <li key={i} className="flex justify-between items-center">
                                   <span className={dbMatch ? 'text-slate-700' : 'text-red-500 font-medium'}>
                                      • {ing.name} {!dbMatch && '(No existe)'}
                                   </span>
                                   <span className="font-mono text-slate-500">{ing.quantity} {ing.unit}</span>
                                </li>
                              );
                           })}
                        </ul>
                     </div>

                     {/* Action Area */}
                     <div className="flex flex-col gap-3">
                        {!canSave && (
                           <div className="bg-red-50 border border-red-200 rounded-lg p-3 flex items-start gap-2 text-sm text-red-800">
                              <AlertTriangle className="flex-shrink-0 mt-0.5" size={16} />
                              <div>
                                 <strong>No se puede guardar:</strong> Faltan ingredientes en tu inventario.
                                 <ul className="list-disc list-inside mt-1 text-xs opacity-80">
                                    {missing.map((m, i) => <li key={i}>Debes crear "{m}" primero.</li>)}
                                 </ul>
                              </div>
                           </div>
                        )}

                        {saveSuccess ? (
                           <div className="bg-green-100 text-green-800 p-3 rounded-lg flex items-center justify-center gap-2 font-bold animate-in zoom-in">
                              <CheckCircle2 /> ¡Receta guardada en Productos!
                           </div>
                        ) : (
                           <button
                              onClick={handleSaveRecipe}
                              disabled={!canSave}
                              className={`w-full py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${
                                 canSave 
                                 ? 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-md' 
                                 : 'bg-slate-200 text-slate-400 cursor-not-allowed'
                              }`}
                           >
                              <Save size={18} /> Guardar Receta
                           </button>
                        )}
                     </div>
                  </div>
               </div>
            )}
          </div>
        ) : (
          <div className="space-y-4 text-center">
            <p className="text-slate-600">Genera un reporte inteligente basado en tus pedidos actuales y niveles de stock.</p>
            <button
              onClick={handleAnalysis}
              disabled={loading}
              className="bg-purple-600 hover:bg-purple-700 text-white px-8 py-3 rounded-lg shadow-md disabled:opacity-50 inline-flex items-center gap-2"
            >
              {loading ? <Loader2 className="animate-spin" /> : <BarChart2 size={20} />}
              Generar Análisis de Negocio
            </button>

            {(analysisResponse || loading) && !errorMsg && (
              <div className="mt-8 p-6 bg-slate-50 rounded-xl border border-slate-200 text-left">
                {loading ? (
                  <div className="flex flex-col items-center justify-center py-8 text-slate-500">
                    <Loader2 className="animate-spin mb-2 w-8 h-8 text-indigo-500" />
                    <p>El Chef está analizando tus datos...</p>
                  </div>
                ) : (
                  <div className="prose prose-indigo max-w-none text-slate-700 whitespace-pre-wrap">
                    {analysisResponse}
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {/* Error Message Area */}
        {errorMsg && (
          <div className="mt-8 p-4 bg-red-50 text-red-700 rounded-lg border border-red-200 flex items-center gap-2">
            <AlertCircle size={20} />
            <span>{errorMsg}</span>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Product, RecipeItem, UnitType, Ingredient } from '../types';
import { UNIT_OPTIONS } from '../constants';
import { Plus, Trash2, ChevronDown, ChevronUp, Calculator, DollarSign, Edit2, Save, X, Search, Layers, StickyNote } from 'lucide-react';
import { fromBaseUnit, formatCurrency } from '../utils/conversions';

export const Recipes: React.FC = () => {
  const { products, ingredients, addProduct, updateProduct } = useBakery();
  const [isCreating, setIsCreating] = useState(false);

  // State to track if we are editing an existing product
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [productName, setProductName] = useState('');
  const [productObservations, setProductObservations] = useState('');
  const [productPrice, setProductPrice] = useState<number | ''>('');
  const [recipeItems, setRecipeItems] = useState<RecipeItem[]>([]);
  const [isIntermediate, setIsIntermediate] = useState(false);

  // Costing Calculator State
  const [fixedCosts, setFixedCosts] = useState<number | ''>('');
  const [estimatedUnits, setEstimatedUnits] = useState<number | ''>('');

  // Ingredient Search & Add State
  // Search Logic now includes BOTH Ingredients AND Intermediate Products
  const [selectedItemId, setSelectedItemId] = useState('');
  const [selectedItemType, setSelectedItemType] = useState<'INGREDIENT' | 'PRODUCT'>('INGREDIENT');
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuggestions, setShowSuggestions] = useState(false);

  const [amount, setAmount] = useState<number | ''>('');
  const [selectedUnit, setSelectedUnit] = useState<UnitType>(UnitType.GRAMS);

  const suggestionsRef = useRef<HTMLDivElement>(null);

  // Close suggestions on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (suggestionsRef.current && !suggestionsRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Combined Suggestions: Ingredients + Intermediate Products
  // SORTED A-Z
  const combinedSuggestions = useMemo(() => {
     const rawIngs = ingredients.map(i => ({
         id: i.id,
         name: i.name,
         type: 'INGREDIENT' as const,
         unit: i.unit,
         cost: i.costPerUnit,
         isIntermediate: false
     }));

     // Only show products that ARE intermediate (Sub-recipes)
     // Prevent circular dependency (simplistic check: don't show self if editing)
     const subProds = products
        .filter(p => p.isIntermediate && p.id !== editingProduct?.id)
        .map(p => ({
            id: p.id,
            name: p.name,
            type: 'PRODUCT' as const,
            unit: UnitType.UNITS, // Default for sub-recipes usually
            cost: 0, // Calculated dynamically later
            isIntermediate: true
        }));

     return [...rawIngs, ...subProds]
        .filter(item => item.name.toLowerCase().includes(searchQuery.toLowerCase()))
        .sort((a, b) => a.name.localeCompare(b.name));
  }, [ingredients, products, searchQuery, editingProduct]);

  const handleSelectItem = (item: typeof combinedSuggestions[0]) => {
    setSelectedItemId(item.id);
    setSelectedItemType(item.type);
    setSearchQuery(item.name);
    setSelectedUnit(item.unit);
    setShowSuggestions(false);
  };

  const handleAddItem = () => {
    if(!selectedItemId) {
        alert("Por favor selecciona un ingrediente o base.");
        return;
    }
    if(!amount || Number(amount) <= 0) {
        alert("Ingresa una cantidad válida.");
        return;
    }

    setRecipeItems([...recipeItems, {
      ingredientId: selectedItemId, // This stores either Ing ID or Prod ID
      type: selectedItemType,
      quantity: Number(amount),
      unit: selectedUnit
    }]);

    // Reset inputs
    setAmount('');
    setSelectedItemId('');
    setSelectedItemType('INGREDIENT');
    setSearchQuery('');
  };

  const handleUpdateItemQuantity = (index: number, newQty: string) => {
    const val = newQty === '' ? 0 : parseFloat(newQty);
    const updatedItems = [...recipeItems];
    updatedItems[index].quantity = val;
    setRecipeItems(updatedItems);
  };

  const handleDeleteItem = (index: number) => {
    const updatedItems = recipeItems.filter((_, i) => i !== index);
    setRecipeItems(updatedItems);
  };

  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setProductName(product.name);
    setProductObservations(product.observations || '');
    setProductPrice(product.price);
    setIsIntermediate(!!product.isIntermediate);

    // Normalize recipe items (handle legacy data missing 'type')
    const normalizedItems = product.recipe.map(item => ({
        ...item,
        type: item.type || 'INGREDIENT' // Default for old data
    }));
    setRecipeItems(normalizedItems.map(item => ({...item}))); 

    setFixedCosts('');
    setEstimatedUnits('');

    setIsCreating(true);
  };

  const handleSaveProduct = async () => {
    // Validation
    if(!productName.trim()) {
        alert("El nombre del producto es obligatorio.");
        return;
    }
    if(recipeItems.length === 0) {
        alert("Debes agregar al menos un ingrediente a la receta.");
        return;
    }

    // If it's NOT intermediate, it needs a price. 
    // If it IS intermediate, price is optional (usually 0/internal).
    if(!isIntermediate && (productPrice === '' || Number(productPrice) < 0)) {
        alert("El precio de venta no es válido.");
        return;
    }

    try {
        const validItems = recipeItems.filter(item => item.quantity > 0);
        const finalPrice = productPrice === '' ? 0 : Number(productPrice);

        const prodData: Product = {
            id: editingProduct ? editingProduct.id : Date.now().toString(),
            name: productName,
            price: finalPrice,
            recipe: validItems,
            isIntermediate: isIntermediate,
            observations: productObservations
        };

        if (editingProduct) {
            await updateProduct(prodData);
        } else {
            await addProduct(prodData);
        }

        closeForm();
    } catch (error) {
        console.error("Error al guardar producto:", error);
        alert("Hubo un error al guardar el producto.");
    }
  };

  const closeForm = () => {
    setIsCreating(false);
    setEditingProduct(null);
    resetForm();
  };

  const resetForm = () => {
    setProductName('');
    setProductObservations('');
    setProductPrice('');
    setRecipeItems([]);
    setFixedCosts('');
    setEstimatedUnits('');
    setEditingProduct(null);
    setSearchQuery('');
    setSelectedItemId('');
    setAmount('');
    setIsIntermediate(false);
  };

  // --- RECURSIVE COST CALCULATOR ---
  const getProductCost = (prodId: string): number => {
      const prod = products.find(p => p.id === prodId);
      if(!prod) return 0;
      return calculateVariableCost(prod.recipe);
  };

  const calculateVariableCost = (items: RecipeItem[]) => {
    return items.reduce((acc, item) => {
      const type = item.type || 'INGREDIENT';

      if (type === 'INGREDIENT') {
          const ing = ingredients.find(i => i.id === item.ingredientId);
          if(!ing) return acc;

          if (item.unit === ing.unit) {
              return acc + (item.quantity * ing.costPerUnit);
          }
          let itemBase = 0;
          switch(item.unit) {
              case UnitType.KILOGRAMS: itemBase = item.quantity * 1000; break;
              case UnitType.LITERS: itemBase = item.quantity * 1000; break;
              default: itemBase = item.quantity;
          }
          const itemQtyInIngUnit = fromBaseUnit(itemBase, ing.unit);
          return acc + (itemQtyInIngUnit * ing.costPerUnit);

      } else {
          // It's a SUB-PRODUCT (Intermediate)
          // Assumption: Cost is calculated per 1 Unit of that recipe (Batch)
          // Ideally we need yield, but for now we assume 1 Unit = 1 Batch Cost.
          const subCost = getProductCost(item.ingredientId);

          // If unit is UNITS, it's a direct multiplier. 
          // If unit is Weight, we are in trouble without yield. We fallback to direct multiplier logic.
          // Usually sub-recipes are added as "0.5 Units" (half batch).

          let multiplier = item.quantity;
          // Very simple fallback if they try to measure a recipe in grams (assuming 1 unit = 1 kg for lack of better data)
          // Ideally: Prevent non-unit measures for sub-products in UI, or assume 1 Unit.

          return acc + (subCost * multiplier);
      }
    }, 0);
  };

  const cvu = calculateVariableCost(recipeItems);

  // Suggested Price Formula
  const calculateSuggestedPrice = () => {
      const cft = Number(fixedCosts) || 0;
      const q = Number(estimatedUnits) || 1; 
      const fixedCostPerUnit = cft / q;
      const totalUnitCost = cvu + fixedCostPerUnit;
      const price = totalUnitCost / (1 - 0.60);
      return Math.round(price);
  };

  const suggestedPrice = calculateSuggestedPrice();

  const toggleCreate = () => {
    if(isCreating) {
        closeForm();
    } else {
        resetForm();
        setIsCreating(true);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Recetas y Productos</h2>
        <button 
          onClick={toggleCreate}
          className="hidden md:flex bg-indigo-600 text-white px-4 py-2 rounded-lg items-center gap-2 hover:bg-indigo-700 shadow-sm"
        >
          {isCreating ? 'Cancelar' : <><Plus size={18} /> Nuevo Producto</>}
        </button>
      </div>

      <button 
        onClick={toggleCreate}
        className={`md:hidden fixed bottom-20 right-4 p-4 rounded-full shadow-lg z-40 transition-colors ${isCreating ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white`}
      >
        {isCreating ? <X size={24} /> : <Plus size={24} />}
      </button>

      {isCreating && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-lg space-y-6 animate-in fade-in slide-in-from-top-4">
          <div className="flex justify-between items-start border-b pb-2">
            <h3 className="font-bold text-lg text-slate-800">
                {editingProduct ? 'Editar Receta' : 'Crear Nueva Receta'}
            </h3>
            {/* Intermediate Switch */}
            <div className="flex items-center gap-2 bg-amber-50 px-3 py-1.5 rounded-full border border-amber-100">
               <input 
                 type="checkbox" 
                 id="isIntermediate"
                 checked={isIntermediate}
                 onChange={e => setIsIntermediate(e.target.checked)}
                 className="w-4 h-4 text-amber-600 rounded focus:ring-amber-500"
               />
               <label htmlFor="isIntermediate" className="text-xs font-bold text-amber-800 cursor-pointer select-none">
                 Es Preparado Base / Intermedio
               </label>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
                <div>
                  <label className="label text-sm font-medium text-slate-700 mb-1">Nombre {isIntermediate ? 'del Preparado' : 'del Producto'}</label>
                  <input 
                    className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={productName} 
                    onChange={e => setProductName(e.target.value)} 
                    placeholder={isIntermediate ? "Ej: Masa Madre, Relleno de Limón" : "Ej: Tarta de Frutilla"}
                  />
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                    <h4 className="font-medium text-slate-700 mb-3 text-sm uppercase tracking-wide">Fórmula (Ingredientes y Bases)</h4>

                    <div className="flex flex-col gap-2 mb-4 bg-white p-3 rounded border border-slate-200 shadow-sm relative" ref={suggestionsRef}>
                      <label className="text-xs font-bold text-slate-500">Agregar Ítem</label>
                      <div className="grid grid-cols-12 gap-2 items-end">

                          {/* Autocomplete Input */}
                          <div className="col-span-12 sm:col-span-5 relative">
                             <div className="flex items-center border rounded bg-white overflow-hidden focus-within:ring-2 focus-within:ring-indigo-500">
                                <Search size={16} className="ml-2 text-slate-400" />
                                <input 
                                    className="w-full p-2 text-sm outline-none"
                                    placeholder="Buscar ingrediente o base..."
                                    value={searchQuery}
                                    onChange={e => {
                                        setSearchQuery(e.target.value);
                                        setSelectedItemId(''); 
                                        setShowSuggestions(true);
                                    }}
                                    onFocus={() => setShowSuggestions(true)}
                                />
                             </div>

                             {/* Combined Suggestions Dropdown */}
                             {showSuggestions && combinedSuggestions.length > 0 && (
                                 <div className="absolute z-10 w-full bg-white border border-slate-200 rounded-lg shadow-lg mt-1 max-h-48 overflow-y-auto">
                                    {combinedSuggestions.map(item => (
                                        <button
                                            key={item.id}
                                            onClick={() => handleSelectItem(item)}
                                            className="w-full text-left px-3 py-2 text-sm hover:bg-indigo-50 text-slate-700 border-b border-slate-50 last:border-none flex justify-between items-center"
                                        >
                                            <span className="flex items-center gap-2">
                                                {item.isIntermediate && <Layers size={12} className="text-amber-500" />}
                                                {item.name}
                                            </span>
                                            <span className="text-xs text-slate-400">
                                                {item.isIntermediate ? 'Receta' : `${formatCurrency(item.cost)}/${item.unit}`}
                                            </span>
                                        </button>
                                    ))}
                                 </div>
                             )}
                          </div>

                          <div className="col-span-4 sm:col-span-3">
                              <input 
                                type="number" 
                                className="w-full p-2 border rounded text-sm outline-none focus:border-indigo-500" 
                                placeholder="Cant."
                                value={amount}
                                onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))}
                                onKeyDown={(e) => { if(e.key === 'Enter') handleAddItem() }}
                              />
                          </div>

                          <div className="col-span-6 sm:col-span-3">
                              <select 
                                className="w-full p-2 border rounded text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={selectedUnit}
                                onChange={e => setSelectedUnit(e.target.value as UnitType)}
                              >
                                {UNIT_OPTIONS.map(u => (
                                  <option key={u.value} value={u.value}>{u.label}</option>
                                ))}
                              </select>
                          </div>

                          <div className="col-span-2 sm:col-span-1">
                              <button 
                                onClick={handleAddItem}
                                className={`w-full text-white p-2 rounded flex items-center justify-center transition-colors h-[38px] ${selectedItemId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-300 cursor-not-allowed'}`}
                                disabled={!selectedItemId}
                              >
                                <Plus size={18} />
                              </button>
                          </div>
                      </div>
                    </div>

                    {recipeItems.length > 0 ? (
                       <div className="space-y-2 mb-2">
                         <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-slate-500 px-2">
                            <div className="col-span-5">Ítem</div>
                            <div className="col-span-5 text-right">Cantidad</div>
                            <div className="col-span-2 text-center"></div>
                         </div>
                         {recipeItems.map((item, idx) => {
                           let name = 'Desconocido';
                           let isSub = false;

                           if (item.type === 'PRODUCT') {
                               name = products.find(p => p.id === item.ingredientId)?.name || 'Base eliminada';
                               isSub = true;
                           } else {
                               name = ingredients.find(i => i.id === item.ingredientId)?.name || 'Ingrediente eliminado';
                           }

                           return (
                             <div key={idx} className={`grid grid-cols-12 gap-2 items-center p-2 border rounded shadow-sm text-sm ${isSub ? 'bg-amber-50 border-amber-100' : 'bg-white border-slate-200'}`}>
                               <div className="col-span-5 truncate font-medium text-slate-700 flex items-center gap-1" title={name}>
                                 {isSub && <Layers size={12} className="text-amber-500 flex-shrink-0" />}
                                 {name}
                                </div>
                               <div className="col-span-5 flex justify-end items-center gap-1">
                                 <input 
                                    type="number"
                                    min="0"
                                    step="any"
                                    className="w-20 p-1 border border-slate-200 rounded text-right focus:border-indigo-500 outline-none bg-white"
                                    value={item.quantity === 0 ? '' : item.quantity}
                                    onChange={(e) => handleUpdateItemQuantity(idx, e.target.value)}
                                 />
                                 <span className="text-xs text-slate-500 w-8">{item.unit}</span>
                               </div>
                               <div className="col-span-2 text-center">
                                 <button 
                                    onClick={() => handleDeleteItem(idx)} 
                                    className="text-red-400 hover:text-red-600 p-1 rounded-full hover:bg-red-50"
                                 >
                                    <Trash2 size={16} />
                                 </button>
                               </div>
                             </div>
                           )
                         })}
                         <div className="flex justify-between items-center pt-3 border-t border-slate-200 mt-3">
                            <span className="text-slate-500 font-medium text-sm">Costo Variable Total (CVU):</span>
                            <span className="text-slate-800 font-bold text-lg">{formatCurrency(cvu)}</span>
                         </div>
                       </div>
                    ) : (
                        <p className="text-xs text-slate-400 italic text-center py-4">Agrega ingredientes o bases para calcular el costo.</p>
                    )}
                </div>
            </div>

            <div className="space-y-4">
               {/* Pricing Calculator - Hide/Dim if Intermediate */}
               <div className={`bg-indigo-50 p-5 rounded-xl border border-indigo-100 ${isIntermediate ? 'opacity-60 grayscale' : ''}`}>
                  <div className="flex items-center gap-2 mb-4 text-indigo-800">
                     <Calculator size={20} />
                     <h4 className="font-bold">Calculadora {isIntermediate ? '(No requerida)' : 'de Precios'}</h4>
                  </div>

                  {!isIntermediate && (
                    <div className="space-y-3 mb-4">
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                            <label className="text-xs font-semibold text-slate-500 block mb-1">Costos Fijos Asignados (CFT)</label>
                            <input 
                                type="number" 
                                className="w-full p-2 border border-indigo-200 rounded text-sm"
                                placeholder="0"
                                value={fixedCosts}
                                onChange={e => setFixedCosts(e.target.value === '' ? '' : Number(e.target.value))}
                            />
                            </div>
                            <div>
                            <label className="text-xs font-semibold text-slate-500 block mb-1">Ventas Estimadas (Q)</label>
                            <input 
                                type="number" 
                                className="w-full p-2 border border-indigo-200 rounded text-sm"
                                placeholder="Unidades/mes"
                                value={estimatedUnits}
                                onChange={e => setEstimatedUnits(e.target.value === '' ? '' : Number(e.target.value))}
                            />
                            </div>
                        </div>

                        <div className="bg-white p-3 rounded-lg border border-indigo-100 space-y-1">
                            <div className="flex justify-between text-xs text-slate-500">
                                <span>Costo Variable (CVU):</span>
                                <span>{formatCurrency(cvu)}</span>
                            </div>
                            <div className="flex justify-between text-xs text-slate-800 font-semibold pt-1 border-t border-slate-100">
                                <span>Costo Total Unitario:</span>
                                <span>{formatCurrency(cvu + ((Number(fixedCosts) && Number(estimatedUnits)) ? (Number(fixedCosts)/Number(estimatedUnits)) : 0))}</span>
                            </div>
                        </div>

                        <div className="flex justify-between items-center bg-indigo-100 p-3 rounded-lg">
                            <div>
                                <span className="text-xs text-indigo-600 font-bold uppercase block">Precio Sugerido</span>
                                <span className="text-[10px] text-indigo-400">Margen 60%</span>
                            </div>
                            <div className="text-xl font-bold text-indigo-800">
                                {formatCurrency(suggestedPrice)}
                            </div>
                        </div>

                        <button 
                            onClick={() => setProductPrice(suggestedPrice)}
                            disabled={!isFinite(suggestedPrice) || suggestedPrice <= 0}
                            className="w-full py-1.5 text-xs bg-indigo-200 text-indigo-800 rounded font-semibold hover:bg-indigo-300 transition-colors disabled:opacity-50"
                        >
                            Usar Precio Sugerido
                        </button>
                    </div>
                  )}

                  <div>
                    <label className="label text-sm font-bold text-slate-700 mb-1 block">
                        {isIntermediate ? 'Costo/Valor Interno (Opcional)' : 'Precio de Venta Final'}
                    </label>
                    <div className="relative">
                        <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input 
                            type="number" 
                            className="w-full pl-9 p-3 border border-slate-300 rounded-lg text-lg font-bold text-slate-800" 
                            value={productPrice} 
                            onChange={e => setProductPrice(e.target.value === '' ? '' : Number(e.target.value))} 
                            placeholder={isIntermediate ? "0" : "0"}
                        />
                    </div>
                  </div>
               </div>
            </div>
          </div>

          {/* Observation Field Moved to Bottom Full Width */}
          <div className="mt-2">
              <label className="label text-sm font-medium text-slate-700 mb-2 flex items-center gap-2">
                 <StickyNote size={16} className="text-indigo-500" /> Observaciones / Instrucciones de Preparación
              </label>
              <textarea 
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm shadow-sm" 
                value={productObservations} 
                onChange={e => setProductObservations(e.target.value)} 
                placeholder="Ej: Instrucciones paso a paso, temperatura de horno, tips de decoración..."
                rows={4}
              />
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
             <button 
                type="button"
                onClick={handleSaveProduct}
                className="bg-green-600 text-white py-3 px-8 rounded-lg font-bold hover:bg-green-700 shadow-md flex items-center gap-2"
             >
                {editingProduct ? 'Actualizar' : 'Guardar'} {isIntermediate ? 'Base' : 'Producto'} <Save size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Product List */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {products.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            ingredients={ingredients} 
            products={products}
            onEdit={handleEditClick}
          />
        ))}
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ 
    product: Product, 
    ingredients: Ingredient[], 
    products: Product[],
    onEdit: (p: Product) => void 
}> = ({ product, ingredients, products, onEdit }) => {
    const [expanded, setExpanded] = useState(false);
    const { deleteProduct } = useBakery();

    const handleDelete = (e: React.MouseEvent) => {
        e.stopPropagation();
        if(window.confirm(`¿Estás seguro que deseas eliminar "${product.name}"?`)) {
            deleteProduct(product.id);
        }
    };

    return (
        <div className={`rounded-xl shadow-sm border overflow-hidden hover:shadow-md transition-shadow ${product.isIntermediate ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-200'}`}>
            <div className="p-4 flex justify-between items-center hover:bg-opacity-80">
                <div 
                    className="flex-1 cursor-pointer"
                    onClick={() => setExpanded(!expanded)}
                >
                    <div className="flex items-center gap-2">
                        {product.isIntermediate && <Layers size={18} className="text-amber-600" />}
                        <h3 className="font-bold text-slate-800 text-lg">{product.name}</h3>
                    </div>
                    <p className="text-slate-500 text-sm flex items-center gap-2">
                        {product.isIntermediate ? 'Receta Base / Preparado' : `${product.recipe.length} componentes`}
                    </p>
                </div>
                <div className="flex items-center gap-3 pl-4">
                    {!product.isIntermediate && (
                        <span className="font-bold text-emerald-600 text-lg bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100 whitespace-nowrap">
                            {formatCurrency(product.price)}
                        </span>
                    )}
                    <button 
                        onClick={(e) => { e.stopPropagation(); onEdit(product); }}
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={handleDelete}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                    >
                        <Trash2 size={18} />
                    </button>
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="p-1 text-slate-400"
                    >
                        {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                    </button>
                </div>
            </div>
            {expanded && (
                <div className="p-4 border-t border-slate-100 animate-in fade-in slide-in-from-top-1 bg-white/50">

                    {/* Observations Display */}
                    {product.observations && (
                        <div className="mb-4 bg-yellow-50 p-2 rounded text-xs text-yellow-800 border border-yellow-100 flex gap-2">
                            <StickyNote size={14} className="flex-shrink-0 mt-0.5" />
                            <p className="whitespace-pre-wrap">{product.observations}</p>
                        </div>
                    )}

                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-3 tracking-wider">Fórmula</h4>
                    <ul className="space-y-2 text-sm">
                        {product.recipe.map((r, i) => {
                            const isSub = r.type === 'PRODUCT';
                            let name = 'Desconocido';

                            if (isSub) {
                                name = products.find(p => p.id === r.ingredientId)?.name || 'Base eliminada';
                            } else {
                                name = ingredients.find(ing => ing.id === r.ingredientId)?.name || 'Ingrediente desconocido';
                            }

                            return (
                                <li key={i} className="flex justify-between items-center text-slate-700 p-2 bg-white rounded border border-slate-100">
                                    <span className="font-medium flex items-center gap-2">
                                        {isSub && <Layers size={12} className="text-amber-500" />}
                                        {name}
                                    </span>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-600">{r.quantity} {r.unit}</div>
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { suggestRecipe, analyzeProductionData, AiRecipeResult } from '../services/geminiService';
import { Sparkles, MessageSquare, Loader2, BarChart2, AlertCircle, ChevronLeft, ChevronRight, Save, CheckCircle2, AlertTriangle, Layers, Lock } from 'lucide-react';
import { UnitType, Product } from '../types';

export const AiAssistant: React.FC = () => {
  const { ingredients, orders, addProduct } = useBakery();
  const [activeTab, setActiveTab] = useState<'recipe' | 'analysis'>('recipe');

  // Recipe State
  const [prompt, setPrompt] = useState('');
  const [recipeSuggestions, setRecipeSuggestions] = useState<AiRecipeResult[]>([]);
  const [currentRecipeIndex, setCurrentRecipeIndex] = useState(0);

  // Analysis State
  const [analysisResponse, setAnalysisResponse] = useState('');

  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [saveSuccess, setSaveSuccess] = useState(false);

  // Helper for friendly error messages
  const getFriendlyErrorMessage = (error: any) => {
    let msg = '';
    if (typeof error === 'string') msg = error;
    else if (error.message) msg = error.message;
    else msg = JSON.stringify(error);

    // Detect specific Google API errors
    if (msg.includes('leaked') || msg.includes('API key')) {
      return '⛔ Tu API Key ha sido revocada por Google (detectada como filtrada). Por favor genera una nueva llave en Google AI Studio y actualiza tu configuración (.env).';
    }
    if (msg.includes('403') || msg.includes('PERMISSION_DENIED')) {
        return '⛔ Permiso denegado. Verifica que tu API Key sea válida y tenga acceso a los modelos de Gemini.';
    }
    if (msg.includes('429') || msg.includes('RESOURCE_EXHAUSTED')) {
        return '⚠️ Has excedido la cuota de uso de la API. Intenta más tarde.';
    }

    return `Error de conexión: ${msg.substring(0, 150)}...`;
  };

  const handleRecipeSuggest = async () => {
    if (!prompt) return;
    setLoading(true);
    setErrorMsg(null);
    setRecipeSuggestions([]);
    setSaveSuccess(false);

    try {
      const results = await suggestRecipe(ingredients, prompt);
      if (results && results.length > 0) {
        setRecipeSuggestions(results);
        setCurrentRecipeIndex(0);
      } else {
        setErrorMsg('El Chef no pudo generar recetas válidas. Intenta ser más específico.');
      }
    } catch (error: any) {
      console.error("AiAssistant Error:", error);
      setErrorMsg(getFriendlyErrorMessage(error));
    } finally {
      setLoading(false);
    }
  };

  const handleAnalysis = async () => {
    setLoading(true);
    setErrorMsg(null);
    setAnalysisResponse('');
    try {
      const result = await analyzeProductionData(orders, ingredients);
      setAnalysisResponse(result || 'Sin datos suficientes.');
    } catch (error: any) {
      console.error("AiAssistant Error:", error);
      setErrorMsg(getFriendlyErrorMessage(error));
    } finally {
      setLoading(false);
    }
  };

