    if (!canSave || !currentRecipe) return;

    try {
      const newProduct: Product = {
        id: Date.now().toString(),
        name: currentRecipe.name,
        price: 0, // Needs to be set manually later
        description: "Receta generada por Chef IA",
        observations: currentRecipe.description,
        isIntermediate: false, // Default to product, user can change later
        recipe: matchedItems
      };

      await addProduct(newProduct);
      setSaveSuccess(true);
      setTimeout(() => setSaveSuccess(false), 3000);
    } catch (e) {
      setErrorMsg('Error al guardar la receta en la base de datos.');
    }
  };

