    if (recipeSuggestions.length > 0) {
      setCurrentRecipeIndex((prev) => (prev + 1) % recipeSuggestions.length);
      setSaveSuccess(false);
    }
  };

  const prevRecipe = () => {
    if (recipeSuggestions.length > 0) {
      setCurrentRecipeIndex((prev) => (prev - 1 + recipeSuggestions.length) % recipeSuggestions.length);
      setSaveSuccess(false);
    }
  };

