import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Printer, TrendingUp, Package, History, Calendar, DollarSign, PieChart, ArrowUpRight, ArrowDownRight, Wallet } from 'lucide-react';
import { formatStock, formatCurrency } from '../utils/conversions';
import { UnitType, RecipeItem } from '../types';

export const Reports: React.FC = () => {
  const { orders, products, ingredients, monthClosures } = useBakery();
  const [activeTab, setActiveTab] = useState<'operativo' | 'contabilidad' | 'historial'>('operativo');
  const [month, setMonth] = useState(new Date().toISOString().slice(0, 7)); // YYYY-MM

  // --- LOGICA DE DATOS ---

  // Pedidos del mes (Entregados o Pagados se consideran "Ventas")
  const monthlyOrders = useMemo(() => orders.filter(o => 
    o.deliveryDate.startsWith(month) && (o.status === 'Entregado' || o.status === 'Pagado')
  ), [orders, month]);

  // Función recursiva para calcular el costo de un producto basado en su receta actual
  const calculateProductCost = (prodId: string): number => {
    const prod = products.find(p => p.id === prodId);
    if (!prod) return 0;

    return prod.recipe.reduce((acc, item) => {
      const type = item.type || 'INGREDIENT';
      if (type === 'INGREDIENT') {
        const ing = ingredients.find(i => i.id === item.ingredientId);
        if (!ing) return acc;

        // Convertir cantidad de la receta a unidad base del ingrediente
        let qtyInBase = item.quantity;
        if (item.unit === UnitType.KILOGRAMS || item.unit === UnitType.LITERS) qtyInBase *= 1000;

        // El costo en la DB ya está normalizado a la unidad mínima (g, ml, u)
        return acc + (qtyInBase * ing.costPerUnit);
      } else {
        // Recursión para sub-productos
        return acc + (calculateProductCost(item.ingredientId) * item.quantity);
      }
    }, 0);
  };

  // Procesamiento de estadísticas
  const stats = useMemo(() => {
    let revenue = 0;
    let totalCogs = 0; // Cost of Goods Sold (CMV)
    const productData: Record<string, { name: string, qty: number, rev: number, cost: number }> = {};

    monthlyOrders.forEach(o => {
      revenue += o.totalPrice;
      o.items.forEach(item => {
        if (!productData[item.productId]) {
          const p = products.find(prod => prod.id === item.productId);
          productData[item.productId] = { 
            name: p?.name || 'Desconocido', 
            qty: 0, 
            rev: 0, 
            cost: calculateProductCost(item.productId) 
          };
        }

        const effectivePrice = item.unitPrice !== undefined ? item.unitPrice : (products.find(p => p.id === item.productId)?.price || 0);

        productData[item.productId].qty += item.quantity;
        productData[item.productId].rev += item.quantity * effectivePrice;
        totalCogs += item.quantity * productData[item.productId].cost;
      });
    });

    const grossProfit = revenue - totalCogs;
    const marginPct = revenue > 0 ? (grossProfit / revenue) * 100 : 0;

    return {
      revenue,
      totalCogs,
      grossProfit,
      marginPct,
      topProducts: Object.values(productData).sort((a, b) => b.rev - a.rev)
    };
  }, [monthlyOrders, products, ingredients]);

  const handlePrint = () => window.print();

  return (
    <div className="space-y-6 pb-12">
      {/* Header Adaptado */}
      <div className="flex flex-col sm:flex-row justify-between items-center gap-4 print:hidden">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Reportes de Negocio</h2>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 shadow-sm overflow-x-auto no-scrollbar max-w-full">
          <button 
            onClick={() => setActiveTab('operativo')}
            className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg transition-all whitespace-nowrap ${activeTab === 'operativo' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <Package size={16} /> Operativo
          </button>
          <button 
            onClick={() => setActiveTab('contabilidad')}
            className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg transition-all whitespace-nowrap ${activeTab === 'contabilidad' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <DollarSign size={16} /> Contabilidad
          </button>
          <button 
            onClick={() => setActiveTab('historial')}
            className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg transition-all whitespace-nowrap ${activeTab === 'historial' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <History size={16} /> Historial
          </button>
        </div>
      </div>

      {/* Selector de Mes y Print */}
      <div className="flex justify-end gap-3 print:hidden">
        <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-lg px-3 py-1.5 shadow-sm">
          <Calendar size={16} className="text-slate-400" />
          <input 
            type="month" 
            value={month} 
            onChange={e => setMonth(e.target.value)}
            className="text-sm font-medium outline-none bg-transparent"
          />
        </div>
        <button 
          onClick={handlePrint}
          className="bg-slate-800 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-slate-900 shadow-sm text-sm"
        >
          <Printer size={16} /> Imprimir
        </button>
      </div>

      {activeTab === 'operativo' && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
          {/* Dashboard Operativo Rápido */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-xs font-bold text-slate-400 uppercase mb-1">Volumen de Ventas</p>
              <h4 className="text-2xl font-bold text-slate-800">{monthlyOrders.length} Pedidos</h4>
              <p className="text-[10px] text-slate-500 mt-1 italic">Entregados y pagados en el periodo.</p>
            </div>
            <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-xs font-bold text-slate-400 uppercase mb-1">Producto Estrella</p>
              <h4 className="text-xl font-bold text-indigo-600 truncate">{stats.topProducts[0]?.name || 'N/A'}</h4>
              <p className="text-[10px] text-slate-500 mt-1">{stats.topProducts[0]?.qty || 0} unidades vendidas.</p>
            </div>
            <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-xs font-bold text-slate-400 uppercase mb-1">Insumos Críticos</p>
              <h4 className="text-2xl font-bold text-red-500">
                {ingredients.filter(i => i.currentStock <= i.minStock).length} Alertas
              </h4>
            </div>
          </div>

          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            <div className="p-4 bg-slate-50 border-b border-slate-200 font-bold text-slate-700 flex items-center gap-2">
              <TrendingUp size={18} className="text-indigo-600" /> Rendimiento por Producto
            </div>
            <table className="w-full text-left text-sm">
              <thead className="bg-white border-b border-slate-100 text-slate-500 uppercase text-[10px] font-bold">
                <tr>
                  <th className="px-6 py-3">Producto</th>
                  <th className="px-6 py-3 text-center">Cant.</th>
                  <th className="px-6 py-3 text-right">Ingresos</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {stats.topProducts.map((p, i) => (
                  <tr key={i} className="hover:bg-slate-50">
                    <td className="px-6 py-4 font-medium text-slate-800">{p.name}</td>
                    <td className="px-6 py-4 text-center text-slate-600 font-mono">{p.qty}</td>
                    <td className="px-6 py-4 text-right font-bold text-slate-800">{formatCurrency(p.rev)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'contabilidad' && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
          {/* Tarjetas Financieras */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Ingresos Totales</p>
              <h4 className="text-2xl font-bold text-indigo-600">{formatCurrency(stats.revenue)}</h4>
            </div>
            <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Costo Ventas (Insumos)</p>
              <h4 className="text-2xl font-bold text-slate-400">{formatCurrency(stats.totalCogs)}</h4>
            </div>
            <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Utilidad Bruta</p>
              <h4 className="text-2xl font-bold text-emerald-600">{formatCurrency(stats.grossProfit)}</h4>
            </div>
            <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Margen Bruto (%)</p>
              <div className="flex items-center gap-2">
                <h4 className="text-2xl font-bold text-slate-800">{stats.marginPct.toFixed(1)}%</h4>
                {stats.marginPct > 40 ? <ArrowUpRight className="text-emerald-500" /> : <ArrowDownRight className="text-amber-500" />}
              </div>
            </div>
          </div>

          {/* Estado de Resultados Simplificado */}
          <div className="bg-white rounded-2xl border border-slate-200 shadow-lg overflow-hidden">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center">
              <div>
                <h3 className="text-xl font-bold">Estado de Resultados</h3>
                <p className="text-xs text-slate-400">Simplificado - Base Insumos</p>
              </div>
              <PieChart size={32} className="text-indigo-400" />
            </div>
            <div className="p-6 space-y-4">
              <div className="flex justify-between items-center py-2 border-b border-slate-100">
                <span className="text-slate-600 font-medium">Ingresos por Ventas (+)</span>
                <span className="text-lg font-bold text-slate-800">{formatCurrency(stats.revenue)}</span>
              </div>
              <div className="flex justify-between items-center py-2 border-b border-slate-100">
                <span className="text-slate-600 font-medium">Costo de Mercadería Vendida (CMV) (-)</span>
                <span className="text-lg font-bold text-red-500">({formatCurrency(stats.totalCogs)})</span>
              </div>
              <div className="flex justify-between items-center py-4 bg-emerald-50 px-4 rounded-xl">
                <span className="text-emerald-800 font-bold text-lg">UTILIDAD BRUTA (=)</span>
                <div className="text-right">
                  <span className="block text-2xl font-black text-emerald-700">{formatCurrency(stats.grossProfit)}</span>
                  <span className="text-xs text-emerald-600 font-medium">Margen del {stats.marginPct.toFixed(1)}% sobre ventas</span>
                </div>
              </div>

              <div className="pt-4">
                <div className="flex items-center gap-2 text-amber-600 text-[10px] font-bold uppercase mb-2">
                  <Wallet size={14} /> Análisis de Rentabilidad por Producto
                </div>
                <div className="space-y-3">
                  {stats.topProducts.slice(0, 5).map((p, idx) => {
                    const unitCost = p.cost;
                    const unitPrice = p.qty > 0 ? (p.rev / p.qty) : 0;
                    const unitProfit = unitPrice - unitCost;
                    const prodMargin = unitPrice > 0 ? (unitProfit / unitPrice) * 100 : 0;

                    return (
                      <div key={idx} className="bg-slate-50 p-3 rounded-lg flex justify-between items-center">
                        <div>
                          <p className="font-bold text-slate-800 text-sm">{p.name}</p>
                          <p className="text-[10px] text-slate-500">Costo: {formatCurrency(unitCost)} | Precio: {formatCurrency(unitPrice)}</p>
                        </div>
                        <div className="text-right">
                          <p className={`font-bold text-sm ${unitProfit > 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                            +{formatCurrency(unitProfit)}/u
                          </p>
                          <span className="text-[10px] bg-white px-2 py-0.5 rounded border border-slate-200 text-slate-600 font-mono">
                            {prodMargin.toFixed(0)}% margin
                          </span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          </div>

          <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 text-[11px] text-indigo-700 italic">
            * Nota: Este informe calcula la utilidad bruta basada exclusivamente en el costo de los ingredientes definidos en tus recetas actuales. No incluye mano de obra, luz, gas o empaques si no están en la receta.
          </div>
        </div>
      )}

      {activeTab === 'historial' && (
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden animate-in fade-in">
          <div className="p-4 bg-slate-50 border-b border-slate-200 font-bold text-slate-700">
            Cierres de Caja Archivados
          </div>
          {monthClosures.length === 0 ? (
            <div className="p-12 text-center text-slate-400 italic">No hay cierres previos registrados.</div>
          ) : (
            <table className="w-full text-left text-sm">
              <thead className="bg-white border-b border-slate-100 text-slate-400 uppercase text-[10px] font-bold">
                <tr>
                  <th className="px-6 py-3">Periodo</th>
                  <th className="px-6 py-3">Fecha</th>
                  <th className="px-6 py-3 text-center">Pedidos</th>
                  <th className="px-6 py-3 text-right">Monto</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {monthClosures.map(c => (
                  <tr key={c.id} className="hover:bg-slate-50">
                    <td className="px-6 py-4 font-bold text-slate-700">{c.periodLabel}</td>
                    <td className="px-6 py-4 text-slate-500 text-xs">
                      {new Date(c.date).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-4 text-center font-mono">{c.totalOrders}</td>
                    <td className="px-6 py-4 text-right font-bold text-emerald-600">{formatCurrency(c.totalRevenue)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useBakery } from '../context/BakeryContext';
import { 
  Printer, 
  TrendingUp, 
  Package, 
  History, 
  Calendar, 
  DollarSign, 
  PieChart, 
  ArrowUpRight, 
  ArrowDownRight, 
  Wallet, 
  ChevronRight, 
  AlertTriangle,
  ReceiptText
} from 'lucide-react';
import { formatStock, formatCurrency, toBaseUnit, fromBaseUnit } from '../utils/conversions';
import { UnitType, RecipeItem } from '../types';

export const Reports: React.FC = () => {
  const { orders, products, ingredients, monthClosures } = useBakery();
  const [activeTab, setActiveTab] = useState<'operativo' | 'contabilidad' | 'historial'>('operativo');
  const [month, setMonth] = useState(new Date().toISOString().slice(0, 7)); // YYYY-MM

  // --- LÓGICA DE CÁLCULO DE COSTOS (CORREGIDA) ---

  // Calcula el costo de producción de 1 unidad de producto de forma recursiva
  const calculateProductCost = (prodId: string): number => {
    const prod = products.find(p => p.id === prodId);
    if (!prod) return 0;

    return prod.recipe.reduce((acc, item) => {
      const type = item.type || 'INGREDIENT';

      if (type === 'INGREDIENT') {
        const ing = ingredients.find(i => i.id === item.ingredientId);
        if (!ing) return acc;

        // 1. Convertir la cantidad de la receta a unidades base (g, ml, u)
        const amountInBase = toBaseUnit(item.quantity, item.unit);
        // 2. Convertir de unidades base a la unidad de compra del ingrediente (ej. kg)
        const amountInIngUnit = fromBaseUnit(amountInBase, ing.unit);
        // 3. Multiplicar por el costo por unidad de compra
        return acc + (amountInIngUnit * ing.costPerUnit);
      } else {
        // Es un sub-producto (recursión)
        // Se asume que la cantidad en la receta es el multiplicador del lote base del subproducto
        return acc + (calculateProductCost(item.ingredientId) * item.quantity);
      }
    }, 0);
  };

  // --- PROCESAMIENTO DE DATOS ---

  const monthlyOrders = useMemo(() => orders.filter(o => 
    o.deliveryDate.startsWith(month) && (o.status === 'Entregado' || o.status === 'Pagado')
  ), [orders, month]);

  const stats = useMemo(() => {
    let revenue = 0;
    let totalCogs = 0; // CMV: Costo de Mercadería Vendida
    const productMap: Record<string, { name: string, qty: number, rev: number, cost: number }> = {};

    monthlyOrders.forEach(o => {
      revenue += o.totalPrice;
      o.items.forEach(item => {
        if (!productMap[item.productId]) {
          const p = products.find(prod => prod.id === item.productId);
          productMap[item.productId] = { 
            name: p?.name || 'Desconocido', 
            qty: 0, 
            rev: 0, 
            cost: calculateProductCost(item.productId) 
          };
        }

        // Usamos el precio guardado en el pedido si existe (histórico), si no el actual del catálogo
        const effectiveUnitPrice = item.unitPrice !== undefined 
          ? item.unitPrice 
          : (products.find(p => p.id === item.productId)?.price || 0);

        productMap[item.productId].qty += item.quantity;
        productMap[item.productId].rev += item.quantity * effectiveUnitPrice;
        totalCogs += item.quantity * productMap[item.productId].cost;
      });
    });

    const grossProfit = revenue - totalCogs;
    const marginPct = revenue > 0 ? (grossProfit / revenue) * 100 : 0;
    const sortedProducts = Object.values(productMap).sort((a, b) => b.rev - a.rev);

    return {
      revenue,
      totalCogs,
      grossProfit,
      marginPct,
      topProducts: sortedProducts
    };
  }, [monthlyOrders, products, ingredients]);

  const lowStockAlerts = ingredients.filter(i => i.currentStock <= i.minStock);

  const handlePrint = () => window.print();

  return (
    <div className="space-y-6 pb-12">
      {/* Selector de Módulos (Tabs) */}
      <div className="flex flex-col sm:flex-row justify-between items-center gap-4 print:hidden">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Reportes de Pastelería</h2>
          <p className="text-slate-500 text-sm">Información operativa y contable del negocio.</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200 shadow-sm overflow-x-auto no-scrollbar max-w-full">
          <button 
            onClick={() => setActiveTab('operativo')}
            className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-xl transition-all whitespace-nowrap ${activeTab === 'operativo' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <Package size={16} /> Gestión Operativa
          </button>
          <button 
            onClick={() => setActiveTab('contabilidad')}
            className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-xl transition-all whitespace-nowrap ${activeTab === 'contabilidad' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <ReceiptText size={16} /> Contabilidad
          </button>
          <button 
            onClick={() => setActiveTab('historial')}
            className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-xl transition-all whitespace-nowrap ${activeTab === 'historial' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <History size={16} /> Historial
          </button>
        </div>
      </div>

      {/* Selector de Mes y Acciones */}
      <div className="flex justify-end gap-3 print:hidden">
        <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-lg px-3 py-1.5 shadow-sm">
          <Calendar size={16} className="text-slate-400" />
          <input 
            type="month" 
            value={month} 
            onChange={e => setMonth(e.target.value)}
            className="text-sm font-medium outline-none bg-transparent"
          />
        </div>
        <button 
          onClick={handlePrint}
          className="bg-slate-800 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-slate-900 shadow-sm text-sm"
        >
          <Printer size={16} /> Imprimir Reporte
        </button>
      </div>

      {/* --- MÓDULO: GESTIÓN OPERATIVA --- */}
      {activeTab === 'operativo' && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-xs font-bold text-slate-400 uppercase mb-2">Pedidos Cerrados</p>
              <h4 className="text-3xl font-black text-slate-800">{monthlyOrders.length}</h4>
              <p className="text-[10px] text-slate-500 mt-1 italic">Ventas finalizadas en el mes.</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-xs font-bold text-slate-400 uppercase mb-2">Más Vendido</p>
              <h4 className="text-xl font-bold text-indigo-600 truncate">{stats.topProducts[0]?.name || '---'}</h4>
              <p className="text-[10px] text-slate-500 mt-1">{stats.topProducts[0]?.qty || 0} unidades totales.</p>
            </div>
            <div className={`p-6 rounded-2xl border shadow-sm ${lowStockAlerts.length > 0 ? 'bg-red-50 border-red-100' : 'bg-white border-slate-200'}`}>
              <p className="text-xs font-bold text-slate-400 uppercase mb-2">Alertas de Stock</p>
              <h4 className={`text-3xl font-black ${lowStockAlerts.length > 0 ? 'text-red-600' : 'text-emerald-600'}`}>
                {lowStockAlerts.length}
              </h4>
              <p className="text-[10px] text-slate-500 mt-1">Insumos bajo el mínimo.</p>
            </div>
          </div>

          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            <div className="p-4 bg-slate-50 border-b border-slate-200 font-bold text-slate-700 flex items-center justify-between">
              <div className="flex items-center gap-2"><TrendingUp size={18} className="text-indigo-600" /> Movimiento de Productos</div>
              <span className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full uppercase">Volumen</span>
            </div>
            <table className="w-full text-left text-sm">
              <thead className="bg-white border-b border-slate-100 text-slate-500 uppercase text-[10px] font-bold">
                <tr>
                  <th className="px-6 py-4">Producto</th>
                  <th className="px-6 py-4 text-center">Cantidad Vendida</th>
                  <th className="px-6 py-4 text-right">Total Ingresos</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {stats.topProducts.map((p, i) => (
                  <tr key={i} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-semibold text-slate-800">{p.name}</td>
