export const TopperDesigner: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [statusMessage, setStatusMessage] = useState('');

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const generateTopper = async () => {
    if (!image) return;

    setLoading(true);
    setError(null);
    setStatusMessage('Analizando referencia y creando diseño...');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const base64Data = image.split(',')[1];
      const mimeType = image.split(';')[0].split(':')[1];

      const prompt = `Act as a professional graphic designer specializing in birthday cake toppers. 
      Create a high-resolution circular birthday topper design strictly based on the provided reference image. 

      REQUIREMENTS:
      1. Composition: A perfect, clean circular design centered on a solid square background.
      2. Theme Fidelity: Maintain the exact central theme, color palette, and characters shown in the reference (e.g., specific cartoons, brands, or styles).
      3. Quality: Vibrant colors, razor-sharp edges, professional digital illustration style.
      4. Typography: Incorporate the text: "${text || '¡Feliz Cumpleaños!'}" in an elegant, stylized font that fits the theme perfectly. The text must be legible and well-integrated.
      5. Atmosphere: Festive, clean, and professional. 

      Output only the final high-quality 1:1 image.`;

      const response = await ai.models.generateContent({
