      // Square canvas for 1:1 output
      canvas.width = 1024;
      canvas.height = 1024;

      // Calculate source and destination
      // We want to draw exactly what's visible in the container
      const containerWidth = container.offsetWidth;
      const containerHeight = container.offsetHeight;

      // Draw a white background first
      ctx.fillStyle = 'white';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Scale ratio from UI to Canvas
      const scaleUItoCanvas = 1024 / containerWidth;

      // Center the image based on zoom and position
      const drawWidth = img.naturalWidth * (containerWidth / img.width) * zoom * scaleUItoCanvas;
      const drawHeight = img.naturalHeight * (containerHeight / img.height) * zoom * scaleUItoCanvas;

      const drawX = (position.x * scaleUItoCanvas) + (canvas.width / 2) - (drawWidth / 2);
      const drawY = (position.y * scaleUItoCanvas) + (canvas.height / 2) - (drawHeight / 2);

      ctx.drawImage(img, drawX, drawY, drawWidth, drawHeight);
