    link.download = `topper_${text.replace(/\s+/g, '_') || 'diseno'}.png`;
    link.click();
  };

  const reset = () => {
    setImage(null);
    setResult(null);
    setText('');
    setError(null);
    setZoom(1);
    setPosition({ x: 0, y: 0 });
