                {/* Zoom Controls */}
                <div className="flex items-center gap-4 bg-slate-50 p-4 rounded-xl border border-slate-100">
                   <button onClick={() => setZoom(Math.max(0.5, zoom - 0.2))} className="p-1 hover:bg-slate-200 rounded text-slate-600 transition-colors">
