                   />
                   <button onClick={() => setZoom(Math.min(4, zoom + 0.2))} className="p-1 hover:bg-slate-200 rounded text-slate-600 transition-colors">
                     <ZoomIn size={20} />
                   </button>
                   <span className="text-xs font-bold text-slate-500 min-w-[3.5rem] text-right">
