        </div>

        {/* Resultado */}
        <div className="bg-slate-900 rounded-3xl p-8 flex flex-col items-center justify-center min-h-[500px] relative overflow-hidden shadow-inner">
          <div className="absolute top-0 left-0 w-full h-full opacity-5 pointer-events-none">
             <div className="grid grid-cols-4 gap-4 rotate-12 scale-150">
