import React, { useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { 
  Upload, 
  Type, 
  Sparkles, 
  Loader2, 
  Download, 
  X, 
  Image as ImageIcon,
  AlertCircle,
  RefreshCcw,
  Circle,
  Sticker,
  ZoomIn,
  ZoomOut,
  Move,
  Palette
} from 'lucide-react';

export const TopperDesigner: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [text, setText] = useState('');
  const [themePrompt, setThemePrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [statusMessage, setStatusMessage] = useState('');

  // Zoom & Pan State
  const [zoom, setZoom] = useState(1);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setZoom(1);
        setPosition({ x: 0, y: 0 });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!image) return;
    setIsDragging(true);
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;
    setDragStart({ x: clientX - position.x, y: clientY - position.y });
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !image) return;
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;
    setPosition({
      x: clientX - dragStart.x,
      y: clientY - dragStart.y
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const getFramedImageBase64 = (): Promise<string | null> => {
    return new Promise((resolve) => {
      if (!image) {
        resolve(null);
        return;
      }
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      const img = imageRef.current;
      const container = containerRef.current;

      if (!ctx || !img || !container) {
        resolve(null);
        return;
      }

      canvas.width = 1024;
      canvas.height = 1024;
      ctx.fillStyle = 'white';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      const containerWidth = container.offsetWidth;
      const containerHeight = container.offsetHeight;
      const scaleFactor = 1024 / containerWidth;

      const imgRatio = img.naturalWidth / img.naturalHeight;
      const containerRatio = containerWidth / containerHeight;

      let baseWidth, baseHeight;
      if (imgRatio > containerRatio) {
        baseWidth = 1024;
        baseHeight = 1024 / imgRatio;
      } else {
        baseWidth = 1024 * imgRatio;
        baseHeight = 1024;
      }

      const finalWidth = baseWidth * zoom;
      const finalHeight = baseHeight * zoom;
      const x = (position.x * scaleFactor) + (1024 / 2) - (finalWidth / 2);
      const y = (position.y * scaleFactor) + (1024 / 2) - (finalHeight / 2);

      ctx.drawImage(img, x, y, finalWidth, finalHeight);
      resolve(canvas.toDataURL('image/jpeg', 0.95).split(',')[1]);
    });
  };

  const generateTopper = async () => {
    if (!image && !themePrompt) {
      setError("Sube una imagen o describe un tema para comenzar.");
      return;
    }

    setLoading(true);
    setError(null);
    setStatusMessage(image ? 'Capturando encuadre...' : 'Ideando diseño...');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const framedBase64 = await getFramedImageBase64();

      let prompt = `Act as a professional cake topper graphic designer. 
      Create a high-resolution 1:1 square image featuring a perfect circular birthday topper.

      REQUIREMENTS:
      1. Composition: A clean circular artwork centered on a solid neutral background.
      2. Content: ${themePrompt ? `The theme is "${themePrompt}". ` : ''}${image ? 'Follow the exact framing and composition of the provided reference image. ' : 'Create a festive and professional original illustration. '}
      3. Quality: Sharp edges, vibrant colors, premium digital illustration style.
      4. Typography: Integrate the text: "${text || '¡Feliz Cumpleaños!'}" in a stylized, readable, and elegant font that fits the theme.
      5. Execution: ${image ? 'Strictly maintain character positions and zoom from the reference. ' : 'Make the composition balanced and professional for cake decoration. '}`;

      const contents: any = {
        parts: [{ text: prompt }]
      };

      if (framedBase64) {
        contents.parts.unshift({ 
          inlineData: { data: framedBase64, mimeType: 'image/jpeg' } 
        });
      }

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents,
        config: {
          imageConfig: { aspectRatio: "1:1" }
        }
      });

      const candidate = response.candidates?.[0];
      if (candidate) {
        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            setResult(`data:${part.inlineData.mimeType};base64,${part.inlineData.data}`);
            setStatusMessage('');
            break;
          }
        }
      }
    } catch (err: any) {
      console.error("Topper Designer Error:", err);
      setError("No se pudo completar el diseño. Intenta con una descripción más detallada.");
    } finally {
      setLoading(false);
    }
  };

  const downloadImage = () => {
    if (!result) return;
    const link = document.createElement('a');
    link.href = result;
    link.download = `topper_${text.replace(/\s+/g, '_') || 'diseno'}.png`;
    link.click();
  };

  const reset = () => {
    setImage(null);
    setResult(null);
    setText('');
    setThemePrompt('');
    setError(null);
    setZoom(1);
    setPosition({ x: 0, y: 0 });
  };

  return (
    <div className="space-y-6 pb-20">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <Sticker className="text-indigo-600" /> Diseñador de Toppers Pro
          </h2>
          <p className="text-slate-500 text-sm">Crea diseños circulares desde fotos o descripciones.</p>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-6">
          {/* 1. Referencia Visual */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <ImageIcon size={18} className="text-indigo-500" /> 1. Imagen de Referencia (Opcional)
            </h3>

            {!image ? (
              <label className="flex flex-col items-center justify-center w-full h-64 border-2 border-dashed border-slate-300 rounded-2xl cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors">
                <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
                  <Upload className="w-8 h-8 mb-3 text-slate-400 mx-auto" />
                  <p className="text-sm text-slate-500">
                    Sube una foto para respetar su encuadre
                  </p>
                </div>
                <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
              </label>
            ) : (
              <div className="space-y-4">
                <div 
                  ref={containerRef}
                  className="relative w-full h-64 bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden cursor-move touch-none"
                  onMouseDown={handleMouseDown}
                  onMouseMove={handleMouseMove}
                  onMouseUp={handleMouseUp}
                  onMouseLeave={handleMouseUp}
                  onTouchStart={handleMouseDown}
                  onTouchMove={handleMouseMove}
                  onTouchEnd={handleMouseUp}
                >
                  <img 
                    ref={imageRef}
                    src={image} 
                    alt="Ref" 
                    className="absolute max-w-none transition-transform duration-75 pointer-events-none select-none"
                    style={{
                      transform: `translate(${position.x}px, ${position.y}px) scale(${zoom})`,
                      left: '50%', top: '50%', marginLeft: '-50%', marginTop: '-50%',
                      width: '100%', height: '100%', objectFit: 'contain'
                    }}
                  />
                  <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                    <div className="w-[220px] h-[220px] rounded-full border-2 border-white/90 shadow-[0_0_0_9999px_rgba(0,0,0,0.5)] flex items-center justify-center">
                       <Move size={32} className="text-white/20" />
                    </div>
                  </div>
                  <button onClick={() => setImage(null)} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full"><X size={14} /></button>
                </div>
                <div className="flex items-center gap-3 bg-slate-50 p-3 rounded-xl">
                   <ZoomOut size={16} className="text-slate-400" />
                   <input type="range" min="0.5" max="4" step="0.1" value={zoom} onChange={e => setZoom(parseFloat(e.target.value))} className="flex-1 accent-indigo-600" />
                   <ZoomIn size={16} className="text-slate-400" />
                </div>
              </div>
            )}
          </div>

          {/* 2. Tema del Diseño */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Palette size={18} className="text-indigo-500" /> 2. Tema de Referencia {!image && '*'}
            </h3>
            <textarea 
              placeholder="Ej: Personajes de Toy Story en la nubes, estilo acuarela, flores rosas con bordes dorados..."
              className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none text-sm min-h-[80px] resize-none"
              value={themePrompt}
              onChange={e => setThemePrompt(e.target.value)}
            />
            {!image && !themePrompt && <p className="text-[10px] text-red-500 mt-2 flex items-center gap-1"><AlertCircle size={10} /> Debes describir un tema si no subes imagen.</p>}
          </div>

          {/* 3. Texto del Diseño */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Type size={18} className="text-indigo-500" /> 3. Texto del Diseño
            </h3>
            <input 
              type="text"
              placeholder="Ej: ¡Feliz Cumpleaños Martín!"
              className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium"
              value={text}
              onChange={(e) => setText(e.target.value)}
            />
          </div>

          <button 
            onClick={generateTopper}
            disabled={(!image && !themePrompt) || loading}
            className={`w-full py-4 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-lg ${
              (!image && !themePrompt) || loading 
                ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-100 hover:-translate-y-0.5'
            }`}
          >
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />}
            {loading ? 'Diseñando...' : (image ? 'Rediseñar Encuadre' : 'Generar desde Tema')}
          </button>
        </div>

        {/* Lado del Resultado */}
        <div className="bg-slate-900 rounded-3xl p-8 flex flex-col items-center justify-center min-h-[500px] relative overflow-hidden shadow-2xl">
          <div className="absolute inset-0 opacity-5 pointer-events-none">
             <div className="grid grid-cols-4 gap-4 rotate-12 scale-150">
                {[...Array(16)].map((_, i) => <Circle key={i} size={120} className="text-white" />)}
             </div>
          </div>

          {!result && !loading && (
            <div className="text-center space-y-4 z-10">
              <div className="w-20 h-20 bg-slate-800/50 backdrop-blur-sm rounded-full flex items-center justify-center mx-auto text-slate-600 border border-slate-700/50">
                <Palette size={40} />
              </div>
              <div className="max-w-xs">
                <h4 className="text-white font-bold text-lg">Estudio de Diseño IA</h4>
                <p className="text-slate-400 text-sm mt-2">Configura tu diseño a la izquierda y presiona el botón para verlo aquí.</p>
              </div>
            </div>
          )}

          {loading && (
            <div className="text-center space-y-6 z-10">
              <div className="relative">
                <div className="w-56 h-56 rounded-full border-4 border-slate-800 flex items-center justify-center shadow-[0_0_50px_rgba(79,70,229,0.1)]">
                  <Loader2 size={64} className="text-indigo-500 animate-spin" />
                </div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="w-48 h-48 rounded-full border-2 border-indigo-500/20 animate-pulse"></div>
                </div>
              </div>
              <p className="text-white font-bold animate-pulse text-lg tracking-wide">{statusMessage}</p>
            </div>
          )}

          {result && (
            <div className="space-y-8 w-full text-center z-10 animate-in zoom-in duration-500">
               <div className="relative group mx-auto max-w-sm">
                 <img src={result} alt="Topper" className="w-full aspect-square object-contain rounded-2xl shadow-2xl border-4 border-white/10 bg-white" />
                 <div className="absolute inset-0 rounded-2xl border-2 border-indigo-500/30 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
               </div>

               <div className="flex flex-col sm:flex-row gap-4 justify-center">
                  <button onClick={downloadImage} className="bg-emerald-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-900/30 hover:-translate-y-1">
                    <Download size={18} /> Descargar PNG
                  </button>
                  <button onClick={reset} className="bg-slate-800 text-slate-300 px-6 py-3 rounded-2xl font-bold text-xs flex items-center justify-center gap-2 hover:bg-slate-700 transition-all border border-slate-700 hover:-translate-y-1">
                    <RefreshCcw size={16} /> Nuevo Diseño
                  </button>
               </div>

               <p className="text-[10px] text-slate-500 flex items-center justify-center gap-1 uppercase tracking-widest font-bold">
                 <AlertCircle size={10} /> 1024x1024 • Alta Resolución • 300 DPI
               </p>
            </div>
          )}

          {error && (
            <div className="bg-red-900/40 border border-red-500/40 p-8 rounded-3xl text-center space-y-4 max-w-sm z-10 backdrop-blur-md">
              <AlertCircle size={32} className="text-red-400 mx-auto" />
              <p className="text-red-100 font-medium text-sm">{error}</p>
              <button onClick={generateTopper} className="text-white bg-red-500 px-6 py-2 rounded-xl text-xs font-bold hover:bg-red-600 shadow-lg">Reintentar</button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { 
  Upload, 
