  Image as ImageIcon,
  AlertCircle,
  RefreshCcw,
  Circle,
  Sticker,
  ZoomIn,
  ZoomOut,
  Move,
  Palette
} from 'lucide-react';

export const TopperDesigner: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [text, setText] = useState('');
  const [themePrompt, setThemePrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [statusMessage, setStatusMessage] = useState('');

  // Zoom & Pan State
  const [zoom, setZoom] = useState(1);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setZoom(1);
        setPosition({ x: 0, y: 0 });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!image) return;
    setIsDragging(true);
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;
    setDragStart({ x: clientX - position.x, y: clientY - position.y });
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !image) return;
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;
    setPosition({
      x: clientX - dragStart.x,
      y: clientY - dragStart.y
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const getFramedImageBase64 = (): Promise<string | null> => {
    return new Promise((resolve) => {
      if (!image) {
        resolve(null);
        return;
      }
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      const img = imageRef.current;
      const container = containerRef.current;

      if (!ctx || !img || !container) {
        resolve(null);
        return;
      }

      canvas.width = 1024;
      canvas.height = 1024;
      ctx.fillStyle = 'white';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      const containerWidth = container.offsetWidth;
      const containerHeight = container.offsetHeight;
      const scaleFactor = 1024 / containerWidth;

      const imgRatio = img.naturalWidth / img.naturalHeight;
      const containerRatio = containerWidth / containerHeight;

      let baseWidth, baseHeight;
      if (imgRatio > containerRatio) {
        baseWidth = 1024;
        baseHeight = 1024 / imgRatio;
      } else {
        baseWidth = 1024 * imgRatio;
        baseHeight = 1024;
      }

      const finalWidth = baseWidth * zoom;
      const finalHeight = baseHeight * zoom;
      const x = (position.x * scaleFactor) + (1024 / 2) - (finalWidth / 2);
      const y = (position.y * scaleFactor) + (1024 / 2) - (finalHeight / 2);

      ctx.drawImage(img, x, y, finalWidth, finalHeight);
      resolve(canvas.toDataURL('image/jpeg', 0.95).split(',')[1]);
    });
  };

  const generateTopper = async () => {
    if (!image && !themePrompt) {
      setError("Sube una imagen o describe un tema para comenzar.");
      return;
    }

    setLoading(true);
    setError(null);
    setStatusMessage(image ? 'Procesando encuadre y estilo...' : 'Generando diseño desde tema...');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const framedBase64 = await getFramedImageBase64();

      let prompt = `Act as a professional cake topper graphic designer. 
      Create a high-resolution 1:1 square image featuring a perfect circular birthday topper design.

      STRICT REQUIREMENTS:
      1. Composition: A clean circular artwork centered perfectly on a solid neutral square background.
      2. Content: ${themePrompt ? `The theme requested is "${themePrompt}". ` : ''}${image ? 'You MUST strictly follow the exact framing, zoom, and positioning provided in the reference image. The characters and elements should stay exactly where they are. ' : 'Create a festive, professional and balanced original illustration based on the theme. '}
      3. Quality: Vibrant colors, professional digital art style, sharp edges.
      4. Typography: Include the text: "${text || '¡Feliz Cumpleaños!'}" using a stylized, high-quality font that integrates seamlessly into the circular design.
      5. Execution: Ensure the final result is a premium-looking cake topper ready for high-quality printing.`;

      const contents: any = {
        parts: [{ text: prompt }]
      };

      if (framedBase64) {
        contents.parts.unshift({ 
          inlineData: { data: framedBase64, mimeType: 'image/jpeg' } 
        });
      }

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents,
        config: {
          imageConfig: { aspectRatio: "1:1" }
        }
      });

      const candidate = response.candidates?.[0];
      if (candidate && candidate.content && candidate.content.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            setResult(`data:${part.inlineData.mimeType};base64,${part.inlineData.data}`);
            setStatusMessage('');
            break;
          }
        }
      } else {
        throw new Error("Respuesta de IA vacía");
      }
    } catch (err: any) {
      console.error("Topper Designer Error:", err);
      setError("No se pudo completar el diseño. Intenta ajustando el tema o el encuadre.");
    } finally {
      setLoading(false);
    }
  };

  const downloadImage = () => {
    if (!result) return;
    const link = document.createElement('a');
    link.href = result;
    link.download = `topper_${text.replace(/\s+/g, '_') || 'diseno'}.png`;
    link.click();
  };

  const reset = () => {
    setImage(null);
    setResult(null);
    setText('');
    setThemePrompt('');
    setError(null);
    setZoom(1);
    setPosition({ x: 0, y: 0 });
  };

  return (
    <div className="space-y-6 pb-20">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <Sticker className="text-indigo-600" /> Diseñador de Toppers Pro
          </h2>
          <p className="text-slate-500 text-sm">Diseño circular inteligente para tus pasteles.</p>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-6">
          {/* 1. Referencia Visual */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <ImageIcon size={18} className="text-indigo-500" /> 1. Imagen de Referencia (Opcional)
            </h3>

            {!image ? (
              <label className="flex flex-col items-center justify-center w-full h-64 border-2 border-dashed border-slate-300 rounded-2xl cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors">
                <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
                  <Upload className="w-8 h-8 mb-3 text-slate-400 mx-auto" />
                  <p className="text-sm text-slate-500">
                    Sube una foto para encuadrar tu diseño
                  </p>
                  <p className="text-[10px] text-slate-400 mt-1">O déjalo en blanco para generar desde un tema.</p>
                </div>
                <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
              </label>
            ) : (
              <div className="space-y-4">
                <div 
                  ref={containerRef}
                  className="relative w-full h-64 bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden cursor-move touch-none shadow-inner"
                  onMouseDown={handleMouseDown}
                  onMouseMove={handleMouseMove}
                  onMouseUp={handleMouseUp}
                  onMouseLeave={handleMouseUp}
                  onTouchStart={handleMouseDown}
                  onTouchMove={handleMouseMove}
                  onTouchEnd={handleMouseUp}
                >
                  <img 
                    ref={imageRef}
                    src={image} 
                    alt="Ref" 
                    className="absolute max-w-none transition-transform duration-75 pointer-events-none select-none"
                    style={{
                      transform: `translate(${position.x}px, ${position.y}px) scale(${zoom})`,
                      left: '50%', top: '50%', marginLeft: '-50%', marginTop: '-50%',
                      width: '100%', height: '100%', objectFit: 'contain'
                    }}
                  />
                  <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                    <div className="w-[220px] h-[220px] rounded-full border-4 border-white/90 shadow-[0_0_0_9999px_rgba(0,0,0,0.6)] flex items-center justify-center">
                       <Move size={32} className="text-white/20" />
                    </div>
                  </div>
                  <button onClick={() => setImage(null)} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full shadow-lg"><X size={14} /></button>
                </div>
                <div className="flex items-center gap-3 bg-slate-50 p-3 rounded-xl border border-slate-100">
                   <ZoomOut size={16} className="text-slate-400" />
                   <input type="range" min="0.5" max="4" step="0.05" value={zoom} onChange={e => setZoom(parseFloat(e.target.value))} className="flex-1 accent-indigo-600" />
                   <ZoomIn size={16} className="text-slate-400" />
                </div>
              </div>
            )}
          </div>

          {/* 2. Tema del Diseño */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Palette size={18} className="text-indigo-500" /> 2. Tema de Referencia {!image && '*'}
            </h3>
            <textarea 
              placeholder="Describe el estilo: 'Castillo de princesa rosa', 'Spider-man en la ciudad', 'Flores boho chic'..."
              className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none text-sm min-h-[80px] resize-none"
              value={themePrompt}
              onChange={e => setThemePrompt(e.target.value)}
            />
            {!image && !themePrompt && <p className="text-[10px] text-red-500 mt-2 flex items-center gap-1"><AlertCircle size={10} /> Requerido si no hay imagen.</p>}
          </div>

          {/* 3. Texto del Diseño */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Type size={18} className="text-indigo-500" /> 3. Texto del Diseño
            </h3>
            <input 
              type="text"
              placeholder="Ej: ¡Feliz Cumpleaños Martín!"
              className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium"
              value={text}
              onChange={(e) => setText(e.target.value)}
            />
          </div>

          <button 
            onClick={generateTopper}
            disabled={(!image && !themePrompt) || loading}
            className={`w-full py-4 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-lg ${
              (!image && !themePrompt) || loading 
                ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-100 hover:-translate-y-0.5'
            }`}
          >
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles />}
            {loading ? 'Creando Diseño...' : (image ? 'Rediseñar desde Foto' : 'Crear desde Tema')}
          </button>
        </div>

        {/* Lado del Resultado */}
        <div className="bg-slate-900 rounded-3xl p-8 flex flex-col items-center justify-center min-h-[500px] relative overflow-hidden shadow-2xl">
          <div className="absolute inset-0 opacity-5 pointer-events-none">
             <div className="grid grid-cols-4 gap-4 rotate-12 scale-150">
                {[...Array(16)].map((_, i) => <Circle key={i} size={120} className="text-white" />)}
             </div>
          </div>

          {!result && !loading && (
            <div className="text-center space-y-4 z-10">
              <div className="w-20 h-20 bg-slate-800/50 backdrop-blur-sm rounded-full flex items-center justify-center mx-auto text-slate-600 border border-slate-700/50">
                <Palette size={40} />
              </div>
              <div className="max-w-xs">
                <h4 className="text-white font-bold text-lg">Estudio Creativo IA</h4>
                <p className="text-slate-400 text-sm mt-2">Personaliza el diseño a la izquierda para ver el resultado profesional aquí.</p>
              </div>
            </div>
          )}

          {loading && (
            <div className="text-center space-y-6 z-10">
              <div className="relative">
                <div className="w-56 h-56 rounded-full border-4 border-slate-800 flex items-center justify-center shadow-[0_0_50px_rgba(79,70,229,0.15)]">
                  <Loader2 size={64} className="text-indigo-500 animate-spin" />
                </div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="w-48 h-48 rounded-full border-2 border-indigo-500/20 animate-pulse"></div>
                </div>
              </div>
              <p className="text-white font-bold animate-pulse text-lg tracking-wide">{statusMessage}</p>
            </div>
          )}

          {result && (
            <div className="space-y-8 w-full text-center z-10 animate-in zoom-in duration-500">
               <div className="relative group mx-auto max-w-sm">
                 <img src={result} alt="Topper" className="w-full aspect-square object-contain rounded-2xl shadow-2xl border-4 border-white/10 bg-white" />
                 <div className="absolute inset-0 rounded-2xl border-2 border-indigo-500/30 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
               </div>

               <div className="flex flex-col sm:flex-row gap-4 justify-center">
                  <button onClick={downloadImage} className="bg-emerald-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-900/30 hover:-translate-y-1">
                    <Download size={18} /> Descargar PNG
                  </button>
                  <button onClick={reset} className="bg-slate-800 text-slate-300 px-6 py-3 rounded-2xl font-bold text-xs flex items-center justify-center gap-2 hover:bg-slate-700 transition-all border border-slate-700 hover:-translate-y-1">
                    <RefreshCcw size={16} /> Nuevo Diseño
                  </button>
               </div>

               <p className="text-[10px] text-slate-500 flex items-center justify-center gap-1 uppercase tracking-widest font-bold">
                 <AlertCircle size={10} /> 1024x1024 • Listo para Recortar • 300 DPI
               </p>
            </div>
          )}

          {error && (
            <div className="bg-red-900/40 border border-red-500/40 p-8 rounded-3xl text-center space-y-4 max-w-sm z-10 backdrop-blur-md">
              <AlertCircle size={32} className="text-red-400 mx-auto" />
              <p className="text-red-100 font-medium text-sm">{error}</p>
              <button onClick={generateTopper} className="text-white bg-red-500 px-6 py-2 rounded-xl text-xs font-bold hover:bg-red-600 shadow-lg">Reintentar</button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useBakery } from '../context/BakeryContext';
import { Customer, Order } from '../types';
import { 
  Plus, 
  Search, 
  Edit2, 
  Trash2, 
  Phone, 
  MapPin, 
  X, 
  FileText, 
  Copy, 
  CheckCircle2, 
  Clock, 
  ExternalLink,
  DollarSign
} from 'lucide-react';
import { formatCurrency, formatDate } from '../utils/conversions';

export const Customers: React.FC = () => {
  const { customers, addCustomer, updateCustomer, deleteCustomer, orders, products, updateOrderStatus } = useBakery();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStatementOpen, setIsStatementOpen] = useState(false);
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Customer>>({
    name: '',
    phone: '',
    email: '',
    address: '',
    notes: ''
  });

  const handleEdit = (customer: Customer) => {
    setEditingId(customer.id);
    setFormData(customer);
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    setEditingId(null);
    setFormData({ name: '', phone: '', email: '', address: '', notes: '' });
    setIsModalOpen(true);
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation(); 
    if (window.confirm('¿Seguro que deseas eliminar este cliente? Se mantendrá el historial de pedidos.')) {
      deleteCustomer(id);
    }
  };

  const handleSave = () => {
    if (!formData.name) return;

    if (editingId) {
      updateCustomer({ ...formData, id: editingId } as Customer);
    } else {
      addCustomer({
        ...formData,
        id: Date.now().toString()
      } as Customer);
    }
    setIsModalOpen(false);
  };

  // --- Lógica de Cobranza ---

  const getCustomerData = (customerId: string) => {
    const customerOrders = orders.filter(o => o.customerId === customerId);

    // Pedidos Entregados pero NO pagados
    const unpaidOrders = customerOrders.filter(o => o.status === 'Entregado');
    const pendingAmount = unpaidOrders.reduce((acc, o) => acc + o.totalPrice, 0);

    // Total histórico (para estadísticas)
    const totalSpent = customerOrders
      .filter(o => o.status === 'Entregado' || o.status === 'Pagado')
      .reduce((acc, o) => acc + o.totalPrice, 0);

    return {
      count: customerOrders.length,
      spent: totalSpent,
      pendingAmount,
      unpaidOrders
    };
  };

  const handleOpenStatement = (customer: Customer) => {
    setSelectedCustomer(customer);
    setIsStatementOpen(true);
  };

  const copyToClipboard = (customer: Customer, unpaidOrders: Order[]) => {
    const header = `*Resumen de Cuenta - Pastelería PRO*\nHola ${customer.name}, te comparto el detalle de tus pedidos pendientes:\n\n`;
    const body = unpaidOrders.map(o => {
      const itemsStr = o.items.map(i => {
        const p = products.find(prod => prod.id === i.productId);
        return `${i.quantity}x ${p?.name || 'Producto'}`;
      }).join(', ');
      return `📅 ${formatDate(o.deliveryDate)}\n🍰 ${itemsStr}\n💰 *${formatCurrency(o.totalPrice)}*\n-------------------`;
    }).join('\n');

    const total = unpaidOrders.reduce((acc, o) => acc + o.totalPrice, 0);
    const footer = `\n*TOTAL PENDIENTE: ${formatCurrency(total)}*`;

    const fullText = header + body + footer;

    navigator.clipboard.writeText(fullText);
    alert('¡Resumen copiado! Ya puedes pegarlo en WhatsApp.');
  };

  const handleMarkAsPaid = async (orderId: string) => {
    if (window.confirm('¿Confirmar que este pedido ya fue pagado?')) {
      await updateOrderStatus(orderId, 'Pagado');
    }
  };

  const filtered = customers.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.phone?.includes(searchTerm)
  );

  return (
    <div className="space-y-6 pb-24 lg:pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Clientes y Cobranza</h2>
          <p className="text-slate-500 text-sm">Gestiona tu cartera de clientes y saldos pendientes.</p>
        </div>
        <button 
          onClick={handleAdd}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm transition-colors text-sm font-medium"
        >
          <Plus size={18} /> Nuevo Cliente
        </button>
      </div>

      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="text" 
          placeholder="Buscar por nombre o teléfono..." 
          className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-white"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filtered.map(customer => {
          const { count, spent, pendingAmount } = getCustomerData(customer.id);
          const hasDebt = pendingAmount > 0;

          return (
            <div key={customer.id} className={`bg-white rounded-2xl p-5 shadow-sm border transition-all hover:shadow-md ${hasDebt ? 'border-l-4 border-l-amber-500 border-y-slate-200 border-r-slate-200' : 'border-slate-200'}`}>
              <div className="flex justify-between items-start mb-4">
                <div className="flex items-center gap-3">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-lg ${hasDebt ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-600'}`}>
                    {customer.name.charAt(0).toUpperCase()}
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800 text-base">{customer.name}</h3>
                    <div className="flex items-center gap-1.5 text-[10px] text-slate-400 font-medium uppercase tracking-wider">
                      <Clock size={10} /> {count} Pedidos totales
                    </div>
                  </div>
                </div>
                <div className="flex gap-1">
                  <button 
                    onClick={() => handleEdit(customer)} 
                    className="p-2 text-slate-400 hover:text-indigo-600 rounded-lg hover:bg-indigo-50 transition-colors"
                  >
                    <Edit2 size={16} />
                  </button>
                  <button 
                    onClick={(e) => handleDelete(customer.id, e)} 
                    className="p-2 text-slate-400 hover:text-red-600 rounded-lg hover:bg-red-50 transition-colors"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>

              <div className="space-y-2 text-sm text-slate-600 mb-5 border-b border-slate-50 pb-4">
                {customer.phone && <div className="flex items-center gap-2 font-medium"><Phone size={14} className="text-slate-300"/> {customer.phone}</div>}
                {customer.address && <div className="flex items-center gap-2"><MapPin size={14} className="text-slate-300"/> <span className="truncate">{customer.address}</span></div>}
              </div>

              {/* Sección de Deuda / Cobranza */}
              {hasDebt ? (
                <div className="bg-amber-50 rounded-xl p-3 mb-4 border border-amber-100 animate-in fade-in zoom-in duration-300">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] font-bold text-amber-600 uppercase">Por Cobrar</span>
                    <span className="text-sm font-black text-amber-700">{formatCurrency(pendingAmount)}</span>
                  </div>
                  <button 
                    onClick={() => handleOpenStatement(customer)}
                    className="w-full mt-2 py-1.5 bg-amber-600 text-white rounded-lg text-xs font-bold flex items-center justify-center gap-1.5 hover:bg-amber-700 transition-colors shadow-sm"
                  >
                    <FileText size={14} /> Ver Detalle de Cobro
                  </button>
                </div>
              ) : (
                <div className="flex justify-between items-center mb-4 px-1">
                  <span className="text-[10px] font-bold text-slate-400 uppercase">Historial Pagado</span>
                  <span className="text-sm font-bold text-emerald-600">{formatCurrency(spent)}</span>
                </div>
              )}

              <button 
                onClick={() => handleOpenStatement(customer)}
