import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { 
  Upload, 
  Type, 
  Sparkles, 
  Loader2, 
  Download, 
  X, 
  Image as ImageIcon,
  AlertCircle,
  RefreshCcw,
  Circle,
  Sticker,
  ZoomIn,
  ZoomOut,
  Move,
  Palette,
  Key
} from 'lucide-react';

export const TopperDesigner: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [text, setText] = useState('');
  const [themePrompt, setThemePrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [statusMessage, setStatusMessage] = useState('');
  const [hasPersonalKey, setHasPersonalKey] = useState(false);

  const [zoom, setZoom] = useState(1);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      if ((window as any).aistudio?.hasSelectedApiKey) {
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        setHasPersonalKey(hasKey);
      }
    };
    checkKey();
  }, []);

  const handleOpenKeySelector = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      await (window as any).aistudio.openSelectKey();
      setHasPersonalKey(true);
      setError(null);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setZoom(1);
        setPosition({ x: 0, y: 0 });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!image) return;
    setIsDragging(true);
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;
    setDragStart({ x: clientX - position.x, y: clientY - position.y });
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !image) return;
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;
    setPosition({
      x: clientX - dragStart.x,
      y: clientY - dragStart.y
    });
  };

  const handleMouseUp = () => setIsDragging(false);

  const getFramedImageBase64 = (): Promise<string | null> => {
    return new Promise((resolve) => {
      if (!image) {
        resolve(null);
        return;
      }
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      const img = imageRef.current;
      const container = containerRef.current;

      if (!ctx || !img || !container) {
        resolve(null);
        return;
      }

      canvas.width = 1024;
      canvas.height = 1024;
      ctx.fillStyle = 'white';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      const containerWidth = container.offsetWidth;
      const containerHeight = container.offsetHeight;
      const scaleFactor = 1024 / containerWidth;

      const imgRatio = img.naturalWidth / img.naturalHeight;
      const containerRatio = containerWidth / containerHeight;

      let baseWidth, baseHeight;
      if (imgRatio > containerRatio) {
        baseWidth = 1024;
        baseHeight = 1024 / imgRatio;
      } else {
        baseWidth = 1024 * imgRatio;
        baseHeight = 1024;
      }

      const finalWidth = baseWidth * zoom;
      const finalHeight = baseHeight * zoom;
      const x = (position.x * scaleFactor) + (1024 / 2) - (finalWidth / 2);
      const y = (position.y * scaleFactor) + (1024 / 2) - (finalHeight / 2);

      ctx.drawImage(img, x, y, finalWidth, finalHeight);
      resolve(canvas.toDataURL('image/jpeg', 0.85).split(',')[1]);
    });
  };

  const generateTopper = async () => {
    if (!image && !themePrompt) {
      setError("Por favor, sube una imagen o describe un tema.");
      return;
