    if (!result) return;
    const link = document.createElement('a');
    link.href = result;
    link.download = `topper_${text.replace(/\s+/g, '_') || 'diseno'}.png`;
    link.click();
  };

  const reset = () => {
    setImage(null);
    setResult(null);
    setText('');
    setError(null);
    setZoom(1);
    setPosition({ x: 0, y: 0 });
  };

  return (
    <div className="space-y-6 pb-20">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <Sticker className="text-indigo-600" /> Diseñador de Toppers Pro
          </h2>
          <p className="text-slate-500 text-sm">Crea diseños circulares profesionales basados en tus fotos.</p>
        </div>
        {!hasPersonalKey && (
          <button 
            onClick={handleOpenKeySelector}
            className="text-xs bg-amber-50 text-amber-700 border border-amber-200 px-3 py-1.5 rounded-full flex items-center gap-2 hover:bg-amber-100 transition-colors shadow-sm"
          >
            <Key size={14} /> Usar mi propia API Key (Sin límites)
          </button>
        )}
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <ImageIcon size={18} className="text-indigo-500" /> 1. Imagen de Referencia *
            </h3>

            {!image ? (
              <label className="flex flex-col items-center justify-center w-full h-64 border-2 border-dashed border-slate-300 rounded-2xl cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors">
                <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
                  <Upload className="w-8 h-8 mb-3 text-slate-400 mx-auto" />
                  <p className="text-sm text-slate-500">Sube la foto que quieres en el topper</p>
                  <p className="text-[10px] text-slate-400 mt-1">Sujeta y arrastra para encuadrar</p>
                </div>
                <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
              </label>
            ) : (
              <div className="space-y-4">
                <div 
                  ref={containerRef}
                  className="relative w-full h-64 bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden cursor-move touch-none"
                  onMouseDown={handleMouseDown}
                  onMouseMove={handleMouseMove}
                  onMouseUp={handleMouseUp}
                  onMouseLeave={handleMouseUp}
                  onTouchStart={handleMouseDown}
                  onTouchMove={handleMouseMove}
                  onTouchEnd={handleMouseUp}
                >
                  <img 
                    ref={imageRef}
                    src={image} 
                    alt="Ref" 
                    className="absolute max-w-none transition-transform duration-75 pointer-events-none select-none"
                    style={{
                      transform: `translate(${position.x}px, ${position.y}px) scale(${zoom})`,
                      left: '50%', top: '50%', marginLeft: '-50%', marginTop: '-50%',
                      width: '100%', height: '100%', objectFit: 'contain'
                    }}
                  />
                  <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                    <div className="w-[220px] h-[220px] rounded-full border-4 border-white/90 shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]"></div>
                  </div>
                  <button onClick={() => setImage(null)} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full shadow-lg"><X size={14} /></button>
                </div>
                <div className="flex items-center gap-3 bg-slate-50 p-3 rounded-xl border border-slate-100">
                   <ZoomOut size={16} className="text-slate-400" />
                   <input type="range" min="0.5" max="4" step="0.05" value={zoom} onChange={e => setZoom(parseFloat(e.target.value))} className="flex-1 accent-indigo-600" />
                   <ZoomIn size={16} className="text-slate-400" />
                </div>
              </div>
