          </button>
        </div>

        <div className="bg-slate-900 rounded-3xl p-8 flex flex-col items-center justify-center min-h-[500px] relative overflow-hidden shadow-2xl">
          {!result && !loading && (
            <div className="text-center space-y-4 z-10">
              <div className="w-20 h-20 bg-slate-800/50 backdrop-blur-sm rounded-full flex items-center justify-center mx-auto text-slate-600">
