                  <Loader2 size={64} className="text-indigo-500 animate-spin" />
                </div>
              </div>
              <p className="text-white font-bold animate-pulse tracking-wide">{statusMessage}</p>
            </div>
          )}

          {result && (
            <div className="space-y-8 w-full text-center z-10 animate-in zoom-in duration-500">
               <img src={result} alt="Topper" className="w-full aspect-square object-contain rounded-2xl shadow-2xl border-4 border-white/10 bg-white mx-auto max-w-sm" />
