      3. CENTERING: All elements, including the reference image and the circular text, must be perfectly centered within the circle.
      4. FRAME: Maintain the exact framing and characters from the provided image.
      5. BACKGROUND: The result must be a high-quality centered circle on a solid white square background.
      6. STYLE: Vibrant digital art, clean lines, professional finish for cake decoration.`;

      const parts: any[] = [
        { inlineData: { data: framedBase64, mimeType: 'image/jpeg' } },
        { text: prompt }
      ];

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: [{ role: 'user', parts }],
        config: { imageConfig: { aspectRatio: "1:1" } }
      });

      const candidate = response.candidates?.[0];
      if (candidate?.content?.parts) {
        const imagePart = candidate.content.parts.find(p => p.inlineData);
        if (imagePart?.inlineData) {
          setResult(`data:${imagePart.inlineData.mimeType};base64,${imagePart.inlineData.data}`);
          setStatusMessage('');
        } else {
          throw new Error("La IA no pudo procesar la imagen.");
        }
      }
    } catch (err: any) {
      console.error("Topper Error:", err);
      if (err.message?.includes("429")) {
        setError("Límite de cuota excedido. Intenta de nuevo en un minuto.");
      } else {
        setError("Error de conexión. Intenta de nuevo.");
      }
    } finally {
      setLoading(false);
    }
  };

  const downloadImage = () => {
    if (!result) return;
    const link = document.createElement('a');
    link.href = result;
    link.download = `topper_${text.replace(/\s+/g, '_') || 'diseno'}.png`;
    link.click();
  };

  const reset = () => {
    setImage(null);
    setResult(null);
    setText('');
    setError(null);
    setZoom(1);
    setPosition({ x: 0, y: 0 });
  };

  return (
    <div className="space-y-6 pb-20">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <Sticker className="text-indigo-600" /> Diseñador de Toppers Pro
          </h2>
          <p className="text-slate-500 text-sm">Crea diseños circulares con texto curvo inteligente.</p>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <ImageIcon size={18} className="text-indigo-500" /> 1. Imagen de Referencia *
            </h3>

            {!image ? (
              <label className="flex flex-col items-center justify-center w-full h-64 border-2 border-dashed border-slate-300 rounded-2xl cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors">
                <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
                  <Upload className="w-8 h-8 mb-3 text-slate-400 mx-auto" />
                  <p className="text-sm text-slate-500 font-medium">Sube la foto para tu topper</p>
                  <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-widest">Encuadra arrastrando la imagen</p>
                </div>
                <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
              </label>
            ) : (
              <div className="space-y-4">
                <div 
                  ref={containerRef}
                  className="relative w-full h-64 bg-slate-200 rounded-2xl border border-slate-300 overflow-hidden cursor-move touch-none shadow-inner"
                  onMouseDown={handleMouseDown}
                  onMouseMove={handleMouseMove}
                  onMouseUp={handleMouseUp}
                  onMouseLeave={handleMouseUp}
                  onTouchStart={handleMouseDown}
                  onTouchMove={handleMouseMove}
                  onTouchEnd={handleMouseUp}
                >
                  <img 
                    ref={imageRef}
                    src={image} 
                    alt="Ref" 
                    className="absolute max-w-none transition-transform duration-75 pointer-events-none select-none"
                    style={{
                      transform: `translate(${position.x}px, ${position.y}px) scale(${zoom})`,
                      left: '50%', top: '50%', marginLeft: '-50%', marginTop: '-50%',
                      width: '100%', height: '100%', objectFit: 'contain'
                    }}
