      ctx.fillRect(0, 0, canvas.width, canvas.height);

      const containerWidth = container.offsetWidth;
      const containerHeight = container.offsetHeight;
      const scaleFactor = 1024 / containerWidth;

      const imgRatio = img.naturalWidth / img.naturalHeight;
      const containerRatio = containerWidth / containerHeight;

      let baseWidth, baseHeight;
      if (imgRatio > containerRatio) {
        baseWidth = 1024;
        baseHeight = 1024 / imgRatio;
      } else {
        baseWidth = 1024 * imgRatio;
        baseHeight = 1024;
      }

      const finalWidth = baseWidth * zoom;
      const finalHeight = baseHeight * zoom;
      const x = (position.x * scaleFactor) + (1024 / 2) - (finalWidth / 2);
      const y = (position.y * scaleFactor) + (1024 / 2) - (finalHeight / 2);

      ctx.drawImage(img, x, y, finalWidth, finalHeight);
      resolve(canvas.toDataURL('image/jpeg', 0.8).split(',')[1]);
    });
  };

  const generateTopper = async () => {
